async function shouldKeepV1ChatOnLegacyIngredientPath(payload) {
  const message = pickFirstTrimmed(
    payload.message,
    payload.text,
    extractLastUserMessageFromChatRequestMessages(payload.messages),
  );
  const trimmedMessage = String(message || '').trim();
  if (!trimmedMessage || trimmedMessage.length > 64) return false;

  const action = normalizeIncomingChatAction(payload.action);
  const actionId =
    typeof action === 'string'
      ? action
      : pickFirstTrimmed(payload.action_id, action && action.action_id);
  if (
    looksLikeProductEvaluationIntentV2(trimmedMessage, actionId) ||
    looksLikeRecommendationRequest(trimmedMessage) ||
    looksLikeRoutineRequest(trimmedMessage, action) ||
    looksLikeSuitabilityRequest(trimmedMessage) ||
    looksLikeCompatibilityOrConflictQuestion(trimmedMessage) ||
    looksLikeWeatherOrEnvironmentQuestion(trimmedMessage)
  ) {
    return false;
  }

  if (
    looksLikeIngredientScienceIntent(trimmedMessage, action) ||
    messageContainsSpecificIngredientScienceTarget(trimmedMessage)
  ) {
    return true;
  }

  const requestLang = pickFirstTrimmed(
    payload.language,
    payload.lang,
    payload.locale,
    isPlainObject(payload.context) ? payload.context.locale : null,
  );
  const language = /^(zh|cn)/i.test(String(requestLang || '').trim()) ? 'CN' : 'EN';
  const entityMatch = ingredientEntityMatchFromText(trimmedMessage, language);
  if (entityMatch && entityMatch.entity_match_type && entityMatch.entity_match_type !== 'none') {
    return true;
  }

  const referenceMatch = await resolveIngredientReferenceRuntimeMatch(trimmedMessage, language);
  if (referenceMatch && referenceMatch.reference) return true;

  const signalMatch = await resolveIngredientSignalRuntimeMatch(trimmedMessage, language);
  if (signalMatch && signalMatch.signal) return true;
  return looksLikeIngredientSignalPhrase(trimmedMessage);
}

function looksLikeContextualRecoContinuationRequest(message = '', latestRecoContext = null) {
  const context = isPlainObject(latestRecoContext) ? latestRecoContext : null;
  if (!context) return false;
  if (String(context.intent || '').trim().toLowerCase() !== 'reco_products') return false;
  const text = String(message || '').trim().toLowerCase();
  if (!text) return false;
  if (
    looksLikeProductEvaluationIntentV2(text, '') ||
    looksLikeCompatibilityOrConflictQuestion(text) ||
    looksLikeWeatherOrEnvironmentQuestion(text)
  ) {
    return false;
  }
  return /\bwhat(?:'s| is)?\s+(?:next|should\s+i\s+(?:add|use|buy|get|try)|can\s+i\s+(?:add|use|buy|get|try))\b/i.test(text) ||
    /\b(?:add|use|buy|get|try)\s+(?:next|first|instead)\b/i.test(text) ||
    /\b(?:recommend|suggest)\b.{0,40}\b(?:product|step|option|routine)\b/i.test(text);
}

async function buildChatIntentContract(body) {
  const payload = isPlainObject(body) ? body : {};
  const action = normalizeIncomingChatAction(payload.action);
  const actionData = isPlainObject(action && action.data) ? action.data : {};
  const bodyParams = isPlainObject(payload.params) ? payload.params : {};
  const actionId =
    typeof action === 'string'
      ? action
      : pickFirstTrimmed(payload.action_id, action && action.action_id);
  const canDelegateActionToV2 = [
    'chip.action.add_to_routine',
    'chip.start.routine',
    'chip.start.travel',
    'chip_start_travel',
    'chip.start.ingredients.entry',
    'chip_start_ingredients_entry',
    'chip.start.ingredients',
    'chip_start_ingredients',
    'chip.action.analyze_product',
    'chip.start.dupes',
    'chip.action.dupe_compare',
  ].includes(actionId);
  const session = isPlainObject(payload.session) ? payload.session : {};
  const sessionMeta = isPlainObject(session.meta) ? session.meta : {};
  const sessionProfile = isPlainObject(session.profile) ? session.profile : {};
  const latestRecoContextFromSessionForContract = extractLatestRecoContextFromSession(session);
  const extractedSessionProfilePatch = extractProfilePatchFromSession(session);
  const sessionProfilePatch = isPlainObject(extractedSessionProfilePatch)
    ? extractedSessionProfilePatch
    : {};
  const extractedActionProfilePatch = extractProfilePatchFromSession({
    profile_patch: parseProfilePatchFromAction(action),
  });
  const actionProfilePatch = isPlainObject(extractedActionProfilePatch)
    ? extractedActionProfilePatch
    : {};
  const implicitAnalysisFollowupActionId = resolveImplicitAnalysisFollowupActionId({
    actionId,
    message: pickFirstTrimmed(payload.message, extractLastUserMessageFromChatRequestMessages(payload.messages)),
    sessionAnalysisContext: isPlainObject(sessionMeta.analysis_context) ? sessionMeta.analysis_context : null,
    lastAnalysis: sessionProfile.lastAnalysis || null,
    latestArtifactId: extractLatestArtifactIdFromSession(session),
  });

  if (
    payload.selected_option_index != null ||
    payload.clarification_id != null ||
    payload.requested_transition != null
  ) {
    return {
      contract_version: 'chat_intent_v1',
      surface: 'chat',
      ownership_domain: 'legacy_quarantine',
      request_class: 'legacy_compat',
      delegate_target: 'legacy_quarantine',
      should_search: false,
      reply_mode: 'followup',
    };
  }

  if (implicitAnalysisFollowupActionId) {
    return {
      contract_version: 'chat_intent_v1',
      surface: 'chat',
      ownership_domain: 'legacy_quarantine',
      request_class: 'legacy_compat',
      delegate_target: 'legacy_quarantine',
      should_search: false,
      reply_mode: 'followup',
    };
  }

  const message = canonicalizeGenericConcernQuery(
    pickFirstTrimmed(
      payload.message,
      payload.text,
      actionData.reply_text,
      actionData.replyText,
      extractLastUserMessageFromChatRequestMessages(payload.messages),
    ) || '',
  );
  const hasMessage = Boolean(message);
  const requestLang = pickFirstTrimmed(
    payload.language,
    payload.lang,
    payload.locale,
    isPlainObject(payload.context) ? payload.context.locale : null,
  );
  const language = /^(zh|cn)/i.test(String(requestLang || '').trim()) ? 'CN' : 'EN';
  const actionLabel =
    typeof payload.action_label === 'string' && payload.action_label.trim()
      ? payload.action_label.trim()
      : actionData && typeof actionData.label === 'string' && actionData.label.trim()
        ? actionData.label.trim()
        : null;
  const canonicalIntentForContract = hasMessage
    ? inferCanonicalIntent({
        message,
        actionId,
        actionLabel,
        language,
      })
    : null;

  if (canDelegateActionToV2) {
    return {
      contract_version: 'chat_intent_v1',
      surface: 'chat',
      ownership_domain: 'legacy_quarantine',
      request_class: 'action_delegate',
      delegate_target: 'v2',
      should_search: false,
      reply_mode: 'action',
    };
  }

  if (
    canonicalIntentForContract &&
    (
      canonicalIntentForContract.intent === INTENT_ENUM.TRAVEL_PLANNING ||
      canonicalIntentForContract.intent === INTENT_ENUM.WEATHER_ENV
    )
  ) {
    return {
      contract_version: 'chat_intent_v1',
      surface: 'chat',
      ownership_domain: 'travel_weather',
      request_class: canonicalIntentForContract.intent,
      delegate_target: 'v1',
      should_search: false,
      reply_mode: 'travel_weather',
      canonical_intent: {
        intent: canonicalIntentForContract.intent,
        source: canonicalIntentForContract.source || 'unknown',
        confidence: Number.isFinite(Number(canonicalIntentForContract.confidence))
          ? Number(canonicalIntentForContract.confidence)
          : null,
      },
    };
  }

  const typedRecoOwnershipKeepsV1Mainline =
    hasMessage ? shouldKeepTypedRecoRequestOnV1MainlinePolicy({ ...payload, message }) : false;
  const contextualRecoContinuationKeepsV1Mainline =
    hasMessage && looksLikeContextualRecoContinuationRequest(message, latestRecoContextFromSessionForContract);
  const beautyRecoTargetContext = hasMessage
    ? resolveRecommendationTargetContext({
        explicitStep: pickFirstTrimmed(
          payload.target_step,
          payload.targetStep,
          bodyParams.target_step,
          bodyParams.targetStep,
          actionData.target_step,
          actionData.targetStep,
        ),
        focus: pickFirstTrimmed(
          payload.focus,
          payload.goal,
          bodyParams.focus,
          bodyParams.goal,
          actionData.focus,
          actionData.goal,
        ),
        text: message,
        entryType: 'chat',
        profileSummary: {
          ...(sessionProfile && typeof sessionProfile === 'object' && !Array.isArray(sessionProfile)
            ? sessionProfile
            : {}),
          ...sessionProfilePatch,
          ...actionProfilePatch,
        },
      })
    : null;

  if ((payload.action != null || payload.action_id != null) && !canDelegateActionToV2) {
    const actionKeepsBeautyMainline =
      hasMessage &&
      isBeautyOwnedChatRecoRequest({
        typedRecoOwnershipKeepsV1Mainline,
        targetContext: beautyRecoTargetContext,
        message,
      });
    if (!actionKeepsBeautyMainline) {
      return {
        contract_version: 'chat_intent_v1',
        surface: 'chat',
        ownership_domain: 'legacy_quarantine',
        request_class: 'legacy_compat',
        delegate_target: 'legacy_quarantine',
        should_search: false,
        reply_mode: 'action',
      };
    }
  }

  const anchorProductId = pickFirstTrimmed(
    payload.anchor_product_id,
    payload.anchorProductId,
    bodyParams.anchor_product_id,
    bodyParams.anchorProductId,
    actionData.anchor_product_id,
    actionData.anchorProductId,
  );
  const anchorProductUrl = pickFirstTrimmed(
    payload.anchor_product_url,
    payload.anchorProductUrl,
    bodyParams.anchor_product_url,
    bodyParams.anchorProductUrl,
    actionData.anchor_product_url,
    actionData.anchorProductUrl,
  );
  const productAnchor =
    (isPlainObject(bodyParams.product_anchor) && Object.keys(bodyParams.product_anchor).length > 0)
      ? bodyParams.product_anchor
      : (isPlainObject(actionData.product_anchor) && Object.keys(actionData.product_anchor).length > 0)
        ? actionData.product_anchor
        : null;
  const shouldKeepFitCheckOnLegacy =
    hasMessage &&
    looksLikeProductEvaluationIntentV2(message, actionId) &&
    !productAnchor &&
    !hasMeaningfulFitCheckAnchor({
      message,
      anchorProductId,
      anchorProductUrl,
    });
  if (shouldKeepFitCheckOnLegacy) {
    return {
      contract_version: 'chat_intent_v1',
      surface: 'chat',
      ownership_domain: 'legacy_quarantine',
      request_class: 'legacy_compat',
      delegate_target: 'legacy_quarantine',
      should_search: false,
      reply_mode: 'fit_check',
    };
  }
  if (hasMessage && looksLikeCompatibilityOrConflictQuestion(message)) {
    return {
      contract_version: 'chat_intent_v1',
      surface: 'chat',
      ownership_domain: 'legacy_quarantine',
      request_class: 'legacy_compat',
      delegate_target: 'legacy_quarantine',
      should_search: false,
      reply_mode: 'compatibility',
    };
  }
  if (
    hasMessage &&
    (
      contextualRecoContinuationKeepsV1Mainline ||
      isBeautyOwnedChatRecoRequest({
        typedRecoOwnershipKeepsV1Mainline,
        targetContext: beautyRecoTargetContext,
        message,
      })
    )
  ) {
    return {
      contract_version: 'chat_intent_v1',
      surface: 'chat',
      ownership_domain: 'beauty_mainline',
      request_class: 'beauty_discovery',
      delegate_target: 'beauty_mainline',
      should_search: true,
      reply_mode:
        beautyRecoTargetContext?.step_aware_intent &&
        beautyRecoTargetContext?.resolved_target_step
          ? 'reco_step_aware'
          : 'reco_framework',
      primary_lane: 'beauty_discovery_mainline',
      target_context: beautyRecoTargetContext,
    };
  }
  if (hasMessage && AURORA_CHAT_CATALOG_AVAIL_FAST_PATH_ENABLED) {
    const availabilityIntent = detectCatalogAvailabilityIntent(message, requestLang || 'EN');
    const allowCatalogShortCircuit = AURORA_CATALOG_DOMAIN_GUARD_V1_ENABLED
      ? shouldAllowCatalogAvailabilityShortCircuit(message)
      : true;
    if (availabilityIntent && allowCatalogShortCircuit) {
      return {
        contract_version: 'chat_intent_v1',
        surface: 'chat',
        ownership_domain: 'legacy_quarantine',
        request_class: 'legacy_compat',
        delegate_target: 'legacy_quarantine',
        should_search: false,
        reply_mode: 'availability',
      };
    }
  }
  if (hasMessage && await shouldKeepV1ChatOnLegacyIngredientPath(payload)) {
    return {
      contract_version: 'chat_intent_v1',
      surface: 'chat',
      ownership_domain: 'legacy_quarantine',
      request_class: 'legacy_compat',
      delegate_target: 'legacy_quarantine',
      should_search: false,
      reply_mode: 'ingredient_advice',
    };
  }
  if (hasMessage) {
    if (looksLikeDiagnosisStart(message)) {
      return {
        contract_version: 'chat_intent_v1',
        surface: 'chat',
        ownership_domain: 'legacy_quarantine',
        request_class: 'legacy_compat',
        delegate_target: 'legacy_quarantine',
        should_search: false,
        reply_mode: 'diagnosis',
      };
    }
    if (looksLikeProgressCheckRequest(message, actionId)) {
      return {
        contract_version: 'chat_intent_v1',
        surface: 'chat',
        ownership_domain: 'legacy_quarantine',
        request_class: 'legacy_compat',
        delegate_target: 'legacy_quarantine',
        should_search: false,
        reply_mode: 'progress_check',
      };
    }
    if (typedRecoOwnershipKeepsV1Mainline) {
      return {
        contract_version: 'chat_intent_v1',
        surface: 'chat',
        ownership_domain: 'beauty_mainline',
        request_class: 'beauty_discovery',
        delegate_target: 'beauty_mainline',
        should_search: true,
        reply_mode: 'reco_step_aware',
        primary_lane: 'beauty_discovery_mainline',
        target_context: beautyRecoTargetContext,
      };
    }
  }
  if (hasMessage) {
    return {
      contract_version: 'chat_intent_v1',
      surface: 'chat',
      ownership_domain: 'legacy_quarantine',
      request_class: 'legacy_compat',
      delegate_target: 'v2',
      should_search: false,
      reply_mode: 'assistant',
    };
  }

  const hasV2Context = isPlainObject(payload.context);
  if (hasV2Context) {
    return {
      contract_version: 'chat_intent_v1',
      surface: 'chat',
      ownership_domain: 'legacy_quarantine',
      request_class: 'legacy_compat',
      delegate_target: 'v2',
      should_search: false,
      reply_mode: 'assistant',
    };
  }

  return {
    contract_version: 'chat_intent_v1',
    surface: 'chat',
    ownership_domain: 'legacy_quarantine',
    request_class: 'legacy_compat',
    delegate_target:
      Boolean(
        pickFirstTrimmed(
          payload.skill_id,
          payload.intent,
          payload.canonical_intent,
        ),
      ) || isPlainObject(payload.params)
        ? 'v2'
        : 'legacy_quarantine',
    should_search: false,
    reply_mode: 'assistant',
  };
}

async function shouldDelegateV1ChatToV2(body) {
  const chatIntentContract = await buildChatIntentContract(body);
  return chatIntentContract?.delegate_target === 'v2';
}

function shouldEarlyLockBeautyOwnedChatReco({
  ingressChatIntentContract = null,
  normalizedActionPayload = null,
  actionId = '',
  actionLabel = '',
  message = '',
  canonicalIntent = null,
} = {}) {
  const contract =
    ingressChatIntentContract && typeof ingressChatIntentContract === 'object' && !Array.isArray(ingressChatIntentContract)
      ? ingressChatIntentContract
      : null;
  if (!contract) return false;
  const canonicalIntentId = String(canonicalIntent && canonicalIntent.intent ? canonicalIntent.intent : '').trim();
  if (canonicalIntentId === INTENT_ENUM.TRAVEL_PLANNING || canonicalIntentId === INTENT_ENUM.WEATHER_ENV) return false;
  if (String(contract.delegate_target || '').trim().toLowerCase() !== 'beauty_mainline') return false;
  if (String(contract.request_class || '').trim().toLowerCase() !== 'beauty_discovery') return false;
  return Boolean(String(message || '').trim());
}

function extractLastUserMessageFromChatRequestMessages(messages) {
  const list = Array.isArray(messages) ? messages : [];
  for (let index = list.length - 1; index >= 0; index -= 1) {
    const row = list[index];
    if (!isPlainObject(row)) continue;
    const role = String(row.role || '').trim().toLowerCase();
    if (role && role !== 'user') continue;
    const content = pickFirstTrimmed(row.content, row.text, row.message);
    if (content) return content;
  }
  return null;
}

function extractPrimaryChatRequestMessage(payload, normalizedActionPayload = null) {
  const body = isPlainObject(payload) ? payload : {};
  const actionReplyText = extractReplyTextFromAction(normalizedActionPayload);
  const actionLabelFromPayload =
    typeof body.action_label === 'string' && body.action_label.trim()
      ? body.action_label.trim()
      : normalizedActionPayload && typeof normalizedActionPayload === 'string' && normalizedActionPayload.trim()
        ? normalizedActionPayload.trim()
        : null;
  return canonicalizeGenericConcernQuery(
    String(body.message || body.query || '').trim() ||
    actionReplyText ||
    actionLabelFromPayload ||
    pickFirstTrimmed(extractLastUserMessageFromChatRequestMessages(body.messages)) ||
    '',
  );
}

function normalizeImplicitAnalysisFollowupPrompt(value) {
  return String(value || '')
    .trim()
    .toLowerCase()
    .replace(/[`"'“”‘’]/g, '')
    .replace(/[^a-z0-9\u4e00-\u9fff]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

const IMPLICIT_DEEP_DIVE_PROMPT_TOKENS = new Set(
  [
    'Tell me more about my skin',
    'Dive deeper into skin',
    'Dive deeper into my skin',
    'Deep dive into skin',
    '深入了解我的皮肤状态',
    '告诉我更多关于我的皮肤',
    '进一步分析我的皮肤',
  ].map((item) => normalizeImplicitAnalysisFollowupPrompt(item)),
);

function looksLikeImplicitDeepDivePrompt(value) {
  const token = normalizeImplicitAnalysisFollowupPrompt(value);
  return Boolean(token) && IMPLICIT_DEEP_DIVE_PROMPT_TOKENS.has(token);
}

function hasMeaningfulAnalysisStorySnapshot(value) {
  if (!isPlainObject(value)) return false;
  if (Array.isArray(value.priority_findings) && value.priority_findings.filter(Boolean).length > 0) return true;
  if (rankAnalysisConfidenceLevel(value && value.confidence_overall && value.confidence_overall.level) > 0) return true;
  if (pickFirstTrimmed(value && value.ui_card_v1 && value.ui_card_v1.headline)) return true;
  if (Array.isArray(value.am_plan) && value.am_plan.filter(Boolean).length > 0) return true;
  if (Array.isArray(value.pm_plan) && value.pm_plan.filter(Boolean).length > 0) return true;
  return false;
}

function normalizeAnalysisStorySnapshotCandidate(value) {
  if (!hasMeaningfulAnalysisStorySnapshot(value)) return null;
  return coerceAnalysisStoryV2(value, value);
}

function hasReusableAnalysisContext({
  sessionAnalysisContext,
  lastAnalysis,
  latestArtifactId,
} = {}) {
  const context = isPlainObject(sessionAnalysisContext) ? sessionAnalysisContext : {};
  const analysis = isPlainObject(lastAnalysis) ? lastAnalysis : {};
  if (hasMeaningfulAnalysisStorySnapshot(context.analysis_story_snapshot)) return true;
  if (normalizeAnalysisPhotoRefs(context.photo_refs).length > 0) return true;
  if (hasMeaningfulAnalysisStorySnapshot(analysis.analysis_story_snapshot)) return true;
  if (Array.isArray(analysis.priority_findings) && analysis.priority_findings.filter(Boolean).length > 0) return true;
  if (pickFirstTrimmed(analysis && analysis.skin_profile && analysis.skin_profile.skin_type_tendency, analysis && analysis.skin_profile && analysis.skin_profile.skin_type)) return true;
  if (String(latestArtifactId || '').trim()) return true;
  return false;
}

function resolveImplicitAnalysisFollowupActionId({
  actionId,
  message,
  sessionAnalysisContext,
  lastAnalysis,
  latestArtifactId,
} = {}) {
  const normalizedActionId = String(actionId || '').trim();
  if (normalizedActionId && ANALYSIS_FOLLOWUP_ACTION_IDS.has(normalizedActionId)) {
    return normalizedActionId;
  }
  if (!looksLikeImplicitDeepDivePrompt(message)) return null;
  if (
    hasReusableAnalysisContext({
      sessionAnalysisContext,
      lastAnalysis,
      latestArtifactId,
    })
  ) {
    return 'chip.aurora.next_action.deep_dive_skin';
  }
  return 'chip.aurora.next_action.deep_dive_skin';
}
