function parseClarificationIdFromActionId(actionId) {
  const id = String(actionId || '').trim();
  if (!id) return '';
  const parts = id.split('.');
  if (parts.length < 4) return '';
  if (parts[0] !== 'chip' || parts[1] !== 'clarify') return '';
  return String(parts[2] || '').trim();
}

function parseClarificationReplyFromActionId(actionId) {
  const id = String(actionId || '').trim();
  if (!id) return '';
  const parts = id.split('.');
  if (parts.length < 4) return '';
  if (parts[0] !== 'chip' || parts[1] !== 'clarify') return '';
  return String(parts.slice(3).join(' ') || '')
    .replace(/_/g, ' ')
    .trim();
}

function stableHashBase36(raw) {
  const input = String(raw == null ? '' : raw);
  const hex = crypto.createHash('sha1').update(input).digest('hex');
  return BigInt(`0x${hex}`).toString(36);
}

function estimateTokenCountFromChars(value) {
  const chars = String(value || '').length;
  if (!chars) return 0;
  return Math.max(1, Math.ceil(chars / 4));
}

function safeStructuredCloneJson(value) {
  if (value == null) return value;
  try {
    return JSON.parse(JSON.stringify(value));
  } catch (_err) {
    return null;
  }
}

function buildRecoPromptTrace({ templateId, query, latencyMs, cacheHit, provider = 'aurora', model = null, coverage = null } = {}) {
  const queryText = String(query || '');
  const hash = queryText ? crypto.createHash('sha1').update(queryText).digest('hex').slice(0, 16) : '';
  return {
    template_id: String(templateId || '').trim() || 'unknown',
    prompt_hash: hash || null,
    prompt_chars: queryText.length,
    token_est: estimateTokenCountFromChars(queryText),
    latency_ms: Number.isFinite(Number(latencyMs)) ? Math.max(0, Math.trunc(Number(latencyMs))) : null,
    cache_hit: Boolean(cacheHit),
    provider: String(provider || '').trim() || null,
    model: String(model || '').trim() || null,
    ...(coverage && typeof coverage === 'object' && !Array.isArray(coverage) ? { coverage } : {}),
  };
}

function buildRecoLlmTraceRef(llmTrace) {
  if (!llmTrace || typeof llmTrace !== 'object' || Array.isArray(llmTrace)) return null;
  const templateId = String(llmTrace.template_id || '').trim();
  const promptHash = String(llmTrace.prompt_hash || '').trim();
  const latencyMs = Number(llmTrace.latency_ms);
  return {
    template_id: templateId || null,
    prompt_hash: promptHash || null,
    ...(Number.isFinite(latencyMs) ? { latency_ms: Math.max(0, Math.trunc(latencyMs)) } : {}),
  };
}

function hasEmptyStructuredRecommendations(value) {
  return Boolean(
    value &&
      typeof value === 'object' &&
      !Array.isArray(value) &&
      Array.isArray(value.recommendations) &&
      value.recommendations.length === 0
  );
}

function normalizeRecoFailureClass(value) {
  const token = String(value || '').trim().toLowerCase();
  if (
    token === 'timeout' ||
    token === 'provider_error' ||
    token === 'policy_skip' ||
    token === 'precheck_fail' ||
    token === 'empty_structured' ||
    token === 'schema_invalid'
  ) {
    return token;
  }
  return '';
}

function normalizeRecoContractTelemetryReason(value) {
  const token = String(value || '').trim().toLowerCase();
  if (
    token === 'timeout_degraded' ||
    token === 'upstream_schema_invalid' ||
    token === 'prompt_contract_mismatch' ||
    token === 'reco_mainline_empty' ||
    token === 'empty_structured' ||
    token === 'catalog_transient_failure'
  ) {
    return token;
  }
  return '';
}

function normalizeRecoProductsEmptyReason(value) {
  return String(value || '').trim().toLowerCase();
}

function allowsContextualRecoMainlineEmptyOverride(productsEmptyReason) {
  const normalizedReason = normalizeRecoProductsEmptyReason(productsEmptyReason);
  return (
    !normalizedReason
    || normalizedReason === 'artifact_missing'
    || normalizedReason === 'empty_structured'
  );
}

function sanitizeRecoClientVisibleToken(value, { allowDefault = false } = {}) {
  const token = String(value || '').trim().toLowerCase();
  if (!token) return '';
  if (token === 'none') return '';
  if (!allowDefault && token === 'default') return '';
  return token;
}

function hasMeaningfulRecoEffectiveFailureClass(value) {
  const token = normalizeRecoEffectiveFailureClass(value);
  return Boolean(token && token !== 'none');
}

function normalizeRecoEffectiveFailureClass(value) {
  const token = String(value || '').trim().toLowerCase();
  if (
    token === 'none' ||
    token === 'intent_resolution_failure' ||
    token === 'context_resolution_failure' ||
    token === 'prompt_contract_mismatch' ||
    token === 'schema_invalid' ||
    token === 'upstream_timeout' ||
    token === 'upstream_timeout_primary_role' ||
    token === 'upstream_dependency_failure' ||
    token === 'catalog_contract_invalid' ||
    token === 'no_valid_catalog_hit_for_target' ||
    token === 'no_viable_candidates_for_target' ||
    token === 'no_recall_from_planned_sources' ||
    token === 'filtered_after_recall' ||
    token === 'weak_viable_pool' ||
    token === 'selector_disagreement_no_safe_winner' ||
    token === 'post_processing_eliminated_candidates'
  ) {
    return token;
  }
  return '';
}

function normalizeRecoFailureOrigin(value) {
  const token = String(value || '').trim().toLowerCase();
  if (token === 'user_input' || token === 'internal_contract' || token === 'upstream_dependency' || token === 'none') {
    return token;
  }
  return 'none';
}

function normalizeRecoPresentationMode(value) {
  const token = String(value || '').trim().toLowerCase();
  if (token === 'full_llm' || token === 'deterministic_degraded') return token;
  return '';
}

function normalizeRecoSuccessMode(value) {
  const token = String(value || '').trim().toLowerCase();
  if (token === 'full_success' || token === 'degraded_success') return token;
  return '';
}

function normalizeRecoViablePoolStrength(value) {
  const token = String(value || '').trim().toLowerCase();
  if (token === 'strong' || token === 'weak' || token === 'empty') return token;
  return '';
}

function normalizeRecoTargetFidelityLevel(value) {
  const token = String(value || '').trim().toLowerCase();
  if (token === 'satisfied' || token === 'partial' || token === 'failed') return token;
  return '';
}

function sanitizeRecoClientVisibleFailureClass(value) {
  const effective = normalizeRecoEffectiveFailureClass(value);
  if (effective && effective !== 'none') return effective;
  return normalizeRecoFailureClass(value);
}

function sanitizeRecoClientVisibleFailureOrigin(value) {
  const token = normalizeRecoFailureOrigin(value);
  return token === 'none' ? '' : token;
}

function resolveRecoFailureReasonContract({ payload, contract, fallback = 'artifact_missing', allowEmpty = false } = {}) {
  const payloadObj = isPlainObject(payload) ? payload : {};
  const contractObj = isPlainObject(contract) ? contract : {};
  const meta = isPlainObject(payloadObj.recommendation_meta) ? payloadObj.recommendation_meta : {};
  const primaryReason = sanitizeRecoClientVisibleToken(
    pickFirstTrimmed(contractObj.primary_failure_reason, meta.primary_failure_reason),
  );
  const surfaceReason = sanitizeRecoClientVisibleToken(
    pickFirstTrimmed(contractObj.surface_reason, meta.surface_reason),
  );
  const telemetryReason = sanitizeRecoClientVisibleToken(
    pickFirstTrimmed(contractObj.telemetry_failure_reason, meta.telemetry_failure_reason),
  );
  const productsEmptyReasonRaw = normalizeRecoProductsEmptyReason(
    pickFirstTrimmed(
      payloadObj.products_empty_reason,
      contractObj.products_empty_reason,
      meta.products_empty_reason,
    ),
  );
  const productsEmptyReason = sanitizeRecoClientVisibleToken(productsEmptyReasonRaw);
  if (surfaceReason) {
    return {
      userFacingReason: surfaceReason,
      primaryReason: primaryReason || surfaceReason,
      telemetryReason,
      surfaceReason,
      productsEmptyReason: productsEmptyReason || surfaceReason,
    };
  }
  if (productsEmptyReasonRaw === 'strict_filter_fallback_only') {
    return {
      userFacingReason: 'strict_filter_dropped',
      primaryReason: primaryReason || 'strict_filter_dropped',
      telemetryReason,
      surfaceReason: 'strict_filter_dropped',
      productsEmptyReason: 'strict_filter_fallback_only',
    };
  }
  if (productsEmptyReason) {
    return {
      userFacingReason: productsEmptyReason,
      primaryReason: primaryReason || productsEmptyReason,
      telemetryReason,
      surfaceReason: productsEmptyReason,
      productsEmptyReason,
    };
  }
  if (allowEmpty) {
    return {
      userFacingReason: '',
      primaryReason: '',
      telemetryReason,
      surfaceReason: '',
      productsEmptyReason: '',
    };
  }
  const fallbackReason = primaryReason || sanitizeRecoClientVisibleToken(fallback);
  const canonicalFallbackReason = fallbackReason || 'artifact_missing';
  return {
    userFacingReason: canonicalFallbackReason,
    primaryReason: canonicalFallbackReason,
    telemetryReason,
    surfaceReason: canonicalFallbackReason,
    productsEmptyReason: canonicalFallbackReason,
  };
}

function getRecoMetaScalar(meta, key) {
  if (!isPlainObject(meta)) return null;
  if (typeof meta[key] === 'boolean') return meta[key];
  if (meta[key] == null) return null;
  const numeric = Number(meta[key]);
  if (Number.isFinite(numeric)) return numeric;
  const text = String(meta[key]).trim();
  return text || null;
}

function extractRecoOutcomeContractArgsFromPayload(payload, fallback = null) {
  const payloadObj = isPlainObject(payload) ? payload : {};
  const meta = isPlainObject(payloadObj.recommendation_meta) ? payloadObj.recommendation_meta : {};
  const fallbackObj = isPlainObject(fallback) ? fallback : {};
  const hasRecommendations = Array.isArray(payloadObj.recommendations) && payloadObj.recommendations.length > 0;
  const explicitEmptyReason = normalizeRecoProductsEmptyReason(
    pickFirstTrimmed(
      payloadObj.products_empty_reason,
      meta.products_empty_reason,
      payloadObj.failure_reason,
      meta.primary_failure_reason,
      meta.surface_reason,
      fallbackObj.products_empty_reason,
      fallbackObj.primary_failure_reason,
      fallbackObj.surface_reason,
    ),
  );
  const suppressInheritedSuccessState = !hasRecommendations && Boolean(explicitEmptyReason);
  const resolvedTargetStep = pickFirstTrimmed(
    typeof meta.resolved_target_step === 'string' ? meta.resolved_target_step : '',
    typeof fallbackObj.resolved_target_step === 'string' ? fallbackObj.resolved_target_step : '',
  );
  const resolvedTargetConfidence = String(
    pickFirstTrimmed(
      typeof meta.resolved_target_step_confidence === 'string' ? meta.resolved_target_step_confidence : '',
      typeof fallbackObj.resolved_target_step_confidence === 'string' ? fallbackObj.resolved_target_step_confidence : '',
      'none',
    ),
  ).trim().toLowerCase();
  const stepAwareSignal = Boolean(resolvedTargetStep) && (resolvedTargetConfidence === 'high' || resolvedTargetConfidence === 'medium');
  const toCount = (value, fallbackValue = null) => {
    if (Number.isFinite(Number(value))) return Math.max(0, Math.trunc(Number(value)));
    if (Number.isFinite(Number(fallbackValue))) return Math.max(0, Math.trunc(Number(fallbackValue)));
    return null;
  };
  const terminalSuccessRaw = getRecoMetaScalar(meta, 'terminal_success');
  if (!stepAwareSignal && !hasMeaningfulRecoEffectiveFailureClass(fallbackObj.effective_failure_class || fallbackObj.failure_class)) {
    return {
      effectiveFailureClass: null,
      failureOrigin: 'none',
      terminalSuccess: null,
      viablePoolStrength: null,
      targetFidelityLevel: null,
      presentationMode: null,
      successMode: null,
      preLlmSelectedCandidateCount: null,
      finalSelectedCandidateCount: null,
      postGuardrailCount: null,
    };
  }
  const normalizedEffectiveFailureClass = normalizeRecoEffectiveFailureClass(
    pickFirstTrimmed(
      typeof meta.effective_failure_class === 'string' ? meta.effective_failure_class : '',
      typeof fallbackObj.effective_failure_class === 'string' ? fallbackObj.effective_failure_class : '',
      typeof fallbackObj.failure_class === 'string' ? fallbackObj.failure_class : '',
    ),
  );
  return {
    effectiveFailureClass: hasMeaningfulRecoEffectiveFailureClass(normalizedEffectiveFailureClass)
      ? normalizedEffectiveFailureClass
      : null,
    failureOrigin: normalizeRecoFailureOrigin(
      pickFirstTrimmed(
        typeof meta.failure_origin === 'string' ? meta.failure_origin : '',
        typeof fallbackObj.failure_origin === 'string' ? fallbackObj.failure_origin : '',
      ),
    ),
    terminalSuccess:
      suppressInheritedSuccessState
        ? false
        : typeof terminalSuccessRaw === 'boolean'
        ? terminalSuccessRaw
        : typeof fallbackObj.terminal_success === 'boolean'
          ? fallbackObj.terminal_success
          : null,
    viablePoolStrength: normalizeRecoViablePoolStrength(
      pickFirstTrimmed(
        typeof meta.viable_pool_strength === 'string' ? meta.viable_pool_strength : '',
        suppressInheritedSuccessState ? '' : (typeof fallbackObj.viable_pool_strength === 'string' ? fallbackObj.viable_pool_strength : ''),
      ),
    ) && (
      !suppressInheritedSuccessState
      || ['weak', 'empty'].includes(
        normalizeRecoViablePoolStrength(
          pickFirstTrimmed(
            typeof meta.viable_pool_strength === 'string' ? meta.viable_pool_strength : '',
            '',
          ),
        ) || normalizeRecoViablePoolStrength(
          pickFirstTrimmed(
            suppressInheritedSuccessState ? '' : (typeof fallbackObj.viable_pool_strength === 'string' ? fallbackObj.viable_pool_strength : ''),
            '',
          ),
        ),
      )
    )
      ? normalizeRecoViablePoolStrength(
        pickFirstTrimmed(
          typeof meta.viable_pool_strength === 'string' ? meta.viable_pool_strength : '',
          suppressInheritedSuccessState ? '' : (typeof fallbackObj.viable_pool_strength === 'string' ? fallbackObj.viable_pool_strength : ''),
        ),
      ) || null
      : null,
    targetFidelityLevel: normalizeRecoTargetFidelityLevel(
      pickFirstTrimmed(
        typeof meta.target_fidelity_level === 'string' ? meta.target_fidelity_level : '',
        suppressInheritedSuccessState ? '' : (typeof fallbackObj.target_fidelity_level === 'string' ? fallbackObj.target_fidelity_level : ''),
      ),
    ) && (
      !suppressInheritedSuccessState
      || ['partial', 'failed'].includes(
        normalizeRecoTargetFidelityLevel(
          pickFirstTrimmed(
            typeof meta.target_fidelity_level === 'string' ? meta.target_fidelity_level : '',
            '',
          ),
        ) || normalizeRecoTargetFidelityLevel(
          pickFirstTrimmed(
            suppressInheritedSuccessState ? '' : (typeof fallbackObj.target_fidelity_level === 'string' ? fallbackObj.target_fidelity_level : ''),
            '',
          ),
        ),
      )
    )
      ? normalizeRecoTargetFidelityLevel(
        pickFirstTrimmed(
          typeof meta.target_fidelity_level === 'string' ? meta.target_fidelity_level : '',
          suppressInheritedSuccessState ? '' : (typeof fallbackObj.target_fidelity_level === 'string' ? fallbackObj.target_fidelity_level : ''),
        ),
      ) || null
      : null,
    presentationMode: suppressInheritedSuccessState
      ? null
      : (normalizeRecoPresentationMode(
        pickFirstTrimmed(
          typeof meta.presentation_mode === 'string' ? meta.presentation_mode : '',
          typeof fallbackObj.presentation_mode === 'string' ? fallbackObj.presentation_mode : '',
        ),
      ) || null),
    successMode: suppressInheritedSuccessState
      ? null
      : (normalizeRecoSuccessMode(
        pickFirstTrimmed(
          typeof meta.success_mode === 'string' ? meta.success_mode : '',
          typeof fallbackObj.success_mode === 'string' ? fallbackObj.success_mode : '',
        ),
      ) || null),
    preLlmSelectedCandidateCount: toCount(meta.pre_llm_selected_candidate_count, fallbackObj.pre_llm_selected_candidate_count),
    finalSelectedCandidateCount: toCount(meta.final_selected_candidate_count, fallbackObj.final_selected_candidate_count),
    postGuardrailCount: toCount(meta.post_guardrail_count, fallbackObj.post_guardrail_count),
  };
}

function deriveRecoCatalogDependencyFailure(catalogDebug) {
  const debugObj = isPlainObject(catalogDebug) ? catalogDebug : null;
  if (!debugObj) return { effective_failure_class: '', failure_origin: 'none' };
  const candidateDropStage = String(debugObj.candidate_drop_stage || '').trim().toLowerCase();
  const skippedReason = String(debugObj.skipped_reason || '').trim().toLowerCase();
  const primaryStageTimeoutClass = String(debugObj.primary_stage_timeout_class || '').trim().toLowerCase();
  if (skippedReason === 'disabled' || skippedReason === 'pivota_backend_not_configured') {
    return {
      effective_failure_class: 'catalog_contract_invalid',
      failure_origin: 'internal_contract',
    };
  }
  if (skippedReason === 'fail_fast_open') {
    return {
      effective_failure_class: 'upstream_timeout',
      failure_origin: 'upstream_dependency',
    };
  }
  const queryCount = Number.isFinite(Number(debugObj.executed_query_count))
    ? Math.max(0, Math.trunc(Number(debugObj.executed_query_count)))
    : Number.isFinite(Number(debugObj.query_count))
      ? Math.max(0, Math.trunc(Number(debugObj.query_count)))
      : 0;
  const okCount = Number.isFinite(Number(debugObj.ok_count)) ? Math.max(0, Math.trunc(Number(debugObj.ok_count))) : 0;
  const statusCounts = isPlainObject(debugObj.status_counts) ? debugObj.status_counts : {};
  const stageTimeoutCounts = isPlainObject(debugObj.stage_timeout_counts) ? debugObj.stage_timeout_counts : {};
  const timeoutCount = Number.isFinite(Number(statusCounts.upstream_timeout)) ? Math.max(0, Math.trunc(Number(statusCounts.upstream_timeout))) : 0;
  const upstreamErrorCount = Number.isFinite(Number(statusCounts.upstream_error)) ? Math.max(0, Math.trunc(Number(statusCounts.upstream_error))) : 0;
  const rateLimitedCount = Number.isFinite(Number(statusCounts.rate_limited)) ? Math.max(0, Math.trunc(Number(statusCounts.rate_limited))) : 0;
  const timeoutCountByStage = Object.values(stageTimeoutCounts).reduce((sum, value) => {
    return sum + (Number.isFinite(Number(value)) ? Math.max(0, Math.trunc(Number(value))) : 0);
  }, 0);
  if (candidateDropStage === 'upstream_timeout_primary_role' || primaryStageTimeoutClass === 'transient_timeout') {
    return {
      effective_failure_class: 'upstream_timeout_primary_role',
      failure_origin: 'upstream_dependency',
    };
  }
  if (candidateDropStage === 'upstream_timeout') {
    return {
      effective_failure_class: 'upstream_timeout',
      failure_origin: 'upstream_dependency',
    };
  }
  if (candidateDropStage === 'no_recall_from_planned_sources') {
    return {
      effective_failure_class: 'no_recall_from_planned_sources',
      failure_origin: 'user_input',
    };
  }
  if (candidateDropStage === 'no_valid_catalog_hit_for_target') {
    return {
      effective_failure_class: 'no_valid_catalog_hit_for_target',
      failure_origin: 'upstream_dependency',
    };
  }
  if (candidateDropStage === 'filtered_after_recall' || candidateDropStage === 'weak_viable_pool') {
    return {
      effective_failure_class: 'weak_viable_pool',
      failure_origin: 'user_input',
    };
  }
  if (queryCount > 0 && okCount === 0) {
    if (Math.max(timeoutCount, timeoutCountByStage) >= queryCount) {
      return {
        effective_failure_class: 'upstream_timeout',
        failure_origin: 'upstream_dependency',
      };
    }
    if ((upstreamErrorCount + rateLimitedCount) >= queryCount) {
      return {
        effective_failure_class: 'upstream_dependency_failure',
        failure_origin: 'upstream_dependency',
      };
    }
  }
  return { effective_failure_class: '', failure_origin: 'none' };
}

function resolveRecoEffectiveFailure({
  targetContext,
  viablePoolState,
  catalogDebug,
  intentResolutionFailed = false,
  contextResolutionFailureOrigin = 'none',
  postGuardrailCount = null,
} = {}) {
  const poolState = isPlainObject(viablePoolState) ? viablePoolState : {};
  const catalogFailure = deriveRecoCatalogDependencyFailure(catalogDebug);
  const preLlmSelectedCandidateCount = Number.isFinite(Number(poolState.pre_llm_selected_candidate_count))
    ? Math.max(0, Math.trunc(Number(poolState.pre_llm_selected_candidate_count)))
    : Number.isFinite(Number(poolState.selected_candidate_count))
      ? Math.max(0, Math.trunc(Number(poolState.selected_candidate_count)))
      : 0;
  const finalCount = Number.isFinite(Number(postGuardrailCount))
    ? Math.max(0, Math.trunc(Number(postGuardrailCount)))
    : Number.isFinite(Number(poolState.final_selected_candidate_count))
      ? Math.max(0, Math.trunc(Number(poolState.final_selected_candidate_count)))
      : preLlmSelectedCandidateCount;
  if (preLlmSelectedCandidateCount > 0 && finalCount === 0) {
    return {
      effective_failure_class: 'post_processing_eliminated_candidates',
      failure_origin: 'internal_contract',
    };
  }
  if (intentResolutionFailed) {
    return {
      effective_failure_class: 'intent_resolution_failure',
      failure_origin: 'user_input',
    };
  }
  if (normalizeRecoFailureOrigin(contextResolutionFailureOrigin) !== 'none') {
    return {
      effective_failure_class: 'context_resolution_failure',
      failure_origin: normalizeRecoFailureOrigin(contextResolutionFailureOrigin),
    };
  }
  if (catalogFailure.effective_failure_class) {
    return catalogFailure;
  }
  if (normalizeRecoViablePoolStrength(poolState.viable_pool_strength) === 'weak' || poolState.weak_viable_pool === true) {
    return {
      effective_failure_class: 'weak_viable_pool',
      failure_origin: 'user_input',
    };
  }
  if (targetContext?.step_aware_intent && preLlmSelectedCandidateCount <= 0) {
    return {
      effective_failure_class: 'no_viable_candidates_for_target',
      failure_origin: 'user_input',
    };
  }
  return {
    effective_failure_class: 'none',
    failure_origin: 'none',
  };
}

function resolveRecoCentralOutcome({
  entryType = 'chat',
  effectiveFailureClass,
  failureOrigin = 'none',
  terminalSuccess = false,
  viablePoolStrength = '',
  targetFidelityLevel = '',
  presentationMode = '',
  successMode = '',
  sourceMode = '',
  groundingStatus = '',
} = {}) {
  const normalizedEffective = normalizeRecoEffectiveFailureClass(effectiveFailureClass);
  const effective = normalizedEffective === 'none' ? '' : normalizedEffective;
  const origin = normalizeRecoFailureOrigin(failureOrigin);
  const normalizedSuccessMode = normalizeRecoSuccessMode(successMode)
    || (terminalSuccess ? (normalizeRecoPresentationMode(presentationMode) === 'deterministic_degraded' ? 'degraded_success' : 'full_success') : '');
  const normalizedPresentationMode = normalizeRecoPresentationMode(presentationMode)
    || (normalizedSuccessMode === 'degraded_success' ? 'deterministic_degraded' : terminalSuccess ? 'full_llm' : '');
  const normalizedSourceMode = String(sourceMode || '').trim().toLowerCase();
  const normalizedGroundingStatus = normalizeRecoGroundingStatus(groundingStatus);
  if (terminalSuccess) {
    const successStatus = normalizedGroundingStatus === 'partially_grounded'
      ? 'partially_grounded'
      : normalizedGroundingStatus === 'ungrounded'
        ? 'ungrounded_success'
        : normalizedSourceMode === 'catalog_grounded' || normalizedSourceMode === 'catalog_transient_fallback'
          ? 'grounded_success'
          : 'grounded_success';
    return {
      surface_kind: 'success',
      surface_reason: null,
      mainline_status: successStatus,
      telemetry_reason: null,
      products_empty_reason: null,
      user_fixable: false,
      effective_failure_class: 'none',
      failure_origin: 'none',
      presentation_mode: normalizedPresentationMode || 'full_llm',
      success_mode: normalizedSuccessMode || 'full_success',
    };
  }
  if (
    origin === 'user_input' &&
    (
      effective === 'intent_resolution_failure'
      || effective === 'context_resolution_failure'
      || effective === 'no_viable_candidates_for_target'
      || effective === 'weak_viable_pool'
      || effective === 'no_recall_from_planned_sources'
      || effective === 'filtered_after_recall'
    )
  ) {
    return {
      surface_kind: entryType === 'chat' ? 'clarify' : 'needs_more_context',
      surface_reason: effective === 'filtered_after_recall' ? 'weak_viable_pool' : effective,
      mainline_status: 'needs_more_context',
      telemetry_reason: effective === 'filtered_after_recall' ? 'weak_viable_pool' : effective,
      products_empty_reason: effective === 'filtered_after_recall' ? 'weak_viable_pool' : effective,
      user_fixable: true,
      effective_failure_class: effective === 'filtered_after_recall' ? 'weak_viable_pool' : effective,
      failure_origin: origin,
      presentation_mode: normalizedPresentationMode || null,
      success_mode: normalizedSuccessMode || null,
    };
  }
  const safeFailureStatus =
    effective === 'upstream_timeout' || effective === 'upstream_timeout_primary_role'
      ? 'upstream_timeout'
      : 'severe_parse_or_prompt_failure';
  const telemetryReason = effective === 'schema_invalid'
    ? 'upstream_schema_invalid'
    : effective || null;
  return {
    surface_kind: 'safe_failure',
    surface_reason: effective || 'artifact_missing',
    mainline_status: safeFailureStatus,
    telemetry_reason: telemetryReason,
    products_empty_reason: effective || 'artifact_missing',
    user_fixable: false,
    effective_failure_class: effective || 'none',
    failure_origin: origin,
    presentation_mode: normalizedPresentationMode || null,
    success_mode: normalizedSuccessMode || null,
  };
}

function deriveRecoEmptyReason(payload, contract) {
  const payloadObj = isPlainObject(payload) ? payload : {};
  const contractObj = isPlainObject(contract) ? contract : {};
  const recommendations = Array.isArray(payloadObj.recommendations) ? payloadObj.recommendations : [];
  if (recommendations.length > 0) return '';
  return resolveRecoFailureReasonContract({ payload: payloadObj, contract: contractObj }).userFacingReason || 'artifact_missing';
}

function restorePlanOnlyRecommendations(payload, { sourceMode = '' } = {}) {
  if (!isPlainObject(payload)) return payload;
  const nextPayload = { ...payload };
  const currentRecommendations = Array.isArray(nextPayload.recommendations) ? nextPayload.recommendations : [];
  if (currentRecommendations.length > 0) return nextPayload;
  if (normalizeRecoProductsEmptyReason(nextPayload.products_empty_reason) !== 'strict_filter_fallback_only') {
    return nextPayload;
  }
  const planOnlyRecommendations = Array.isArray(nextPayload.plan_only_recommendations)
    ? nextPayload.plan_only_recommendations
        .filter((row) => isPlainObject(row))
        .map((row) => ({
          ...row,
          grounding_status: pickFirstTrimmed(row.grounding_status, 'ungrounded') || 'ungrounded',
          metadata: {
            ...(isPlainObject(row.metadata) ? row.metadata : {}),
            reco_render_mode: pickFirstTrimmed(row?.metadata?.reco_render_mode, 'plan_only') || 'plan_only',
          },
        }))
    : [];
  if (!planOnlyRecommendations.length) return nextPayload;
  const normalizedSourceMode = pickFirstTrimmed(
    sourceMode,
    nextPayload.recommendation_meta && nextPayload.recommendation_meta.source_mode,
    nextPayload.source,
    'llm_primary',
  ) || 'llm_primary';
  const existingMeta = isPlainObject(nextPayload.recommendation_meta) ? nextPayload.recommendation_meta : {};
  nextPayload.recommendations = planOnlyRecommendations;
  nextPayload.grounding_status = 'ungrounded';
  nextPayload.grounded_count = 0;
  nextPayload.ungrounded_count = planOnlyRecommendations.length;
  nextPayload.mainline_status = 'plan_only_fallback';
  nextPayload.source = pickFirstTrimmed(nextPayload.source, normalizedSourceMode) || normalizedSourceMode;
  nextPayload.recommendation_meta = {
    ...existingMeta,
    source_mode: pickFirstTrimmed(existingMeta.source_mode, normalizedSourceMode) || normalizedSourceMode,
    grounding_status: 'ungrounded',
    grounded_count: 0,
    ungrounded_count: planOnlyRecommendations.length,
    mainline_status: 'plan_only_fallback',
    products_empty_reason: 'strict_filter_fallback_only',
  };
  return nextPayload;
}

function deriveRecoContractStatus({
  promptContractOk,
  recommendations,
  llmFailureClass,
  fieldMissing,
  productsEmptyReason,
} = {}) {
  if (promptContractOk === false) return 'prompt_contract_mismatch';
  if (Array.isArray(recommendations) && recommendations.length > 0) return 'recommendations_ready';
  if (normalizeRecoProductsEmptyReason(productsEmptyReason)) return 'recommendations_empty';
  const normalizedFailure = normalizeRecoFailureClass(llmFailureClass || '');
  if (normalizedFailure === 'timeout') return 'upstream_timeout';
  if (normalizedFailure === 'schema_invalid') return 'schema_invalid';
  if (normalizedFailure === 'empty_structured') return 'empty_structured';
  const missingRows = Array.isArray(fieldMissing) ? fieldMissing : [];
  const recoFieldMissing = missingRows.find((row) => row && row.field === 'recommendations') || null;
  const missingReason = String(recoFieldMissing && recoFieldMissing.reason ? recoFieldMissing.reason : '').trim().toLowerCase();
  if (missingReason === 'upstream_missing_or_empty') return 'recommendations_empty';
  return 'upstream_missing_or_unstructured';
}

function deriveRecoTelemetryFailureReason({
  llmFailureClass,
  upstreamFailureCode,
  contractStatus,
  productsEmptyReason,
} = {}) {
  if (normalizeRecoProductsEmptyReason(productsEmptyReason) === 'reco_mainline_empty') {
    return 'reco_mainline_empty';
  }
  const normalizedFailure = normalizeRecoFailureClass(llmFailureClass || '');
  if (normalizedFailure === 'timeout' || isTransientRecoUpstreamFailureCode(upstreamFailureCode)) {
    return 'timeout_degraded';
  }
  if (normalizedFailure === 'schema_invalid' || contractStatus === 'schema_invalid') {
    return 'upstream_schema_invalid';
  }
  if (contractStatus === 'empty_structured' || contractStatus === 'recommendations_empty') {
    return 'empty_structured';
  }
  if (contractStatus === 'prompt_contract_mismatch') {
    return 'prompt_contract_mismatch';
  }
  return '';
}

function deriveRecoFailureFromStepAwareLlmFallback({
  initialLlmOutcome,
  llmFailureClass,
  upstreamFailureCode,
  promptContractOk = true,
} = {}) {
  const normalizedOutcome = String(initialLlmOutcome || '').trim().toLowerCase();
  const normalizedFailure = normalizeRecoFailureClass(llmFailureClass || '');
  if (promptContractOk === false || normalizedOutcome === 'prompt_contract_mismatch') {
    return {
      effectiveFailureClass: 'prompt_contract_mismatch',
      failureOrigin: 'llm_contract',
      productsEmptyReason: 'prompt_contract_mismatch',
      telemetryReason: 'prompt_contract_mismatch',
      mainlineStatus: 'severe_parse_or_prompt_failure',
    };
  }
  if (
    normalizedOutcome === 'upstream_timeout' ||
    normalizedFailure === 'timeout' ||
    isTransientRecoUpstreamFailureCode(upstreamFailureCode)
  ) {
    return {
      effectiveFailureClass: 'upstream_timeout',
      failureOrigin: 'llm_upstream',
      productsEmptyReason: 'upstream_timeout',
      telemetryReason: 'timeout_degraded',
      mainlineStatus: 'upstream_timeout',
    };
  }
  if (normalizedOutcome === 'schema_invalid' || normalizedFailure === 'schema_invalid') {
    return {
      effectiveFailureClass: 'schema_invalid',
      failureOrigin: 'llm_contract',
      productsEmptyReason: 'schema_invalid',
      telemetryReason: 'upstream_schema_invalid',
      mainlineStatus: 'severe_parse_or_prompt_failure',
    };
  }
  if (normalizedOutcome === 'upstream_dependency_failure') {
    return {
      effectiveFailureClass: 'upstream_dependency_failure',
      failureOrigin: 'llm_upstream',
      productsEmptyReason: 'upstream_dependency_failure',
      telemetryReason: '',
      mainlineStatus: 'severe_parse_or_prompt_failure',
    };
  }
  return null;
}

function buildRecoMainlineContract({
  recommendations,
  sourceMode,
  source,
  llmFailureClass,
  upstreamFailureCode,
  promptContractOk = true,
  fieldMissing = null,
  structuredSource = '',
  catalogSkipReason = null,
  productsEmptyReason = null,
  groundingStatus = null,
  groundedCount = null,
  ungroundedCount = null,
  mainlineStatusOverride = null,
  promptTemplateId = null,
  entryType = 'chat',
  effectiveFailureClass = null,
  failureOrigin = 'none',
  terminalSuccess = null,
  viablePoolStrength = null,
  targetFidelityLevel = null,
  presentationMode = null,
  successMode = null,
  preLlmSelectedCandidateCount = null,
  finalSelectedCandidateCount = null,
  postGuardrailCount = null,
  surfaceReason = null,
} = {}) {
  const recoRows = Array.isArray(recommendations) ? recommendations : [];
  const hasRecommendations = recoRows.length > 0;
  const failureClass = normalizeRecoFailureClass(llmFailureClass);
  const normalizedSourceMode = inferRecoSourceMode(sourceMode, source, { defaultValue: 'legacy_notice' });
  const upstreamCode = String(upstreamFailureCode || '').trim().toUpperCase();
  const normalizedProductsEmptyReason = normalizeRecoProductsEmptyReason(productsEmptyReason);
  const normalizedGroundingStatus = normalizeRecoGroundingStatus(groundingStatus);
  const groundedCountValue = Number.isFinite(Number(groundedCount)) ? Math.max(0, Math.trunc(Number(groundedCount))) : null;
  const ungroundedCountValue = Number.isFinite(Number(ungroundedCount)) ? Math.max(0, Math.trunc(Number(ungroundedCount))) : null;
  const suppressStaleSuccessState = !hasRecommendations && Boolean(normalizedProductsEmptyReason);
  const mainlineStatusOverrideValue = pickFirstTrimmed(mainlineStatusOverride);
  const sanitizedMainlineStatusOverride =
    suppressStaleSuccessState &&
    (
      mainlineStatusOverrideValue === 'grounded_success'
      || mainlineStatusOverrideValue === 'partially_grounded'
      || mainlineStatusOverrideValue === 'ungrounded_success'
    )
      ? ''
      : mainlineStatusOverrideValue;
  const effectiveGroundingStatus = suppressStaleSuccessState ? null : (normalizedGroundingStatus || null);
  const effectiveGroundedCount = suppressStaleSuccessState ? 0 : groundedCountValue;
  const effectiveUngroundedCount = suppressStaleSuccessState ? 0 : ungroundedCountValue;
  const contractStatus = deriveRecoContractStatus({
    promptContractOk,
    recommendations: recoRows,
    llmFailureClass: failureClass,
    fieldMissing,
    productsEmptyReason: normalizedProductsEmptyReason,
  });
  const normalizedEffectiveFailureClass = normalizeRecoEffectiveFailureClass(
    effectiveFailureClass || llmFailureClass,
  );
  const meaningfulEffectiveFailureClass = hasMeaningfulRecoEffectiveFailureClass(normalizedEffectiveFailureClass)
    ? normalizedEffectiveFailureClass
    : '';
  const normalizedFailureOrigin = normalizeRecoFailureOrigin(failureOrigin);
  const normalizedPresentationMode = normalizeRecoPresentationMode(presentationMode);
  const normalizedSuccessMode = normalizeRecoSuccessMode(successMode);
  const normalizedViablePoolStrength = normalizeRecoViablePoolStrength(viablePoolStrength);
  const normalizedTargetFidelityLevel = normalizeRecoTargetFidelityLevel(targetFidelityLevel);
  const normalizedPreGateCount = Number.isFinite(Number(preLlmSelectedCandidateCount))
    ? Math.max(0, Math.trunc(Number(preLlmSelectedCandidateCount)))
    : null;
  const normalizedFinalSelectedCandidateCount = Number.isFinite(Number(finalSelectedCandidateCount))
    ? Math.max(0, Math.trunc(Number(finalSelectedCandidateCount)))
    : null;
  const normalizedPostGateCount = Number.isFinite(Number(postGuardrailCount))
    ? Math.max(0, Math.trunc(Number(postGuardrailCount)))
    : null;
  const normalizedTerminalSuccess =
    typeof terminalSuccess === 'boolean'
      ? terminalSuccess
      : hasRecommendations;
  const blockingGateId =
    !normalizedTerminalSuccess
    && normalizedPreGateCount != null
    && normalizedPreGateCount > 0
    && normalizedPostGateCount === 0
      ? (
        sanitizeRecoClientVisibleToken(meaningfulEffectiveFailureClass)
        || sanitizeRecoClientVisibleToken(normalizedProductsEmptyReason)
        || 'post_processing_eliminated_candidates'
      )
      : null;
  const blockingReason = blockingGateId
    ? (
      sanitizeRecoClientVisibleToken(surfaceReason)
      || sanitizeRecoClientVisibleToken(normalizedProductsEmptyReason)
      || blockingGateId
    )
    : null;
  const forceExplicitEmptyContract = normalizedProductsEmptyReason === 'reco_mainline_empty';
  const useCentralizedFailureMapping = Boolean(
    !forceExplicitEmptyContract &&
    AURORA_BFF_RECO_CENTRALIZED_FAILURE_MAPPING_ENABLED
      && (
        meaningfulEffectiveFailureClass
        || normalizedPresentationMode
        || normalizedSuccessMode
        || normalizedViablePoolStrength
      ),
  );
  if (useCentralizedFailureMapping) {
    const outcome = resolveRecoCentralOutcome({
      entryType,
      effectiveFailureClass: meaningfulEffectiveFailureClass,
      failureOrigin: normalizedFailureOrigin,
      terminalSuccess: normalizedTerminalSuccess,
      viablePoolStrength: normalizedViablePoolStrength,
      targetFidelityLevel: normalizedTargetFidelityLevel,
      presentationMode: normalizedPresentationMode,
      successMode: normalizedSuccessMode,
      sourceMode: normalizedSourceMode,
      groundingStatus: effectiveGroundingStatus,
    });
    return {
      ok: normalizedTerminalSuccess,
      contract_status: normalizedTerminalSuccess
        ? 'recommendations_ready'
        : outcome.user_fixable
          ? 'recommendations_empty'
          : outcome.effective_failure_class === 'prompt_contract_mismatch'
            ? 'prompt_contract_mismatch'
            : outcome.effective_failure_class === 'schema_invalid'
              ? 'schema_invalid'
              : outcome.effective_failure_class === 'upstream_timeout'
                || outcome.effective_failure_class === 'upstream_timeout_primary_role'
                ? 'upstream_timeout'
                : 'upstream_missing_or_unstructured',
      source_mode: normalizedSourceMode,
      source: String(source || '').trim() || null,
      primary_failure_reason: normalizedTerminalSuccess ? null : outcome.products_empty_reason || 'artifact_missing',
      telemetry_failure_reason: sanitizeRecoClientVisibleToken(outcome.telemetry_reason) || null,
      failure_class: normalizedTerminalSuccess
        ? null
        : (hasMeaningfulRecoEffectiveFailureClass(outcome.effective_failure_class) ? outcome.effective_failure_class : null),
      effective_failure_class: outcome.effective_failure_class || 'none',
      failure_origin: outcome.failure_origin || 'none',
      upstream_status: normalizedTerminalSuccess
        ? 'ok'
        : outcome.effective_failure_class === 'upstream_timeout'
          || outcome.effective_failure_class === 'upstream_timeout_primary_role'
          ? 'timeout'
          : outcome.effective_failure_class === 'schema_invalid'
            ? 'schema_invalid'
            : outcome.effective_failure_class === 'prompt_contract_mismatch'
              ? 'prompt_contract_mismatch'
              : outcome.effective_failure_class === 'upstream_dependency_failure'
                ? 'upstream_dependency_failure'
                : outcome.effective_failure_class === 'catalog_contract_invalid'
                  ? 'catalog_contract_invalid'
                  : outcome.effective_failure_class === 'filtered_after_recall'
                    ? 'weak_viable_pool'
                    : outcome.effective_failure_class === 'no_recall_from_planned_sources'
                      ? 'no_recall_from_planned_sources'
                      : outcome.effective_failure_class === 'weak_viable_pool'
                        ? 'weak_viable_pool'
                        : outcome.effective_failure_class === 'selector_disagreement_no_safe_winner'
                          ? 'selector_disagreement_no_safe_winner'
                          : 'artifact_missing',
      mainline_status: outcome.mainline_status,
      surface_kind: outcome.surface_kind,
      surface_reason: normalizedTerminalSuccess
        ? null
        : (sanitizeRecoClientVisibleToken(surfaceReason) || sanitizeRecoClientVisibleToken(outcome.surface_reason) || null),
      user_fixable: outcome.user_fixable,
      catalog_skip_reason: pickFirstTrimmed(catalogSkipReason) || null,
      products_empty_reason: normalizedTerminalSuccess
        ? null
        : (sanitizeRecoClientVisibleToken(outcome.products_empty_reason) || null),
      grounding_status: effectiveGroundingStatus,
      grounded_count: effectiveGroundedCount,
      ungrounded_count: effectiveUngroundedCount,
      prompt_template_id: pickFirstTrimmed(promptTemplateId) || null,
      viable_pool_strength: normalizedViablePoolStrength || null,
      target_fidelity_level: normalizedTargetFidelityLevel || null,
      terminal_success: normalizedTerminalSuccess,
      presentation_mode: outcome.presentation_mode || null,
      success_mode: outcome.success_mode || null,
      pre_llm_selected_candidate_count: normalizedPreGateCount,
      final_selected_candidate_count: normalizedFinalSelectedCandidateCount,
      post_guardrail_count: normalizedPostGateCount,
      blocking_gate_id: blockingGateId,
      pre_gate_count: blockingGateId ? normalizedPreGateCount : null,
      post_gate_count: blockingGateId ? normalizedPostGateCount : null,
      blocking_reason: blockingReason,
    };
  }
  let normalizedTelemetryReason = normalizeRecoContractTelemetryReason(
    deriveRecoTelemetryFailureReason({
      llmFailureClass: failureClass,
      upstreamFailureCode: upstreamCode,
      contractStatus,
      productsEmptyReason: normalizedProductsEmptyReason,
    }),
  );
  if (!normalizedTelemetryReason && !hasRecommendations && normalizedSourceMode === 'catalog_transient_fallback') {
    normalizedTelemetryReason = 'catalog_transient_failure';
  }
  const recommendationStatus = hasRecommendations
    ? (effectiveGroundingStatus === 'ungrounded'
      ? 'ungrounded_success'
      : effectiveGroundingStatus === 'partially_grounded'
        ? 'partially_grounded'
        : effectiveGroundingStatus === 'grounded'
          ? 'grounded_success'
          : Number.isFinite(effectiveGroundedCount) && Number.isFinite(effectiveUngroundedCount)
            ? (effectiveGroundedCount > 0 && effectiveUngroundedCount > 0
              ? 'partially_grounded'
              : effectiveGroundedCount > 0
                ? 'grounded_success'
                : effectiveUngroundedCount > 0
                  ? 'ungrounded_success'
                  : '')
            : '')
    : '';
  const mainlineStatus = pickFirstTrimmed(sanitizedMainlineStatusOverride, recommendationStatus)
    || deriveRecoMainlineStatus({
      recommendations: recoRows,
      structuredSource: structuredSource || normalizedSourceMode,
      catalogSkipReason,
      llmFailureClass: failureClass,
      upstreamFailureCode: upstreamCode,
      contractStatus,
      productsEmptyReason: normalizedProductsEmptyReason,
    });
  let upstreamStatus = 'ok';
  if (!hasRecommendations) {
    if (normalizedTelemetryReason === 'timeout_degraded') upstreamStatus = 'timeout';
    else if (normalizedTelemetryReason === 'upstream_schema_invalid') upstreamStatus = 'schema_invalid';
    else if (normalizedTelemetryReason === 'prompt_contract_mismatch') upstreamStatus = 'prompt_contract_mismatch';
    else if (normalizedTelemetryReason === 'reco_mainline_empty') upstreamStatus = 'ok';
    else if (normalizedTelemetryReason === 'empty_structured') upstreamStatus = 'schema_invalid';
    else if (normalizedTelemetryReason === 'catalog_transient_failure') upstreamStatus = 'catalog_transient_failure';
    else upstreamStatus = 'artifact_missing';
  }
  const primaryFailureReason = hasRecommendations
    ? null
    : contractStatus === 'prompt_contract_mismatch'
      ? 'prompt_contract_mismatch'
    : normalizedProductsEmptyReason === 'strict_filter_fallback_only'
      ? 'strict_filter_dropped'
      : normalizedProductsEmptyReason === 'reco_mainline_empty'
        ? 'reco_mainline_empty'
      : (sanitizeRecoClientVisibleToken(normalizedProductsEmptyReason) || 'artifact_missing');
  const clientVisibleProductsEmptyReason = hasRecommendations
    ? null
    : normalizedProductsEmptyReason === 'strict_filter_fallback_only'
      ? 'strict_filter_fallback_only'
      : (sanitizeRecoClientVisibleToken(normalizedProductsEmptyReason) || primaryFailureReason);
  const clientVisibleSurfaceReason = hasRecommendations
    ? null
    : sanitizeRecoClientVisibleToken(surfaceReason)
      || (normalizedProductsEmptyReason === 'strict_filter_fallback_only'
        ? 'strict_filter_dropped'
        : (sanitizeRecoClientVisibleToken(normalizedProductsEmptyReason) || primaryFailureReason));

  return {
    ok: hasRecommendations,
    contract_status: contractStatus,
    source_mode: normalizedSourceMode,
    source: String(source || '').trim() || null,
    primary_failure_reason: primaryFailureReason,
    telemetry_failure_reason: normalizedTelemetryReason || null,
    failure_class: contractStatus === 'prompt_contract_mismatch'
      ? 'prompt_contract_mismatch'
      : failureClass || null,
    upstream_status: upstreamStatus,
    mainline_status: mainlineStatus,
    surface_reason: clientVisibleSurfaceReason,
    catalog_skip_reason: pickFirstTrimmed(catalogSkipReason) || null,
    products_empty_reason: clientVisibleProductsEmptyReason,
    grounding_status: effectiveGroundingStatus,
    grounded_count: effectiveGroundedCount,
    ungrounded_count: effectiveUngroundedCount,
    prompt_template_id: pickFirstTrimmed(promptTemplateId) || null,
    blocking_gate_id: blockingGateId,
    pre_gate_count: blockingGateId ? normalizedPreGateCount : null,
    post_gate_count: blockingGateId ? normalizedPostGateCount : null,
    blocking_reason: blockingReason,
  };
}

function attachRecoContractMeta(payload, contract) {
  if (!isPlainObject(payload)) return payload;
  const contractObj = isPlainObject(contract) ? contract : {};
  const metaExisting = isPlainObject(payload.recommendation_meta) ? payload.recommendation_meta : {};
  const hasRecommendations = Array.isArray(payload.recommendations) && payload.recommendations.length > 0;
  const payloadForFailureResolution = hasRecommendations
    ? {
        ...payload,
        products_empty_reason: '',
        recommendation_meta: {
          ...metaExisting,
          primary_failure_reason: '',
          telemetry_failure_reason: '',
          failure_class: '',
          effective_failure_class: '',
          failure_origin: '',
          surface_reason: '',
          products_empty_reason: '',
        },
      }
    : payload;
  const resolvedFailure = resolveRecoFailureReasonContract({
    payload: payloadForFailureResolution,
    contract: contractObj,
    allowEmpty: hasRecommendations,
  });
  const failureClass = sanitizeRecoClientVisibleFailureClass(contractObj.failure_class);
  const effectiveFailureClass = sanitizeRecoClientVisibleFailureClass(contractObj.effective_failure_class);
  const failureOrigin = sanitizeRecoClientVisibleFailureOrigin(contractObj.failure_origin);
  const nextRecommendationMeta = {
    ...metaExisting,
  };
  delete nextRecommendationMeta.primary_failure_reason;
  delete nextRecommendationMeta.telemetry_failure_reason;
  delete nextRecommendationMeta.failure_class;
  delete nextRecommendationMeta.effective_failure_class;
  delete nextRecommendationMeta.failure_origin;
  delete nextRecommendationMeta.surface_reason;
  delete nextRecommendationMeta.products_empty_reason;
  const nextPayloadRoot = {
    ...payload,
  };
  if (hasRecommendations) {
    delete nextPayloadRoot.products_empty_reason;
    delete nextPayloadRoot.surface_reason;
  }
  return {
    ...nextPayloadRoot,
    ...(contractObj.mainline_status ? { mainline_status: contractObj.mainline_status } : {}),
    ...(contractObj.grounding_status ? { grounding_status: contractObj.grounding_status } : {}),
    ...(Number.isFinite(Number(contractObj.grounded_count)) ? { grounded_count: Number(contractObj.grounded_count) } : {}),
    ...(Number.isFinite(Number(contractObj.ungrounded_count)) ? { ungrounded_count: Number(contractObj.ungrounded_count) } : {}),
    ...(contractObj.prompt_template_id ? { prompt_template_id: contractObj.prompt_template_id } : {}),
    recommendation_meta: {
      ...nextRecommendationMeta,
      ...(contractObj.source_mode ? { source_mode: contractObj.source_mode } : {}),
      ...(contractObj.contract_status ? { contract_status: contractObj.contract_status } : {}),
      ...(resolvedFailure.primaryReason ? { primary_failure_reason: resolvedFailure.primaryReason } : {}),
      ...(resolvedFailure.telemetryReason ? { telemetry_failure_reason: resolvedFailure.telemetryReason } : {}),
      ...(failureClass ? { failure_class: failureClass } : {}),
      ...(effectiveFailureClass ? { effective_failure_class: effectiveFailureClass } : {}),
      ...(failureOrigin ? { failure_origin: failureOrigin } : {}),
      ...(contractObj.upstream_status ? { upstream_status: contractObj.upstream_status } : {}),
      ...(contractObj.mainline_status ? { mainline_status: contractObj.mainline_status } : {}),
      ...(contractObj.surface_kind ? { surface_kind: contractObj.surface_kind } : {}),
      ...(resolvedFailure.surfaceReason ? { surface_reason: resolvedFailure.surfaceReason } : {}),
      ...(typeof contractObj.user_fixable === 'boolean' ? { user_fixable: contractObj.user_fixable } : {}),
      ...(contractObj.catalog_skip_reason ? { catalog_skip_reason: contractObj.catalog_skip_reason } : {}),
      ...(resolvedFailure.productsEmptyReason ? { products_empty_reason: resolvedFailure.productsEmptyReason } : {}),
      ...(contractObj.grounding_status ? { grounding_status: contractObj.grounding_status } : {}),
      ...(contractObj.viable_pool_strength ? { viable_pool_strength: contractObj.viable_pool_strength } : {}),
      ...(contractObj.target_fidelity_level ? { target_fidelity_level: contractObj.target_fidelity_level } : {}),
      ...(typeof contractObj.terminal_success === 'boolean' ? { terminal_success: contractObj.terminal_success } : {}),
      ...(contractObj.presentation_mode ? { presentation_mode: contractObj.presentation_mode } : {}),
      ...(contractObj.success_mode ? { success_mode: contractObj.success_mode } : {}),
      ...(Number.isFinite(Number(contractObj.pre_llm_selected_candidate_count)) ? { pre_llm_selected_candidate_count: Number(contractObj.pre_llm_selected_candidate_count) } : {}),
      ...(Number.isFinite(Number(contractObj.final_selected_candidate_count)) ? { final_selected_candidate_count: Number(contractObj.final_selected_candidate_count) } : {}),
      ...(Number.isFinite(Number(contractObj.post_guardrail_count)) ? { post_guardrail_count: Number(contractObj.post_guardrail_count) } : {}),
      ...(contractObj.blocking_gate_id ? { blocking_gate_id: contractObj.blocking_gate_id } : {}),
      ...(Number.isFinite(Number(contractObj.pre_gate_count)) ? { pre_gate_count: Number(contractObj.pre_gate_count) } : {}),
      ...(Number.isFinite(Number(contractObj.post_gate_count)) ? { post_gate_count: Number(contractObj.post_gate_count) } : {}),
      ...(contractObj.blocking_reason ? { blocking_reason: contractObj.blocking_reason } : {}),
      ...(Number.isFinite(Number(contractObj.grounded_count)) ? { grounded_count: Number(contractObj.grounded_count) } : {}),
      ...(Number.isFinite(Number(contractObj.ungrounded_count)) ? { ungrounded_count: Number(contractObj.ungrounded_count) } : {}),
      ...(contractObj.prompt_template_id ? { prompt_template_id: contractObj.prompt_template_id } : {}),
    },
  };
}

function deriveRecoMainlineStatus({
  recommendations,
  structuredSource,
  catalogSkipReason,
  llmFailureClass,
  upstreamFailureCode,
  contractStatus,
  productsEmptyReason,
} = {}) {
  if (Array.isArray(recommendations) && recommendations.length > 0) return 'grounded_success';
  const catalogSkip = String(catalogSkipReason || '').trim().toLowerCase();
  if (catalogSkip === 'disabled') return 'catalog_skipped_disabled';
  if (catalogSkip === 'fail_fast_open') return 'catalog_skipped_fail_fast';
  if (catalogSkip === 'queries_empty') return 'catalog_queries_empty';
  if (contractStatus === 'prompt_contract_mismatch') {
    return 'severe_parse_or_prompt_failure';
  }
  if (normalizeRecoProductsEmptyReason(productsEmptyReason) === 'reco_mainline_empty') {
    return 'reco_mainline_empty';
  }
  if (normalizeRecoProductsEmptyReason(productsEmptyReason)) {
    return 'empty_structured';
  }
  if (normalizeRecoFailureClass(llmFailureClass || '') === 'timeout' || isTransientRecoUpstreamFailureCode(upstreamFailureCode)) {
    return 'upstream_timeout';
  }
  if (normalizeRecoFailureClass(llmFailureClass || '') === 'schema_invalid' || contractStatus === 'schema_invalid') {
    return 'upstream_schema_invalid';
  }
  if (contractStatus === 'empty_structured' || contractStatus === 'recommendations_empty') {
    return 'empty_structured';
  }
  return 'empty_structured';
}

function buildRecoRequestedEventData({
  explicit = true,
  payload,
  source = '',
  reason = '',
  telemetryReason = '',
  failureClass = '',
  llmTraceRef = null,
  lowConfidence = null,
  confidenceLevel = '',
  sourceDetail = '',
  recomputeFromProfileUpdate = false,
  blocked = false,
  upstreamFailureCode = '',
} = {}) {
  const payloadObj = isPlainObject(payload) ? payload : {};
  const recommendations = Array.isArray(payloadObj.recommendations) ? payloadObj.recommendations : [];
  const meta = isPlainObject(payloadObj.recommendation_meta) ? payloadObj.recommendation_meta : {};
  const resolvedFailure = resolveRecoFailureReasonContract({
    payload: payloadObj,
    contract: meta,
    fallback: recommendations.length ? '' : 'artifact_missing',
    allowEmpty: recommendations.length > 0,
  });
  const eventReason = sanitizeRecoClientVisibleToken(reason)
    || resolvedFailure.primaryReason
    || (recommendations.length ? '' : resolvedFailure.primaryReason || 'artifact_missing');
  const eventTelemetryReason = sanitizeRecoClientVisibleToken(telemetryReason) || resolvedFailure.telemetryReason;
  const eventFailureClass = sanitizeRecoClientVisibleFailureClass(failureClass) || sanitizeRecoClientVisibleFailureClass(meta.failure_class);
  const rawMetaMainlineStatus = pickFirstTrimmed(meta.mainline_status);
  const eventMainlineStatus =
    recommendations.length === 0 && (
      rawMetaMainlineStatus === 'grounded_success'
      || rawMetaMainlineStatus === 'partially_grounded'
      || rawMetaMainlineStatus === 'ungrounded_success'
    )
      ? ''
      : rawMetaMainlineStatus;
  const data = {
    explicit: explicit === true,
    source: String(source || payloadObj.source || meta.source_mode || 'legacy_notice').trim() || 'legacy_notice',
    ...(pickFirstTrimmed(sourceDetail) ? { source_detail: pickFirstTrimmed(sourceDetail) } : {}),
    ...(recomputeFromProfileUpdate === true ? { recompute_from_profile_update: true } : {}),
    ...(typeof lowConfidence === 'boolean' ? { low_confidence: lowConfidence } : {}),
    ...(pickFirstTrimmed(confidenceLevel) ? { confidence_level: pickFirstTrimmed(confidenceLevel) } : {}),
    ...(blocked === true ? { blocked: true } : {}),
    ...(eventReason ? { reason: eventReason } : {}),
    ...(eventTelemetryReason ? { telemetry_reason: eventTelemetryReason } : {}),
    ...(eventFailureClass ? { failure_class: eventFailureClass } : {}),
    ...(pickFirstTrimmed(payloadObj.grounding_status, meta.grounding_status) ? { grounding_status: pickFirstTrimmed(payloadObj.grounding_status, meta.grounding_status) } : {}),
    ...(Number.isFinite(Number(payloadObj.grounded_count)) ? { grounded_count: Number(payloadObj.grounded_count) } : Number.isFinite(Number(meta.grounded_count)) ? { grounded_count: Number(meta.grounded_count) } : {}),
    ...(Number.isFinite(Number(payloadObj.ungrounded_count)) ? { ungrounded_count: Number(payloadObj.ungrounded_count) } : Number.isFinite(Number(meta.ungrounded_count)) ? { ungrounded_count: Number(meta.ungrounded_count) } : {}),
    ...(eventMainlineStatus ? { mainline_status: eventMainlineStatus } : {}),
    ...(pickFirstTrimmed(meta.catalog_skip_reason) ? { catalog_skip_reason: pickFirstTrimmed(meta.catalog_skip_reason) } : {}),
    ...(resolvedFailure.productsEmptyReason ? { products_empty_reason: resolvedFailure.productsEmptyReason } : {}),
    ...(resolvedFailure.surfaceReason ? { surface_reason: resolvedFailure.surfaceReason } : {}),
    ...(pickFirstTrimmed(meta.prompt_template_id) ? { prompt_template_id: pickFirstTrimmed(meta.prompt_template_id) } : {}),
    ...(pickFirstTrimmed(meta.owner_source) ? { owner_source: pickFirstTrimmed(meta.owner_source) } : {}),
    ...(pickFirstTrimmed(meta.final_outcome_owner) ? { final_outcome_owner: pickFirstTrimmed(meta.final_outcome_owner) } : {}),
    ...(pickFirstTrimmed(meta.primary_target_id) ? { primary_target_id: pickFirstTrimmed(meta.primary_target_id) } : {}),
    ...(pickFirstTrimmed(upstreamFailureCode, meta.upstream_failure_code) ? { upstream_failure_code: pickFirstTrimmed(upstreamFailureCode, meta.upstream_failure_code) } : {}),
    ...(isPlainObject(llmTraceRef) ? { llm_trace_ref: llmTraceRef } : {}),
  };
  return data;
}

function buildRecoInputCoverage({ profileSummary, recentLogs, requestText } = {}) {
  const profileObj = profileSummary && typeof profileSummary === 'object' && !Array.isArray(profileSummary) ? profileSummary : {};
  const goals = Array.isArray(profileObj.goals) ? profileObj.goals : [];
  return {
    has_skin_type: Boolean(String(profileObj.skinType || '').trim()),
    has_sensitivity: Boolean(String(profileObj.sensitivity || '').trim()),
    has_barrier_status: Boolean(String(profileObj.barrierStatus || '').trim()),
    has_goals: goals.length > 0,
    has_recent_logs: Array.isArray(recentLogs) && recentLogs.length > 0,
    has_request_text: Boolean(String(requestText || '').trim()),
  };
}

function loadRecoPromptTemplateFile(fileName, { parseJson = false, fallback = '' } = {}) {
  const key = `${parseJson ? 'json' : 'text'}:${String(fileName || '').trim()}`;
  if (recoPromptTemplateCache.has(key)) return recoPromptTemplateCache.get(key);
  const target = path.resolve(RECO_PROMPTS_ROOT_DIR, fileName);
  let value = fallback;
  try {
    const raw = fs.readFileSync(target, 'utf8');
    value = parseJson ? JSON.parse(raw) : raw;
  } catch (_err) {
    value = fallback;
  }
  recoPromptTemplateCache.set(key, value);
  return value;
}

function resolveRecoMainPromptSpec({ ingredientContext } = {}) {
  const normalizedIngredientContext = normalizeIngredientRecoContextValue(ingredientContext);
  const ingredientMode = Boolean(
    normalizedIngredientContext &&
      typeof normalizedIngredientContext === 'object' &&
      !Array.isArray(normalizedIngredientContext) &&
      (
        pickFirstTrimmed(
          normalizedIngredientContext.query,
          normalizedIngredientContext.goal,
          normalizedIngredientContext.sensitivity,
        ) ||
        (Array.isArray(normalizedIngredientContext.candidates) && normalizedIngredientContext.candidates.length > 0)
      ),
  );
  const templateId = ingredientMode ? RECO_INGREDIENT_PROMPT_TEMPLATE_ID : RECO_MAIN_PROMPT_TEMPLATE_ID;
  return {
    ingredient_mode: ingredientMode,
    llm_mode: ingredientMode ? 'ingredient_filtered_products' : 'goal_based_products',
    template_id: templateId,
    schema_file: `${templateId}.user_schema.json`,
    system_file: `${templateId}.system.txt`,
  };
}

function normalizeRecoPromptLanguage(lang) {
  return String(lang || '').trim().toUpperCase() === 'CN' ? 'CN' : 'EN';
}

function normalizeRecoPromptRegion(profile) {
  const raw = pickFirstTrimmed(profile && profile.region, profile && profile.country, 'US');
  return raw || 'US';
}

function formatAuroraPromptQuery({ templateId, systemPrompt, userPayload } = {}) {
  const promptSystem = String(systemPrompt || '').trim();
  const payloadJson = JSON.stringify(userPayload && typeof userPayload === 'object' ? userPayload : {}, null, 2);
  return [
    `PROMPT_TEMPLATE_ID=${String(templateId || '').trim() || 'unknown'}`,
    'SYSTEM_PROMPT:',
    promptSystem,
    'USER_PROMPT_JSON:',
    payloadJson,
    'OUTPUT_REQUIREMENT: Return only a valid JSON object that strictly follows the schema and hard rules.',
  ].join('\n');
}

function parsePromptTemplateIdFromQuery(query) {
  const text = String(query || '');
  if (!text) return '';
  const match = text.match(/(?:^|\n)PROMPT_TEMPLATE_ID=([^\n\r]+)/);
  if (!match || !match[1]) return '';
  return String(match[1]).trim();
}

function validateRecoPromptContract({ query, expectedTemplateId = '', expectedPromptHash = '' } = {}) {
  const text = String(query || '');
  const issues = [];
  if (!text.includes('PROMPT_TEMPLATE_ID=')) issues.push('missing_prompt_template_id');
  if (!text.includes('SYSTEM_PROMPT:')) issues.push('missing_system_prompt_block');
  if (!text.includes('USER_PROMPT_JSON:')) issues.push('missing_user_prompt_json_block');

  const templateIdInQuery = parsePromptTemplateIdFromQuery(text);
  if (!templateIdInQuery) {
    issues.push('template_id_unparseable');
  } else if (expectedTemplateId && templateIdInQuery !== String(expectedTemplateId).trim()) {
    issues.push('template_id_mismatch');
  }

  const promptHashActual = text
    ? crypto.createHash('sha1').update(text).digest('hex').slice(0, 16)
    : null;
  const expectedHashToken = String(expectedPromptHash || '').trim() || null;
  if (expectedHashToken && promptHashActual !== expectedHashToken) {
    issues.push('prompt_hash_mismatch');
  }

  return {
    ok: issues.length === 0,
    issues,
    template_id: templateIdInQuery || null,
    prompt_hash_actual: promptHashActual,
    prompt_hash_expected: expectedHashToken,
  };
}

const RECO_WARNING_LIKE_CODES = new Set([
  'over_budget',
  'price_unknown',
  'availability_unknown',
  'recent_logs_missing',
  'itinerary_unknown',
  'analysis_missing',
  'upstream_analysis_missing',
  'evidence_missing',
  'upstream_missing_or_unstructured',
  'upstream_missing_or_empty',
  'alternatives_partial',
]);

const RECO_WARNING_INTERNAL_ONLY_CODES = new Set([
  'analysis_missing',
  'upstream_analysis_missing',
  'recent_logs_missing',
  'itinerary_unknown',
  'evidence_missing',
  'upstream_missing_or_unstructured',
  'upstream_missing_or_empty',
]);

function splitRecoWarningCodes({ warnings = [], missingInfo = [] } = {}) {
  const merged = uniqCaseInsensitiveStrings(
    [
      ...asStringArray(warnings),
      ...asStringArray(missingInfo).filter((code) => RECO_WARNING_LIKE_CODES.has(String(code || '').trim().toLowerCase())),
    ],
    16,
  );
  const internal = merged.map((code) => String(code || '').trim()).filter(Boolean);
  const userVisible = internal.filter((code) => !RECO_WARNING_INTERNAL_ONLY_CODES.has(String(code || '').trim().toLowerCase()));
  return {
    internal,
    user_visible: userVisible,
  };
}

function applyRecoWarningVisibilityContract(payload) {
  const base = isPlainObject(payload) ? { ...payload } : {};
  const split = splitRecoWarningCodes({
    warnings: base.warnings,
    missingInfo: base.missing_info,
  });
  return {
    payload: {
      ...base,
      warnings: split.user_visible,
      warning_codes_internal: split.internal,
      warning_codes_user_visible: split.user_visible,
    },
    split,
  };
}

function hasItineraryContextForReco(profileSummary) {
  const profileObj =
    profileSummary && typeof profileSummary === 'object' && !Array.isArray(profileSummary)
      ? profileSummary
      : null;
  if (!profileObj) return false;
  if (String(profileObj.itinerary || '').trim()) return true;
  const travelPlan =
    profileObj.travel_plan && typeof profileObj.travel_plan === 'object' && !Array.isArray(profileObj.travel_plan)
      ? profileObj.travel_plan
      : null;
  if (!travelPlan) return false;
  return Boolean(
    String(travelPlan.destination || '').trim() ||
    String(travelPlan.start_date || '').trim() ||
    String(travelPlan.end_date || '').trim(),
  );
}

function normalizeClarificationField(raw) {
  const rawText = String(raw == null ? '' : raw).trim();
  const lowered = rawText.toLowerCase();
  let norm = lowered
    .normalize('NFKC')
    .replace(/[^\p{L}\p{N}_:]+/gu, '_')
    .replace(/_+/g, '_')
    .replace(/^_+|_+$/g, '');

  if (!norm) {
    recordClarificationIdNormalizedEmpty();
    norm = `cid_${stableHashBase36(rawText).slice(0, 12)}`;
  }

  const haystack = `${lowered} ${norm}`;
  if (/(budget|price|spend|预算|价位|预算档)/.test(haystack)) return 'budgetTier';
  if (/(goal|concern|target|focus|目标|诉求|优先|最想|想解决)/.test(haystack)) return 'goals';
  if (/(barrier|sting|red|irrit|reactive|屏障|耐受|刺痛|泛红|发红|刺激)/.test(haystack)) return 'barrierStatus';
  if (/(sensit|敏感程度|敏感性)/.test(haystack)) return 'sensitivity';
  if (/(skin|肤质|皮肤类型|油皮|干皮|混合|中性|oily|dry|combo|combination|mixed|normal)/.test(haystack)) return 'skinType';
  return norm;
}

const FILTERABLE_CLARIFICATION_FIELDS = new Set(['skinType', 'sensitivity', 'barrierStatus', 'goals', 'budgetTier']);
const RESUME_KNOWN_PROFILE_FIELDS = Object.freeze(['skinType', 'sensitivity', 'barrierStatus', 'goals', 'budgetTier']);
const RESUME_PREFIX_KNOWN_FIELD_MAX_VALUE = 40;
const RESUME_PREFIX_KNOWN_GOALS_MAX_ITEMS = 5;

const RESUME_REASK_PATTERNS = Object.freeze({
  skinType: [
    /what(?:'s| is)\s+your\s+skin\s+type/i,
    /which\s+skin\s+type/i,
    /(?:你的|您).{0,8}(?:肤质|皮肤类型).{0,8}(?:是|属于|吗|\?|？)/i,
  ],
  barrierStatus: [
    /is\s+your\s+barrier\s+(?:stable|healthy|ok)/i,
    /do\s+you\s+have\s+stinging(?:\/|\s+or\s+)redness/i,
    /stinging\/redness/i,
    /(?:屏障).{0,12}(?:稳定|刺痛|泛红|受损).{0,6}(?:吗|\?|？)/i,
  ],
  goals: [
    /what(?:'s| is)\s+your\s+(?:main|top)\s+goal/i,
    /what\s+is\s+your\s+goal/i,
    /(?:你的|您).{0,8}(?:主要|首要|最想).{0,8}(?:目标|诉求).{0,6}(?:是|吗|\?|？)/i,
  ],
});

function truncateResumeKnownValue(raw) {
  const text = typeof raw === 'string' ? raw.trim() : '';
  if (!text || isUnsureToken(text)) return '';
  if (text.length <= RESUME_PREFIX_KNOWN_FIELD_MAX_VALUE) return text;
  return text.slice(0, RESUME_PREFIX_KNOWN_FIELD_MAX_VALUE);
}

function hasKnownClarificationFieldValue(profileSummary, field) {
  if (!field || !profileSummary || typeof profileSummary !== 'object') return false;
  const norm = (v) => (typeof v === 'string' ? v.trim().toLowerCase() : '');
  if (field === 'skinType') {
    const v = norm(profileSummary.skinType);
    return Boolean(v && v !== 'unknown');
  }
  if (field === 'sensitivity') {
    const v = norm(profileSummary.sensitivity);
    return Boolean(v && v !== 'unknown');
  }
  if (field === 'barrierStatus') {
    const v = norm(profileSummary.barrierStatus);
    return Boolean(v && v !== 'unknown');
  }
  if (field === 'goals') {
    const goals = Array.isArray(profileSummary.goals) ? profileSummary.goals : [];
    return goals.some((g) => norm(g));
  }
  if (field === 'budgetTier') {
    const v = norm(profileSummary.budgetTier);
    return Boolean(v && v !== 'unknown');
  }
  return false;
}

function buildResumeKnownProfileFields(profileSummary) {
  if (!profileSummary || typeof profileSummary !== 'object') return null;
  const out = {};

  if (hasKnownClarificationFieldValue(profileSummary, 'skinType')) {
    const skinType = truncateResumeKnownValue(profileSummary.skinType);
    if (skinType) out.skinType = skinType;
  }

  if (hasKnownClarificationFieldValue(profileSummary, 'sensitivity')) {
    const sensitivity = truncateResumeKnownValue(profileSummary.sensitivity);
    if (sensitivity) out.sensitivity = sensitivity;
  }

  if (hasKnownClarificationFieldValue(profileSummary, 'barrierStatus')) {
    const barrierStatus = truncateResumeKnownValue(profileSummary.barrierStatus);
    if (barrierStatus) out.barrierStatus = barrierStatus;
  }

  if (hasKnownClarificationFieldValue(profileSummary, 'goals')) {
    const goals = (Array.isArray(profileSummary.goals) ? profileSummary.goals : [])
      .map((g) => truncateResumeKnownValue(g))
      .filter(Boolean)
      .slice(0, RESUME_PREFIX_KNOWN_GOALS_MAX_ITEMS);
    if (goals.length) out.goals = goals;
  }

  if (hasKnownClarificationFieldValue(profileSummary, 'budgetTier')) {
    const budgetTier = truncateResumeKnownValue(profileSummary.budgetTier);
    if (budgetTier) out.budgetTier = budgetTier;
  }

  return Object.keys(out).length ? out : null;
}

function classifyResumeResponseMode(answerText) {
  const text = String(answerText || '').trim();
  if (!text) return 'mixed';
  const leading = text.slice(0, 400);
  const leadingNorm = leading.replace(/\s+/g, ' ').trim();
  const questionMarks = (text.match(/[?？]/g) || []).length;
  const startsWithIntakePrompt =
    /^(before i can|before i recommend)/i.test(leadingNorm) ||
    /(quick skin profile|quick skin-profile detail)/i.test(leadingNorm);
  const numberedQuestionLines = (leading.match(/(?:^|\n)\s*\d+\s*[\)\.:\uff1a]/g) || []).length >= 2;
  if (questionMarks >= 2 || startsWithIntakePrompt || numberedQuestionLines) return 'question';

  const answerLike = /(am\/pm|routine|plan|onboarding|ingredient|buying criteria|方案|步骤|早晚|建议|计划)/i.test(text);
  if (answerLike && questionMarks <= 1) return 'answer';
  return 'mixed';
}

function detectResumePlaintextReaskFields(answerText, knownProfileFields) {
  const text = String(answerText || '');
  if (!text || !knownProfileFields || typeof knownProfileFields !== 'object') return [];
  const detected = [];
  for (const field of RESUME_KNOWN_PROFILE_FIELDS) {
    if (!Object.prototype.hasOwnProperty.call(knownProfileFields, field)) continue;
    const patterns = RESUME_REASK_PATTERNS[field];
    if (!Array.isArray(patterns) || !patterns.length) continue;
    if (patterns.some((pattern) => pattern.test(text))) detected.push(field);
  }
  return detected;
}

function filterClarificationQuestionsForChips({ clarification, profileSummary, filterKnown } = {}) {
  if (!clarification || typeof clarification !== 'object') return [];

  const rawQuestions = clarification.questions;
  if (!Array.isArray(rawQuestions)) {
    recordClarificationSchemaInvalid({ reason: 'questions_not_array' });
    return [];
  }

  const questions = [];
  let filteredKnownCount = 0;
  let validQuestionCount = 0;
  for (const rawQuestion of rawQuestions) {
    if (!rawQuestion || typeof rawQuestion !== 'object' || Array.isArray(rawQuestion)) {
      recordClarificationSchemaInvalid({ reason: 'question_not_object' });
      continue;
    }

    const qidRaw = typeof rawQuestion.id === 'string' ? rawQuestion.id.trim() : '';
    const qid = qidRaw || 'clarify';
    if (!qidRaw) {
      recordClarificationSchemaInvalid({ reason: 'question_id_missing' });
    }

    if (!Array.isArray(rawQuestion.options)) {
      recordClarificationSchemaInvalid({ reason: 'question_options_not_array' });
      continue;
    }

    let hasInvalidOptionType = false;
    const options = [];
    for (const rawOption of rawQuestion.options) {
      if (typeof rawOption !== 'string') {
        hasInvalidOptionType = true;
        continue;
      }
      const option = rawOption.trim();
      if (option) options.push(option);
    }
    if (hasInvalidOptionType) {
      recordClarificationSchemaInvalid({ reason: 'question_option_non_string' });
    }
    if (!options.length) {
      recordClarificationSchemaInvalid({ reason: 'question_options_empty' });
      continue;
    }
    const question = typeof rawQuestion.question === 'string' ? rawQuestion.question.trim() : '';

    validQuestionCount += 1;
    const field = normalizeClarificationField(qid);
    const shouldFilterKnown =
      Boolean(filterKnown) &&
      FILTERABLE_CLARIFICATION_FIELDS.has(field) &&
      hasKnownClarificationFieldValue(profileSummary, field);
    if (shouldFilterKnown) {
      filteredKnownCount += 1;
      recordClarificationQuestionFiltered({ field });
      // Keep existing observability for repeated asks, even when we filter the chips.
      recordRepeatedClarifyField({ field });
      continue;
    }

    questions.push({ id: qid, question, options });
  }

  if (Boolean(filterKnown) && validQuestionCount > 0 && filteredKnownCount > 0 && questions.length === 0) {
    recordClarificationAllQuestionsFiltered();
  }

  return questions;
}

const PENDING_CLARIFICATION_SCHEMA_V1 = 1;
const PENDING_CLARIFICATION_MAX_RESUME_USER_TEXT = 800;
const PENDING_CLARIFICATION_MAX_QUEUE = 5;
const PENDING_CLARIFICATION_MAX_OPTIONS = 8;
const PENDING_CLARIFICATION_MAX_QUESTION = 200;
const PENDING_CLARIFICATION_MAX_OPTION = 80;
const PENDING_CLARIFICATION_MAX_HISTORY = 6;

function makeFlowId() {
  const rand = crypto.randomBytes(6).toString('hex').slice(0, 12);
  return `pc_${rand || Math.random().toString(36).slice(2, 10)}`;
}

function truncate(value, maxChars) {
  const text = typeof value === 'string' ? value.trim() : '';
  if (!text) return { value: '', truncated: false };
  if (text.length <= maxChars) return { value: text, truncated: false };
  return { value: text.slice(0, maxChars), truncated: true };
}

function capArray(items, maxCount) {
  const list = Array.isArray(items) ? items : [];
  if (list.length <= maxCount) return { values: list, dropped: 0 };
  return { values: list.slice(0, maxCount), dropped: list.length - maxCount };
}

function normalizePendingClarificationId(rawId) {
  const idRaw = typeof rawId === 'string' ? rawId.trim() : '';
  const id = idRaw || 'clarify';
  const normId = normalizeClarificationField(id);
  return { id, norm_id: normId };
}

function recordPendingClarificationTruncationFields(fields) {
  for (const field of Array.from(fields || [])) {
    recordPendingClarificationTruncated({ field });
  }
}

function normalizeClarificationQuestionForPending(rawQuestion, { recordTruncationMetrics = true, truncationFields } = {}) {
  if (!rawQuestion || typeof rawQuestion !== 'object' || Array.isArray(rawQuestion)) return null;
  if (!Array.isArray(rawQuestion.options)) return null;

  const localTruncationFields = new Set();
  const idInfo = normalizePendingClarificationId(rawQuestion.id);
  const questionTextRaw = typeof rawQuestion.question === 'string' ? rawQuestion.question.trim() : '';
  const questionTrimmed = truncate(questionTextRaw, PENDING_CLARIFICATION_MAX_QUESTION);
  if (questionTrimmed.truncated) localTruncationFields.add('question');

  const options = [];
  for (const rawOption of rawQuestion.options) {
    if (typeof rawOption !== 'string') continue;
    const optionText = rawOption.trim();
    if (!optionText) continue;
    const optionTrimmed = truncate(optionText, PENDING_CLARIFICATION_MAX_OPTION);
    if (optionTrimmed.truncated) localTruncationFields.add('option');
    options.push(optionTrimmed.value);
  }
  if (!options.length) return null;

  const cappedOptions = capArray(options, PENDING_CLARIFICATION_MAX_OPTIONS);
  if (cappedOptions.dropped > 0) localTruncationFields.add('options');

  for (const field of Array.from(localTruncationFields)) {
    if (truncationFields && truncationFields.add) truncationFields.add(field);
  }
  if (recordTruncationMetrics && localTruncationFields.size > 0) {
    recordPendingClarificationTruncationFields(localTruncationFields);
  }

  return {
    id: idInfo.id,
    norm_id: idInfo.norm_id,
    question: questionTrimmed.value,
    options: cappedOptions.values,
  };
}

function isClarifyChipAction(action, { actionId, clarificationId } = {}) {
  const id =
    typeof actionId === 'string'
      ? actionId.trim()
      : typeof action === 'string'
        ? action.trim()
        : action && typeof action === 'object' && typeof action.action_id === 'string'
          ? action.action_id.trim()
          : '';
  if (id.toLowerCase().startsWith('chip.clarify.')) return true;
  if (parseClarificationIdFromActionId(id)) return true;
  return Boolean(typeof clarificationId === 'string' && clarificationId.trim());
}

function hasPendingClarificationStateHint(action) {
  if (!action || typeof action !== 'object' || Array.isArray(action)) return false;
  const data = action.data && typeof action.data === 'object' ? action.data : null;
  if (!data) return false;
  if (Object.prototype.hasOwnProperty.call(data, 'clarification_step')) return true;
  if (typeof data.clarification_question_id === 'string' && data.clarification_question_id.trim()) return true;
  if (typeof data.clarificationQuestionId === 'string' && data.clarificationQuestionId.trim()) return true;
  return false;
}

function extractClarificationQuestionIdFromAction(action) {
  if (!action || typeof action !== 'object' || Array.isArray(action)) return '';
  const data = action.data && typeof action.data === 'object' ? action.data : null;
  if (!data) return '';
  const raw =
    (typeof data.clarification_question_id === 'string' && data.clarification_question_id) ||
    (typeof data.clarificationQuestionId === 'string' && data.clarificationQuestionId) ||
    '';
  return String(raw || '').trim();
}

function sanitizePendingClarification(rawPending, { recordMetrics = true } = {}) {
  if (!rawPending || typeof rawPending !== 'object' || Array.isArray(rawPending)) return null;
  const truncationFields = new Set();

  const createdAtRaw = Number(rawPending.created_at_ms);
  if (!Number.isFinite(createdAtRaw) || createdAtRaw <= 0) return null;
  const createdAtMs = Math.trunc(createdAtRaw);

  const resumeTextRaw = typeof rawPending.resume_user_text === 'string' ? rawPending.resume_user_text.trim() : '';
  if (!resumeTextRaw) return null;
  const resumeText = truncate(resumeTextRaw, PENDING_CLARIFICATION_MAX_RESUME_USER_TEXT);
  if (resumeText.truncated) truncationFields.add('resume_user_text');

  const flowIdRaw = typeof rawPending.flow_id === 'string' ? rawPending.flow_id.trim() : '';
  const flowId = /^pc_[a-z0-9]+$/i.test(flowIdRaw) ? flowIdRaw.slice(0, 32) : makeFlowId();

  const resumeUserHashRaw = typeof rawPending.resume_user_hash === 'string' ? rawPending.resume_user_hash.trim() : '';
  const resumeUserHashSafe = (resumeUserHashRaw || stableHashBase36(resumeText.value).slice(0, 20))
    .replace(/[^a-zA-Z0-9_-]/g, '')
    .slice(0, 24);

  if (!Array.isArray(rawPending.queue)) return null;
  const normalizedQueue = [];
  for (const rawQuestion of rawPending.queue) {
    const normalized = normalizeClarificationQuestionForPending(rawQuestion, {
      recordTruncationMetrics: false,
      truncationFields,
    });
    if (normalized) normalizedQueue.push(normalized);
  }
  if (normalizedQueue.length < rawPending.queue.length) truncationFields.add('queue');
  const cappedQueue = capArray(normalizedQueue, PENDING_CLARIFICATION_MAX_QUEUE);
  if (cappedQueue.dropped > 0) truncationFields.add('queue');

  let current = null;
  if (rawPending.current && typeof rawPending.current === 'object' && !Array.isArray(rawPending.current)) {
    const currentIdRaw = typeof rawPending.current.id === 'string' ? rawPending.current.id.trim() : '';
    if (currentIdRaw) {
      const currentIdInfo = normalizePendingClarificationId(currentIdRaw);
      current = { id: currentIdInfo.id, norm_id: currentIdInfo.norm_id };
    }
  }

  const historyRaw = Array.isArray(rawPending.history) ? rawPending.history : [];
  if (!Array.isArray(rawPending.history) && rawPending.history != null) {
    truncationFields.add('history');
  }
  const normalizedHistory = [];
  for (const entry of historyRaw) {
    if (!entry || typeof entry !== 'object' || Array.isArray(entry)) continue;
    const questionIdRaw = typeof entry.question_id === 'string' ? entry.question_id.trim() : '';
    const optionRaw = typeof entry.option === 'string' ? entry.option.trim() : '';
    const tsMsRaw = Number(entry.ts_ms);
    if (!questionIdRaw || !optionRaw || !Number.isFinite(tsMsRaw) || tsMsRaw <= 0) continue;

    const questionIdInfo = normalizePendingClarificationId(questionIdRaw);
    const optionTrimmed = truncate(optionRaw, PENDING_CLARIFICATION_MAX_OPTION);
    if (optionTrimmed.truncated) truncationFields.add('option');

    normalizedHistory.push({
      question_id: questionIdInfo.id,
      norm_id:
        typeof entry.norm_id === 'string' && entry.norm_id.trim()
          ? entry.norm_id.trim().slice(0, 80)
          : questionIdInfo.norm_id,
      option: optionTrimmed.value,
      ts_ms: Math.trunc(tsMsRaw),
    });
  }
  if (normalizedHistory.length < historyRaw.length) truncationFields.add('history');
  let history = normalizedHistory;
  if (normalizedHistory.length > PENDING_CLARIFICATION_MAX_HISTORY) {
    history = normalizedHistory.slice(-PENDING_CLARIFICATION_MAX_HISTORY);
    truncationFields.add('history');
  }

  const canonical = {
    v: PENDING_CLARIFICATION_SCHEMA_V1,
    flow_id: flowId,
    created_at_ms: createdAtMs,
    resume_user_text: resumeText.value,
    ...(resumeUserHashSafe ? { resume_user_hash: resumeUserHashSafe } : {}),
    step_index: history.length,
    ...(current ? { current } : {}),
    queue: cappedQueue.values,
    history,
  };

  const upgraded = Number(rawPending.v) !== PENDING_CLARIFICATION_SCHEMA_V1;
  if (recordMetrics) {
    if (upgraded) recordPendingClarificationUpgraded({ from: 'legacy' });
    if (truncationFields.size > 0) recordPendingClarificationTruncationFields(truncationFields);
  }

  return { pending: canonical, upgraded };
}

function getPendingClarification(session) {
  const s = session && typeof session === 'object' ? session : null;
  if (!s) return null;
  const state = s.state && typeof s.state === 'object' && !Array.isArray(s.state) ? s.state : null;
  if (!state) return null;
  const raw = state.pending_clarification;
  if (!raw || typeof raw !== 'object' || Array.isArray(raw)) return null;
  return sanitizePendingClarification(raw, { recordMetrics: true });
}

function emitPendingClarificationPatch(sessionPatch, pendingOrNull) {
  if (!sessionPatch || typeof sessionPatch !== 'object') return;
  const state = isPlainObject(sessionPatch.state) ? { ...sessionPatch.state } : {};
  state.pending_clarification = pendingOrNull || null;
  sessionPatch.state = state;
}

function buildChipsForQuestion(question, { stepIndex } = {}) {
  const q = normalizeClarificationQuestionForPending(question);
  if (!q) return [];
  const qid = String(q.id || 'clarify').trim() || 'clarify';
  const step = Number.isFinite(Number(stepIndex)) ? Math.max(1, Math.trunc(Number(stepIndex))) : 1;
  return q.options.slice(0, 8).map((option) => ({
    chip_id: `chip.clarify.${qid}.${option.trim().slice(0, 40).replace(/\s+/g, '_')}`,
    label: option,
    kind: 'quick_reply',
    data: {
      reply_text: option,
      clarification_id: qid,
      clarification_question_id: qid,
      clarification_norm_id: String(q.norm_id || ''),
      clarification_step: step,
    },
  }));
}

function advancePendingClarification(pending, selectedOption, selectedQuestionId) {
  const nowMs = Date.now();
  const option = typeof selectedOption === 'string' ? selectedOption.trim() : '';
  const currentId =
    (typeof selectedQuestionId === 'string' && selectedQuestionId.trim()) ||
    (pending && pending.current && typeof pending.current.id === 'string' && pending.current.id.trim()) ||
    'clarify';
  const currentIdInfo = normalizePendingClarificationId(currentId);
  const optionTrimmed = truncate(option || '(empty)', PENDING_CLARIFICATION_MAX_OPTION);
  if (optionTrimmed.truncated) {
    recordPendingClarificationTruncated({ field: 'option' });
  }
  const entry = {
    question_id: currentIdInfo.id,
    norm_id: currentIdInfo.norm_id,
    option: optionTrimmed.value || '(empty)',
    ts_ms: nowMs,
  };

  const history = Array.isArray(pending && pending.history) ? [...pending.history, entry] : [entry];
  const queue = Array.isArray(pending && pending.queue) ? pending.queue : [];
  const historyState = sanitizePendingClarification(
    {
      v: PENDING_CLARIFICATION_SCHEMA_V1,
      flow_id: pending && typeof pending.flow_id === 'string' ? pending.flow_id : makeFlowId(),
      created_at_ms: Number(pending && pending.created_at_ms) || nowMs,
      resume_user_text: typeof pending?.resume_user_text === 'string' ? pending.resume_user_text : '(no message)',
      ...(pending && typeof pending.resume_user_hash === 'string' ? { resume_user_hash: pending.resume_user_hash } : {}),
      step_index: history.length,
      ...(pending && pending.current ? { current: pending.current } : {}),
      queue,
      history,
    },
    { recordMetrics: true },
  );
  const boundedHistory = historyState ? historyState.pending.history : history.slice(-PENDING_CLARIFICATION_MAX_HISTORY);
  if (!queue.length) {
    return { nextPending: null, nextQuestion: null, history: boundedHistory };
  }

  const nextQuestion = normalizeClarificationQuestionForPending(queue[0], { recordTruncationMetrics: true });
  if (!nextQuestion) return { nextPending: null, nextQuestion: null, history: boundedHistory };
  const nextPendingState = sanitizePendingClarification(
    {
      v: PENDING_CLARIFICATION_SCHEMA_V1,
      flow_id: pending && typeof pending.flow_id === 'string' ? pending.flow_id : makeFlowId(),
      created_at_ms: Number(pending && pending.created_at_ms) || nowMs,
      resume_user_text: typeof pending?.resume_user_text === 'string' ? pending.resume_user_text : '(no message)',
      ...(pending && typeof pending.resume_user_hash === 'string' ? { resume_user_hash: pending.resume_user_hash } : {}),
      step_index: boundedHistory.length,
      current: { id: nextQuestion.id, norm_id: nextQuestion.norm_id },
      queue: queue.slice(1),
      history: boundedHistory,
    },
    { recordMetrics: true },
  );
  if (!nextPendingState || !nextPendingState.pending) {
    return { nextPending: null, nextQuestion: null, history: boundedHistory };
  }
  return { nextPending: nextPendingState.pending, nextQuestion, history: nextPendingState.pending.history };
}

function compactClarificationHistory(history) {
  const out = [];
  const list = Array.isArray(history) ? history : [];
  for (const item of list) {
    if (!item || typeof item !== 'object' || Array.isArray(item)) continue;
    const questionId = typeof item.question_id === 'string' ? item.question_id.trim() : '';
    const option = typeof item.option === 'string' ? item.option.trim() : '';
    if (!questionId || !option) continue;
    out.push({
      question_id: questionId.slice(0, 120),
      option: option.slice(0, 120),
    });
    if (out.length >= 5) break;
  }
  return out;
}

function isUnsureToken(raw) {
  const text = String(raw || '').trim().toLowerCase();
  if (!text) return false;
  return (
    text === 'unknown' ||
    text === 'unsure' ||
    text === 'not sure' ||
    text === 'n/a' ||
    text === 'na' ||
    /不确定|不知道|不清楚/.test(text)
  );
}

function inferGoalFromClarificationText(raw) {
  const text = String(raw || '').trim().toLowerCase();
  if (!text) return '';
  if (/(acne|breakout|blemish|comedo|控痘|痘|闭口|粉刺)/.test(text)) return 'acne';
  if (/(oil control|oily|oiliness|sebum|shine|greasy|pore|控油|出油|毛孔)/.test(text)) return 'oil control';
  if (/(redness|sensitive|reactive|泛红|敏感|刺痛|修护屏障|屏障)/.test(text)) return 'redness';
  if (/(dark spot|pigment|bright|tone|淡斑|美白|提亮|暗沉|色沉|痘印)/.test(text)) return 'dark_spots';
  if (/(dry|hydrate|moist|保湿|补水|干燥|紧绷)/.test(text)) return 'dehydration';
  if (/(wrinkle|fine line|firm|anti[- ]?aging|抗老|抗衰|细纹|紧致|提拉)/.test(text)) return 'wrinkles';
  return '';
}

function inferProfilePatchFromClarification({ clarificationId, replyText }) {
  const field = normalizeClarificationField(clarificationId);
  const raw = String(replyText || '').trim();
  const text = raw.toLowerCase();
  if (!field || !raw) return null;

  if (field === 'skinType') {
    if (/\boily\b/.test(text) || /(油皮|油性|出油)/.test(text)) return { skinType: 'oily' };
    if (/\bdry\b/.test(text) || /(干皮|干性|干燥|紧绷)/.test(text)) return { skinType: 'dry' };
    if (/\b(combo|combination|mixed)\b/.test(text) || /混合/.test(text)) return { skinType: 'combination' };
    if (/\bnormal\b/.test(text) || /中性/.test(text)) return { skinType: 'normal' };
    if (/\bsensitive\b/.test(text) || /敏感/.test(text)) return { skinType: 'sensitive' };
    if (isUnsureToken(text)) return { skinType: 'unknown' };
    return null;
  }

  if (field === 'barrierStatus') {
    if (/(stable|healthy|normal|ok|good|稳定|健康)/.test(text)) return { barrierStatus: 'healthy' };
    if (/(sting|stinging|red|irrit|burn|reactive|impaired|damaged|刺痛|泛红|发红|刺激|不稳定|受损)/.test(text)) return { barrierStatus: 'impaired' };
    if (isUnsureToken(text)) return { barrierStatus: 'unknown' };
    return null;
  }

  if (field === 'sensitivity') {
    if (/(^|\b)(low|mild)\b|低|轻/.test(text)) return { sensitivity: 'low' };
    if (/(^|\b)(medium|mid|moderate)\b|中/.test(text)) return { sensitivity: 'medium' };
    if (/(^|\b)(high|severe|very)\b|高|重/.test(text)) return { sensitivity: 'high' };
    if (/(^|\b)yes(\b|$)|有|容易刺痛/.test(text)) return { sensitivity: 'high' };
    if (/(^|\b)no(\b|$)|无|不敏感/.test(text)) return { sensitivity: 'low' };
    if (isUnsureToken(text)) return { sensitivity: 'unknown' };
    return null;
  }

  if (field === 'goals') {
    if (isUnsureToken(text)) return { goals: ['unknown'] };
    const goal = inferGoalFromClarificationText(text);
    if (goal) return { goals: [goal] };
    const normalized = raw.replace(/\s+/g, ' ').trim().slice(0, 80);
    return normalized ? { goals: [normalized] } : null;
  }

  if (field === 'budgetTier') {
    const budget = normalizeBudgetHint(raw);
    return { budgetTier: budget || raw.slice(0, 40) };
  }

  return null;
}

function parseProfilePatchFromAction(action) {
  const normalizedAction = normalizeIncomingChatAction(action);
  if (!normalizedAction) return null;
  const actionValue = normalizedAction;
  if (typeof actionValue === 'object' && actionValue.data && typeof actionValue.data === 'object') {
    const patch = actionValue.data.profile_patch || actionValue.data.profilePatch;
    if (patch && typeof patch === 'object') return patch;
  }

  const id = typeof actionValue === 'string' ? actionValue : actionValue && actionValue.action_id;
  if (typeof actionValue === 'object' && actionValue && typeof actionValue.data === 'object' && actionValue.data) {
    const clarificationIdRaw =
      actionValue.data.clarification_id || actionValue.data.clarificationId || parseClarificationIdFromActionId(id);
    const replyText = extractReplyTextFromAction(actionValue) || parseClarificationReplyFromActionId(id);
    const patchFromClarification = inferProfilePatchFromClarification({
      clarificationId: clarificationIdRaw,
      replyText,
    });
    if (patchFromClarification) return patchFromClarification;
  }

  // Fallback: parse chip ids like "profile.skinType.oily".
  if (!id || typeof id !== 'string') return null;
  const parts = id.split('.');
  if (parts.length < 3 || parts[0] !== 'profile') return null;
  const key = parts[1];
  const value = parts.slice(2).join('.');
  if (!key || !value) return null;
  if (key === 'goals') return { goals: [value] };
  if (key === 'skinType') return { skinType: value };
  if (key === 'sensitivity') return { sensitivity: value };
  if (key === 'barrierStatus') return { barrierStatus: value };
  return null;
}

function mergeMissingProfilePatchFields(target, source) {
  const base = target && typeof target === 'object' ? target : {};
  const extra = source && typeof source === 'object' ? source : null;
  if (!extra) return base;
  if (!base.skinType && typeof extra.skinType === 'string' && extra.skinType.trim()) base.skinType = extra.skinType.trim();
  if (!base.sensitivity && typeof extra.sensitivity === 'string' && extra.sensitivity.trim()) base.sensitivity = extra.sensitivity.trim();
  if (!base.barrierStatus && typeof extra.barrierStatus === 'string' && extra.barrierStatus.trim()) {
    base.barrierStatus = extra.barrierStatus.trim();
  }
  if ((!Array.isArray(base.goals) || base.goals.length === 0) && Array.isArray(extra.goals) && extra.goals.length) {
    base.goals = extra.goals.slice(0, 12);
  }
  return base;
}

function extractQuickProfileLightweightPatch(raw = null) {
  const node = raw && typeof raw === 'object' && !Array.isArray(raw) ? raw : null;
  if (!node) return null;

  const patch = {};
  const skinFeel = pickFirstTrimmed(node.skin_feel, node.skinFeel).toLowerCase();
  if (skinFeel === 'oily' || skinFeel === 'dry' || skinFeel === 'combination') patch.skinType = skinFeel;
  else if (skinFeel === 'unsure') patch.skinType = 'unknown';

  const goalPrimary = pickFirstTrimmed(node.goal_primary, node.goalPrimary).toLowerCase();
  if (goalPrimary === 'breakouts') patch.goals = ['acne'];
  else if (goalPrimary === 'brightening') patch.goals = ['brightening'];
  else if (goalPrimary === 'antiaging') patch.goals = ['wrinkles'];
  else if (goalPrimary === 'barrier') patch.goals = ['barrier'];
  else if (goalPrimary === 'spf') patch.goals = ['uv_protection'];
  else if (goalPrimary === 'other') patch.goals = ['other'];

  const sensitivityFlag = pickFirstTrimmed(node.sensitivity_flag, node.sensitivityFlag).toLowerCase();
  if (sensitivityFlag === 'yes') patch.sensitivity = 'high';
  else if (sensitivityFlag === 'no') patch.sensitivity = 'low';
  else if (sensitivityFlag === 'unsure') patch.sensitivity = 'unknown';

  const parsed = UserProfilePatchSchema.safeParse(patch);
  if (!parsed.success) return null;
  const clean = parsed.data;
  return Object.keys(clean).length ? clean : null;
}

function extractProfilePatchFromSession(session) {
  const s = session && typeof session === 'object' ? session : null;
  if (!s) return null;

  const rawProfile =
    (s.profile_patch && typeof s.profile_patch === 'object' ? s.profile_patch : null) ||
    (s.profilePatch && typeof s.profilePatch === 'object' ? s.profilePatch : null) ||
    (s.profile && typeof s.profile === 'object' ? s.profile : null) ||
    null;
  if (!rawProfile) return null;

  const patch = {};

  // Strings
  const copyString = (toKey, ...fromKeys) => {
    for (const k of fromKeys) {
      const v = rawProfile[k];
      if (typeof v !== 'string') continue;
      const t = v.trim();
      if (!t) continue;
      patch[toKey] = t;
      return;
    }
  };
  copyString('skinType', 'skinType', 'skin_type');
  copyString('sensitivity', 'sensitivity');
  copyString('barrierStatus', 'barrierStatus', 'barrier_status');
  copyString('region', 'region');
  copyString('budgetTier', 'budgetTier', 'budget_tier');
  copyString('age_band', 'age_band', 'ageBand');
  copyString('pregnancy_status', 'pregnancy_status', 'pregnancyStatus');
  copyString('lactation_status', 'lactation_status', 'lactationStatus');
  const dropUnknownOptionalSafetyField = (key) => {
    const raw = patch[key];
    if (typeof raw !== 'string') return;
    if (raw.trim().toLowerCase() !== 'unknown') return;
    delete patch[key];
  };
  dropUnknownOptionalSafetyField('age_band');
  dropUnknownOptionalSafetyField('pregnancy_status');
  dropUnknownOptionalSafetyField('lactation_status');
  const pregnancyDueDateRaw =
    typeof rawProfile.pregnancy_due_date === 'string'
      ? rawProfile.pregnancy_due_date
      : typeof rawProfile.pregnancyDueDate === 'string'
        ? rawProfile.pregnancyDueDate
        : '';
  const pregnancyDueDate = pregnancyDueDateRaw.trim();
  if (/^\d{4}-\d{2}-\d{2}$/.test(pregnancyDueDate)) patch.pregnancy_due_date = pregnancyDueDate;

  // Arrays
  if (Array.isArray(rawProfile.goals)) {
    const goals = rawProfile.goals
      .map((v) => (typeof v === 'string' ? v.trim() : ''))
      .filter(Boolean)
      .slice(0, 12);
    if (goals.length) patch.goals = goals;
  }
  if (Array.isArray(rawProfile.contraindications)) {
    const contraindications = rawProfile.contraindications
      .map((v) => (typeof v === 'string' ? v.trim() : ''))
      .filter(Boolean)
      .slice(0, 24);
    if (contraindications.length) patch.contraindications = contraindications;
  }
  if (Array.isArray(rawProfile.high_risk_medications)) {
    const medications = rawProfile.high_risk_medications
      .map((v) => (typeof v === 'string' ? v.trim() : ''))
      .filter(Boolean)
      .slice(0, 30);
    if (medications.length) patch.high_risk_medications = medications;
  }

  // Mixed types
  if (rawProfile.currentRoutine != null) patch.currentRoutine = normalizeRoutineInputWithPmShortcut(rawProfile.currentRoutine);
  if (rawProfile.current_routine != null) patch.currentRoutine = normalizeRoutineInputWithPmShortcut(rawProfile.current_routine);
  if (rawProfile.itinerary != null) patch.itinerary = rawProfile.itinerary;
  if (rawProfile.travel_plan && typeof rawProfile.travel_plan === 'object' && !Array.isArray(rawProfile.travel_plan)) {
    patch.travel_plan = rawProfile.travel_plan;
  }
  if (rawProfile.travelPlan && typeof rawProfile.travelPlan === 'object' && !Array.isArray(rawProfile.travelPlan)) {
    patch.travel_plan = rawProfile.travelPlan;
  }
  mergeMissingProfilePatchFields(patch, extractProfilePatchFromRoutinePayload(patch.currentRoutine));
  mergeMissingProfilePatchFields(patch, extractQuickProfileLightweightPatch(rawProfile));

  const parsed = UserProfilePatchSchema.safeParse(patch);
  if (!parsed.success) return null;
  const clean = parsed.data;
  return Object.keys(clean).length ? clean : null;
}

function extractProfilePatchFromRequestContextPayload(payload) {
  const root = payload && typeof payload === 'object' && !Array.isArray(payload) ? payload : null;
  if (!root) return null;

  const candidates = [];
  const visited = new Set();
  const visit = (node, depth = 0) => {
    if (depth > 2 || !node || typeof node !== 'object' || Array.isArray(node) || visited.has(node)) return;
    visited.add(node);
    candidates.push(node);
    for (const key of ['profile', 'profile_patch', 'profilePatch', 'skin_profile', 'skinProfile', 'goal_profile', 'goalProfile', 'meta', 'metadata', 'context']) {
      visit(node[key], depth + 1);
    }
  };
  visit(root);

  const readString = (...aliases) => {
    for (const node of candidates) {
      for (const alias of aliases) {
        const value = node && typeof node === 'object' ? node[alias] : null;
        if (typeof value !== 'string') continue;
        const trimmed = value.trim();
        if (!trimmed) continue;
        return trimmed;
      }
    }
    return '';
  };

  const readGoalArray = () => {
    const out = [];
    const seen = new Set();
    const pushGoal = (value) => {
      const normalized = typeof value === 'string' ? value.trim() : '';
      if (!normalized) return;
      const key = normalized.toLowerCase();
      if (seen.has(key)) return;
      seen.add(key);
      out.push(normalized);
    };

    for (const node of candidates) {
      for (const alias of ['goals', 'selected_goals', 'selectedGoals', 'pending_goals', 'pendingGoals']) {
        const values = node && typeof node === 'object' ? node[alias] : null;
        if (!Array.isArray(values)) continue;
        values.forEach(pushGoal);
      }
    }

    return out.slice(0, 12);
  };

  const patch = {};
  const skinType = readString('skinType', 'skin_type', 'skin_type_tendency', 'skinTypeTendency');
  if (skinType) patch.skinType = skinType;
  const sensitivity = readString('sensitivity', 'sensitivity_level', 'sensitivityLevel', 'sensitivity_tendency', 'sensitivityTendency');
  if (sensitivity) patch.sensitivity = sensitivity;
  const barrierStatus = readString('barrierStatus', 'barrier_status', 'barrier', 'barrier_state', 'barrierState');
  if (barrierStatus) patch.barrierStatus = barrierStatus;
  const goals = readGoalArray();
  if (goals.length) patch.goals = goals;
  for (const node of candidates) {
    mergeMissingProfilePatchFields(patch, extractQuickProfileLightweightPatch(node));
  }

  const readPlainObject = (...aliases) => {
    for (const node of candidates) {
      for (const alias of aliases) {
        const value = node && typeof node === 'object' ? node[alias] : null;
        if (value && typeof value === 'object' && !Array.isArray(value)) return value;
      }
    }
    return null;
  };

  const travelPlan = readPlainObject('travel_plan', 'travelPlan');
  if (travelPlan) patch.travel_plan = travelPlan;

  const currentRoutine = readPlainObject('currentRoutine', 'current_routine', 'routine', 'routine_state');
  if (currentRoutine) {
    patch.currentRoutine = normalizeRoutineInputWithPmShortcut(currentRoutine);
  } else {
    const currentRoutineText = readString('currentRoutine', 'current_routine', 'routine_text', 'routineText');
    if (currentRoutineText) patch.currentRoutine = normalizeRoutineInputWithPmShortcut(currentRoutineText);
  }

  const parsed = UserProfilePatchSchema.safeParse(patch);
  if (!parsed.success) return null;
  const clean = parsed.data;
  return Object.keys(clean).length ? clean : null;
}

function extractAnalysisProfileContextOverlay(...sources) {
  const patch = {};
  const assignString = (key, value) => {
    if (typeof value !== 'string') return;
    const trimmed = value.trim();
    if (!trimmed) return;
    patch[key] = trimmed;
  };
  const assignGoals = (value) => {
    if (!Array.isArray(value)) return;
    const goals = value
      .map((item) => (typeof item === 'string' ? item.trim() : ''))
      .filter(Boolean)
      .slice(0, 12);
    if (goals.length) patch.goals = goals;
  };

  for (const source of sources) {
    const node = source && typeof source === 'object' && !Array.isArray(source) ? source : null;
    if (!node) continue;
    assignString('skinType', node.skinType);
    assignString('sensitivity', node.sensitivity);
    assignString('barrierStatus', node.barrierStatus);
    assignGoals(node.goals);
  }

  const parsed = UserProfilePatchSchema.safeParse(patch);
  if (!parsed.success) return null;
  const clean = parsed.data;
  return Object.keys(clean).length ? clean : null;
}

function extractProfilePatchFromRoutinePayload(routineInput) {
  const routineRoot = (isPlainObject(routineInput) ? routineInput : null) || tryParseRoutineObject(routineInput);
  if (!routineRoot) return null;

  const candidates = [];
  const visited = new Set();
  const visit = (node, depth = 0) => {
    if (depth > 3 || !isPlainObject(node) || visited.has(node)) return;
    visited.add(node);
    candidates.push(node);
    for (const key of ['profile', 'profile_patch', 'profilePatch', 'skin_profile', 'skinProfile', 'goal_profile', 'goalProfile', 'meta', 'metadata', 'context']) {
      visit(node[key], depth + 1);
    }
  };
  visit(routineRoot);

  const readString = (...aliases) => {
    for (const node of candidates) {
      for (const alias of aliases) {
        const value = node && typeof node === 'object' ? node[alias] : null;
        if (typeof value !== 'string') continue;
        const trimmed = value.trim();
        if (!trimmed) continue;
        return trimmed;
      }
    }
    return '';
  };

  const readGoalArray = () => {
    const out = [];
    const seen = new Set();
    const pushGoal = (value) => {
      const normalized = typeof value === 'string' ? value.trim() : '';
      if (!normalized) return;
      const key = normalized.toLowerCase();
      if (seen.has(key)) return;
      seen.add(key);
      out.push(normalized);
    };

    for (const node of candidates) {
      for (const alias of ['goals', 'selected_goals', 'selectedGoals', 'pending_goals', 'pendingGoals']) {
        const values = node && typeof node === 'object' ? node[alias] : null;
        if (!Array.isArray(values)) continue;
        values.forEach(pushGoal);
      }
      pushGoal(node && typeof node === 'object' ? node.custom_input : null);
      pushGoal(node && typeof node === 'object' ? node.customInput : null);
    }

    return out.slice(0, 12);
  };

  const patch = {};
  const skinType = readString('skinType', 'skin_type', 'skin_type_tendency', 'skinTypeTendency');
  if (skinType) patch.skinType = skinType;
  const sensitivity = readString('sensitivity', 'sensitivity_level', 'sensitivityLevel', 'sensitivity_tendency', 'sensitivityTendency');
  if (sensitivity) patch.sensitivity = sensitivity;
  const barrierStatus = readString('barrierStatus', 'barrier_status', 'barrier', 'barrier_state', 'barrierState');
  if (barrierStatus) patch.barrierStatus = barrierStatus;
  const goals = readGoalArray();
  if (goals.length) patch.goals = goals;
  for (const node of candidates) {
    mergeMissingProfilePatchFields(patch, extractQuickProfileLightweightPatch(node));
  }

  const parsed = UserProfilePatchSchema.safeParse(patch);
  if (!parsed.success) return null;
  const clean = parsed.data;
  return Object.keys(clean).length ? clean : null;
}

function parseTravelTimeWindowFromText(message) {
  const text = String(message || '').trim();
  if (!text) return null;
  if (/下周|\bnext\s+week\b/i.test(text)) return 'next_week';
  if (/这周|\bthis\s+week\b/i.test(text)) return 'this_week';
  if (/下个月|\bnext\s+month\b/i.test(text)) return 'next_month';
  if (/这个月|\bthis\s+month\b/i.test(text)) return 'this_month';
  if (/周末|\bweekend\b/i.test(text)) return 'weekend';
  if (/明天|\btomorrow\b/i.test(text)) return 'tomorrow';
  if (/今天|\btoday\b/i.test(text)) return 'today';
  if (/travel|trip|itinerary|出差|旅行/i.test(text)) return 'unknown';
  return null;
}

function normalizePregnancyStatusForPolicy(value) {
  const raw = String(value || '').trim().toLowerCase();
  if (!raw) return 'unknown';
  if (raw === 'not_pregnant' || raw === 'pregnant' || raw === 'trying' || raw === 'unknown') return raw;
  if (/not[_\s-]?pregnant/.test(raw)) return 'not_pregnant';
  if (/pregnan|怀孕|孕/.test(raw)) return 'pregnant';
  if (/trying|ttc|备孕|准备怀孕/.test(raw)) return 'trying';
  return 'unknown';
}

function normalizePregnancyDueDateForPolicy(value) {
  if (value == null) return null;
  const raw = String(value).trim();
  if (!raw) return null;
  if (!/^\d{4}-\d{2}-\d{2}$/.test(raw)) return null;
  return raw;
}

function utcTodayIsoDate() {
  return new Date().toISOString().slice(0, 10);
}

function derivePregnancyPolicyPatch({ profile, message, todayUtc } = {}) {
  const source = profile && typeof profile === 'object' && !Array.isArray(profile) ? profile : {};
  const text = String(message || '');
  const nowUtc = normalizePregnancyDueDateForPolicy(todayUtc) || utcTodayIsoDate();
  let status = normalizePregnancyStatusForPolicy(source.pregnancy_status);
  let dueDate = normalizePregnancyDueDateForPolicy(source.pregnancy_due_date);
  const patch = {};
  const events = [];

  const tryingDetected = /\b(trying(\s+to\s+conceive)?|ttc)\b/i.test(text) || /备孕|准备怀孕/.test(text);
  if (tryingDetected && status !== 'trying') {
    status = 'trying';
    patch.pregnancy_status = 'trying';
  }

  if (status !== 'pregnant' && dueDate) {
    dueDate = null;
    patch.pregnancy_due_date = null;
  }

  if (status === 'pregnant' && dueDate && dueDate < nowUtc) {
    status = 'not_pregnant';
    dueDate = null;
    patch.pregnancy_status = 'not_pregnant';
    patch.pregnancy_due_date = null;
    events.push({
      event_name: 'pregnancy_status_auto_reset',
      data: { from: 'pregnant', to: 'not_pregnant', effective_date_utc: nowUtc },
    });
  }

  if (status === 'unknown') {
    status = 'not_pregnant';
    dueDate = null;
    patch.pregnancy_status = 'not_pregnant';
    patch.pregnancy_due_date = null;
    events.push({
      event_name: 'pregnancy_status_defaulted',
      data: { default_status: 'not_pregnant', reason: 'missing_or_unknown', effective_date_utc: nowUtc },
    });
  }

  return {
    patch: Object.keys(patch).length > 0 ? patch : null,
    events,
  };
}

function extractProfilePatchFromFreeText({ message, canonicalIntent } = {}) {
  const text = String(message || '').trim();
  if (!text) return null;
  const lower = text.toLowerCase();
  const patch = {};

  if (/(怀孕|孕期|孕妇|妊娠|孕\s*\d+\s*周|\bpregnan(t|cy)\b|\b\d+\s*weeks?\s*pregnant\b)/i.test(text)) {
    patch.pregnancy_status = 'pregnant';
  } else if (/备孕|准备怀孕|trying to conceive|ttc/i.test(text)) {
    patch.pregnancy_status = 'trying';
  } else if (/未怀孕|没怀孕|\bnot\s+pregnant\b/i.test(text)) {
    patch.pregnancy_status = 'not_pregnant';
  }

  if (/哺乳|母乳|正在喂奶|breastfeed|breastfeeding|lactat/i.test(text)) {
    patch.lactation_status = 'lactating';
  } else if (/不哺乳|未哺乳|not\s+lactating|not\s+breastfeeding/i.test(lower)) {
    patch.lactation_status = 'not_lactating';
  }

  if (/(油皮|油性|出油|oily\b|very oily|greasy)/i.test(text)) {
    patch.skinType = 'oily';
  } else if (/(干皮|干性|起皮|紧绷|dry skin|very dry|dry\b)/i.test(text)) {
    patch.skinType = 'dry';
  } else if (/(混合皮|混合性|t区|combination|combo)/i.test(text)) {
    patch.skinType = 'combination';
  } else if (/(中性皮|normal skin|normal\b)/i.test(text)) {
    patch.skinType = 'normal';
  } else if (/(敏感肌|敏感性皮肤|sensitive skin)/i.test(text)) {
    patch.skinType = 'sensitive';
  }

  if (/(高敏|敏感严重|very sensitive|high sensitivity|easily irritated)/i.test(text)) {
    patch.sensitivity = 'high';
  } else if (/(低敏|不敏感|not sensitive|low sensitivity|resilient)/i.test(text)) {
    patch.sensitivity = 'low';
  } else if (/(中敏|medium sensitivity|moderately sensitive)/i.test(text)) {
    patch.sensitivity = 'medium';
  }

  if (/(屏障受损|屏障不稳|刺痛|泛红|barrier impaired|barrier damaged|stinging|burning|reactive)/i.test(text)) {
    patch.barrierStatus = 'impaired';
  } else if (/(屏障稳定|状态稳定|barrier healthy|barrier stable|well tolerated)/i.test(text)) {
    patch.barrierStatus = 'healthy';
  }

  const inferredGoal = inferGoalFromClarificationText(text);
  if (inferredGoal) {
    patch.goals = Array.from(
      new Set([...(Array.isArray(patch.goals) ? patch.goals : []), inferredGoal]),
    ).slice(0, 4);
  }

  const routineMatch =
    text.match(/(?:current routine|my routine|现在在用|目前在用|当前用的是|routine[:：])\s*([^\n]{4,260})/i) ||
    text.match(/(?:am|pm|早上|晚上).{0,160}(?:cleanser|serum|cream|spf|洁面|精华|面霜|防晒)/i);
  if (routineMatch) {
    const routineText = String(routineMatch[1] || routineMatch[0] || '').trim();
    if (routineText) {
      patch.currentRoutine = routineText.slice(0, 500);
    }
  }

  const travelEntities = canonicalIntent && canonicalIntent.entities && typeof canonicalIntent.entities === 'object'
    ? canonicalIntent.entities
    : {};
  const looksTravel = canonicalIntent && (canonicalIntent.intent === INTENT_ENUM.TRAVEL_PLANNING || canonicalIntent.intent === INTENT_ENUM.WEATHER_ENV);
  if (looksTravel || /出差|旅行|飞行|flight|trip|itinerary|weather|climate|天气|气候/i.test(text)) {
    const baseTravel = {};
    if (typeof travelEntities.departure_region === 'string' && travelEntities.departure_region.trim()) {
      baseTravel.departure_region = travelEntities.departure_region.trim().slice(0, 140);
    }
    if (typeof travelEntities.destination === 'string' && travelEntities.destination.trim()) {
      baseTravel.destination = travelEntities.destination.trim().slice(0, 100);
    }
    if (travelEntities.date_range && typeof travelEntities.date_range === 'object') {
      if (typeof travelEntities.date_range.start === 'string' && travelEntities.date_range.start.trim()) {
        baseTravel.start_date = travelEntities.date_range.start.trim().slice(0, 20);
      }
      if (typeof travelEntities.date_range.end === 'string' && travelEntities.date_range.end.trim()) {
        baseTravel.end_date = travelEntities.date_range.end.trim().slice(0, 20);
      }
    }
    const inferredWindow =
      (typeof travelEntities.time_window === 'string' && travelEntities.time_window.trim()) ||
      parseTravelTimeWindowFromText(text);
    if (inferredWindow) baseTravel.time_window = String(inferredWindow).trim().slice(0, 20);
    if (Object.keys(baseTravel).length) patch.travel_plan = baseTravel;
  }

  const parsed = UserProfilePatchSchema.safeParse(patch);
  if (!parsed.success) return null;
  const clean = parsed.data;
  return Object.keys(clean).length ? clean : null;
}

function normalizeChatRouteActionPayload(data = {}) {
  const body = isPlainObject(data) ? data : {};
  if (body.action) return normalizeIncomingChatAction(body.action);
  if (typeof body.action_id === 'string' && body.action_id.trim()) {
    return {
      action_id: body.action_id.trim(),
      kind: 'action',
      ...(body.action_data && typeof body.action_data === 'object' && !Array.isArray(body.action_data)
        ? { data: body.action_data }
        : {}),
    };
  }
  if (typeof body.action_label === 'string' && body.action_label.trim()) {
    return body.action_label.trim();
  }
  return null;
}

function buildChatIngressSignalSnapshot({ data = null, language = 'EN' } = {}) {
  const body = isPlainObject(data) ? data : {};
  const normalizedActionPayload = normalizeChatRouteActionPayload(body);
  const actionLabel =
    typeof body.action_label === 'string' && body.action_label.trim()
      ? body.action_label.trim()
      : normalizedActionPayload && typeof normalizedActionPayload === 'string' && normalizedActionPayload.trim()
        ? normalizedActionPayload.trim()
        : null;
  const explicitActionId =
    (normalizedActionPayload && typeof normalizedActionPayload === 'object'
      ? normalizedActionPayload.action_id
      : typeof normalizedActionPayload === 'string'
        ? normalizedActionPayload
        : null) ||
    body.action_id ||
    null;
  const message = extractPrimaryChatRequestMessage(body, normalizedActionPayload);
  const canonicalIntent = inferCanonicalIntent({
    message,
    actionId: explicitActionId,
    actionLabel,
    language,
  });
  const latestRecoContextFromSession = extractLatestRecoContextFromSession(body.session);
  const profilePatchFromSession = extractProfilePatchFromSession(body.session);
  const profilePatchFromRequestContext = extractProfilePatchFromRequestContextPayload(body);
  const profilePatchFromAction = extractProfilePatchFromSession({
    profile_patch: parseProfilePatchFromAction(normalizedActionPayload),
  });
  const profilePatchFromFreeText = extractProfilePatchFromFreeText({
    message,
    canonicalIntent,
  });
  const profileOverlay = extractAnalysisProfileContextOverlay(
    profilePatchFromSession,
    profilePatchFromFreeText,
    profilePatchFromRequestContext,
    profilePatchFromAction,
  );
  return {
    normalizedActionPayload,
    actionLabel,
    explicitActionId,
    message,
    canonicalIntent,
    latestRecoContextFromSession,
    profilePatchFromSession,
    profilePatchFromRequestContext,
    profilePatchFromAction,
    profilePatchFromFreeText,
    profileOverlay,
    includeAlternatives: extractIncludeAlternativesFromAction(normalizedActionPayload),
  };
}

function extractTrackerLogFromFreeText({ message } = {}) {
  const text = String(message || '').trim();
  if (!text) return null;
  if (!/(today|recent|最近|今天|check[- ]?in|打卡|泛红|痘|爆痘|出油|干燥|刺痛|hydration|redness|acne)/i.test(text)) {
    return null;
  }

  const clamp0to5 = (value) => {
    const n = Number(value);
    if (!Number.isFinite(n)) return null;
    return Math.max(0, Math.min(5, Math.trunc(n)));
  };
  const parseScore = (re) => {
    const m = text.match(re);
    if (!m) return null;
    return clamp0to5(m[1]);
  };

  const redness = parseScore(/(?:redness|泛红|发红)\s*[:=]?\s*([0-5])/i);
  const acne = parseScore(/(?:acne|breakout|痘痘|爆痘|闭口)\s*[:=]?\s*([0-5])/i);
  const hydration = parseScore(/(?:hydration|dryness|保湿|干燥)\s*[:=]?\s*([0-5])/i);
  const sensationMatch = text.match(/(?:sensation|感觉|体感)\s*[:：]?\s*([^\n]{2,120})/i);
  const notes = text.slice(0, 380);

  const log = {
    date: utcTodayIsoDate(),
    ...(redness != null ? { redness } : {}),
    ...(acne != null ? { acne } : {}),
    ...(hydration != null ? { hydration } : {}),
    ...(sensationMatch && sensationMatch[1] ? { sensation: String(sensationMatch[1]).trim().slice(0, 120) } : {}),
    notes,
  };
  const parsed = TrackerLogSchema.safeParse(log);
  if (!parsed.success) return null;
  return parsed.data;
}

function normalizeSafetyPromptStateForChat(rawState) {
  if (!rawState || typeof rawState !== 'object' || Array.isArray(rawState)) {
    return { asked_once_fields: {}, asked_at_ms: null };
  }
  const askedRaw =
    rawState.asked_once_fields && typeof rawState.asked_once_fields === 'object' && !Array.isArray(rawState.asked_once_fields)
      ? rawState.asked_once_fields
      : {};
  const askedOnce = {};
  for (const [keyRaw, valueRaw] of Object.entries(askedRaw)) {
    const key = String(keyRaw || '').trim();
    if (!key || valueRaw !== true) continue;
    askedOnce[key] = true;
  }
  const askedAtRaw = Number(rawState.asked_at_ms);
  const askedAt = Number.isFinite(askedAtRaw) ? Math.max(0, Math.trunc(askedAtRaw)) : null;
  return {
    asked_once_fields: askedOnce,
    asked_at_ms: askedAt,
  };
}

function profileHasOptionalSafetyFieldValue(profile, field) {
  const source = profile && typeof profile === 'object' ? profile : {};
  if (field === 'high_risk_medications') {
    return Array.isArray(source.high_risk_medications);
  }
  if (field === 'pregnancy_status' || field === 'age_band') {
    const value = typeof source[field] === 'string' ? source[field].trim().toLowerCase() : '';
    return Boolean(value) && value !== 'unknown';
  }
  return false;
}

function buildSafetyAdvisoryChipsByField({ field, language }) {
  const lang = language === 'CN' ? 'CN' : 'EN';
  if (field === 'pregnancy_status') {
    return [
      {
        chip_id: 'chip.profile.pregnancy.not_pregnant',
        label: lang === 'CN' ? '未怀孕' : 'Not pregnant',
        kind: 'quick_reply',
        data: { profile_patch: { pregnancy_status: 'not_pregnant' }, reply_text: lang === 'CN' ? '未怀孕' : 'Not pregnant' },
      },
      {
        chip_id: 'chip.profile.pregnancy.pregnant',
        label: lang === 'CN' ? '怀孕中' : 'Pregnant',
        kind: 'quick_reply',
        data: { profile_patch: { pregnancy_status: 'pregnant' }, reply_text: lang === 'CN' ? '怀孕中' : 'Pregnant' },
      },
      {
        chip_id: 'chip.profile.pregnancy.trying',
        label: lang === 'CN' ? '备孕中' : 'Trying',
        kind: 'quick_reply',
        data: { profile_patch: { pregnancy_status: 'trying' }, reply_text: lang === 'CN' ? '备孕中' : 'Trying to conceive' },
      },
    ];
  }
  if (field === 'age_band') {
    return [
      {
        chip_id: 'chip.profile.age.18_24',
        label: '18-24',
        kind: 'quick_reply',
        data: { profile_patch: { age_band: '18_24' }, reply_text: '18-24' },
      },
      {
        chip_id: 'chip.profile.age.25_34',
        label: '25-34',
        kind: 'quick_reply',
        data: { profile_patch: { age_band: '25_34' }, reply_text: '25-34' },
      },
      {
        chip_id: 'chip.profile.age.35_44',
        label: '35-44',
        kind: 'quick_reply',
        data: { profile_patch: { age_band: '35_44' }, reply_text: '35-44' },
      },
    ];
  }
  if (field === 'high_risk_medications') {
    return [
      {
        chip_id: 'chip.profile.medications.none',
        label: lang === 'CN' ? '无高风险药物' : 'No high-risk meds',
        kind: 'quick_reply',
        data: {
          profile_patch: { high_risk_medications: [] },
          reply_text: lang === 'CN' ? '我目前没有高风险药物' : 'I have no high-risk medications',
        },
      },
    ];
  }
  return [];
}

function hasRoutineSosSignal(message) {
  const text = String(message || '').toLowerCase();
  if (!text) return false;
  return /(burn(ing)?|sting(ing)?|peel(ing)?|flak(e|ing)|paper-thin|redness|灼热|刺痛|脱皮|爆皮|红肿|泛红|屏障受损)/.test(text);
}

function looksLikeLowRiskSkincareTask(message) {
  const text = String(message || '').toLowerCase();
  if (!text) return false;
  const lowRiskSignal =
    /(sunscreen|spf|moisturizer|hydrator|barrier cream|cleanser|防晒|保湿|面霜|乳液|洁面|修护)/.test(text);
  const highRiskSignal =
    /(prescription|isotretinoin|accutane|tretinoin|adapalene|hydroquinone|抗生素|处方|异维a酸|维a酸|氢醌)/.test(text);
  return lowRiskSignal && !highRiskSignal;
}

function enrichRoutineExpertWithMessageSignals({ expert, message, language } = {}) {
  if (!expert || typeof expert !== 'object' || Array.isArray(expert)) return expert;
  const lang = language === 'CN' ? 'CN' : 'EN';
  const raw = String(message || '');
  const text = raw.toLowerCase();

  const addUniqueLine = (list, line, front = false) => {
    if (!Array.isArray(list)) return;
    const value = typeof line === 'string' ? line.trim() : '';
    if (!value) return;
    const normalized = value.toLowerCase();
    const exists = list.some((item) => String(item || '').trim().toLowerCase() === normalized);
    if (exists) return;
    if (front) list.unshift(value);
    else list.push(value);
  };

  if (!Array.isArray(expert.key_issues)) expert.key_issues = [];
  if (!Array.isArray(expert.why_it_happens)) expert.why_it_happens = [];
  if (!expert.plan_7d || typeof expert.plan_7d !== 'object' || Array.isArray(expert.plan_7d)) {
    expert.plan_7d = { am: [], pm: [], observe_metrics: [], stop_conditions: [] };
  }
  if (!Array.isArray(expert.plan_7d.am)) expert.plan_7d.am = [];
  if (!Array.isArray(expert.plan_7d.pm)) expert.plan_7d.pm = [];
  if (!Array.isArray(expert.plan_7d.observe_metrics)) expert.plan_7d.observe_metrics = [];
  if (!Array.isArray(expert.plan_7d.stop_conditions)) expert.plan_7d.stop_conditions = [];
  if (!expert.phase_plan || typeof expert.phase_plan !== 'object' || Array.isArray(expert.phase_plan)) {
    expert.phase_plan = { phase_1_14d: [], phase_2_3_6w: [] };
  }
  if (!Array.isArray(expert.phase_plan.phase_1_14d)) expert.phase_plan.phase_1_14d = [];
  if (!Array.isArray(expert.phase_plan.phase_2_3_6w)) expert.phase_plan.phase_2_3_6w = [];
  if (!Array.isArray(expert.ask_3_questions)) expert.ask_3_questions = [];
  if (!Array.isArray(expert.conditional_followups)) expert.conditional_followups = [];

  const addIssue = ({ id, severity = 'medium', title, evidence, impact }) => {
    const key = String(id || '').trim();
    if (!key) return;
    const exists = expert.key_issues.some((row) => row && String(row.id || '').trim() === key);
    if (exists) return;
    expert.key_issues.unshift({
      id: key,
      severity,
      title,
      evidence: Array.isArray(evidence) ? evidence.filter(Boolean).slice(0, 3) : [],
      impact: impact || '',
    });
    if (expert.key_issues.length > 5) expert.key_issues = expert.key_issues.slice(0, 5);
  };

  const setPrimaryQuestion = (question) => {
    const q = typeof question === 'string' ? question.trim() : '';
    if (!q) return;
    expert.primary_question = q;
    expert.ask_3_questions = [q, ...expert.ask_3_questions.filter((item) => String(item || '').trim() !== q)].slice(0, 3);
  };

  const hasMale = /(男生|男性|\bmale\b|\bman\b|\bbeard\b|胡子|胡茬)/i.test(raw);
  const hasSimplePref = /(极简|越简单|简单即可|minimal|simple|minimalist)/i.test(raw);
  const hasScrubCleanser = /(磨砂|颗粒|scrub|micro-?particles|physical exfoliation)/i.test(raw);
  const hasHighCleanFreq = /(一天洗三次|3\s*times|three\s*times|3x)/i.test(text);
  const hasShaving = /(刮胡|剃须|shav)/i.test(text);
  const hasBha2 = /(2%\s*(bha|水杨酸)|bha\s*2%|水杨酸\s*2%)/i.test(text);
  const hasFullFace = /(全脸|full[\s-]?face)/i.test(text);
  const hasStingOrPeel = /(刺痛|灼热|stinging|burning|起皮|脱皮|peel|white\s*flakes?)/i.test(text);
  const hasTravelColdWind = /(哈尔滨|零下|冷|干|大风|cold|dry|wind|ski|alpine|altitude|snow)/i.test(text);
  const hasPregnancy = /(怀孕|孕|pregnan|trimester)/i.test(text);
  const hasAzelaic = /(壬二酸|azelaic)/i.test(text);
  const hasAhaOrGlycolic = /(果酸|glycolic|aha)/i.test(text);
  const asksRestartTonight = /(今晚|tonight).*(重启|restart|继续)/i.test(text) || /(can i restart)/i.test(text);
  const hasSpfRefusal = /(不涂防晒|refuse.*sunscreen|no\s*spf|don'?t use sunscreen)/i.test(text);
  const hasStacking = /(same night|同晚|叠涂|stack|2%\s*bha.*lactic.*retinol|retinol.*bha|lactic.*retinol)/i.test(text);

  if (hasMale || hasSimplePref) {
    addIssue({
      id: 'male_minimalist_context',
      severity: 'medium',
      title: lang === 'CN' ? '已识别 male / 极简偏好（minimal routine）' : 'Male + minimalist preference recognized',
      evidence: [lang === 'CN' ? '将优先给 2-step gentle cleanse + lightweight hydration。' : 'Prioritizing a 2-step plan: gentle cleanse + lightweight hydration.'],
      impact: lang === 'CN' ? '减少步骤复杂度，提高长期执行率。' : 'Keeps routine executable and consistent.',
    });
  }

  if (hasScrubCleanser || hasHighCleanFreq) {
    addIssue({
      id: 'over_cleansing_scrub_risk',
      severity: 'high',
      title: lang === 'CN' ? '立即停用 scrub/磨砂洁面，清洁降到 1-2 次/天' : 'Stop scrub cleanser now; reduce cleansing to 1-2x/day',
      evidence: [lang === 'CN' ? '磨砂颗粒 + 高频清洁会放大紧绷/刺痛与屏障压力。' : 'Scrub particles + high frequency cleansing increases barrier stress and stinging.'],
      impact: lang === 'CN' ? '先止损可快速降低紧绷和刺激。' : 'Immediate risk reduction for tightness/irritation.',
    });
    addUniqueLine(
      expert.plan_7d.am,
      lang === 'CN'
        ? '清洁频次控制在每天 1-2 次（avoid over-cleansing）。'
        : 'Keep cleansing frequency at 1-2x/day (avoid over-cleansing).',
      true
    );
  }

  if (hasShaving) {
    addIssue({
      id: 'post_shave_irritation',
      severity: 'high',
      title: lang === 'CN' ? '剃须区（chin/beard area）按敏感区处理' : 'Treat shaved chin/beard area as high-sensitivity zone',
      evidence: [lang === 'CN' ? '剃须后优先舒缓：Centella / Allantoin / Panthenol。' : 'Post-shave soothing focus: Centella / Allantoin / Panthenol.'],
      impact: lang === 'CN' ? '减少下颌线反复刺痛与泛红。' : 'Reduces recurring post-shave irritation.',
    });
    addUniqueLine(
      expert.plan_7d.pm,
      lang === 'CN'
        ? '剃须后仅做舒缓修护，beard area 避免强活性。'
        : 'Post-shave, do soothing repair only; avoid strong actives on the beard area.',
      true
    );
  }

  if (hasBha2 || hasFullFace) {
    addIssue({
      id: 'bha_full_face_risk',
      severity: 'high',
      title: lang === 'CN' ? '2% BHA 全脸风险高，先停并改为分区低频' : 'Full-face 2% BHA is high-risk; pause and reintroduce by zones',
      evidence: [lang === 'CN' ? '先从 nose/forehead spot use，avoid lower face/beard area。' : 'Reintroduce only on nose/forehead, avoid lower face/beard area.'],
      impact: lang === 'CN' ? '避免剃须区刺激叠加。' : 'Prevents overlap with shaving-related irritation.',
    });
    addUniqueLine(
      expert.phase_plan.phase_2_3_6w,
      lang === 'CN'
        ? 'BHA 回归仅限 T 区，每周 1-2 次起步。'
        : 'Reintroduce BHA only on the T-zone, starting at 1-2x/week.',
      true
    );
  }

  if (hasStingOrPeel) {
    addIssue({
      id: 'acute_barrier_flare',
      severity: 'high',
      title: lang === 'CN' ? '急性屏障波动：先修复再升级（Phase 1 recovery first）' : 'Acute barrier flare: recovery first, actives later',
      evidence: [lang === 'CN' ? '出现刺痛/脱皮时立即停强活性。' : 'Stop strong actives immediately when stinging/peeling appears.'],
      impact: lang === 'CN' ? '先把灼热和脱皮压下去，再谈提效。' : 'Stabilization first prevents rebound flares.',
    });
    addUniqueLine(
      expert.plan_7d.stop_conditions,
      lang === 'CN'
        ? '若刺痛持续 >30-60 秒或扩散，立即停活性并仅保湿修护。'
        : 'If stinging lasts >30-60 seconds or spreads, stop actives immediately and use barrier-only repair.',
      true
    );
    addUniqueLine(
      expert.plan_7d.observe_metrics,
      lang === 'CN'
        ? '观察刺痛是否从约 40 秒逐步降到接近 0 秒。'
        : 'Track whether stinging drops from ~40 seconds toward near 0 seconds.',
      true
    );
  }

  if (hasTravelColdWind) {
    addIssue({
      id: 'extreme_weather_shift',
      severity: 'high',
      title: lang === 'CN' ? '已识别 cold + dry + wind 场景，需临时升级保湿封闭性' : 'Extreme cold/dry/wind shift detected; increase occlusion',
      evidence: [lang === 'CN' ? '旅行期从轻薄保湿升级到 ceramides/panthenol + occlusive。' : 'Upgrade from lightweight hydration to ceramides/panthenol + occlusive protection.'],
      impact: lang === 'CN' ? '降低风吹与低温导致的 windburn 风险。' : 'Reduces windburn risk in harsh climate.',
    });
    addUniqueLine(
      expert.plan_7d.am,
      lang === 'CN'
        ? '旅行期 AM：面霜从 lightweight 升级为 heavier occlusive（Ceramides/Panthenol）。'
        : 'Travel AM: upgrade from lightweight moisturizer to a heavier occlusive (Ceramides/Panthenol).',
      true
    );
    addUniqueLine(
      expert.plan_7d.pm,
      lang === 'CN'
        ? '外出时加物理防护（scarf/mask）保护 chin。'
        : 'Use physical protection (scarf/mask) outdoors to protect the chin.',
      true
    );
    addUniqueLine(expert.plan_7d.am, lang === 'CN' ? '雪地/高反射环境优先 gentle mineral SPF。' : 'For snow/high-reflection settings, use gentle mineral SPF.', false);
    setPrimaryQuestion(lang === 'CN' ? '你手头有更厚的修护面霜或修护膏吗？' : 'Do you already have a thicker barrier cream/ointment for this trip?');
  }

  if (hasPregnancy) {
    addIssue({
      id: 'pregnancy_safety_mode',
      severity: 'high',
      title: lang === 'CN' ? '已切换 PREGNANCY SAFETY：停 Retinoids，走保守修护' : 'PREGNANCY SAFETY mode: no retinoids, conservative repair plan',
      evidence: [lang === 'CN' ? '孕期优先 soothing + barrier repair，再做温和抗痘。' : 'Prioritize soothing/barrier repair first during pregnancy.'],
      impact: lang === 'CN' ? '降低不必要风险，保证可执行性。' : 'Improves safety and consistency.',
    });
    addUniqueLine(
      expert.phase_plan.phase_1_14d,
      lang === 'CN'
        ? '孕期 Phase 1：停用 Retinol/Retinoids，仅保湿修护。'
        : 'Pregnancy Phase 1: stop Retinol/Retinoids and stay on barrier-only hydration.',
      true
    );
  }

  if (hasAzelaic) {
    addIssue({
      id: 'azelaic_reintro',
      severity: 'medium',
      title: lang === 'CN' ? 'Azelaic Acid 可作为孕期相对稳妥的后续选项' : 'Azelaic Acid is a practical pregnancy-safe option after stabilization',
      evidence: [lang === 'CN' ? '15% 壬二酸先做 patch test，再低频接入。' : 'Start 15% azelaic with patch test, then low-frequency integration.'],
      impact: lang === 'CN' ? '在安全边界内兼顾痘痘与泛红。' : 'Balances acne/redness goals within safety limits.',
    });
    addUniqueLine(
      expert.phase_plan.phase_2_3_6w,
      lang === 'CN'
        ? 'Phase 2：15% 壬二酸隔晚起步，若耐受再加频。'
        : 'Phase 2: start 15% azelaic acid on alternating nights, then increase only if tolerated.',
      true
    );
    addUniqueLine(
      expert.plan_7d.observe_metrics,
      lang === 'CN'
        ? 'Azelaic 初期轻微刺痒 <5 分钟可观察。'
        : 'Mild early azelaic tingling under 5 minutes can be observed.',
      false
    );
    addUniqueLine(
      expert.plan_7d.stop_conditions,
      lang === 'CN'
        ? '若出现明显红斑/瘙痒加重，立即停用并回到修护基线。'
        : 'Stop immediately and return to barrier baseline if marked erythema/itching worsens.',
      false
    );
    addUniqueLine(expert.plan_7d.am, lang === 'CN' ? '白天仍需防晒（sunscreen mandatory）。' : 'Daily sunscreen remains mandatory.', false);
  }

  if (hasAhaOrGlycolic || hasSpfRefusal) {
    addIssue({
      id: 'aha_uv_risk',
      severity: 'high',
      title: lang === 'CN' ? 'AHA/Glycolic + 无 SPF 会放大 UVA 光损伤风险' : 'AHA/Glycolic without SPF raises UVA photodamage risk',
      evidence: [lang === 'CN' ? '若 SPF 是 hard NO，优先改 non-photosensitizing brighteners（Niacinamide/Alpha Arbutin）。' : 'If SPF is a hard NO, switch to non-photosensitizing brighteners (Niacinamide/Alpha Arbutin).'],
      impact: lang === 'CN' ? '避免暗沉和色沉反弹。' : 'Prevents rebound darkening/hyperpigmentation.',
    });
  }

  if (asksRestartTonight && hasAhaOrGlycolic) {
    setPrimaryQuestion(
      lang === 'CN'
        ? '你之前的 warmth/redness 是否已 100% 消退？'
        : 'Has the previous warmth/redness fully resolved to 100%?'
    );
    addUniqueLine(
      expert.phase_plan.phase_2_3_6w,
      lang === 'CN'
        ? '若已完全恢复：Glycolic 先每周 2 次（2x/week），不要每晚用。'
        : 'If fully recovered: restart glycolic at 2x/week, not nightly.',
      true,
    );
    addUniqueLine(
      expert.phase_plan.phase_2_3_6w,
      lang === 'CN'
        ? '若仍有热感/刺痛：再等 3-5 天，仅做修护。'
        : 'If warmth/stinging persists: wait 3-5 more days and keep repair-only routine.',
      false,
    );
  }

  if (hasStacking) {
    addIssue({
      id: 'active_stacking_overload',
      severity: 'high',
      title: lang === 'CN' ? '同晚叠加多活性（BHA/Lactic/Retinol）风险极高' : 'Same-night stacking of BHA/Lactic/Retinol is high-risk',
      evidence: [lang === 'CN' ? '先 stop all actives，执行 SOS 修护 2-4 周。' : 'Stop all actives and run SOS barrier repair for 2-4 weeks.'],
      impact: lang === 'CN' ? '降低 delayed flare（48-72h）概率。' : 'Reduces delayed 48-72h barrier crash risk.',
    });
  }

  return expert;
}

function buildRulesOnlyRoutineExpertFromContext({ message, profile, recentLogs, language } = {}) {
  const candidateFromProfile = profile && profile.currentRoutine ? profile.currentRoutine : null;
  const candidate =
    hasNonEmptyRoutineInput(candidateFromProfile)
      ? candidateFromProfile
      : { notes: String(message || '').slice(0, 800) };
  const expert = buildRoutineExpertV1({
    routineCandidate: candidate,
    profileSummary: profile && typeof profile === 'object' ? profile : {},
    recentLogs,
    language,
  });
  if (expert) return enrichRoutineExpertWithMessageSignals({ expert, message, language });
  const lang = language === 'CN' ? 'CN' : 'EN';
  const fallbackExpert = {
    contract: 'aurora.routine_expert.v1',
    snapshot: {
      summary: lang === 'CN' ? '已进入保守规则兜底（无完整上游结构化结果）。' : 'Conservative rules-only fallback is active (no complete upstream structured result).',
      am_steps: [],
      pm_steps: [],
      active_families: [],
      risk_flags: [],
    },
    key_issues: [
      {
        id: 'fallback_rules_only',
        severity: 'medium',
        title: lang === 'CN' ? '先执行低风险基线，避免空转' : 'Apply low-risk baseline first to avoid stalling',
        evidence: [lang === 'CN' ? '上游结构化内容缺失，已切到规则兜底。' : 'Upstream structured content is missing; switched to rules fallback.'],
        impact: lang === 'CN' ? '可继续推进，不需要重试才能获得可执行建议。' : 'Progress can continue without requiring retries.',
      },
    ],
    why_it_happens: [
      lang === 'CN' ? '当上游结构化内容不完整时，规则兜底可保证建议连续性。' : 'When upstream structured content is incomplete, rules fallback keeps advice continuous.',
    ],
    plan_7d: {
      am: [
        lang === 'CN' ? '早上：温和清洁（或清水）+ 保湿 + 防晒。' : 'AM: gentle cleanse (or water only) + moisturizer + sunscreen.',
      ],
      pm: [
        lang === 'CN' ? '晚上：温和清洁 + 修护保湿，暂停强活性叠加。' : 'PM: gentle cleanse + repair moisturizer, pause strong active stacking.',
      ],
      observe_metrics: [
        lang === 'CN' ? '观察刺痛/泛红是否下降。' : 'Track whether stinging/redness decreases.',
      ],
      stop_conditions: [
        lang === 'CN' ? '若刺痛/灼热持续加重，立即停活性并回到基线。' : 'If stinging/burning worsens, stop actives and revert to baseline.',
      ],
    },
    upgrade_path: [
      {
        week: lang === 'CN' ? '第 2 周' : 'Week 2',
        focus: lang === 'CN' ? '单变量升级' : 'single-variable upgrade',
        action: lang === 'CN' ? '每次只新增 1 个变量，观察 72 小时。' : 'Add only one variable at a time and observe for 72 hours.',
        guardrail: lang === 'CN' ? '出现刺激即降频或暂停。' : 'Reduce frequency or pause at first irritation signal.',
      },
    ],
    primary_question:
      lang === 'CN'
        ? '你现在最困扰的是刺痛、泛红，还是爆皮？'
        : 'What is the dominant issue right now: stinging, redness, or peeling?',
    conditional_followups: [],
    phase_plan: {
      phase_1_14d: [
        lang === 'CN' ? '先稳屏障：温和清洁 + 保湿 + 防晒。' : 'Stabilize barrier first: gentle cleanse + moisturizer + sunscreen.',
      ],
      phase_2_3_6w: [
        lang === 'CN' ? '稳住后再低频引入单一活性。' : 'After stability, reintroduce one active at low frequency.',
      ],
    },
    ask_3_questions: [
      lang === 'CN' ? '你现在最困扰的是刺痛、泛红，还是爆皮？' : 'What is the dominant issue right now: stinging, redness, or peeling?',
      lang === 'CN' ? '你白天是否稳定使用防晒？' : 'Are you using sunscreen consistently in daytime?',
      lang === 'CN' ? '你目前晚间是否仍在叠加强活性？' : 'Are you still stacking strong actives at night?',
    ],
  };
  return enrichRoutineExpertWithMessageSignals({ expert: fallbackExpert, message, language });
}

function shouldPersistProfilePatch(baseProfile, patch) {
  if (!patch || typeof patch !== 'object') return false;
  const keys = Object.keys(patch);
  if (keys.length === 0) return false;
  if (!baseProfile) return true;

  for (const k of keys) {
    const next = patch[k];
    if (next == null) continue;

    const prev = baseProfile[k];
    if (k === 'goals' || k === 'contraindications') {
      const prevArr = Array.isArray(prev) ? prev : [];
      const nextArr = Array.isArray(next) ? next : [];
      if (nextArr.length && prevArr.length === 0) return true;
      continue;
    }

    if (typeof next === 'string') {
      const prevText = typeof prev === 'string' ? prev.trim() : '';
      if (!prevText) return true;
      continue;
    }

    if (prev == null) return true;
  }

  return false;
}

function extractReplyTextFromAction(action) {
  const normalizedAction = normalizeIncomingChatAction(action);
  if (!normalizedAction || typeof normalizedAction !== 'object') return null;
  const data = normalizedAction.data && typeof normalizedAction.data === 'object' ? normalizedAction.data : null;
  if (!data) return null;
  const raw =
    (typeof data.reply_text === 'string' && data.reply_text) ||
    (typeof data.replyText === 'string' && data.replyText) ||
    (typeof data.text === 'string' && data.text) ||
    null;
  const text = raw ? String(raw).trim() : '';
  return text || null;
}

function normalizeIncomingChatAction(action) {
  if (typeof action === 'string') {
    const trimmed = action.trim();
    return trimmed || null;
  }
  if (!isPlainObject(action)) return null;
  const data = isPlainObject(action.data) ? action.data : null;
  const actionId = pickFirstTrimmed(
    action.action_id,
    action.id,
    data && data.action_id,
    data && data.aurora_action_id,
    action.type,
  );
  const kindValue = pickFirstTrimmed(action.kind, action.type);
  const normalizedKind = kindValue
    ? /(^|[._-])chip([._-]|$)/i.test(kindValue)
      ? 'chip'
      : 'action'
    : null;
  return {
    ...(actionId ? { action_id: actionId } : {}),
    ...(normalizedKind ? { kind: normalizedKind } : {}),
    ...(data ? { data } : {}),
  };
}

function coerceBoolean(value) {
  if (typeof value === 'boolean') return value;
  if (typeof value === 'number') return value === 1;
  if (typeof value !== 'string') return false;
  const s = value.trim().toLowerCase();
  return s === 'true' || s === '1' || s === 'yes' || s === 'y' || s === 'on';
}

function normalizeChatLlmProvider(value) {
  return normalizeAuroraLlmProvider(value);
}

function shouldHonorExternalLlmRouteOverride() {
  return shouldAllowAuroraPublicLlmOverride({
    productionLike: isProductionLikeAuroraBffEnv(),
  });
}

function getDiagForceGeminiModel() {
  const picked = pickConfiguredEnv(['AURORA_DIAG_FORCE_GEMINI_MODEL', 'AURORA_ANALYSIS_STORY_MODEL_GEMINI', 'GEMINI_MODEL']);
  return resolveNonImageGeminiModel({
    model: picked.value,
    fallbackModel: 'gemini-3-pro-preview',
    envSource: picked.envSource || 'AURORA_DIAG_FORCE_GEMINI_MODEL',
    callPath: 'aurora_diag_force',
  }).effectiveModel;
}

function normalizeChatLlmModel(value) {
  return normalizeAuroraLlmModel(value);
}

function resolveProductIntelLlmRoute({ req = null, requestedProvider = null, requestedModel = null } = {}) {
  const allowExternalOverride = shouldHonorExternalLlmRouteOverride();
  const headerProvider =
    allowExternalOverride && req && typeof req.get === 'function'
      ? normalizeChatLlmProvider(req.get('X-LLM-Provider') ?? req.get('X-Aurora-LLM-Provider'))
      : null;
  const headerModel =
    allowExternalOverride && req && typeof req.get === 'function'
      ? normalizeChatLlmModel(req.get('X-LLM-Model') ?? req.get('X-Aurora-LLM-Model'))
      : null;
  const llm_provider =
    (allowExternalOverride ? normalizeChatLlmProvider(requestedProvider) : null) ||
    headerProvider ||
    AURORA_PRODUCT_INTEL_LLM_PROVIDER ||
    null;
  const llm_model =
    (allowExternalOverride ? normalizeChatLlmModel(requestedModel) : null) ||
    headerModel ||
    AURORA_PRODUCT_INTEL_LLM_MODEL ||
    null;
  if (AURORA_DIAG_FORCE_GEMINI) {
    return {
      llm_provider: 'gemini',
      llm_model: AURORA_DIAG_FORCE_GEMINI_MODEL,
    };
  }
  return { llm_provider, llm_model };
}

function resolveProductIntelEscalationRoute({ req = null } = {}) {
  if (AURORA_DIAG_FORCE_GEMINI) {
    return {
      llm_provider: 'gemini',
      llm_model: AURORA_DIAG_FORCE_GEMINI_MODEL,
      stage: 'stage_2',
      trigger_reason: 'diag_force_gemini',
    };
  }
  const allowExternalOverride = shouldHonorExternalLlmRouteOverride();
  const headerProvider =
    allowExternalOverride && req && typeof req.get === 'function'
      ? normalizeChatLlmProvider(req.get('X-LLM-Escalation-Provider') ?? req.get('X-Aurora-LLM-Escalation-Provider'))
      : null;
  const headerModel =
    allowExternalOverride && req && typeof req.get === 'function'
      ? normalizeChatLlmModel(req.get('X-LLM-Escalation-Model') ?? req.get('X-Aurora-LLM-Escalation-Model'))
      : null;
  const llm_provider = headerProvider || AURORA_PRODUCT_INTEL_ESCALATION_PROVIDER || null;
  const llm_model = headerModel || AURORA_PRODUCT_INTEL_ESCALATION_MODEL || null;
  return {
    llm_provider,
    llm_model,
    stage: 'stage_2',
    trigger_reason: 'unknown_low_evidence',
  };
}

function isUnknownProductAnalysisPayload(payload) {
  const assessment = isPlainObject(payload?.assessment) ? payload.assessment : {};
  const verdict = String(assessment?.verdict || '').trim().toLowerCase();
  return !verdict || verdict === 'unknown' || verdict === '未知';
}

function getProductAnalysisEvidenceCoverageScore(payload) {
  const p = isPlainObject(payload) ? payload : {};
  const evidence = isPlainObject(p.evidence) ? p.evidence : {};
  const science = isPlainObject(evidence.science) ? evidence.science : {};
  const social = isPlainObject(evidence.social_signals || evidence.socialSignals) ? (evidence.social_signals || evidence.socialSignals) : {};
  const keyIngredients = Array.isArray(science.key_ingredients || science.keyIngredients) ? (science.key_ingredients || science.keyIngredients) : [];
  const mechanisms = Array.isArray(science.mechanisms) ? science.mechanisms : [];
  const fitNotes = Array.isArray(science.fit_notes || science.fitNotes) ? (science.fit_notes || science.fitNotes) : [];
  const riskNotes = Array.isArray(science.risk_notes || science.riskNotes) ? (science.risk_notes || science.riskNotes) : [];
  const expertNotes = Array.isArray(evidence.expert_notes || evidence.expertNotes) ? (evidence.expert_notes || evidence.expertNotes) : [];
  const socialSignals = [
    ...(Array.isArray(social.typical_positive || social.typicalPositive) ? (social.typical_positive || social.typicalPositive) : []),
    ...(Array.isArray(social.typical_negative || social.typicalNegative) ? (social.typical_negative || social.typicalNegative) : []),
    ...(Array.isArray(social.risk_for_groups || social.riskForGroups) ? (social.risk_for_groups || social.riskForGroups) : []),
  ];
  const sources = Array.isArray(evidence.sources) ? evidence.sources : [];
  let score = 0;
  if (keyIngredients.length) score += 0.35;
  if (mechanisms.length || fitNotes.length) score += 0.2;
  if (riskNotes.length) score += 0.15;
  if (expertNotes.length) score += 0.1;
  if (socialSignals.length) score += 0.1;
  if (sources.length) score += 0.1;
  return Math.max(0, Math.min(1, Number(score.toFixed(3))));
}

function shouldTriggerProductIntelEscalation(payload) {
  if (!payload || typeof payload !== 'object' || Array.isArray(payload)) return true;
  if (!hasValidFormulaIntentInPayload(payload)) return true;
  if (!isUnknownProductAnalysisPayload(payload)) return false;
  return getProductAnalysisEvidenceCoverageScore(payload) < 0.45;
}

function isProductIntelPayloadCandidateBetter(nextPayload, currentPayload) {
  const nextAssessment = isPlainObject(nextPayload?.assessment);
  const currentAssessment = isPlainObject(currentPayload?.assessment);
  if (nextAssessment && !currentAssessment) return true;
  if (!nextAssessment) return false;
  const nextScore = getProductAnalysisEvidenceCoverageScore(nextPayload);
  const currentScore = getProductAnalysisEvidenceCoverageScore(currentPayload);
  if (nextScore > currentScore + 0.08) return true;
  if (!isUnknownProductAnalysisPayload(nextPayload) && isUnknownProductAnalysisPayload(currentPayload)) return true;
  return false;
}

function appendProductIntelSourceChain(payload, chainEntries = []) {
  const p = isPlainObject(payload) ? payload : {};
  const provenance = isPlainObject(p.provenance) ? p.provenance : {};
  const existing = Array.isArray(provenance.source_chain) ? provenance.source_chain : [];
  const merged = uniqCaseInsensitiveStrings(
    [
      ...existing,
      ...(Array.isArray(chainEntries) ? chainEntries : []),
    ],
    10,
  );
  return {
    ...p,
    provenance: {
      ...provenance,
      ...(merged.length ? { source_chain: merged } : {}),
    },
  };
}

function attachProductIntelLlmRouteProvenance(payload, llmRouteMeta = null) {
  const p = isPlainObject(payload) ? payload : payload;
  if (!isPlainObject(p)) return payload;
  const route = isPlainObject(llmRouteMeta) ? llmRouteMeta : {};
  const provider = String(route.provider || route.llm_provider || '').trim();
  const model = String(route.model || route.llm_model || '').trim();
  const stage = String(route.stage || '').trim() || 'stage_1';
  const triggerReason = String(route.trigger_reason || route.triggerReason || '').trim() || 'primary';
  const provenance = isPlainObject(p.provenance) ? p.provenance : {};
  return {
    ...p,
    provenance: {
      ...provenance,
      llm_route: {
        stage,
        provider: provider || null,
        model: model || null,
        trigger_reason: triggerReason,
      },
    },
  };
}

function classifyStorageError(err) {
  const code = err && err.code ? String(err.code) : null;
  const sqlState = code && /^[0-9A-Z]{5}$/.test(code) ? code : null;
  const netCodes = new Set(['ECONNREFUSED', 'ETIMEDOUT', 'ECONNRESET', 'EPIPE', 'ENOTFOUND', 'EAI_AGAIN']);

  const dbNotConfigured = code === 'NO_DATABASE';
  const dbSchemaError = sqlState === '42P01' || sqlState === '42703' || sqlState === '42883';
  const dbError = dbNotConfigured || Boolean(sqlState) || netCodes.has(code);
  return { code, sqlState, dbError, dbNotConfigured, dbSchemaError };
}

function extractIncludeAlternativesFromAction(action) {
  if (!action || typeof action !== 'object') return false;
  const data = action.data && typeof action.data === 'object' ? action.data : null;
  if (!data) return false;
  return coerceBoolean(data.include_alternatives ?? data.includeAlternatives);
}

function summarizeProfileForContext(profile, options = {}) {
  if (!profile) return null;
  const includeProfileV2 =
    Object.prototype.hasOwnProperty.call(options, 'profileV2Enabled')
      ? Boolean(options.profileV2Enabled)
      : AURORA_PROFILE_V2_ENABLED;
  const currentRoutine = getRoutineStateSummaryValue(profile.currentRoutine ?? profile.current_routine);

  const itineraryRaw = profile.itinerary;
  let itinerary = null;
  if (typeof itineraryRaw === 'string') {
    const t = itineraryRaw.trim();
    itinerary = t ? t.slice(0, 1200) : null;
  } else if (itineraryRaw && typeof itineraryRaw === 'object') {
    try {
      const json = JSON.stringify(itineraryRaw);
      itinerary = json.length > 1500 ? `${json.slice(0, 1500)}…` : json;
    } catch {
      itinerary = null;
    }
  }

  const contraindications = Array.isArray(profile.contraindications)
    ? profile.contraindications.filter((v) => typeof v === 'string' && v.trim()).slice(0, 12)
    : [];
  const highRiskMedications = Array.isArray(profile.high_risk_medications)
    ? profile.high_risk_medications.filter((v) => typeof v === 'string' && v.trim()).slice(0, 16)
    : [];

  const travelPlanRaw = profile.travel_plan && typeof profile.travel_plan === 'object' && !Array.isArray(profile.travel_plan)
    ? profile.travel_plan
    : null;
  const travelPlan = travelPlanRaw
    ? {
      ...(typeof travelPlanRaw.destination === 'string' && travelPlanRaw.destination.trim()
        ? { destination: travelPlanRaw.destination.trim().slice(0, 100) }
        : {}),
      ...(typeof travelPlanRaw.start_date === 'string' && travelPlanRaw.start_date.trim()
        ? { start_date: travelPlanRaw.start_date.trim().slice(0, 20) }
        : {}),
      ...(typeof travelPlanRaw.end_date === 'string' && travelPlanRaw.end_date.trim()
        ? { end_date: travelPlanRaw.end_date.trim().slice(0, 20) }
        : {}),
      ...(typeof travelPlanRaw.time_window === 'string' && travelPlanRaw.time_window.trim()
        ? { time_window: travelPlanRaw.time_window.trim().slice(0, 20) }
        : {}),
      ...(Number.isFinite(Number(travelPlanRaw.indoor_outdoor_ratio))
        ? { indoor_outdoor_ratio: Math.max(0, Math.min(1, Number(travelPlanRaw.indoor_outdoor_ratio))) }
        : {}),
    }
    : null;

  return {
    skinType: profile.skinType || null,
    sensitivity: profile.sensitivity || null,
    barrierStatus: profile.barrierStatus || null,
    goals: Array.isArray(profile.goals) ? profile.goals : [],
    region: profile.region || null,
    budgetTier: profile.budgetTier || null,
    currentRoutine,
    itinerary,
    contraindications,
    ...(includeProfileV2
      ? {
        age_band: profile.age_band || 'unknown',
        pregnancy_status: profile.pregnancy_status || 'unknown',
        pregnancy_due_date: normalizePregnancyDueDateForPolicy(profile.pregnancy_due_date),
        lactation_status: profile.lactation_status || 'unknown',
        high_risk_medications: highRiskMedications,
        travel_plan: travelPlan,
      }
      : {}),
  };
}

