function buildIngredientSignalFallback(signal, language = 'EN', inputName = '') {
  if (!signal || typeof signal !== 'object') return null;
  const lang = language === 'CN' ? 'CN' : 'EN';
  const displayName = pickFirstTrimmed(signal.display_signal_name, inputName) || inputName;
  const category = formatIngredientSignalBucket(signal.signal_bucket, lang);
  return {
    inci: displayName,
    display_name: displayName,
    aliases: buildIngredientSignalAliases(signal),
    category,
    what_it_is:
      lang === 'CN'
        ? `${displayName} 是 reviewed signal dictionary 中登记的信号词，不一定对应单一 canonical INCI。`
        : `${displayName} is a reviewed signal-dictionary term and may not correspond to one single canonical INCI row.`,
    one_liner:
      lang === 'CN'
        ? `${displayName} 已在 reviewed signal dictionary 中登记，当前按 ${category} 处理。`
        : `${displayName} is tracked in the reviewed signal dictionary and is currently treated as ${category}.`,
    benefits: buildIngredientSignalBenefits(signal, lang),
    watchouts: buildIngredientSignalWatchouts(signal, lang),
    pair_well: [],
    separate: [],
  };
}

async function extractIngredientLookupTargetFromText(message, language = 'EN') {
  const raw = String(message || '').trim();
  if (!raw) return '';
  const lang = language === 'CN' ? 'CN' : 'EN';
  const entityMatch = ingredientEntityMatchFromText(raw, lang);
  const referenceMatch = await resolveIngredientReferenceRuntimeMatch(raw, lang);
  if (referenceMatch && referenceMatch.canonical_query) {
    return String(referenceMatch.canonical_query).slice(0, 120);
  }
  const signalMatch = await resolveIngredientSignalRuntimeMatch(raw, lang);
  if (shouldPreferSignalRuntimeMatch(signalMatch, entityMatch, referenceMatch) && signalMatch.canonical_query) {
    return String(signalMatch.canonical_query).slice(0, 120);
  }
  if (!referenceMatch && looksLikeIngredientSignalPhrase(raw)) {
    return raw.slice(0, 120);
  }

  const knownActives = extractKnownActivesFromText(raw, lang);
  for (const token of knownActives) {
    const mapped = mapRoutineActiveTokenToIngredientQuery(token, lang);
    if (mapped) return String(mapped).slice(0, 120);
  }

  const ontologyHits = matchIngredientOntology({ text: raw, language: lang, max: 8 });
  const ontologyPreferred = pickFirstTrimmed(
    ...ontologyHits
      .map((row) => (row && typeof row === 'object' ? row.matched_text : ''))
      .filter((value) => normalizeIngredientLookupToken(value)),
  );
  if (ontologyPreferred) return String(ontologyPreferred).slice(0, 120);

  const normalized = String(entityMatch.entity_key || '').trim();
  const normalizedQuery = mapIngredientLookupTokenToQuery(normalized, lang);
  if (normalizedQuery) return String(normalizedQuery).slice(0, 120);

  const ontologyAny = pickFirstTrimmed(
    ...ontologyHits
      .map((row) => (row && typeof row === 'object' ? row.matched_text : ''))
      .filter(Boolean),
  );
  if (ontologyAny) return String(ontologyAny).slice(0, 120);

  if (looksLikeFreeTextIngredientName(raw)) return raw.slice(0, 120);
  return '';
}

function looksLikeFreeTextIngredientName(raw) {
  const text = String(raw || '').trim();
  if (!text) return false;
  if (!/^[A-Za-z][A-Za-z0-9'()+\-\s]{3,120}$/.test(text)) return false;
  const lower = text.toLowerCase();
  const tokens = lower.split(/\s+/).filter(Boolean);
  if (!tokens.length || tokens.length > 5) return false;

  // Avoid routing plain action/request phrases into ingredient lookup.
  if (
    /\b(start|diagnosis|analysis|routine|recommend|recommendation|product|products|skin|profile|help|please|can|should|need|want|send|link|url|evaluate|check)\b/.test(
      lower,
    )
  ) {
    return false;
  }

  if (
    /(acid|amide|retinol|niacinamide|ceramide|peptide|salicylate|glycol|ascorb|benzoyl|tretinoin|adapalene|azelaic|tocopherol|panthenol|hyaluron|squalane|glycerin|alcohol|extract|oxide|sulfate|phosphate|siloxane|butyl|ethyl|methyl|propyl)/.test(
      lower,
    )
  ) {
    return true;
  }

  const originalTokens = text.split(/\s+/).filter(Boolean);
  const titleCaseLike = originalTokens.every((token) => /^[A-Z][a-z0-9()+\-']+$/.test(token));
  if (titleCaseLike && originalTokens.length <= 3 && originalTokens.join('').length >= 12) {
    return true;
  }

  return false;
}

function normalizeIngredientResearchKey(raw) {
  return ingredient_query_normalize(raw)
    .replace(/[^a-z0-9\u4e00-\u9fff+\s']/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function classifyIngredientProviderError(reason) {
  const token = String(reason || '').trim().toLowerCase();
  if (!token) return 'provider_unavailable';
  if (token.includes('timeout')) return 'gemini_timeout';
  if (token.includes('rate') || token.includes('quota') || token.includes('429')) return 'gemini_rate_limited';
  if (token.includes('auth') || token.includes('key') || token.includes('permission') || token.includes('401') || token.includes('403')) {
    return 'gemini_auth';
  }
  if (token.includes('json')) return 'gemini_invalid_json';
  if (token.includes('network') || token.includes('socket') || token.includes('dns') || token.includes('econn') || token.includes('enotfound')) {
    return 'gemini_network';
  }
  if (token.includes('5xx') || token.includes('500') || token.includes('502') || token.includes('503') || token.includes('504') || token.includes('upstream')) {
    return 'gemini_upstream_5xx';
  }
  return 'gemini_unknown';
}

function extractFirstJsonObjectFromText(text) {
  const raw = String(text || '');
  if (!raw) return null;
  const start = raw.indexOf('{');
  if (start < 0) return null;
  let depth = 0;
  for (let i = start; i < raw.length; i += 1) {
    const ch = raw[i];
    if (ch === '{') depth += 1;
    if (ch === '}') {
      depth -= 1;
      if (depth === 0) {
        const candidate = raw.slice(start, i + 1);
        try {
          const parsed = JSON.parse(candidate);
          if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) return parsed;
        } catch {
          return null;
        }
      }
    }
  }
  return null;
}

function normalizeIngredientConfidenceLevel(raw, fallback = 'medium') {
  const token = String(raw || '').trim().toLowerCase();
  if (token === 'low' || token === 'medium' || token === 'high') return token;
  return fallback;
}

function normalizeIngredientUsageTime(raw) {
  const token = String(raw || '').trim().toLowerCase();
  if (token === 'am') return 'AM';
  if (token === 'pm') return 'PM';
  if (token === 'both' || token === 'am_pm' || token === 'am/pm') return 'Both';
  return 'Both';
}

function normalizeIngredientUsageObject(rawUsage) {
  const usage = asResearchObject(rawUsage) || {};
  const avoid = asResearchStringArray(usage.avoid, 8);
  const frequency = pickFirstTrimmed(usage.frequency, usage.freq) || null;
  return {
    time: normalizeIngredientUsageTime(usage.time || usage.time_of_day || usage.timing),
    frequency: frequency || null,
    avoid,
  };
}

function buildIngredientMinimalResearch({
  query = '',
  normalizedQuery = '',
  language = 'EN',
  errorCode = 'provider_unavailable',
  provider = 'gemini',
} = {}) {
  const lang = language === 'CN' ? 'CN' : 'EN';
  const ingredientName = String(query || '').trim() || (lang === 'CN' ? '该成分' : 'this ingredient');
  const oneLiner = lang === 'CN'
    ? `当前先返回 ${ingredientName} 的快速结论，增强证据稍后可继续刷新。`
    : `Returning a quick brief for ${ingredientName} now; enhanced evidence can be refreshed shortly.`;
  return {
    status: 'fallback',
    ingredient_query: ingredientName.slice(0, 120),
    provider,
    error_code: String(errorCode || 'provider_unavailable').slice(0, 60),
    normalized_query: String(normalizedQuery || '').slice(0, 120) || null,
    confidence_level: 'low',
    ingredient: {
      inci: ingredientName.slice(0, 120),
      display_name: ingredientName.slice(0, 120),
      aliases: [],
    },
    overview: oneLiner,
    what_it_is: lang === 'CN'
      ? `${ingredientName} 的快速摘要（增强研究暂不可用）。`
      : `Quick snapshot for ${ingredientName} (enhanced research currently unavailable).`,
    benefits: [
      {
        concern: 'general',
        strength: 1,
        what_it_means: lang === 'CN'
          ? '建议结合个人目标与敏感度后再做精准匹配。'
          : 'Add your goal and sensitivity for a more precise match.',
      },
    ],
    safety: {
      irritation_risk: null,
      watchouts: [
        {
          issue: lang === 'CN' ? '信息不足' : 'Limited evidence',
          likelihood: null,
          what_to_do: lang === 'CN'
            ? '先进行小范围试用并观察耐受。'
            : 'Patch-test first and monitor tolerance.',
        },
      ],
    },
    usage: {
      time: 'Both',
      frequency: null,
      avoid: [],
      routine_step: null,
      pair_well: [],
      consider_separating: [],
      notes: [],
    },
    evidence: {
      grade: null,
      summary: lang === 'CN'
        ? '当前为最小可读卡片，增强证据生成中或暂时不可用。'
        : 'This is a minimal readable card while enhanced evidence is pending/unavailable.',
      citations: [],
    },
    top_products: {
      budget: [],
      mid: [],
      premium: [],
    },
    updated_at_ms: Date.now(),
  };
}

function recordIngredientProviderWindow({ ok }) {
  const now = Date.now();
  ingredientProviderRecentCalls1m.push({ ts: now, ok: ok === true });
  ingredientProviderRecentCalls5m.push({ ts: now, ok: ok === true });
  while (ingredientProviderRecentCalls1m.length && now - ingredientProviderRecentCalls1m[0].ts > 60 * 1000) {
    ingredientProviderRecentCalls1m.shift();
  }
  while (ingredientProviderRecentCalls5m.length && now - ingredientProviderRecentCalls5m[0].ts > 5 * 60 * 1000) {
    ingredientProviderRecentCalls5m.shift();
  }
}

function getIngredientProviderCircuitState() {
  const now = Date.now();
  if (ingredientProviderCircuit.state === 'open') {
    if (now - Number(ingredientProviderCircuit.opened_at_ms || 0) >= AURORA_INGREDIENT_CIRCUIT_OPEN_MS) {
      ingredientProviderCircuit.state = 'half_open';
      ingredientProviderCircuit.half_open_probe_count = 0;
    }
  }
  return ingredientProviderCircuit.state;
}

function updateIngredientProviderCircuit({ outcome = 'ok' } = {}) {
  const now = Date.now();
  const fail = outcome !== 'ok';
  recordIngredientProviderWindow({ ok: !fail });
  if (ingredientProviderCircuit.state === 'half_open') {
    ingredientProviderCircuit.half_open_probe_count = Number(ingredientProviderCircuit.half_open_probe_count || 0) + 1;
    if (fail) {
      ingredientProviderCircuit.state = 'open';
      ingredientProviderCircuit.opened_at_ms = now;
      ingredientProviderCircuit.half_open_probe_count = 0;
      return ingredientProviderCircuit.state;
    }
    if (ingredientProviderCircuit.half_open_probe_count >= AURORA_INGREDIENT_CIRCUIT_HALF_OPEN_PROBES) {
      ingredientProviderCircuit.state = 'closed';
      ingredientProviderCircuit.opened_at_ms = 0;
      ingredientProviderCircuit.half_open_probe_count = 0;
    }
    return ingredientProviderCircuit.state;
  }
  if (ingredientProviderCircuit.state === 'closed') {
    const oneMinuteTotal = ingredientProviderRecentCalls1m.length;
    const oneMinuteFail = ingredientProviderRecentCalls1m.filter((row) => row.ok !== true).length;
    const fiveMinuteTotal = ingredientProviderRecentCalls5m.length;
    const fiveMinuteFail = ingredientProviderRecentCalls5m.filter((row) => row.ok !== true).length;
    const oneMinuteRate = oneMinuteTotal > 0 ? oneMinuteFail / oneMinuteTotal : 0;
    const fiveMinuteRate = fiveMinuteTotal > 0 ? fiveMinuteFail / fiveMinuteTotal : 0;
    if (
      (oneMinuteTotal >= 20 && oneMinuteRate >= 0.35) ||
      (fiveMinuteTotal >= 20 && fiveMinuteRate >= 0.2)
    ) {
      ingredientProviderCircuit.state = 'open';
      ingredientProviderCircuit.opened_at_ms = now;
      ingredientProviderCircuit.half_open_probe_count = 0;
    }
  }
  return ingredientProviderCircuit.state;
}

function compactIngredientRateCounter(map, now, windowMs = 60 * 1000) {
  for (const [key, value] of map.entries()) {
    if (!value || typeof value !== 'object') {
      map.delete(key);
      continue;
    }
    if (now - Number(value.window_started_at_ms || 0) >= windowMs) {
      map.delete(key);
    }
  }
}

function checkIngredientLookupRateLimit({ sessionKey = '', ipKey = '' } = {}) {
  const now = Date.now();
  compactIngredientRateCounter(ingredientLookupSessionRateCounter, now);
  compactIngredientRateCounter(ingredientLookupIpRateCounter, now);
  const windowMs = 60 * 1000;
  let sessionExceeded = false;
  let ipExceeded = false;
  if (sessionKey) {
    const row = ingredientLookupSessionRateCounter.get(sessionKey) || {
      count: 0,
      window_started_at_ms: now,
    };
    if (now - Number(row.window_started_at_ms || 0) >= windowMs) {
      row.count = 0;
      row.window_started_at_ms = now;
    }
    row.count += 1;
    ingredientLookupSessionRateCounter.set(sessionKey, row);
    sessionExceeded = Number(row.count || 0) > AURORA_INGREDIENT_LOOKUP_SESSION_PER_MIN;
  }
  if (ipKey) {
    const row = ingredientLookupIpRateCounter.get(ipKey) || {
      count: 0,
      window_started_at_ms: now,
    };
    if (now - Number(row.window_started_at_ms || 0) >= windowMs) {
      row.count = 0;
      row.window_started_at_ms = now;
    }
    row.count += 1;
    ingredientLookupIpRateCounter.set(ipKey, row);
    ipExceeded = Number(row.count || 0) > AURORA_INGREDIENT_LOOKUP_IP_PER_MIN;
  }
  return {
    blocked: sessionExceeded || ipExceeded,
    reason: sessionExceeded ? 'session_rate_limited' : ipExceeded ? 'ip_rate_limited' : '',
  };
}

function isPlainResearchObject(value) {
  return Boolean(value) && typeof value === 'object' && !Array.isArray(value);
}

function buildIngredientResearchCacheArtifact() {
  const entries = {};
  for (const [rawKey, rawValue] of ingredientResearchCache.entries()) {
    const key = normalizeIngredientResearchKey(rawKey);
    if (!key || !isPlainResearchObject(rawValue)) continue;
    entries[key] = rawValue;
  }
  return {
    schema_version: 'aurora.ingredient_profile_v1.cache',
    updated_at_ms: Date.now(),
    entries,
  };
}

function persistIngredientResearchCacheNow({ logger } = {}) {
  if (!AURORA_INGREDIENT_RESEARCH_PERSIST_ENABLED || !AURORA_INGREDIENT_RESEARCH_KB_PATH) return;
  try {
    const dir = path.dirname(AURORA_INGREDIENT_RESEARCH_KB_PATH);
    fs.mkdirSync(dir, { recursive: true });
    const payload = buildIngredientResearchCacheArtifact();
    const tmpPath = `${AURORA_INGREDIENT_RESEARCH_KB_PATH}.${process.pid}.${Date.now()}.tmp`;
    fs.writeFileSync(tmpPath, JSON.stringify(payload), 'utf8');
    fs.renameSync(tmpPath, AURORA_INGREDIENT_RESEARCH_KB_PATH);
  } catch (err) {
    logger?.warn?.(
      {
        path: AURORA_INGREDIENT_RESEARCH_KB_PATH,
        err: err && err.message ? err.message : String(err),
      },
      'aurora bff: ingredient research cache persist failed',
    );
  }
}

function scheduleIngredientResearchCachePersist({ logger } = {}) {
  if (!AURORA_INGREDIENT_RESEARCH_PERSIST_ENABLED || !AURORA_INGREDIENT_RESEARCH_KB_PATH) return;
  ingredientResearchCachePersistPending = true;
  if (ingredientResearchCachePersistTimer) return;
  ingredientResearchCachePersistTimer = setTimeout(() => {
    ingredientResearchCachePersistTimer = null;
    if (!ingredientResearchCachePersistPending) return;
    ingredientResearchCachePersistPending = false;
    persistIngredientResearchCacheNow({ logger });
  }, 250);
  if (ingredientResearchCachePersistTimer && typeof ingredientResearchCachePersistTimer.unref === 'function') {
    ingredientResearchCachePersistTimer.unref();
  }
}

function hydrateIngredientResearchCacheFromDisk({ logger } = {}) {
  if (ingredientResearchCacheLoadedFromDisk) return;
  ingredientResearchCacheLoadedFromDisk = true;
  if (!AURORA_INGREDIENT_RESEARCH_PERSIST_ENABLED || !AURORA_INGREDIENT_RESEARCH_KB_PATH) return;
  try {
    if (!fs.existsSync(AURORA_INGREDIENT_RESEARCH_KB_PATH)) return;
    const raw = fs.readFileSync(AURORA_INGREDIENT_RESEARCH_KB_PATH, 'utf8');
    const parsed = JSON.parse(raw);
    const entries = isPlainResearchObject(parsed && parsed.entries) ? parsed.entries : {};
    for (const [rawKey, rawValue] of Object.entries(entries)) {
      const key = normalizeIngredientResearchKey(rawKey);
      if (!key || !isPlainResearchObject(rawValue)) continue;
      touchIngredientResearchCache(key, rawValue, { persist: false });
    }
  } catch (err) {
    logger?.warn?.(
      {
        path: AURORA_INGREDIENT_RESEARCH_KB_PATH,
        err: err && err.message ? err.message : String(err),
      },
      'aurora bff: ingredient research cache hydrate failed',
    );
  }
}

function touchIngredientResearchCache(key, value, { persist = false, logger = null } = {}) {
  if (!key) return;
  ingredientResearchCache.delete(key);
  ingredientResearchCache.set(key, value);
  while (ingredientResearchCache.size > AURORA_INGREDIENT_RESEARCH_CACHE_MAX) {
    const oldest = ingredientResearchCache.keys().next();
    if (!oldest || oldest.done) break;
    ingredientResearchCache.delete(oldest.value);
  }
  if (persist) scheduleIngredientResearchCachePersist({ logger });
}

function getIngredientResearchCache(query) {
  hydrateIngredientResearchCacheFromDisk();
  const key = normalizeIngredientResearchKey(query);
  if (!key) return null;
  const row = ingredientResearchCache.get(key) || null;
  if (!row) return null;
  touchIngredientResearchCache(key, row);
  return row;
}

async function upsertIngredientResearchKbEntrySafe({
  query,
  language = 'EN',
  layer = 'generic',
  goal = '',
  sensitivity = '',
  status = 'ready',
  provider = 'gemini',
  errorCode = null,
  ingredientProfile = {},
  sourceMeta = {},
  revision = 1,
  logger = null,
} = {}) {
  try {
    const kbKey = buildIngredientResearchKbKey({
      query,
      lang: language,
      layer,
      goal,
      sensitivity,
    });
    const queryNorm = normalizeIngredientResearchKey(query);
    if (!kbKey || !queryNorm) return null;
    const payload = asResearchObject(ingredientProfile) || {};
    const nowIso = new Date().toISOString();
    await upsertIngredientResearchKbEntry({
      kb_key: kbKey,
      query_norm: queryNorm,
      lang: language === 'CN' ? 'CN' : 'EN',
      kb_layer: layer === 'variant' ? 'variant' : 'generic',
      variant_key:
        layer === 'variant'
          ? [goal ? `goal=${String(goal || '').trim().toLowerCase()}` : '', sensitivity ? `sensitivity=${String(sensitivity || '').trim().toLowerCase()}` : '']
            .filter(Boolean)
            .join(';')
          : '',
      revision,
      status,
      provider,
      error_code: errorCode || null,
      ingredient_profile_json: payload,
      source_meta: sourceMeta && typeof sourceMeta === 'object' ? sourceMeta : {},
      updated_at: nowIso,
      expires_at: new Date(Date.now() + 30 * 24 * 3600 * 1000).toISOString(),
    });
    return { kb_key: kbKey, revision };
  } catch (err) {
    logger?.warn?.(
      {
        ingredient_query: String(query || '').slice(0, 120),
        kb_layer: layer,
        err: err && err.message ? err.message : String(err),
      },
      'aurora bff: ingredient KB upsert failed',
    );
    return null;
  }
}

const INGREDIENT_RESEARCH_V2_LITE_JSON_SCHEMA = Object.freeze({
  type: 'object',
  additionalProperties: false,
  required: ['schema_version', 'ingredient', 'overview', 'benefits', 'safety', 'usage', 'confidence', 'evidence'],
  properties: {
    schema_version: { type: 'string', enum: ['v2-lite'] },
    ingredient: {
      type: 'object',
      additionalProperties: false,
      required: ['inci', 'display_name', 'aliases', 'what_it_is'],
      properties: {
        inci: { type: 'string' },
        display_name: { type: 'string' },
        aliases: { type: 'array', maxItems: 8, items: { type: 'string' } },
        what_it_is: { type: 'string' },
      },
    },
    overview: { type: 'string' },
    benefits: {
      type: 'array',
      maxItems: 3,
      items: {
        type: 'object',
        additionalProperties: false,
        required: ['concern', 'strength', 'what_it_means'],
        properties: {
          concern: { type: 'string' },
          strength: { type: 'integer', enum: [0, 1, 2, 3] },
          what_it_means: { type: 'string' },
        },
      },
    },
    safety: {
      type: 'object',
      additionalProperties: false,
      required: ['irritation_risk', 'watchouts'],
      properties: {
        irritation_risk: { type: ['string', 'null'], enum: ['low', 'medium', 'high', null] },
        watchouts: {
          type: 'array',
          maxItems: 3,
          items: {
            type: 'object',
            additionalProperties: false,
            required: ['issue', 'likelihood', 'what_to_do'],
            properties: {
              issue: { type: 'string' },
              likelihood: { type: ['string', 'null'], enum: ['rare', 'uncommon', 'common', null] },
              what_to_do: { type: 'string' },
            },
          },
        },
      },
    },
    usage: {
      type: 'object',
      additionalProperties: false,
      required: ['time', 'frequency', 'avoid', 'routine_step', 'pair_well', 'consider_separating', 'notes'],
      properties: {
        time: { type: 'string', enum: ['AM', 'PM', 'Both'] },
        frequency: { type: ['string', 'null'] },
        avoid: { type: 'array', maxItems: 8, items: { type: 'string' } },
        routine_step: { type: ['string', 'null'] },
        pair_well: { type: 'array', maxItems: 8, items: { type: 'string' } },
        consider_separating: { type: 'array', maxItems: 8, items: { type: 'string' } },
        notes: { type: 'array', maxItems: 4, items: { type: 'string' } },
      },
    },
    confidence: { type: 'string', enum: ['low', 'medium', 'high'] },
    evidence: {
      type: 'object',
      additionalProperties: false,
      required: ['grade', 'summary', 'citations'],
      properties: {
        grade: { type: ['string', 'null'], enum: ['A', 'B', 'C', null] },
        summary: { type: 'string' },
        citations: {
          type: 'array',
          maxItems: 2,
          items: {
            type: 'object',
            additionalProperties: false,
            required: ['title', 'url', 'year', 'source'],
            properties: {
              title: { type: 'string' },
              url: { type: 'string' },
              year: { type: ['integer', 'null'] },
              source: { type: 'string' },
            },
          },
        },
      },
    },
  },
});

function buildProductRetrieverJsonSchema(maxN = 6) {
  return {
    type: 'object',
    additionalProperties: false,
    required: ['products'],
    properties: {
      products: {
        type: 'array',
        maxItems: Math.max(1, Math.min(12, Math.trunc(Number(maxN) || 6))),
        items: {
          type: 'object',
          additionalProperties: false,
          required: ['name', 'brand', 'category', 'pdp_url', 'why'],
          properties: {
            name: { type: 'string' },
            brand: { type: 'string' },
            category: { type: 'string', enum: ['cleanser', 'serum', 'moisturizer', 'sunscreen', 'treatment'] },
            pdp_url: { type: 'string' },
            why: { type: 'string' },
          },
        },
      },
    },
  };
}

function buildRecoAlternativesSchema(maxN = 6) {
  return {
    type: 'object',
    additionalProperties: false,
    required: ['products'],
    properties: {
      products: {
        type: 'array',
        maxItems: Math.max(0, Math.min(8, Math.trunc(Number(maxN) || 6))),
        items: {
          type: 'object',
          additionalProperties: false,
          required: ['id', 'why'],
          properties: {
            id: { type: 'string', maxLength: 120 },
            why: { type: 'string', maxLength: 180 },
          },
        },
      },
    },
  };
}

function buildIngredientResearchPrompts({
  query,
  language = 'EN',
  goal = null,
  sensitivity = null,
  profileSummary = null,
  analysisContext = null,
  sources = [],
} = {}) {
  const normalizedLanguage = language === 'CN' ? 'CN' : 'EN';
  const promptLanguage = normalizedLanguage === 'CN' ? 'ZH' : 'EN';
  const userContext = {
    ingredient_query: String(query || '').trim(),
    language: promptLanguage,
    ...(goal ? { goal: String(goal).trim().toLowerCase() } : {}),
    ...(sensitivity ? { sensitivity: String(sensitivity).trim().toLowerCase() } : {}),
    ...(profileSummary && typeof profileSummary === 'object' ? { profile_summary: profileSummary } : {}),
    ...(analysisContext && typeof analysisContext === 'object'
      ? {
          analysis_context: {
            hard: analysisContext.task_hard_context || {},
            soft: analysisContext.task_soft_context || {},
            evidence: Array.isArray(analysisContext.evidence_summary) ? analysisContext.evidence_summary.slice(0, 5) : [],
            conflicts: Array.isArray(analysisContext.analysis_context_conflicts) ? analysisContext.analysis_context_conflicts.slice(0, 4) : [],
            context_mode: String(analysisContext.context_mode || '').trim() || 'no_context',
          },
        }
      : {}),
    ...(Array.isArray(sources) && sources.length ? { sources } : {}),
  };

  const systemPrompt = [
    `You are a skincare ingredient analyst. Prompt version: ${INGREDIENT_PROMPT_VERSION}.`,
    'Output MUST be a single valid JSON object. No markdown, no code fences, no prose outside the JSON.',
    'Goal: produce a compact ingredient research packet for ONLY the named ingredient.',
    'Follow the requested schema exactly. Do not add extra keys or rename fields.',
    'Use ONLY context.sources for citations. Never invent studies, journals, URLs, years, or evidence grades.',
    'Stay non-medical, conservative, and brief.',
    'If context.analysis_context is present, treat hard signals as strong context and soft signals as uncertainty-bearing hints only.',
    'Do not restate analysis_context as if the user explicitly said it.',
  ].join('\n');

  const userPrompt = [
    `[SYSTEM_CONTRACT][version=${INGREDIENT_PROMPT_VERSION}]`,
    'Role: compact skincare ingredient research analyst.',
    `Task: Analyze ONLY the ingredient "${userContext.ingredient_query}".`,
    `Language for ALL strings: "${userContext.language}".`,
    '',
    'Output contract:',
    '- Top-level keys: schema_version, ingredient, overview, benefits, safety, usage, confidence, evidence.',
    '- schema_version MUST be "v2-lite".',
    '- ingredient MUST contain inci, display_name, aliases, what_it_is.',
    '- safety MUST contain irritation_risk and watchouts.',
    '- usage MUST contain time, frequency, avoid, routine_step, pair_well, consider_separating, notes.',
    '- evidence MUST contain grade, summary, citations.',
    '- top_products may be included, but if present it must use tier buckets only: budget/mid/premium.',
    '',
    'Hard rules:',
    '1) Output JSON only, matching the schema EXACTLY. No extra keys.',
    '2) Do NOT mention other ingredients. Do NOT provide medical diagnosis or treatment.',
    '3) If unsure, use null or [] (never output the literal string "unknown").',
    '4) Cite ONLY context.sources entries. If there are no allowed sources, evidence.citations MUST be [] and evidence.grade MUST be null.',
    '5) Do NOT fabricate product picks. top_products is optional and may be empty.',
    '6) Keep benefits, watchouts, usage notes, and evidence summary non-repetitive.',
    '7) Respect context.analysis_context: hard context may shape stronger fit calls; soft context must stay uncertainty-bearing.',
    '',
    'Limits (to control latency):',
    '- benefits: max 3 items',
    '- safety.watchouts: max 3 items',
    '- usage.notes: max 4 items',
    '- evidence.citations: max 2 items',
    '- Keep each string field brief (ideally <= 20 words; overview/evidence.summary <= 40 words).',
    '',
    'Allowed values:',
    '- benefits[].strength: 0 | 1 | 2 | 3',
    '- safety.irritation_risk: "low" | "medium" | "high" | null',
    '- safety.watchouts[].likelihood: "rare" | "uncommon" | "common" | null',
    '- usage.time: "AM" | "PM" | "Both"',
    '- confidence: "low" | "medium" | "high"',
    '- evidence.grade: "A" | "B" | "C" | null',
    '',
    'Evidence & citations rule (NO hallucinations):',
    '- You may ONLY include citations that come from context.sources (exact title/url/year/source).',
    '- If context.sources is missing or empty, set evidence.grade=null and evidence.citations=[].',
    '- If evidence is weak but sources exist, keep evidence.summary brief and confidence conservative.',
    '',
    'Missing-data policy:',
    '- If the ingredient signal is sparse, keep confidence="low" and benefits/watchouts limited instead of guessing.',
    '- Use null/[] rather than filler prose or generic shopping advice.',
    '',
    'Schema (arrays may be empty):',
    '{',
    '  "schema_version": "v2-lite",',
    '  "ingredient": {',
    '    "inci": "",',
    '    "display_name": "",',
    '    "aliases": [],',
    '    "what_it_is": ""',
    '  },',
    '  "overview": "",',
    '  "benefits": [],',
    '  "safety": {',
    '    "irritation_risk": null,',
    '    "watchouts": []',
    '  },',
    '  "usage": {',
    '    "time": "Both",',
    '    "frequency": null,',
    '    "avoid": [],',
    '    "routine_step": null,',
    '    "pair_well": [],',
    '    "consider_separating": [],',
    '    "notes": []',
    '  },',
    '  "confidence": "low",',
    '  "evidence": {',
    '    "grade": null,',
    '    "summary": "",',
    '    "citations": []',
    '  }',
    '}',
    '',
    'Item shapes (use only if applicable):',
    '- benefits[] item: { "concern": "", "strength": 0, "what_it_means": "" }',
    '- safety.watchouts[] item: { "issue": "", "likelihood": null, "what_to_do": "" }',
    '- evidence.citations[] item (MUST match a context.sources entry): { "title": "", "url": "", "year": null, "source": "" }',
    '- top_products item shape if used: { "budget": string[], "mid": string[], "premium": string[] }',
    '',
    `context=${JSON.stringify(userContext)}`,
    '',
    'Fail-safe short-circuit:',
    'If you cannot comply perfectly, output the schema with empty arrays, nulls, and confidence="low".',
    '[/SYSTEM_CONTRACT]',
  ].join('\n');

  const promptHash = crypto.createHash('sha1').update(`${systemPrompt}||${userPrompt}`).digest('hex');
  return {
    systemPrompt,
    userPrompt,
    promptVersion: INGREDIENT_PROMPT_VERSION,
    promptHash,
    inputChars: userPrompt.length + systemPrompt.length,
    responseJsonSchema: INGREDIENT_RESEARCH_V2_LITE_JSON_SCHEMA,
  };
}

function asResearchObject(value) {
  return value && typeof value === 'object' && !Array.isArray(value) ? value : null;
}

function asResearchStringArray(value, max = 8) {
  const source = Array.isArray(value) ? value : [];
  const out = [];
  const seen = new Set();
  for (const row of source) {
    const text = String(row || '').trim();
    if (!text) continue;
    const key = text.toLowerCase();
    if (seen.has(key)) continue;
    seen.add(key);
    out.push(text.slice(0, 160));
    if (out.length >= max) break;
  }
  return out;
}

function normalizeIngredientResearchSources(rawSources) {
  const out = [];
  const seen = new Set();
  for (const row of Array.isArray(rawSources) ? rawSources : []) {
    const obj = asResearchObject(row);
    if (!obj) continue;
    const title = String(obj.title || '').trim().slice(0, 160);
    const url = String(obj.url || '').trim().slice(0, 400);
    const source = String(obj.source || '').trim().slice(0, 120);
    const year = Number.isFinite(Number(obj.year)) ? Math.trunc(Number(obj.year)) : null;
    if (!title && !url) continue;
    const key = `${title.toLowerCase()}::${url.toLowerCase()}`;
    if (seen.has(key)) continue;
    seen.add(key);
    out.push({
      ...(title ? { title } : {}),
      ...(url ? { url } : {}),
      year,
      ...(source ? { source } : {}),
    });
    if (out.length >= 8) break;
  }
  return out;
}

function normalizeUnknownLiteral(value) {
  if (typeof value === 'string') {
    const token = value.trim().toLowerCase();
    return token === 'unknown' ? null : value;
  }
  if (Array.isArray(value)) return value.map((item) => normalizeUnknownLiteral(item));
  if (value && typeof value === 'object') {
    const out = {};
    for (const [key, val] of Object.entries(value)) {
      out[key] = normalizeUnknownLiteral(val);
    }
    return out;
  }
  return value;
}

function sanitizeIngredientResearchOutput(raw, { query = '', language = 'EN', sources = [] } = {}) {
  const parsed = asResearchObject(normalizeUnknownLiteral(raw)) || {};
  const ingredientNode = asResearchObject(parsed.ingredient) || {};
  const verdictNode = asResearchObject(parsed.verdict) || {};
  const safetyNode = asResearchObject(parsed.safety) || {};
  const usageNode = asResearchObject(parsed.usage) || {};
  const howToUseNode = asResearchObject(parsed.how_to_use || parsed.howToUse) || {};
  const evidenceNode = asResearchObject(parsed.evidence) || {};
  const topProductsNode = asResearchObject(parsed.top_products || parsed.topProducts) || {};
  const normalizedSources = normalizeIngredientResearchSources(sources);
  const allowedCitationKeys = new Set(
    normalizedSources.map((row) => {
      const title = String(row && row.title ? row.title : '').trim().toLowerCase();
      const url = String(row && row.url ? row.url : '').trim().toLowerCase();
      return `${title}::${url}`;
    }),
  );

  const citationsRaw = Array.isArray(evidenceNode.citations) ? evidenceNode.citations : [];
  const citations = citationsRaw
    .map((row) => asResearchObject(row))
    .filter(Boolean)
    .map((row) => ({
      title: String(row.title || '').trim().slice(0, 160),
      url: String(row.url || '').trim().slice(0, 400),
      year: Number.isFinite(Number(row.year)) ? Math.trunc(Number(row.year)) : null,
      source: String(row.source || '').trim().slice(0, 120),
    }))
    .filter((row) => row.title || row.url)
    .filter((row) => {
      if (!normalizedSources.length) return false;
      const key = `${String(row.title || '').trim().toLowerCase()}::${String(row.url || '').trim().toLowerCase()}`;
      return allowedCitationKeys.has(key);
    })
    .slice(0, 2);

  const lang = language === 'CN' ? 'CN' : 'EN';
  const ingredientName = String(query || '').trim() || (lang === 'CN' ? '该成分' : 'this ingredient');
  const watchoutsSource = (Array.isArray(safetyNode.watchouts) ? safetyNode.watchouts : []).length
    ? safetyNode.watchouts
    : Array.isArray(parsed.watchouts)
      ? parsed.watchouts
      : [];
  const watchouts = watchoutsSource
    .map((row) => asResearchObject(row))
    .filter(Boolean)
    .map((row) => ({
      issue: String(row.issue || '').trim().slice(0, 120),
      likelihood: ['rare', 'uncommon', 'common'].includes(String(row.likelihood || '').trim().toLowerCase())
        ? String(row.likelihood || '').trim().toLowerCase()
        : null,
      what_to_do: String(row.what_to_do || row.whatToDo || '').trim().slice(0, 220),
    }))
    .filter((row) => row.issue || row.what_to_do)
    .slice(0, 3);
  const usageSource = Object.keys(usageNode).length ? usageNode : howToUseNode;
  const topProductsFromArray = (Array.isArray(parsed.top_products) ? parsed.top_products : [])
    .map((row) => {
      if (typeof row === 'string') return row;
      const obj = asResearchObject(row);
      if (!obj) return '';
      return pickFirstTrimmed(obj.name, obj.title, obj.display_name, obj.displayName) || '';
    })
    .map((name) => String(name || '').trim())
    .filter(Boolean)
    .slice(0, 8);
  const topProducts = {
    budget: asResearchStringArray(topProductsNode.budget, 8),
    mid: asResearchStringArray(topProductsNode.mid, 8),
    premium: asResearchStringArray(topProductsNode.premium, 8),
  };
  if (!topProducts.budget.length && !topProducts.mid.length && !topProducts.premium.length && topProductsFromArray.length) {
    topProducts.mid = topProductsFromArray;
  }
  const whatItIs = pickFirstTrimmed(
    ingredientNode.what_it_is,
    ingredientNode.whatItIs,
    parsed.what_it_is,
    parsed.whatItIs,
    parsed.overview,
    verdictNode.one_liner,
  );

  return {
    schema_version: 'v2-lite',
    ingredient: {
      inci: String(ingredientNode.inci || query || '').trim().slice(0, 120),
      display_name: String(ingredientNode.display_name || ingredientNode.displayName || query || '').trim().slice(0, 120),
      aliases: asResearchStringArray(ingredientNode.aliases, 8),
      what_it_is: String(whatItIs || '').trim().slice(0, 200),
    },
    overview: String(pickFirstTrimmed(parsed.overview, verdictNode.one_liner) || '')
      .trim()
      .slice(0, 320),
    benefits: (Array.isArray(parsed.benefits) ? parsed.benefits : [])
      .map((row) => asResearchObject(row))
      .filter(Boolean)
      .map((row) => ({
        concern: String(row.concern || '').trim().slice(0, 64),
        strength: Number.isFinite(Number(row.strength)) ? Math.max(0, Math.min(3, Math.trunc(Number(row.strength)))) : 1,
        what_it_means: String(row.what_it_means || row.whatItMeans || '').trim().slice(0, 220),
      }))
      .filter((row) => row.concern || row.what_it_means)
      .slice(0, 3),
    safety: {
      irritation_risk: ['low', 'medium', 'high'].includes(
        String(pickFirstTrimmed(safetyNode.irritation_risk, verdictNode.irritation_risk) || '').trim().toLowerCase(),
      )
        ? String(pickFirstTrimmed(safetyNode.irritation_risk, verdictNode.irritation_risk) || '')
            .trim()
            .toLowerCase()
        : null,
      watchouts: watchouts.length
        ? watchouts
        : [
          {
            issue: lang === 'CN' ? '信息不足' : 'Limited evidence',
            likelihood: null,
            what_to_do: lang === 'CN' ? '先小范围试用并观察耐受。' : 'Patch-test first and monitor tolerance.',
          },
        ],
    },
    usage: {
      ...normalizeIngredientUsageObject(usageSource),
      routine_step: String(usageSource.routine_step || usageSource.routineStep || '').trim().toLowerCase() || null,
      pair_well: asResearchStringArray(usageSource.pair_well || usageSource.pairWell || usageSource.pairWellWith, 8),
      consider_separating: asResearchStringArray(
        usageSource.consider_separating || usageSource.considerSeparating || usageSource.separate,
        8,
      ),
      notes: asResearchStringArray(usageSource.notes, 4),
    },
    confidence: normalizeIngredientConfidenceLevel(parsed.confidence, 'low'),
    evidence: {
      grade: normalizedSources.length
        ? ['A', 'B', 'C'].includes(String(evidenceNode.grade || '').trim().toUpperCase())
          ? String(evidenceNode.grade || '').trim().toUpperCase()
          : null
        : null,
      summary: String(evidenceNode.summary || '').trim().slice(0, 320),
      citations,
    },
    top_products: topProducts,
    what_it_is: String(whatItIs || '')
      .trim()
      .slice(0, 300),
  };
}

function extractResearchObjectFromRawText(rawText) {
  const raw = String(rawText || '').trim();
  if (!raw) return null;
  const strict = parseJsonOnlyObject(unwrapCodeFence(raw));
  if (strict && typeof strict === 'object' && !Array.isArray(strict)) return strict;
  const byKeys = extractJsonObjectByKeys(raw, ['ingredient', 'benefits', 'safety', 'usage', 'evidence']);
  if (byKeys && typeof byKeys === 'object' && !Array.isArray(byKeys)) return byKeys;
  return extractFirstJsonObjectFromText(raw);
}

async function runIngredientResearchSync({
  query,
  normalizedQuery = '',
  language = 'EN',
  goal = null,
  sensitivity = null,
  profileSummary = null,
  analysisContext = null,
  sources = [],
  logger = null,
} = {}) {
  const provider = 'gemini';
  const modelTier = 'flash';
  const providerAttempts = [];
  const startedAt = Date.now();
  const circuitState = getIngredientProviderCircuitState();
  if (INGREDIENT_KB_ONLY_MODE || circuitState === 'open' || !hasAuroraGeminiApiKey(AURORA_GEMINI_KEY_FEATURE_ENV)) {
    const reason = INGREDIENT_KB_ONLY_MODE ? 'kb_only_mode' : circuitState === 'open' ? 'circuit_open' : 'provider_unavailable';
    if (circuitState === 'open') {
      recordAuroraIngredientsFlowMetric({ stage: 'circuit_open', hit: true });
    }
    recordAuroraIngredientProviderMetric({
      stage: 'final',
      provider,
      outcome: reason,
    });
    return {
      ok: false,
      provider,
      provider_model_tier: modelTier,
      provider_circuit_state: circuitState,
      research_error_code: reason === 'provider_unavailable' ? 'provider_unavailable' : reason,
      research: buildIngredientMinimalResearch({
        query,
        normalizedQuery,
        language,
        errorCode: reason,
        provider,
      }),
      provider_attempts: providerAttempts,
      prompt_meta: null,
      fallback_reason: reason,
    };
  }
  const prompt = buildIngredientResearchPrompts({
    query,
    language,
    goal,
    sensitivity,
    profileSummary,
    analysisContext,
    sources,
  });
  const maxAttempts = 2;
  let finalErrorCode = 'provider_unavailable';
  for (let attempt = 0; attempt < maxAttempts; attempt += 1) {
    const remainingBudget = AURORA_INGREDIENT_SYNC_TOTAL_BUDGET_MS - (Date.now() - startedAt);
    if (remainingBudget <= 200) {
      finalErrorCode = 'gemini_timeout';
      break;
    }
    const callTimeoutMs = Math.max(800, Math.min(AURORA_INGREDIENT_SYNC_REPORT_TIMEOUT_MS, remainingBudget));
    const callStartedAt = Date.now();
    const resp = await callGeminiJsonObjectImpl({
      model: ANALYSIS_STORY_MODEL_GEMINI,
      systemPrompt: prompt.systemPrompt,
      userPrompt: prompt.userPrompt,
      timeoutMs: callTimeoutMs,
      temperature: 0.3,
      maxOutputTokens: 700,
      responseJsonSchema: prompt.responseJsonSchema,
    });
    const latencyMs = Math.max(0, Date.now() - callStartedAt);
    if (resp && resp.ok && resp.json && typeof resp.json === 'object' && !Array.isArray(resp.json)) {
      const parsed = sanitizeIngredientResearchOutput(resp.json, {
        query,
        language,
        sources,
      });
      providerAttempts.push({
        provider,
        outcome: 'ok',
        reason_code: null,
        latency_ms: latencyMs,
      });
      recordAuroraIngredientProviderMetric({ stage: 'attempt', provider, outcome: 'ok' });
      recordAuroraIngredientProviderMetric({ stage: 'final', provider, outcome: 'ok' });
      updateIngredientProviderCircuit({ outcome: 'ok' });
      return {
        ok: true,
        provider,
        provider_model_tier: modelTier,
        provider_circuit_state: getIngredientProviderCircuitState(),
        research: parsed,
        provider_attempts: providerAttempts,
        prompt_meta: {
          prompt_version: prompt.promptVersion,
          prompt_hash: prompt.promptHash,
          input_chars: prompt.inputChars,
          output_chars: JSON.stringify(parsed).length,
        },
      };
    }
    const reasonCode = classifyIngredientProviderError(resp && resp.reason);
    const recoveredParsed = resp && typeof resp.raw_text === 'string'
      ? sanitizeIngredientResearchOutput(extractResearchObjectFromRawText(resp.raw_text), {
        query,
        language,
        sources,
      })
      : null;
    if (recoveredParsed && typeof recoveredParsed === 'object' && !Array.isArray(recoveredParsed)) {
      providerAttempts.push({
        provider,
        outcome: 'ok',
        reason_code: 'json_recovered',
        latency_ms: latencyMs,
      });
      recordAuroraIngredientProviderMetric({ stage: 'attempt', provider, outcome: 'ok' });
      recordAuroraIngredientProviderMetric({ stage: 'final', provider, outcome: 'ok' });
      updateIngredientProviderCircuit({ outcome: 'ok' });
      return {
        ok: true,
        provider,
        provider_model_tier: modelTier,
        provider_circuit_state: getIngredientProviderCircuitState(),
        research: recoveredParsed,
        provider_attempts: providerAttempts,
        prompt_meta: {
          prompt_version: prompt.promptVersion,
          prompt_hash: prompt.promptHash,
          input_chars: prompt.inputChars,
          output_chars: String(resp.raw_text || '').length,
        },
      };
    }
    providerAttempts.push({
      provider,
      outcome: 'error',
      reason_code: reasonCode,
      latency_ms: latencyMs,
    });
    recordAuroraIngredientProviderMetric({ stage: 'attempt', provider, outcome: reasonCode });
    finalErrorCode = reasonCode;
    const shouldRetry = reasonCode === 'gemini_network' && attempt === 0;
    if (!shouldRetry) break;
  }
  const afterCircuitState = updateIngredientProviderCircuit({ outcome: 'error' });
  recordAuroraIngredientProviderMetric({
    stage: 'final',
    provider,
    outcome: finalErrorCode,
  });
  if (finalErrorCode === 'gemini_invalid_json') {
    recordAuroraIngredientsFlowMetric({ stage: 'invalid_json', hit: true });
  }
  if (afterCircuitState === 'open') {
    recordAuroraIngredientsFlowMetric({ stage: 'circuit_open', hit: true });
  }
  const fallback = buildIngredientMinimalResearch({
    query,
    normalizedQuery,
    language,
    errorCode: finalErrorCode,
    provider,
  });
  logger?.warn?.(
    {
      ingredient_query: String(query || '').slice(0, 120),
      normalized_query: String(normalizedQuery || '').slice(0, 120),
      provider,
      provider_model_tier: modelTier,
      provider_circuit_state: afterCircuitState,
      research_error_code: finalErrorCode,
      attempts: providerAttempts,
    },
    'aurora bff: ingredient sync research fallback',
  );
  return {
    ok: false,
    provider,
    provider_model_tier: modelTier,
    provider_circuit_state: afterCircuitState,
    research_error_code: finalErrorCode,
    research: fallback,
    provider_attempts: providerAttempts.slice(0, 3),
    prompt_meta: {
      prompt_version: prompt.promptVersion,
      prompt_hash: prompt.promptHash,
      input_chars: prompt.inputChars,
      output_chars: 0,
    },
    fallback_reason: finalErrorCode,
  };
}

function enqueueIngredientResearchJob({ query, language = 'EN', requestId = '', traceId = '', logger } = {}) {
  hydrateIngredientResearchCacheFromDisk({ logger });
  const key = normalizeIngredientResearchKey(query);
  if (!key) return null;
  const normalizedLanguage = language === 'CN' ? 'CN' : 'EN';
  const jobId = `ingr_${crypto.createHash('sha1').update(`${key}|${normalizedLanguage}`).digest('hex').slice(0, 20)}`;
  const existing = ingredientResearchCache.get(key);
  if (existing && existing.status === 'ready') return { key, status: 'ready', job_id: existing.job_id || jobId };
  if (ingredientResearchInflight.has(key)) {
    recordAuroraIngredientsFlowMetric({ stage: 'duplicate_job_dedup', hit: true });
    return { key, status: 'queued', job_id: existing && existing.job_id ? existing.job_id : jobId };
  }
  const base = {
    status: 'queued',
    ingredient_query: String(query || '').slice(0, 120),
    normalized_query: key,
    job_id: jobId,
    updated_at_ms: Date.now(),
  };
  touchIngredientResearchCache(key, base, { persist: false });
  ingredientResearchInflight.add(key);
  setImmediate(async () => {
    const startedAtMs = Date.now();
    try {
      if (!AURORA_INGREDIENT_RESEARCH_ASYNC_ENABLED || USE_AURORA_BFF_MOCK) {
        touchIngredientResearchCache(key, {
          ...base,
          status: 'skipped',
          reason: 'research_disabled',
          updated_at_ms: Date.now(),
        }, { persist: true, logger });
        return;
      }
      const syncResult = await runIngredientResearchSync({
        query,
        normalizedQuery: key,
        language: normalizedLanguage,
        logger,
      });
      const payload = asResearchObject(syncResult && syncResult.research) || {};
      const ingredient = asResearchObject(payload.ingredient) || {};
      const safety = asResearchObject(payload.safety) || {};
      const usage = asResearchObject(payload.usage) || {};
      const evidence = asResearchObject(payload.evidence) || {};
      const topProducts = asResearchObject(payload.top_products) || asResearchObject(payload.topProducts) || {};
      const confidenceLevel = normalizeIngredientConfidenceLevel(
        payload.confidence ||
          payload.confidence_level ||
          payload.confidenceLevel,
        syncResult && syncResult.ok ? 'medium' : 'low',
      );
      const whatItIs = pickFirstTrimmed(payload.what_it_is, ingredient.what_it_is, ingredient.whatItIs, payload.overview);
      const watchouts = (Array.isArray(safety.watchouts) ? safety.watchouts : [])
        .map((row) => asResearchObject(row))
        .filter(Boolean)
        .map((row) => ({
          issue: String(row.issue || '').slice(0, 120),
          likelihood: String(row.likelihood || '').toLowerCase() || null,
          what_to_do: String(row.what_to_do || row.whatToDo || '').slice(0, 220),
        }))
        .filter((row) => row.issue || row.what_to_do)
        .slice(0, 6);
      const ready = {
        status: syncResult && syncResult.ok ? 'ready' : 'fallback',
        job_id: jobId,
        schema_version: 'v2-lite',
        provider: syncResult && syncResult.provider ? syncResult.provider : 'gemini',
        provider_model_tier: syncResult && syncResult.provider_model_tier ? syncResult.provider_model_tier : 'flash',
        provider_circuit_state: syncResult && syncResult.provider_circuit_state ? syncResult.provider_circuit_state : getIngredientProviderCircuitState(),
        error_code: syncResult && syncResult.research_error_code ? syncResult.research_error_code : null,
        confidence_level: confidenceLevel,
        ingredient: {
          inci: String(ingredient.inci || query || '').slice(0, 120),
          display_name: String(ingredient.display_name || ingredient.displayName || query || '').slice(0, 120),
          aliases: asResearchStringArray(ingredient.aliases, 6),
          what_it_is: String(whatItIs || '').slice(0, 300),
        },
        overview: String(payload.overview || whatItIs || '').slice(0, 320),
        benefits: (Array.isArray(payload.benefits) ? payload.benefits : [])
          .map((row) => asResearchObject(row))
          .filter(Boolean)
          .map((row) => ({
            concern: String(row.concern || '').slice(0, 64),
            strength: Number.isFinite(Number(row.strength)) ? Math.max(0, Math.min(3, Math.trunc(Number(row.strength)))) : 1,
            what_it_means: String(row.what_it_means || row.whatItMeans || '').slice(0, 220),
          }))
          .slice(0, 6),
        safety: {
          irritation_risk: String(safety.irritation_risk || safety.irritationRisk || '').toLowerCase() || null,
          watchouts,
        },
        usage: {
          ...normalizeIngredientUsageObject(usage),
          routine_step: String(usage.routine_step || usage.routineStep || '').toLowerCase() || null,
          pair_well: asResearchStringArray(usage.pair_well || usage.pairWell, 8),
          consider_separating: asResearchStringArray(usage.consider_separating || usage.considerSeparating, 8),
          notes: asResearchStringArray(usage.notes, 8),
        },
        evidence: {
          grade: String(evidence.grade || evidence.evidence_grade || '').toUpperCase() || null,
          summary: String(evidence.summary || '').slice(0, 280),
          citations: (Array.isArray(evidence.citations) ? evidence.citations : [])
            .map((row) => asResearchObject(row))
            .filter(Boolean)
            .map((row) => ({
              title: String(row.title || '').slice(0, 160),
              url: String(row.url || '').slice(0, 400),
              year: Number.isFinite(Number(row.year)) ? Math.trunc(Number(row.year)) : null,
              source: String(row.source || '').slice(0, 120),
            }))
            .slice(0, 8),
        },
        top_products: {
          budget: asResearchStringArray(topProducts.budget, 8),
          mid: asResearchStringArray(topProducts.mid, 8),
          premium: asResearchStringArray(topProducts.premium, 8),
        },
        prompt_meta: syncResult && syncResult.prompt_meta ? syncResult.prompt_meta : null,
        provider_attempts: Array.isArray(syncResult && syncResult.provider_attempts)
          ? syncResult.provider_attempts.slice(0, 3)
          : [],
        updated_at_ms: Date.now(),
        request_id: requestId || null,
        trace_id: traceId || null,
      };
      const passQualityGate = confidenceLevel !== 'low' && Boolean(ready.ingredient.what_it_is) && ready.safety.watchouts.length > 0;
      const previousKb = await getIngredientResearchKbEntry({
        query,
        lang: normalizedLanguage,
        layer: 'generic',
      });
      const nextRevision = previousKb && Number.isFinite(Number(previousKb.revision))
        ? Math.max(1, Math.trunc(Number(previousKb.revision)) + 1)
        : 1;
      if (!passQualityGate) {
        await upsertIngredientResearchKbEntrySafe({
          query,
          language: normalizedLanguage,
          layer: 'generic',
          status: 'fallback',
          provider: ready.provider,
          errorCode: ready.error_code || 'quality_gate_failed',
          ingredientProfile: {
            ...ready,
            status: 'fallback',
            error_code: ready.error_code || 'quality_gate_failed',
          },
          sourceMeta: {
            prompt_meta: ready.prompt_meta || null,
            request_id: requestId || null,
            trace_id: traceId || null,
          },
          revision: nextRevision,
          logger,
        });
        touchIngredientResearchCache(key, {
          ...base,
          status: 'fallback',
          provider: ready.provider,
          provider_model_tier: ready.provider_model_tier,
          provider_circuit_state: ready.provider_circuit_state,
          error_code: ready.error_code || 'quality_gate_failed',
          updated_at_ms: Date.now(),
        }, { persist: true, logger });
        recordAuroraIngredientsFlowMetric({ stage: 'empty_section_prevented', hit: true });
      } else {
        const persisted = await upsertIngredientResearchKbEntrySafe({
          query,
          language: normalizedLanguage,
          layer: 'generic',
          status: 'ready',
          provider: ready.provider,
          ingredientProfile: {
            ...ready,
            status: 'ready',
            kb_revision: String(nextRevision),
          },
          sourceMeta: {
            prompt_meta: ready.prompt_meta || null,
            request_id: requestId || null,
            trace_id: traceId || null,
          },
          revision: nextRevision,
          logger,
        });
        if (persisted && persisted.revision) {
          ready.kb_revision = String(persisted.revision);
          recordAuroraIngredientsFlowMetric({ stage: 'kb_updated', hit: true });
        }
        touchIngredientResearchCache(key, ready, { persist: true, logger });
      }
    } catch (err) {
      touchIngredientResearchCache(key, {
        ...base,
        status: 'error',
        error: err && err.message ? String(err.message).slice(0, 200) : 'research_error',
        updated_at_ms: Date.now(),
      }, { persist: true, logger });
      logger?.warn?.(
        {
          request_id: requestId || null,
          trace_id: traceId || null,
          ingredient_query: String(query || '').slice(0, 120),
          err: err && err.message ? err.message : String(err),
        },
        'aurora bff: ingredient async research failed',
      );
      recordAuroraIngredientsFlowMetric({ stage: 'research_error', hit: true });
    } finally {
      const finishedAtMs = Date.now();
      const finalState = ingredientResearchCache.get(key);
      if (finalState && (finalState.status === 'ready' || finalState.status === 'fallback')) {
        logger?.info?.(
          {
            request_id: requestId || null,
            trace_id: traceId || null,
            ingredient_query: String(query || '').slice(0, 120),
            normalized_query: key,
            job_id: jobId,
            latency_ms: Math.max(0, finishedAtMs - startedAtMs),
            status: finalState.status,
            provider: finalState.provider || 'gemini',
          },
          'aurora bff: ingredient_research_completed',
        );
        recordAuroraIngredientsFlowMetric({ stage: 'research_completed', hit: true });
      }
      ingredientResearchInflight.delete(key);
    }
  });
  return { key, status: 'queued', job_id: jobId };
}

function normalizeIngredientEvidenceGrade(raw, fallback = null) {
  const token = String(raw || '').trim().toUpperCase();
  if (token === 'A' || token === 'B' || token === 'C') return token;
  return fallback;
}

function normalizeIngredientIrritationRisk(raw, fallback = null) {
  const token = String(raw || '').trim().toLowerCase();
  if (token === 'low' || token === 'medium' || token === 'high') return token;
  return fallback;
}

function normalizeIngredientLikelihood(raw) {
  const token = String(raw || '').trim().toLowerCase();
  if (token === 'rare' || token === 'uncommon' || token === 'common') return token;
  return null;
}

function normalizeIngredientSlugKey(raw) {
  return String(raw || '')
    .trim()
    .toLowerCase()
    .replace(/[’‘`´]/g, "'")
    .replace(/[^a-z0-9\u4e00-\u9fff]+/g, '_')
    .replace(/^_+|_+$/g, '')
    .slice(0, 96);
}

function shouldPreferIngredientReferenceProfile(reference, libraryProfile) {
  if (!reference || typeof reference !== 'object' || !libraryProfile || typeof libraryProfile !== 'object') return false;
  const referenceKey = normalizeIngredientSlugKey(
    pickFirstTrimmed(reference.canonical_inci_name, reference.canonical_display_name),
  );
  const libraryKey = normalizeIngredientSlugKey(
    pickFirstTrimmed(libraryProfile.inci, libraryProfile.display_name),
  );
  return Boolean(referenceKey && libraryKey && referenceKey !== libraryKey);
}

function doesIngredientReferenceMatchLibraryProfile(reference, libraryProfile) {
  if (!reference || typeof reference !== 'object' || !libraryProfile || typeof libraryProfile !== 'object') return false;
  const referenceKey = normalizeIngredientSlugKey(
    pickFirstTrimmed(reference.canonical_inci_name, reference.canonical_display_name),
  );
  const libraryKey = normalizeIngredientSlugKey(
    pickFirstTrimmed(libraryProfile.inci, libraryProfile.display_name),
  );
  return Boolean(referenceKey && libraryKey && referenceKey === libraryKey);
}

function inferIngredientFamilyKeyFromInputName(inputName) {
  const text = ingredient_query_normalize(inputName);
  if (!text) return '';
  if (/(retinoid|retinol|retinal|tretinoin|adapalene|retin-?a|vitamin a|维a|a醇|维甲酸|维a酸)/.test(text)) return 'retinoid';
  if (/(salicylic|bha|beta hydroxy|水杨酸)/.test(text)) return 'bha';
  if (/(glycolic|lactic|mandelic|aha|alpha hydroxy|果酸|甘醇酸|乙醇酸|乳酸|杏仁酸)/.test(text)) return 'aha';
  if (/(benzoyl peroxide|bpo|azelaic|壬二酸|过氧化苯甲酰)/.test(text)) return 'acne_active';
  if (/(zinc oxide|titanium dioxide|zno|tio2|氧化锌|二氧化钛)/.test(text)) return 'mineral_filter';
  if (/(avobenzone|octocrylene|octisalate|homosalate|sunscreen filter|uv filter|防晒剂)/.test(text)) return 'uv_filter';
  if (/(ceramide|神经酰胺)/.test(text)) return 'ceramide';
  if (/(hyaluronic|glycerin|glycerol|panthenol|urea|sodium pca|透明质酸|玻尿酸|甘油|泛醇)/.test(text)) return 'humectant';
  if (/(siloxane|silicone|dimethicone|cyclopentasiloxane|硅氧烷|硅油)/.test(text)) return 'silicone';
  if (/(behenyl|cetyl|stearyl|cetearyl|fatty alcohol|脂肪醇|醇)/.test(text)) return 'fatty_alcohol';
  if (/(ester|triglyceride|squalane|squalene|oil|butter|caprylic|capric|ethylhexyl)/.test(text)) return 'oil_emollient';
  if (/(tranexamic|arbutin|kojic|alpha-arbutin|熊果苷|传明酸|氨甲环酸|曲酸)/.test(text)) return 'brightening';
  if (/(vitamin|tocopherol|ascorb|niacinamide|维生素|抗坏血酸|烟酰胺)/.test(text)) return 'vitamin';
  if (/(acid|peel|exfoliant|去角质)/.test(text)) return 'exfoliant';
  return '';
}

