function isBudgetClarificationAction(actionId, clarificationId) {
  const id = String(actionId || '').trim().toLowerCase();
  const cid = String(clarificationId || '').trim().toLowerCase();
  return id.startsWith('chip.clarify.budget') || id.startsWith('chip.budget.') || cid === 'budget';
}

function isBareBudgetSelectionMessage(message) {
  const text = String(message || '').trim();
  if (!text) return false;
  if (normalizeBudgetHint(text)) return true;
  return /^(not\s+sure|不确定)$/i.test(text);
}

function buildBudgetGatePrompt(language) {
  const lang = language === 'CN' ? 'CN' : 'EN';
  if (lang === 'CN') {
    return '如果你愿意，我可以按预算再优化一版。你的月预算大概是多少？（可选）';
  }
  return 'If you want, I can optimize this by budget. What monthly budget feels comfortable? (optional)';
}

function buildBudgetGateChips(language) {
  const lang = language === 'CN' ? 'CN' : 'EN';
  const opts = [
    ['¥200', '¥200'],
    ['¥500', '¥500'],
    ['¥1000+', '¥1000+'],
    ['不确定', lang === 'CN' ? '不确定' : 'Not sure'],
  ];
  return opts.map(([tier, label]) => ({
    chip_id: `chip.budget.${tier.replace(/[^\w]+/g, '_')}`,
    label,
    kind: 'quick_reply',
    data: {
      profile_patch: { budgetTier: tier },
      include_alternatives: true,
      reply_text:
        lang === 'CN'
          ? tier === '不确定'
            ? '先不设预算，继续当前方案。'
            : `把当前 AM/PM 方案按 ${tier} 预算优化（保留核心功效）。`
          : tier === '不确定'
            ? 'Skip budget for now and continue.'
            : `Optimize the current AM/PM routine around ${tier} budget while keeping core efficacy.`,
    },
  }));
}

function isBudgetOptimizationEntryAction(actionId) {
  const id = String(actionId || '').trim().toLowerCase();
  return id === 'chip.budget.optimize.entry' || id === 'chip.action.budget_optimize';
}

function buildBudgetOptimizationEntryChip(language) {
  const lang = language === 'CN' ? 'CN' : 'EN';
  return {
    chip_id: 'chip.budget.optimize.entry',
    label: lang === 'CN' ? '按预算优化（可选）' : 'Optimize by budget (optional)',
    kind: 'quick_reply',
    data: {
      include_alternatives: true,
      reply_text:
        lang === 'CN'
          ? '我想在当前方案基础上做预算优化。'
          : 'I want to optimize the current routine by budget.',
    },
  };
}

async function mapWithConcurrency(items, limit, worker) {
  const list = Array.isArray(items) ? items : [];
  if (!list.length) return [];

  const concurrency = Math.max(1, Math.min(8, Number.isFinite(Number(limit)) ? Math.trunc(Number(limit)) : 1));
  const out = new Array(list.length);
  let cursor = 0;

  async function runOne() {
    while (cursor < list.length) {
      const idx = cursor;
      cursor += 1;
      try {
        // eslint-disable-next-line no-await-in-loop
        out[idx] = await worker(list[idx], idx);
      } catch (err) {
        out[idx] = { ok: false, error: err instanceof Error ? err.message : String(err) };
      }
    }
  }

  const workers = Array.from({ length: Math.min(concurrency, list.length) }, () => runOne());
  await Promise.all(workers);
  return out;
}

function extractAnchorIdFromProductLike(obj) {
  const source = unwrapProductLike(obj);
  if (!source) return null;
  const raw =
    (typeof source.sku_id === 'string' && source.sku_id) ||
    (typeof source.skuId === 'string' && source.skuId) ||
    (typeof source.product_id === 'string' && source.product_id) ||
    (typeof source.productId === 'string' && source.productId) ||
    null;
  const v = raw ? String(raw).trim() : '';
  return v || null;
}

function normalizeRecoDedupeToken(raw) {
  const token = String(raw || '').trim().toLowerCase().replace(/\s+/g, ' ');
  return token || '';
}

function normalizeRecoNameToken(raw) {
  const token = normalizeRecoDedupeToken(raw).replace(/[^a-z0-9]+/g, ' ').trim();
  return token || '';
}

function normalizeRecoUrlToken(raw) {
  const text = String(raw || '').trim();
  if (!text) return '';
  try {
    const parsed = new URL(text);
    const path = parsed.pathname ? parsed.pathname.replace(/\/+$/, '') : '';
    return `${String(parsed.hostname || '').toLowerCase()}${path}`.toLowerCase();
  } catch {
    return normalizeRecoDedupeToken(text);
  }
}

function buildRecoRecommendationDedupeKey(item) {
  const base = item && typeof item === 'object' && !Array.isArray(item) ? item : null;
  if (!base) return '';
  const candidate =
    base.sku && typeof base.sku === 'object'
      ? base.sku
      : base.product && typeof base.product === 'object'
        ? base.product
        : base;

  const productId = normalizeRecoDedupeToken(
    pickFirstTrimmed(candidate.product_id, candidate.productId, base.product_id, base.productId),
  );
  if (productId) return `pid:${productId}`;

  const skuId = normalizeRecoDedupeToken(pickFirstTrimmed(candidate.sku_id, candidate.skuId, base.sku_id, base.skuId));
  const merchantId = normalizeRecoDedupeToken(
    pickFirstTrimmed(candidate.merchant_id, candidate.merchantId, base.merchant_id, base.merchantId),
  );
  if (merchantId && skuId) return `merchant_sku:${merchantId}:${skuId}`;
  if (skuId) return `sku:${skuId}`;

  const openUrl = normalizeRecoUrlToken(
    pickFirstTrimmed(
      extractCandidateOpenUrl(base),
      extractCandidateOpenUrl(candidate),
      base.url,
      base.product_url,
      candidate.url,
      candidate.product_url,
    ),
  );
  if (openUrl) return `url:${openUrl}`;

  const brand = normalizeRecoNameToken(pickFirstTrimmed(candidate.brand, base.brand));
  const name = normalizeRecoNameToken(
    pickFirstTrimmed(candidate.display_name, candidate.name, base.display_name, base.name),
  );
  if (brand || name) return `name:${brand}::${name}`;

  const fallbackInput = normalizeRecoNameToken(
    buildProductInputText(candidate, base && typeof base.url === 'string' ? base.url : null),
  );
  if (fallbackInput) return `txt:${fallbackInput}`;
  return '';
}

function dedupeRecoRecommendationsStrict(recommendations, { maxItems = 8 } = {}) {
  const list = Array.isArray(recommendations) ? recommendations : [];
  const out = [];
  const seenKeys = new Set();
  const seenProductIds = new Set();
  const cap = Number.isFinite(Number(maxItems)) ? Math.max(1, Math.min(12, Math.trunc(Number(maxItems)))) : 8;
  for (const item of list) {
    if (!item || typeof item !== 'object' || Array.isArray(item)) continue;
    const base = item;
    const productId = normalizeRecoDedupeToken(
      pickFirstTrimmed(
        base.product_id,
        base.productId,
        base?.sku?.product_id,
        base?.sku?.productId,
        base?.product?.product_id,
        base?.product?.productId,
      ),
    );
    if (productId) {
      if (seenProductIds.has(productId)) continue;
      seenProductIds.add(productId);
    }
    const dedupeKey = buildRecoRecommendationDedupeKey(base) || (productId ? `pid:${productId}` : '');
    if (!dedupeKey) continue;
    if (seenKeys.has(dedupeKey)) continue;
    seenKeys.add(dedupeKey);
    out.push({ ...base });
    if (out.length >= cap) break;
  }
  return {
    recommendations: out,
    dropped_count: Math.max(0, list.length - out.length),
  };
}

function buildRecoAlternativesCacheKey({ inputText, anchorId, productObj, lang, recommendationMode = 'pool_only', profileMode = 'anchor_only' } = {}) {
  const langToken = normalizeRecoDedupeToken(lang || 'EN') || 'en';
  const modeToken = normalizeRecoDedupeToken(recommendationMode) || 'pool_only';
  const profileToken = normalizeRecoDedupeToken(profileMode) || 'anchor_only';
  const anchorToken = normalizeRecoDedupeToken(anchorId);
  if (anchorToken) return `anchor:${langToken}:${modeToken}:${profileToken}:${anchorToken}`;
  const product = productObj && typeof productObj === 'object' && !Array.isArray(productObj) ? productObj : {};
  const productIdToken = normalizeRecoDedupeToken(
    pickFirstTrimmed(product.product_id, product.productId, product.sku_id, product.skuId),
  );
  if (productIdToken) return `product:${langToken}:${modeToken}:${profileToken}:${productIdToken}`;
  const inputToken = normalizeRecoNameToken(inputText);
  return inputToken ? `input:${langToken}:${modeToken}:${profileToken}:${inputToken}` : '';
}

function readRecoAlternativesCache(cacheKey, { allowStale = false } = {}) {
  const key = String(cacheKey || '').trim();
  if (!key) return null;
  const entry = recoAlternativesResponseCache.get(key);
  if (!entry || typeof entry !== 'object') return null;
  const ageMs = Date.now() - Number(entry.createdAtMs || 0);
  if (!allowStale && (!Number.isFinite(ageMs) || ageMs > RECO_ALTERNATIVES_CACHE_TTL_MS)) return null;
  if (!Array.isArray(entry.alternatives) || !entry.alternatives.length) return null;
  return {
    alternatives: safeStructuredCloneJson(entry.alternatives) || [],
    llm_trace: entry.llm_trace && typeof entry.llm_trace === 'object' ? { ...entry.llm_trace } : null,
    age_ms: Number.isFinite(ageMs) ? ageMs : null,
    stale: Number.isFinite(ageMs) ? ageMs > RECO_ALTERNATIVES_CACHE_TTL_MS : true,
  };
}

function writeRecoAlternativesCache(cacheKey, alternatives, llmTrace = null) {
  const key = String(cacheKey || '').trim();
  if (!key) return;
  const rows = Array.isArray(alternatives) ? alternatives : [];
  if (!rows.length) return;
  const payload = safeStructuredCloneJson(rows);
  if (!Array.isArray(payload) || !payload.length) return;
  if (!recoAlternativesResponseCache.has(key) && recoAlternativesResponseCache.size >= RECO_ALTERNATIVES_CACHE_MAX_KEYS) {
    const oldestKey = recoAlternativesResponseCache.keys().next().value;
    if (oldestKey) recoAlternativesResponseCache.delete(oldestKey);
  }
  recoAlternativesResponseCache.set(key, {
    createdAtMs: Date.now(),
    alternatives: payload,
    llm_trace: llmTrace && typeof llmTrace === 'object' ? { ...llmTrace } : null,
  });
}

function mergeFieldMissing(a, b) {
  const out = [];
  const seen = new Set();
  for (const item of [...(Array.isArray(a) ? a : []), ...(Array.isArray(b) ? b : [])]) {
    if (!item || typeof item !== 'object') continue;
    const field = typeof item.field === 'string' ? item.field.trim() : '';
    const reason = typeof item.reason === 'string' ? item.reason.trim() : '';
    if (!field || !reason) continue;
    const key = `${field}::${reason}`;
    if (seen.has(key)) continue;
    seen.add(key);
    out.push({ field, reason });
  }
  return out;
}

function normalizeAlternativesSkinType(raw) {
  const token = String(raw || '').trim().toLowerCase();
  if (!token) return '';
  if (token.includes('oily')) return 'Oily';
  if (token.includes('dry')) return 'Dry';
  if (token.includes('combo') || token.includes('mix')) return 'Combo/Mixed';
  return '';
}

function normalizeAlternativesSensitivity(raw) {
  const token = String(raw || '').trim().toLowerCase();
  if (!token) return '';
  if (token.includes('high') || token.includes('sensitive') || token.includes('reactive')) return 'High';
  if (token.includes('low')) return 'Low';
  if (token.includes('medium') || token.includes('mid')) return 'Medium';
  return '';
}

function normalizeAlternativesBarrier(raw) {
  const token = String(raw || '').trim().toLowerCase();
  if (!token) return '';
  if (token.includes('impaired') || token.includes('stinging') || token.includes('red') || token.includes('damaged') || token.includes('reactive')) {
    return 'Impaired';
  }
  if (token.includes('stable') || token.includes('normal') || token.includes('healthy')) return 'Stable';
  return '';
}

function normalizeAlternativesGoal(raw) {
  const token = String(raw || '').trim();
  if (!token) return '';
  const lower = token.toLowerCase();
  if (lower.includes('acne') || lower.includes('texture') || lower.includes('pore')) return 'Acne/Texture';
  if (lower.includes('bright') || lower.includes('dark spot') || lower.includes('tone')) return 'Dark spots/Brightening';
  if (lower.includes('aging') || lower.includes('firm') || lower.includes('wrinkle')) return 'Aging';
  if (lower.includes('red') || lower.includes('barrier') || lower.includes('repair') || lower.includes('soothing')) return 'Redness/Barrier repair';
  if (lower.includes('hydrat') || lower.includes('moist')) return 'Hydration';
  return token.slice(0, 40);
}

function buildAlternativesProfileSnapshot(profileObjRaw) {
  const profileObjSafe = profileObjRaw && typeof profileObjRaw === 'object' && !Array.isArray(profileObjRaw) ? profileObjRaw : {};
  const skinTypeKnown = normalizeAlternativesSkinType(
    pickFirstTrimmed(profileObjSafe.skinType, profileObjSafe.skin_type, profileObjSafe.skin_type_text),
  );
  const sensitivityKnown = normalizeAlternativesSensitivity(
    pickFirstTrimmed(profileObjSafe.sensitivity, profileObjSafe.sensitivity_level),
  );
  const barrierKnown = normalizeAlternativesBarrier(
    pickFirstTrimmed(profileObjSafe.barrierStatus, profileObjSafe.barrier_status),
  );
  const goalsKnown = uniqCaseInsensitiveStrings(
    Array.isArray(profileObjSafe.goals) ? profileObjSafe.goals.map((item) => normalizeAlternativesGoal(item)).filter(Boolean) : [],
    4,
  );
  return {
    skinType: skinTypeKnown || 'unknown',
    sensitivity: sensitivityKnown || 'unknown',
    barrierStatus: barrierKnown || 'unknown',
    goals: goalsKnown,
    context_present: Boolean(skinTypeKnown || sensitivityKnown || barrierKnown || goalsKnown.length),
  };
}

function normalizeAlternativesProfileMode(raw) {
  return String(raw || '').trim().toLowerCase() === 'personalized' ? 'personalized' : 'anchor_only';
}

function normalizeRecoAlternativesMode(raw) {
  const token = String(raw || '').trim().toLowerCase();
  if (token === 'hybrid_fallback' || token === 'pool_open_world_mixed') return 'pool_open_world_mixed';
  if (token === 'open_world_only') return 'open_world_only';
  return 'pool_only';
}

function resolveRecoAlternativesPromptSpec(modeRaw) {
  const mode = normalizeRecoAlternativesMode(modeRaw);
  if (mode === 'pool_only') {
    return {
      mode,
      templateId: RECO_ALTERNATIVES_PROMPT_TEMPLATE_ID,
      systemFile: 'reco_alternatives_v1_0.system.txt',
      schemaFile: 'reco_alternatives_v1_0.user_schema.json',
      queryLine: 'Select up to task.max_alternatives alternatives ONLY from context.candidates.',
    };
  }
  return {
    mode,
    templateId: RECO_ALTERNATIVES_HYBRID_PROMPT_TEMPLATE_ID,
    systemFile: 'reco_alternatives_hybrid_v1.system.txt',
    schemaFile: 'reco_alternatives_hybrid_v1.user_schema.json',
    queryLine: mode === 'open_world_only'
      ? 'Generate up to task.max_alternatives distinct, conservative, anchor-based alternatives for target_product. In open_world_only mode, ignore candidate-pool dependence and use target_product itself as the anchor basis. For common anchors, aim to return 2-4 viable real-product alternatives whenever possible. A viable open-world item must have a non-null product.brand, a non-null product.name, anchor-linked reasons, and at least one concrete tradeoff or uncertainty; do not return hollow or placeholder items.'
      : 'Use context.candidates first and supplement with distinct, conservative open-world alternatives only when the local pool is insufficient. Every returned item must be viable: distinct from the anchor, non-placeholder, and supported by anchor-linked reasons plus at least one concrete tradeoff or uncertainty.',
  };
}

function normalizeAlternativesSelectorCandidate(row, { index = 0 } = {}) {
  const normalized = normalizeRecoCatalogProduct(row) || (row && typeof row === 'object' && !Array.isArray(row) ? row : null);
  if (!normalized || typeof normalized !== 'object') return null;
  const productId = pickFirstTrimmed(normalized.product_id, normalized.productId);
  const skuId = pickFirstTrimmed(normalized.sku_id, normalized.skuId);
  const brand = pickFirstTrimmed(normalized.brand);
  const name = pickFirstTrimmed(normalized.display_name, normalized.displayName, normalized.name, normalized.title);
  const category = pickFirstTrimmed(normalized.category, normalized.category_name, normalized.product_type, normalized.type);
  const pdpUrl = extractCandidateOpenUrl(normalized);
  const idMaterial = pickFirstTrimmed(productId, skuId, brand && name ? `${brand}:${name}` : name);
  const id = idMaterial
    ? String(idMaterial).trim()
    : `cand_${stableHashBase36(`${name || ''}|${brand || ''}|${pdpUrl || ''}|${index}`).slice(0, 18)}`;
  if (!id || !name) return null;
  const priceObj = normalized.price && typeof normalized.price === 'object' && !Array.isArray(normalized.price)
    ? normalized.price
    : Number.isFinite(Number(normalized.price_usd))
      ? { amount: Number(normalized.price_usd), currency: 'USD' }
      : null;
  return {
    id: String(id).trim().slice(0, 120),
    product_id: productId || null,
    sku_id: skuId || null,
    name: String(name).trim().slice(0, 140),
    brand: brand || null,
    category: category || null,
    pdp_url: pdpUrl || null,
    similarity_score: Number.isFinite(Number(normalized.similarity_score))
      ? Math.max(0, Math.min(100, Number(normalized.similarity_score) > 1 ? Number(normalized.similarity_score) : Number(normalized.similarity_score) * 100))
      : null,
    signals: uniqCaseInsensitiveStrings(
      [
        ...asStringArray(normalized.why_candidate),
        ...asStringArray(normalized.compare_highlights),
      ],
      4,
    ),
    ...(priceObj ? { price: priceObj } : {}),
  };
}

function buildRecoAlternativesCandidatePool({ sharedCandidates = [], productObj = null, anchorId = '', maxCandidates = 16 } = {}) {
  const out = [];
  const seen = new Set();
  const anchor = String(anchorId || '').trim().toLowerCase();
  const limit = Math.max(1, Math.min(24, Number.isFinite(Number(maxCandidates)) ? Math.trunc(Number(maxCandidates)) : 16));
  const maybePush = (row, idx = 0) => {
    const normalized = normalizeAlternativesSelectorCandidate(row, { index: idx });
    if (!normalized) return;
    const idKey = String(normalized.id || '').trim().toLowerCase();
    if (!idKey || seen.has(idKey)) return;
    const pidKey = String(normalized.product_id || normalized.sku_id || '').trim().toLowerCase();
    if ((anchor && idKey === anchor) || (anchor && pidKey === anchor)) return;
    seen.add(idKey);
    out.push(normalized);
  };
  let idx = 0;
  for (const row of Array.isArray(sharedCandidates) ? sharedCandidates : []) {
    maybePush(row, idx);
    idx += 1;
    if (out.length >= limit) break;
  }
  const product = productObj && typeof productObj === 'object' && !Array.isArray(productObj) ? productObj : {};
  const listCandidates = [
    product.candidates,
    product.product_candidates,
    product.alternatives,
    product.alternative_candidates,
    product.related_products && product.related_products.candidates,
    product.relatedProducts && product.relatedProducts.candidates,
    product.competitors && product.competitors.candidates,
    product.dupes && product.dupes.candidates,
  ];
  for (const list of listCandidates) {
    for (const row of Array.isArray(list) ? list : []) {
      maybePush(row, idx);
      idx += 1;
      if (out.length >= limit) break;
    }
    if (out.length >= limit) break;
  }
  return out.slice(0, limit);
}

const RECO_ALTERNATIVES_GENERIC_INGREDIENT_RE =
  /\b(water|aqua|glycerin|butylene glycol|propylene glycol|caprylic|capric|dimethicone|silica|parfum|fragrance|phenoxyethanol|carbomer|citric acid|sodium hydroxide)\b/i;

function pushRecoPromptText(out, seen, raw, { max = 6, maxLen = 80 } = {}) {
  const text = String(raw || '').trim().replace(/\s+/g, ' ');
  if (!text) return;
  const trimmed = text.slice(0, maxLen);
  const key = trimmed.toLowerCase();
  if (seen.has(key)) return;
  seen.add(key);
  out.push(trimmed);
  if (out.length > max) out.length = max;
}

function collectRecoPromptTextList(values, { max = 6, maxLen = 80 } = {}) {
  const out = [];
  const seen = new Set();
  for (const entry of Array.isArray(values) ? values : []) {
    if (out.length >= max) break;
    if (typeof entry === 'string' || typeof entry === 'number') {
      pushRecoPromptText(out, seen, entry, { max, maxLen });
      continue;
    }
    if (!isPlainObject(entry)) continue;
    pushRecoPromptText(
      out,
      seen,
      pickFirstTrimmed(
        entry.name,
        entry.display_name,
        entry.displayName,
        entry.ingredient_name,
        entry.inci,
        entry.claim,
        entry.claim_en,
        entry.text,
        entry.text_en,
        entry.label,
        entry.title,
        entry.value,
        entry.benefit,
        entry.benefit_en,
      ),
      { max, maxLen },
    );
  }
  return out.slice(0, max);
}

function normalizeRecoPromptNarrative(value) {
  return String(value || '')
    .replace(/<\s*br\s*\/?>/gi, ' ')
    .replace(/<\/?\s*(?:p|div|section|article|header|footer|blockquote|h[1-6]|ul|ol|li)\b[^>]*>/gi, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function inferRecoAlternativesUsageRole(...values) {
  const text = values.filter(Boolean).join(' ').toLowerCase();
  if (!text) return 'unknown';
  if (/\b(spf\s*\d{2,3}\+?|spf|sunscreen|sun fluid|sun cream|sun lotion|sun serum|sun gel|sun milk|uv)\b/.test(text)) return 'sunscreen';
  if (/\b(cleanser|cleansing|face wash|foam wash|gel cleanser|wash)\b/.test(text)) return 'cleanser';
  if (/\b(toner|mist)\b/.test(text)) return 'toner';
  if (/\b(essence)\b/.test(text)) return 'essence';
  if (/\b(serum|ampoule)\b/.test(text)) return 'serum';
  if (/\b(moisturizer|moisturiser|cream|lotion|gel cream|water gel|emulsion)\b/.test(text)) return 'moisturizer';
  if (/\b(mask)\b/.test(text)) return 'mask';
  if (/\b(facial oil|face oil|treatment oil|beauty oil|marula oil|squalane oil|rosehip oil)\b/.test(text)) return 'oil';
  if (/\b(treatment|exfoliant|peel|spot|retinol|retinoid|acid)\b/.test(text)) return 'treatment';
  return 'unknown';
}

function inferRecoAlternativesUsageRoleFromRoleScope(roleScope) {
  const text = String(roleScope || '').trim().toLowerCase().replace(/[_-]+/g, ' ');
  if (!text) return '';
  if (/\b(spf|sunscreen|sun)\b/.test(text)) return 'sunscreen';
  if (/\bcleanser\b/.test(text)) return 'cleanser';
  if (/\btoner\b/.test(text)) return 'toner';
  if (/\bessence\b/.test(text) && !/\bserum\b/.test(text)) return 'essence';
  if (/\bserum\b/.test(text)) return 'serum';
  if (/\bmoisturizer|moisturiser|cream|lotion|barrier\b/.test(text)) return 'moisturizer';
  return '';
}

function inferRecoAlternativesSearchUsageRole(targetSignals) {
  const target = isPlainObject(targetSignals) ? targetSignals : {};
  const usageRole = String(target.usageRole || '').trim().toLowerCase().replace(/_/g, ' ');
  if (usageRole && usageRole !== 'unknown') return usageRole;
  const roleScopeText = String(target.roleScope || '').trim().toLowerCase().replace(/[_-]+/g, ' ');
  const roleScopeRole = inferRecoAlternativesUsageRoleFromRoleScope(roleScopeText);
  if (roleScopeRole) return roleScopeRole;
  if (/\b(?:oil control|tone|mark|acne|pore|treatment)\b/.test(roleScopeText)) return 'serum';
  return '';
}

function pickRecoAlternativesAuthoritativeUsageRole({ roleScope, structuralUsageRole, inferredUsageRole } = {}) {
  const roleScopeRole = inferRecoAlternativesUsageRoleFromRoleScope(roleScope);
  if (roleScopeRole) return roleScopeRole;
  const structuralRole = String(structuralUsageRole || '').trim().toLowerCase();
  if (structuralRole && structuralRole !== 'unknown') return structuralRole;
  const noisyRole = String(inferredUsageRole || '').trim().toLowerCase();
  return noisyRole && noisyRole !== 'unknown' ? noisyRole : 'unknown';
}

function buildRecoAlternativesLocalSeedSearchRole(targetSignals) {
  const target = isPlainObject(targetSignals) ? targetSignals : {};
  const searchUsageRole = inferRecoAlternativesSearchUsageRole(target);
  const preferredStep =
    normalizeRecoTargetStep(searchUsageRole) ||
    normalizeRecoTargetStep(target.usageRole) ||
    normalizeRecoTargetStep(target.productType) ||
    normalizeRecoTargetStep(target.category) ||
    '';
  const roleScope = pickFirstTrimmed(target.roleScope);
  const queryTerms = uniqCaseInsensitiveStrings(
    [
      ...(Array.isArray(target.primaryClaims) ? target.primaryClaims : []),
      ...(Array.isArray(target.knownActives) ? target.knownActives : []),
    ],
    8,
  );
  const fitKeywords = uniqCaseInsensitiveStrings(
    [
      ...(Array.isArray(target.textureHints) ? target.textureHints : []),
      ...(Array.isArray(target.heroIngredients) ? target.heroIngredients : []),
      ...(Array.isArray(target.knownActives) ? target.knownActives : []),
    ],
    8,
  );
  const productTypeHypotheses = uniqCaseInsensitiveStrings(
    [
      target.productType,
      target.category,
      preferredStep,
      searchUsageRole,
    ],
    6,
  );
  return {
    role_id: roleScope || (preferredStep ? `reco_alternatives_${preferredStep}` : 'reco_alternatives_pool'),
    label: roleScope ? roleScope.replace(/[_-]+/g, ' ') : `${preferredStep || 'product'} alternatives`,
    preferred_step: preferredStep,
    rank: 2,
    query_terms: queryTerms,
    fit_keywords: fitKeywords,
    product_type_hypotheses: productTypeHypotheses,
  };
}

function inferRecoAlternativesClaimHints(...values) {
  const text = values.filter(Boolean).join(' ').toLowerCase();
  const out = [];
  const seen = new Set();
  const push = (value) => pushRecoPromptText(out, seen, value, { max: 6, maxLen: 48 });
  if (!text) return out;
  if (/\b(?:hydrat\w*|moist\w*|hyaluronic|plump\w*)\b/.test(text)) push('hydration');
  if (/\b(?:barrier|repair\w*|sooth\w*|calm\w*|redness)\b/.test(text)) push('barrier support');
  if (/\b(?:bright\w*|dark spot\w*|tone\w*|vitamin c|glow\w*|niacinamide)\b/.test(text)) push('brightening');
  if (/\b(?:acne|blemish\w*|clarif\w*|salicylic|bha|breakout\w*|pore\w*)\b/.test(text)) push('blemish care');
  if (/\b(?:retinol|retinoid\w*|firm\w*|wrinkle\w*|aging|ageing|line\w*)\b/.test(text)) push('anti-aging');
  if (/\b(?:oil control|oil-free|matt\w*|shine\w*)\b/.test(text)) push('oil control');
  if (/\b(?:spf|sunscreen|uv)\b/.test(text)) push('sun protection');
  if (/\b(?:exfoliat\w*|aha|bha|pha|acid\w*|peel\w*)\b/.test(text)) push('exfoliation');
  return out;
}

function normalizeRecoAlternativePrimaryClaimsForRoleScope(claims, roleScope) {
  const list = uniqCaseInsensitiveStrings(Array.isArray(claims) ? claims : [], 6);
  const roleText = String(roleScope || '').trim().toLowerCase().replace(/[_-]+/g, ' ');
  if (!list.length || !roleText) return list;
  if (/\b(?:hydrating|barrier|moisturizer|moisturiser|cream|lotion)\b/.test(roleText)) {
    const scoped = list.filter((claim) =>
      /\b(?:hydrat\w*|moist\w*|barrier|ceramides?|glycerin|hyaluronic|sooth\w*|calm\w*|redness|sensitive|lightweight|non[-\s]?comedogenic|gel|water)\b/i.test(
        String(claim || ''),
      ),
    );
    return scoped.length ? uniqCaseInsensitiveStrings(scoped, 6) : list;
  }
  if (/\b(?:sunscreen|spf|sun|uv)\b/.test(roleText)) {
    const scoped = list.filter((claim) =>
      /\b(?:spf|sun|uv|protection|white\s*cast|matte|oil[-\s]?control|non[-\s]?greasy|lightweight|hydrat\w*)\b/i.test(
        String(claim || ''),
      ),
    );
    return scoped.length ? uniqCaseInsensitiveStrings(scoped, 6) : list;
  }
  return list;
}

function inferRecoAlternativesTextureHints(...values) {
  const text = values.filter(Boolean).join(' ').toLowerCase();
  const out = [];
  const seen = new Set();
  const push = (value) => pushRecoPromptText(out, seen, value, { max: 5, maxLen: 40 });
  if (!text) return out;
  if (/\bwater gel\b/.test(text)) push('water-gel texture');
  if (/\bgel(-cream)?\b/.test(text)) push('gel texture');
  if (/\blotion\b/.test(text)) push('lotion texture');
  if (/\bcream\b/.test(text)) push('cream texture');
  if (/\bserum\b/.test(text)) push('serum texture');
  if (/\bbalm\b/.test(text)) push('balm texture');
  if (/\boil\b/.test(text)) push('oil texture');
  if (/\blightweight\b/.test(text)) push('lightweight finish');
  if (/\brich\b/.test(text)) push('richer finish');
  if (/\bmatte\b/.test(text)) push('matte finish');
  if (/\bdewy\b/.test(text)) push('dewy finish');
  return out;
}

function buildRecoAlternativesTargetSignals(product, { productInput = '', lang = 'EN' } = {}) {
  const row = isPlainObject(product) ? product : {};
  const sku = isPlainObject(row.sku) ? row.sku : {};
  const category =
    pickFirstTrimmed(
      row.category,
      row.category_name,
      row.product_type,
      row.productType,
      row.type,
      sku.category,
      sku.category_name,
      sku.product_type,
      sku.productType,
      sku.type,
    ) || null;
  const productType =
    pickFirstTrimmed(
      row.product_type,
      row.productType,
      row.type,
      row.category,
      row.category_name,
      sku.product_type,
      sku.productType,
      sku.type,
      sku.category,
      sku.category_name,
    ) || null;
  const name = pickFirstTrimmed(
    row.display_name,
    row.displayName,
    row.name,
    row.product_name,
    sku.display_name,
    sku.displayName,
    sku.name,
    sku.product_name,
    productInput,
  );
  const brand = pickFirstTrimmed(row.brand, row.manufacturer, sku.brand, sku.manufacturer);
  const roleScope = pickFirstTrimmed(
    row.role_scope,
    row.selected_target_id,
    row.matched_role_id,
    row.matchedRoleId,
    sku.role_scope,
    sku.selected_target_id,
    sku.matched_role_id,
    sku.matchedRoleId,
  );
  const keyFeatureSignals = collectRecoPromptTextList(
    [
      ...(Array.isArray(row.key_features) ? row.key_features : []),
      ...(Array.isArray(row.keyFeatures) ? row.keyFeatures : []),
      ...(Array.isArray(sku.key_features) ? sku.key_features : []),
      ...(Array.isArray(sku.keyFeatures) ? sku.keyFeatures : []),
    ],
    { max: 6, maxLen: 48 },
  );
  const narrativeSignals = collectRecoPromptTextList(
    [
      normalizeRecoPromptNarrative(row.short_description),
      normalizeRecoPromptNarrative(row.shortDescription),
      normalizeRecoPromptNarrative(row.why_this_one),
      normalizeRecoPromptNarrative(row.whyThisOne),
      normalizeRecoPromptNarrative(row.description),
      normalizeRecoPromptNarrative(row.summary),
      normalizeRecoPromptNarrative(row.subtitle),
      normalizeRecoPromptNarrative(sku.short_description),
      normalizeRecoPromptNarrative(sku.shortDescription),
      normalizeRecoPromptNarrative(sku.why_this_one),
      normalizeRecoPromptNarrative(sku.whyThisOne),
      normalizeRecoPromptNarrative(sku.description),
      normalizeRecoPromptNarrative(sku.summary),
      normalizeRecoPromptNarrative(sku.subtitle),
    ],
    { max: 4, maxLen: 120 },
  );

  const explicitHeroIngredients = collectRecoPromptTextList(
    [
      ...(Array.isArray(row.hero_ingredients) ? row.hero_ingredients : []),
      ...(Array.isArray(row.heroIngredients) ? row.heroIngredients : []),
      ...(Array.isArray(row.known_actives) ? row.known_actives : []),
      ...(Array.isArray(row.keyActives) ? row.keyActives : []),
      ...(Array.isArray(row.key_actives) ? row.key_actives : []),
      ...(Array.isArray(sku.hero_ingredients) ? sku.hero_ingredients : []),
      ...(Array.isArray(sku.heroIngredients) ? sku.heroIngredients : []),
      ...(Array.isArray(sku.known_actives) ? sku.known_actives : []),
      ...(Array.isArray(sku.keyActives) ? sku.keyActives : []),
      ...(Array.isArray(sku.key_actives) ? sku.key_actives : []),
    ],
    { max: 6, maxLen: 48 },
  );

  const ingredientLabels = collectRecoPromptTextList(
    [
      ...(Array.isArray(row.ingredients) ? row.ingredients : []),
      ...(Array.isArray(sku.ingredients) ? sku.ingredients : []),
    ],
    {
      max: 8,
      maxLen: 48,
    },
  );
  const heroIngredients = uniqCaseInsensitiveStrings(
    [
      ...explicitHeroIngredients,
      ...ingredientLabels.filter((entry) => !RECO_ALTERNATIVES_GENERIC_INGREDIENT_RE.test(entry)).slice(0, 5),
    ],
    5,
  );

  const explicitClaims = collectRecoPromptTextList(
    [
      ...(Array.isArray(row.claims) ? row.claims : []),
      ...(Array.isArray(row.notable_claims) ? row.notable_claims : []),
      ...(Array.isArray(row.notableClaims) ? row.notableClaims : []),
      ...(Array.isArray(row.benefits) ? row.benefits : []),
      ...(Array.isArray(row.highlights) ? row.highlights : []),
      ...(Array.isArray(row.compare_highlights) ? row.compare_highlights : []),
      ...(Array.isArray(sku.claims) ? sku.claims : []),
      ...(Array.isArray(sku.notable_claims) ? sku.notable_claims : []),
      ...(Array.isArray(sku.notableClaims) ? sku.notableClaims : []),
      ...(Array.isArray(sku.benefits) ? sku.benefits : []),
      ...(Array.isArray(sku.highlights) ? sku.highlights : []),
      ...(Array.isArray(sku.compare_highlights) ? sku.compare_highlights : []),
      ...keyFeatureSignals,
    ],
    { max: 6, maxLen: 56 },
  );
  const claimHints = inferRecoAlternativesClaimHints(
    name,
    category,
    productType,
    productInput,
    explicitClaims.join(' '),
    keyFeatureSignals.join(' '),
    narrativeSignals.join(' '),
    heroIngredients.join(' '),
  );
  const primaryClaims = normalizeRecoAlternativePrimaryClaimsForRoleScope(
    uniqCaseInsensitiveStrings([...claimHints, ...explicitClaims], 6),
    roleScope,
  );

  const explicitKnownActives = collectRecoPromptTextList(
    [
      ...(Array.isArray(row.known_actives) ? row.known_actives : []),
      ...(Array.isArray(row.keyActives) ? row.keyActives : []),
      ...(Array.isArray(row.key_actives) ? row.key_actives : []),
      ...(Array.isArray(sku.known_actives) ? sku.known_actives : []),
      ...(Array.isArray(sku.keyActives) ? sku.keyActives : []),
      ...(Array.isArray(sku.key_actives) ? sku.key_actives : []),
    ],
    { max: 8, maxLen: 48 },
  );
  const activeTokens = extractKnownActivesFromText(
    [
      name,
      productInput,
      heroIngredients.join(', '),
      keyFeatureSignals.join(', '),
      narrativeSignals.join(', '),
      primaryClaims.join(', '),
    ]
      .filter(Boolean)
      .join(' '),
    lang,
  );
  const knownActives = uniqCaseInsensitiveStrings(
    [
      ...explicitKnownActives,
      ...heroIngredients,
      ...activeTokens.map((token) => mapRoutineActiveTokenToIngredientQuery(token, lang) || token.replace(/_/g, ' ')),
    ],
    8,
  );

  const textureHints = uniqCaseInsensitiveStrings(
    [
      ...collectRecoPromptTextList(
        [
          row.texture,
          row.finish,
          ...(Array.isArray(row.texture_hints) ? row.texture_hints : []),
          sku.texture,
          sku.finish,
          ...(Array.isArray(sku.texture_hints) ? sku.texture_hints : []),
        ],
        {
          max: 5,
          maxLen: 40,
        },
      ),
      ...inferRecoAlternativesTextureHints(
        name,
        category,
        productType,
        explicitClaims.join(' '),
        keyFeatureSignals.join(' '),
        narrativeSignals.join(' '),
        productInput,
      ),
    ],
    5,
  );

  const structuralUsageRole = inferRecoAlternativesUsageRole(
    name,
    category,
    productType,
  );
  const inferredUsageRole = inferRecoAlternativesUsageRole(
    name,
    category,
    productType,
    keyFeatureSignals.join(' '),
    narrativeSignals.join(' '),
    primaryClaims.join(' '),
  );
  const usageRole = pickRecoAlternativesAuthoritativeUsageRole({
    roleScope,
    structuralUsageRole,
    inferredUsageRole,
  });
  const notes = pickFirstTrimmed(
    row.notes,
    row.anchor_notes,
    row.short_description,
    row.shortDescription,
    row.why_this_one,
    row.whyThisOne,
    row.summary,
    row.description,
    row.subtitle,
    sku.notes,
    sku.short_description,
    sku.shortDescription,
    sku.why_this_one,
    sku.whyThisOne,
    sku.summary,
    sku.description,
    sku.subtitle,
    primaryClaims.length ? primaryClaims.join('; ') : '',
  ) || null;

  return {
    brand: brand || null,
    name: name || null,
    category,
    productType,
    usageRole,
    roleScope: roleScope || null,
    heroIngredients,
    knownActives,
    explicitClaims,
    primaryClaims,
    textureHints,
    notes,
  };
}

function buildRecoAlternativesPromptPayload({
  lang,
  profileSnapshot,
  productInput,
  productObj,
  maxTotal,
  region,
  candidates = [],
  anchorId = '',
  mode = 'pool_only',
  profileMode = 'anchor_only',
} = {}) {
  const promptSpec = resolveRecoAlternativesPromptSpec(mode);
  const normalizedProfileMode = normalizeAlternativesProfileMode(profileMode);
  const fallbackSchema = {
    meta: {
      lang: 'EN',
      intent: 'alternatives_selector',
      region: 'US',
      recommendation_mode: promptSpec.mode,
      profile_mode: normalizedProfileMode,
      profile_context_present: false,
    },
    profile: {
      skinType: 'unknown',
      sensitivity: 'unknown',
      barrierStatus: 'unknown',
      goals: [],
    },
    target_product: {
      anchor_id: null,
      brand: null,
      name: null,
      query: null,
      region_variant: 'US|EU|unknown',
      category: null,
      product_type: null,
      usage_role: 'unknown',
      hero_ingredients: [],
      known_actives: [],
      primary_claims: [],
      texture_hints: [],
      notes: null,
    },
    task: {
      max_alternatives: 3,
      reco_trigger: 'explicit_user_action',
      recommendation_mode: promptSpec.mode,
      profile_mode: normalizedProfileMode,
    },
    hard_rules: promptSpec.mode === 'pool_only'
      ? [
        'Select ONLY from candidates[].',
        'Never claim exact formula equivalence when target_product.known_actives is empty or uncertain.',
      ]
      : [],
    output_item_schema: {
      kind: 'dupe|similar|premium',
      candidate_origin: promptSpec.mode === 'pool_only' ? 'catalog' : 'catalog|open_world',
      grounding_status: promptSpec.mode === 'pool_only' ? 'catalog_verified' : 'catalog_verified|name_only',
      ranking_mode: 'personalized|anchor_only',
      product: {
        brand: 'string|null',
        name: 'string|null',
        product_id: 'string|null',
        sku_id: 'string|null',
        url: 'string|null',
      },
      similarity_score: 'integer 0-100',
      reasons: ['string (max 2)'],
      profile_fit_reason: ['string (max 2)'],
      tradeoffs: {
        missing_actives: ['string'],
        added_benefits: ['string'],
        texture_finish_differences: ['string'],
        availability_note: 'string|null',
        price_delta_usd: 'number|null',
      },
      evidence: {
        kb_citations: ['string'],
      },
      missing_info: ['string'],
    },
    candidates: [],
  };
  const template = loadRecoPromptTemplateFile(promptSpec.schemaFile, {
    parseJson: true,
    fallback: fallbackSchema,
  });
  const payload = safeStructuredCloneJson(template) || safeStructuredCloneJson(fallbackSchema) || {};
  const profileObj = profileSnapshot && typeof profileSnapshot === 'object' && !Array.isArray(profileSnapshot) ? profileSnapshot : {};
  const product = productObj && typeof productObj === 'object' && !Array.isArray(productObj) ? productObj : {};
  const limit = Number.isFinite(Number(maxTotal)) ? Math.max(1, Math.min(6, Math.trunc(Number(maxTotal)))) : 3;
  const langCode = normalizeRecoPromptLanguage(lang);
  const targetSignals = buildRecoAlternativesTargetSignals(product, { productInput, lang: langCode });
  const normalizedCandidates = (Array.isArray(candidates) ? candidates : [])
    .map((row) => (row && typeof row === 'object' && !Array.isArray(row) ? row : null))
    .filter(Boolean)
    .slice(0, 20);
  payload.meta = {
    ...(payload.meta && typeof payload.meta === 'object' ? payload.meta : {}),
    lang: langCode,
    intent: 'alternatives_selector',
    region: String(region || 'US').trim() || 'US',
    recommendation_mode: promptSpec.mode,
    profile_mode: normalizedProfileMode,
    profile_context_present: profileObj.context_present === true,
  };
  payload.profile = {
    ...(payload.profile && typeof payload.profile === 'object' ? payload.profile : {}),
    skinType: pickFirstTrimmed(profileObj.skinType, 'unknown') || 'unknown',
    sensitivity: pickFirstTrimmed(profileObj.sensitivity, 'unknown') || 'unknown',
    barrierStatus: pickFirstTrimmed(profileObj.barrierStatus, 'unknown') || 'unknown',
    goals: uniqCaseInsensitiveStrings(Array.isArray(profileObj.goals) ? profileObj.goals : [], 4),
  };
  payload.target_product = {
    ...(payload.target_product && typeof payload.target_product === 'object' ? payload.target_product : {}),
    anchor_id: String(anchorId || '').trim() || null,
    brand: targetSignals.brand,
    name: targetSignals.name,
    query: String(productInput || '').trim().slice(0, 180) || null,
    region_variant: pickFirstTrimmed(product.region_variant, product.regionVariant, product.region) || 'unknown',
    category: targetSignals.category,
    product_type: targetSignals.productType,
    usage_role: targetSignals.usageRole,
    hero_ingredients: targetSignals.heroIngredients,
    known_actives: targetSignals.knownActives,
    primary_claims: targetSignals.primaryClaims,
    texture_hints: targetSignals.textureHints,
    notes: targetSignals.notes,
  };
  payload.task = {
    ...(payload.task && typeof payload.task === 'object' ? payload.task : {}),
    max_alternatives: limit,
    reco_trigger: 'explicit_user_action',
    recommendation_mode: promptSpec.mode,
    profile_mode: normalizedProfileMode,
  };
  if (promptSpec.mode === 'pool_only') {
    const rules = Array.isArray(payload.hard_rules) ? payload.hard_rules.slice(0, 16) : [];
    rules.push('Select ONLY from candidates[] and copy identifiers from the chosen candidate exactly.');
    rules.push('Do not claim exact dupe or identical formula when target_product.known_actives is empty or uncertain.');
    payload.hard_rules = uniqCaseInsensitiveStrings(rules, 16);
  } else if (Array.isArray(payload.hard_rules)) {
    payload.hard_rules = uniqCaseInsensitiveStrings(payload.hard_rules.slice(0, 16), 16);
  } else {
    payload.hard_rules = [];
  }
  payload.candidates = normalizedCandidates.map((row) => ({
    id: row.id,
    name: row.name,
    brand: row.brand || null,
    category: row.category || null,
    pdp_url: row.pdp_url || null,
    similarity_score: Number.isFinite(Number(row.similarity_score)) ? Number(row.similarity_score) : null,
    signals: Array.isArray(row.signals) ? row.signals.slice(0, 4) : [],
  }));
  return payload;
}

function buildAuroraRecoAlternativesQuery({
  lang,
  profileSnapshot,
  productInput,
  productObj,
  maxTotal,
  region,
  candidates,
  anchorId,
  mode = 'pool_only',
  profileMode = 'anchor_only',
}) {
  const promptSpec = resolveRecoAlternativesPromptSpec(mode);
  const fallbackSystemPrompt = promptSpec.mode === 'pool_only'
    ? [
      'You are a strict skincare recommendation selector.',
      'Output MUST be valid JSON only. No markdown and no extra keys.',
      'Never invent product names, brands, or URLs.',
      'Select ONLY from context.candidates and keep each reason short.',
    ].join('\n')
    : [
      'You are a strict skincare alternatives selector for a dupe-finding workflow.',
      'Output MUST be valid JSON only. No markdown and no extra keys.',
      'Use context.candidates first, but you may supplement with conservative open-world products under the hard rules.',
      'Never invent product IDs, SKUs, URLs, prices, exact INCI lists, or formula identity.',
    ].join('\n');
  const systemPrompt = loadRecoPromptTemplateFile(promptSpec.systemFile, {
    parseJson: false,
    fallback: fallbackSystemPrompt,
  });
  const payload = buildRecoAlternativesPromptPayload({
    lang,
    profileSnapshot,
    productInput,
    productObj,
    maxTotal,
    region,
    candidates,
    anchorId,
    mode: promptSpec.mode,
    profileMode,
  });
  const promptBody = formatAuroraPromptQuery({
    templateId: promptSpec.templateId,
    systemPrompt,
    userPayload: payload,
  });
  return {
    templateId: promptSpec.templateId,
    systemPrompt,
    payload,
    query: `Task: ${promptSpec.queryLine}\n${promptBody}`,
  };
}

function summarizeRecoAlternativesRaw(alternatives, { previewLimit = 3, keyLimit = 8 } = {}) {
  const rows = Array.isArray(alternatives) ? alternatives : [];
  const preview = [];
  let withProductObject = 0;
  let withNestedBrandName = 0;
  let withFlatBrandName = 0;
  let withTradeoffsObject = 0;

  for (const item of rows) {
    const row = isPlainObject(item) ? item : null;
    if (!row) continue;
    const product = isPlainObject(row.product) ? row.product : null;
    const tradeoffs = isPlainObject(row.tradeoffs) ? row.tradeoffs : null;
    const flatBrand = pickFirstTrimmed(row.brand);
    const flatName = pickFirstTrimmed(row.name, row.display_name, row.displayName, row.product_name);
    const nestedBrand = product ? pickFirstTrimmed(product.brand) : null;
    const nestedName = product
      ? pickFirstTrimmed(product.name, product.display_name, product.displayName, product.product_name)
      : null;

    if (product) withProductObject += 1;
    if (nestedBrand && nestedName) withNestedBrandName += 1;
    if (!product && flatBrand && flatName) withFlatBrandName += 1;
    if (tradeoffs) withTradeoffsObject += 1;

    if (preview.length >= previewLimit) continue;
    preview.push({
      top_level_keys: Object.keys(row).slice(0, keyLimit),
      has_product_object: Boolean(product),
      product_keys: product ? Object.keys(product).slice(0, keyLimit) : [],
      brand: nestedBrand || flatBrand || null,
      name: nestedName || flatName || null,
      similarity_score: Number.isFinite(Number(row.similarity_score))
        ? Number(row.similarity_score)
        : Number.isFinite(Number(row.similarity))
          ? Number(row.similarity)
          : null,
      candidate_origin: pickFirstTrimmed(row.candidate_origin) || null,
      grounding_status: pickFirstTrimmed(row.grounding_status) || null,
    });
  }

  return {
    raw_output_item_count: rows.length,
    raw_items_with_product_object: withProductObject,
    raw_items_with_nested_brand_name: withNestedBrandName,
    raw_items_with_flat_brand_name: withFlatBrandName,
    raw_items_with_tradeoffs_object: withTradeoffsObject,
    raw_preview: preview,
  };
}

function classifyAlternativesFailureCode(reason) {
  const token = String(reason || '').trim().toLowerCase();
  if (!token) return 'provider_error';
  if (token.includes('timeout') || token.includes('timed_out') || token.includes('aborted')) return 'timeout';
  if (token.includes('rate') || token.includes('quota')) return 'rate_limited';
  if (token.includes('network') || token.includes('econn') || token.includes('enotfound') || token.includes('eai_again')) return 'network';
  if (token.includes('5xx') || token.includes('503') || token.includes('500')) return 'upstream_5xx';
  if (token.includes('json_invalid') || token.includes('invalid_json')) return 'invalid_json';
  if (token.includes('auth') || token.includes('api_key')) return 'auth';
  return 'provider_error';
}

function mapAlternativesFailureToRootCause(code) {
  if (code === 'budget_exhausted') return 'budget_exceeded';
  if (code === 'timeout') return 'provider_timeout';
  if (code === 'rate_limited') return 'rate_limited';
  if (code === 'network') return 'network';
  return 'unknown';
}

function mapSelectorCandidatesToAlternatives(candidates, { maxTotal = 3, lang = 'EN', reasonLine = '' } = {}) {
  const rows = (Array.isArray(candidates) ? candidates : [])
    .map((row) => (row && typeof row === 'object' && !Array.isArray(row) ? row : null))
    .filter(Boolean)
    .slice(0, Math.max(1, Math.min(6, Number(maxTotal) || 3)));
  if (!rows.length) return [];
  const raw = rows.map((candidate, idx) => ({
    kind: 'similar',
    candidate_origin: 'catalog',
    grounding_status: 'catalog_verified',
    product: {
      ...(candidate.product_id ? { product_id: candidate.product_id } : {}),
      ...(candidate.sku_id ? { sku_id: candidate.sku_id } : {}),
      ...(candidate.brand ? { brand: candidate.brand } : {}),
      name: candidate.name,
      ...(candidate.category ? { category: candidate.category } : {}),
      ...(candidate.price && typeof candidate.price === 'object' ? { price: candidate.price } : {}),
      ...(candidate.pdp_url ? { pdp_url: candidate.pdp_url, url: candidate.pdp_url } : {}),
    },
    similarity_score: Number.isFinite(Number(candidate.similarity_score))
      ? Number(candidate.similarity_score)
      : Math.max(55, 82 - idx * 5),
    reasons: uniqCaseInsensitiveStrings(
      [
        reasonLine,
        ...asStringArray(candidate.signals),
      ],
      2,
    ),
    tradeoffs: Array.isArray(candidate.signals) ? candidate.signals.slice(0, 3) : [],
    evidence: {},
    missing_info: [],
  }));
  return mapAuroraAlternativesToRecoAlternatives(raw, { lang, maxTotal });
}

function getRecoAlternativeProductObject(row) {
  const item = row && typeof row === 'object' && !Array.isArray(row) ? row : {};
  return item.product && typeof item.product === 'object' && !Array.isArray(item.product) ? item.product : {};
}

function getRecoAlternativeIdentityKeys(row) {
  const item = row && typeof row === 'object' && !Array.isArray(row) ? row : {};
  const product = getRecoAlternativeProductObject(item);
  const keys = [];
  const push = (kind, raw) => {
    const token = kind === 'url' ? normalizeRecoUrlToken(raw) : normalizeRecoNameToken(raw);
    if (!token) return;
    keys.push(`${kind}:${token}`);
  };
  push('pid', pickFirstTrimmed(product.product_id, product.productId, item.product_id, item.productId));
  push('sku', pickFirstTrimmed(product.sku_id, product.skuId, item.sku_id, item.skuId));
  push(
    'url',
    pickFirstTrimmed(
      product.pdp_url,
      product.url,
      product.product_url,
      item.pdp_url,
      item.url,
      item.product_url,
      extractCandidateOpenUrl(item),
      extractCandidateOpenUrl(product),
    ),
  );
  const brand = pickFirstTrimmed(product.brand, item.brand);
  const name = pickFirstTrimmed(product.display_name, product.displayName, product.name, item.display_name, item.displayName, item.name);
  if (brand || name) push('name', `${brand || ''}::${name || ''}`);
  const coreKey = getRecoAlternativeComparableCoreKey(item);
  if (coreKey) keys.push(`core:${coreKey}`);
  return uniqCaseInsensitiveStrings(keys, 8);
}

function getRecoAlternativeComparableCoreKey(row) {
  const item = row && typeof row === 'object' && !Array.isArray(row) ? row : {};
  const product = getRecoAlternativeProductObject(item);
  const brand = normalizeRecoNameToken(pickFirstTrimmed(product.brand, item.brand));
  let name = normalizeRecoNameToken(
    pickFirstTrimmed(product.display_name, product.displayName, product.name, item.display_name, item.displayName, item.name),
  );
  name = name
    .replace(/\[[^\]]*(?:deal|subscription|subscribe|shade|refill)[^\]]*\]/g, ' ')
    .replace(/\b(?:deal|subscription|subscribe(?:\s*(?:and|&)\s*save)?)\b/g, ' ')
    .replace(/\brefill(?:\s+(?:pouch|pack|pod|cartridge|bottle))?\b/g, ' ')
    .replace(/\b(?:pouch|pack|pod|cartridge|bottle)\s+refill\b/g, ' ')
    .replace(/\breplacement\s+(?:pouch|pack|pod|cartridge|bottle)\b/g, ' ')
    .replace(/\b(?:duo|bundle|kit|set\s+of\s+\d+|value\s+set|jumbo|mini|travel\s+size)\b/g, ' ')
    .replace(/\b\d+(?:\.\d+)?\s*(?:ml|mL|g|oz|fl\.?\s*oz)\b/g, ' ')
    .replace(/\b(?:dy|ln|mp|mn|lp|dn|md|lt|deep|fair|light|medium|tan)\s*\d{2,4}\b/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
  return brand || name ? `${brand}::${name}` : '';
}

function isRecoAlternativePackagingVariant(row) {
  const item = row && typeof row === 'object' && !Array.isArray(row) ? row : {};
  const product = getRecoAlternativeProductObject(item);
  const text = [
    product.name,
    product.display_name,
    product.displayName,
    item.name,
    item.display_name,
    item.displayName,
    product.category,
    item.category,
    product.product_type,
    item.product_type,
  ]
    .map((value) => String(value || '').trim())
    .filter(Boolean)
    .join(' ');
  if (!text) return false;
  return /\b(?:deal|subscription|subscribe(?:\s*(?:and|&)\s*save)?|refill(?:\s+(?:pouch|pack|pod|cartridge|bottle))?|(?:pouch|pack|pod|cartridge|bottle)\s+refill|replacement\s+(?:pouch|pack|pod|cartridge|bottle)|duo|bundle|kit|set\s+of\s+\d+|value\s+set|jumbo|mini|travel\s+size|\d+(?:\.\d+)?\s*(?:ml|mL|g|oz|fl\.?\s*oz)|(?:dy|ln|mp|mn|lp|dn|md|lt)\s*\d{2,4})\b/i.test(text);
}

function mergeRecoAlternativeDuplicateRows(existing, incoming) {
  const left = existing && typeof existing === 'object' && !Array.isArray(existing) ? existing : {};
  const right = incoming && typeof incoming === 'object' && !Array.isArray(incoming) ? incoming : {};
  const leftProduct = getRecoAlternativeProductObject(left);
  const rightProduct = getRecoAlternativeProductObject(right);
  const leftCatalog =
    String(left.grounding_status || '').trim() === 'catalog_verified' ||
    Boolean(pickFirstTrimmed(leftProduct.product_id, leftProduct.sku_id, leftProduct.pdp_url, leftProduct.url, left.pdp_open));
  const rightCatalog =
    String(right.grounding_status || '').trim() === 'catalog_verified' ||
    Boolean(pickFirstTrimmed(rightProduct.product_id, rightProduct.sku_id, rightProduct.pdp_url, rightProduct.url, right.pdp_open));
  const leftVariant = isRecoAlternativePackagingVariant(left);
  const rightVariant = isRecoAlternativePackagingVariant(right);
  const base = rightCatalog && !leftCatalog
    ? right
    : leftCatalog && !rightCatalog
      ? left
      : leftVariant && !rightVariant
        ? right
        : rightVariant && !leftVariant
          ? left
          : left;
  const support = base === right ? left : right;
  const baseProduct = getRecoAlternativeProductObject(base);
  const supportProduct = getRecoAlternativeProductObject(support);
  const openWorldFirst = String(left.candidate_origin || '') === 'open_world' ? [left, right] : [right, left];
  const reasons = uniqCaseInsensitiveStrings(openWorldFirst.flatMap((row) => asStringArray(row?.reasons, 3)), 3);
  const tradeoffNotes = uniqCaseInsensitiveStrings(
    openWorldFirst.flatMap((row) => [
      ...asStringArray(row?.tradeoff_notes, 3),
      ...asStringArray(row?.tradeoffs, 3),
    ]),
    3,
  );
  const origins = uniqCaseInsensitiveStrings([left.candidate_origin, right.candidate_origin].filter(Boolean), 3);
  const next = {
    ...support,
    ...base,
    product: {
      ...supportProduct,
      ...baseProduct,
      brand: pickFirstTrimmed(baseProduct.brand, supportProduct.brand) || undefined,
      name: pickFirstTrimmed(baseProduct.name, supportProduct.name) || undefined,
      category: pickFirstTrimmed(baseProduct.category, supportProduct.category) || undefined,
    },
    candidate_origin: rightCatalog || leftCatalog ? 'pool' : pickFirstTrimmed(base.candidate_origin, support.candidate_origin),
    grounding_status: rightCatalog || leftCatalog ? 'catalog_verified' : pickFirstTrimmed(base.grounding_status, support.grounding_status),
    ...(reasons.length ? { reasons } : {}),
    ...(tradeoffNotes.length ? { tradeoff_notes: tradeoffNotes } : {}),
    similarity_score: Math.max(Number(left.similarity_score) || 0, Number(right.similarity_score) || 0) || undefined,
    pdp_open: base.pdp_open || support.pdp_open,
    metadata: {
      ...(support.metadata && typeof support.metadata === 'object' && !Array.isArray(support.metadata) ? support.metadata : {}),
      ...(base.metadata && typeof base.metadata === 'object' && !Array.isArray(base.metadata) ? base.metadata : {}),
      ...(origins.length > 1 ? { merged_candidate_origins: origins } : {}),
    },
    _mixed_score: Math.max(Number(left._mixed_score) || 0, Number(right._mixed_score) || 0) || undefined,
  };
  return next;
}

function isRecoAlternativeWeakPoolOnly(row) {
  const item = row && typeof row === 'object' && !Array.isArray(row) ? row : {};
  const origin = String(item.candidate_origin || '').trim().toLowerCase();
  if (origin !== 'pool' && origin !== 'catalog') return false;
  const metadata = item.metadata && typeof item.metadata === 'object' && !Array.isArray(item.metadata) ? item.metadata : {};
  const mergedOrigins = Array.isArray(metadata.merged_candidate_origins) ? metadata.merged_candidate_origins : [];
  if (mergedOrigins.some((value) => String(value || '').trim().toLowerCase() === 'open_world')) return false;
  const reasonsText = [
    ...asStringArray(item.reasons, 5),
    ...asStringArray(item.tradeoff_notes, 5),
    ...asStringArray(item.tradeoffs, 5),
  ]
    .join(' ')
    .toLowerCase();
  if (!reasonsText) return false;
  const hasAnchorSpecificSignal =
    /\b(?:ingredient|active|claim|texture|overlap|matches key|niacinamide|zinc|hyaluronic|ceramide|spf|uv|oil control|sebum|pore|hydration|barrier|lightweight|gel|dewy|matte)\b/i.test(
      reasonsText,
    );
  if (hasAnchorSpecificSignal) return false;
  const rawScore = Number.isFinite(Number(item._mixed_score))
    ? Number(item._mixed_score)
    : Number.isFinite(Number(item.similarity_score))
      ? Number(item.similarity_score) / 100
      : 0;
  return rawScore > 0 && rawScore < 0.68;
}

function getRecoAlternativeBrandToken(row) {
  const item = row && typeof row === 'object' && !Array.isArray(row) ? row : {};
  const product = getRecoAlternativeProductObject(item);
  return normalizeRecoNameToken(pickFirstTrimmed(product.brand, item.brand));
}

function diversifyRecoAlternativesByBrand(rows, { maxTotal = 3 } = {}) {
  const limit = Math.max(1, Math.min(8, Number.isFinite(Number(maxTotal)) ? Math.trunc(Number(maxTotal)) : 3));
  const list = (Array.isArray(rows) ? rows : []).filter((row) => row && typeof row === 'object' && !Array.isArray(row));
  const brandSet = new Set(list.map((row) => getRecoAlternativeBrandToken(row)).filter(Boolean));
  if (brandSet.size <= 1 || limit <= 1) return list.slice(0, limit);

  const maxPerBrand = limit <= 2 ? 1 : Math.max(1, limit - 1);
  const out = [];
  const deferred = [];
  const brandCounts = new Map();
  for (const row of list) {
    const brand = getRecoAlternativeBrandToken(row);
    const count = brand ? brandCounts.get(brand) || 0 : 0;
    if (brand && count >= maxPerBrand) {
      deferred.push(row);
      continue;
    }
    out.push(row);
    if (brand) brandCounts.set(brand, count + 1);
  }
  return [...out, ...deferred].slice(0, limit);
}

function finalizeRecoAlternativesForCompetitiveQuality(rows, { maxTotal = 3 } = {}) {
  const limit = Math.max(1, Math.min(8, Number.isFinite(Number(maxTotal)) ? Math.trunc(Number(maxTotal)) : 3));
  const list = (Array.isArray(rows) ? rows : []).filter((row) => row && typeof row === 'object' && !Array.isArray(row));
  const nonVariantCoreKeys = new Set();
  let nonVariantCount = 0;
  let strongNonVariantCount = 0;
  for (const row of list) {
    if (isRecoAlternativePackagingVariant(row)) continue;
    nonVariantCount += 1;
    if (!isRecoAlternativeWeakPoolOnly(row)) strongNonVariantCount += 1;
    const coreKey = getRecoAlternativeComparableCoreKey(row);
    if (coreKey) nonVariantCoreKeys.add(coreKey);
  }
  const out = [];
  const sufficientNonVariantCount = nonVariantCount >= Math.min(3, limit);
  const sufficientStrongNonVariantCount = strongNonVariantCount >= Math.min(3, limit);
  for (const row of list) {
    if (isRecoAlternativePackagingVariant(row)) {
      const coreKey = getRecoAlternativeComparableCoreKey(row);
      if ((coreKey && nonVariantCoreKeys.has(coreKey)) || sufficientNonVariantCount) continue;
    }
    if (sufficientStrongNonVariantCount && isRecoAlternativeWeakPoolOnly(row)) continue;
    out.push(row);
  }
  return diversifyRecoAlternativesByBrand(out, { maxTotal: limit });
}

function classifyRecoAlternativeSunscreenTradeoffBucket(row) {
  const text = buildRecoAlternativePoolCandidateText(row).toLowerCase();
  if (!text) return '';
  if (/\b(mineral|zinc oxide|titanium dioxide)\b/.test(text)) return 'mineral';
  if (/\b(milk|creamier|cream-based|moisturizing|hydrating|colloidal oatmeal|cushier)\b/.test(text)) return 'hydrating';
  if (/\b(matte|shine[-\s]?control|oil[-\s]?control|less slip)\b/.test(text)) return 'matte';
  if (/\b(serum|watery|water[-\s]?fit|fresh|thinner sunscreen feel|ultra-lightweight fluid)\b/.test(text)) return 'serum';
  if (/\b(dewy|dewier)\b/.test(text)) return 'dewy';
  if (/\b(light|lighter|smooth|smoother|weightless)\b/.test(text)) return 'lightweight';
  return '';
}

function hasRecoAlternativeSunscreenTradeoffCoverage(rows, { targetSignals = null, maxTotal = 3 } = {}) {
  if (!isExternalSeedFinishFitSunscreenTarget(targetSignals)) return false;
  const limit = Math.max(1, Math.min(8, Number.isFinite(Number(maxTotal)) ? Math.trunc(Number(maxTotal)) : 3));
  const list = (Array.isArray(rows) ? rows : []).filter((row) => row && typeof row === 'object' && !Array.isArray(row));
  if (list.length < Math.min(3, limit)) return false;
  const buckets = new Set(
    list
      .slice(0, Math.max(3, limit))
      .map((row) => classifyRecoAlternativeSunscreenTradeoffBucket(row))
      .filter(Boolean),
  );
  return buckets.size >= 3 || (buckets.has('mineral') && buckets.has('hydrating'));
}

function mergeRecoAlternativesForHybrid(primary, fallback, { maxTotal = 3, preferBestScore = false } = {}) {
  const limit = Math.max(1, Math.min(8, Number.isFinite(Number(maxTotal)) ? Math.trunc(Number(maxTotal)) : 3));
  const ordered = [
    ...(Array.isArray(primary) ? primary : []),
    ...(Array.isArray(fallback) ? fallback : []),
  ].filter((row) => row && typeof row === 'object' && !Array.isArray(row));
  if (preferBestScore) {
    ordered.sort((left, right) => {
      const scoreDiff = Number(right?._mixed_score || 0) - Number(left?._mixed_score || 0);
      if (scoreDiff !== 0) return scoreDiff;
      if (String(left?.candidate_origin || '') !== String(right?.candidate_origin || '')) {
        return String(left?.candidate_origin || '') === 'pool' ? -1 : 1;
      }
      return String(left?.product?.name || '').localeCompare(String(right?.product?.name || ''));
    });
  }
  const out = [];
  const keyToIndex = new Map();
  for (const row of ordered) {
    const keys = getRecoAlternativeIdentityKeys(row);
    if (!keys.length) continue;
    const duplicateIndex = keys.map((key) => keyToIndex.get(key)).find((idx) => Number.isInteger(idx));
    if (Number.isInteger(duplicateIndex)) {
      out[duplicateIndex] = mergeRecoAlternativeDuplicateRows(out[duplicateIndex], row);
      for (const key of getRecoAlternativeIdentityKeys(out[duplicateIndex])) keyToIndex.set(key, duplicateIndex);
      continue;
    }
    const nextIndex = out.length;
    out.push(row);
    for (const key of keys) keyToIndex.set(key, nextIndex);
  }
  return finalizeRecoAlternativesForCompetitiveQuality(out, { maxTotal: limit });
}

function computeRecoAlternativeExperienceQualityBonus(row) {
  const item = isPlainObject(row) ? row : {};
  let bonus = 0;
  if (pickRecoProductIntelBundle(item) || pickRecoPivotaInsights(item)) bonus += 0.012;
  const compareHighlightCount = asStringArray(item.compare_highlights, 4).length;
  if (compareHighlightCount >= 2) bonus += 0.004;
  else if (compareHighlightCount === 1) bonus += 0.002;
  if (pickRecoShoppingCardPayload(item) || pickRecoSearchCardPayload(item)) bonus += 0.004;
  return Math.min(0.02, bonus);
}

function maybeAnnotateRecoAlternativeExperienceQuality(row) {
  const item = isPlainObject(row) ? row : null;
  if (!item) return row;
  const bonus = computeRecoAlternativeExperienceQualityBonus(item);
  if (!(bonus > 0)) return item;
  const metadata = isPlainObject(item.metadata) ? item.metadata : {};
  return {
    ...item,
    metadata: {
      ...metadata,
      evidence_quality_bonus: Number(bonus.toFixed(3)),
      ranking_signals_used: uniqCaseInsensitiveStrings([
        ...asStringArray(metadata.ranking_signals_used, 6),
        pickFirstTrimmed(metadata.ranking_signal),
        'reviewed_experience_evidence_bonus',
      ], 6),
    },
  };
}

function getRecoAlternativeMixedRankingScore(row, { useExperienceQualityBonus = false } = {}) {
  const baseScore = Number.isFinite(Number(row?._mixed_score))
    ? Number(row._mixed_score)
    : normalizeMaybePercentScore(row?.similarity_score);
  const safeBase = Number.isFinite(baseScore) ? clamp01Score(baseScore) : 0;
  const bonus = useExperienceQualityBonus ? computeRecoAlternativeExperienceQualityBonus(row) : 0;
  const grounding = String(row?.grounding_status || '').trim().toLowerCase();
  const authorityAdjustment = grounding === 'catalog_verified'
    ? 0.08
    : grounding === 'name_only'
      ? -0.16
      : 0;
  return clamp01Score(safeBase + bonus + authorityAdjustment);
}

function sortRecoAlternativesByMixedScore(rows, { useExperienceQualityBonus = false } = {}) {
  return (Array.isArray(rows) ? rows : [])
    .filter((row) => row && typeof row === 'object' && !Array.isArray(row))
    .map((row) => (useExperienceQualityBonus ? maybeAnnotateRecoAlternativeExperienceQuality(row) : row))
    .slice()
    .sort((left, right) => {
      const scoreDiff = getRecoAlternativeMixedRankingScore(right, { useExperienceQualityBonus }) -
        getRecoAlternativeMixedRankingScore(left, { useExperienceQualityBonus });
      if (scoreDiff !== 0) return scoreDiff;
      if (String(left?.candidate_origin || '') !== String(right?.candidate_origin || '')) {
        return String(left?.candidate_origin || '') === 'pool' ? -1 : 1;
      }
      return String(left?.product?.name || left?.name || '').localeCompare(String(right?.product?.name || right?.name || ''));
    });
}

function isExternalRecoAlternativesSeedProduct(product) {
  const row = isPlainObject(product) ? product : {};
  const metadata = isPlainObject(row.metadata) ? row.metadata : {};
  const pdpOpen = isPlainObject(row.pdp_open) ? row.pdp_open : isPlainObject(row.pdpOpen) ? row.pdpOpen : {};
  const sku = isPlainObject(row.sku) ? row.sku : {};
  const canonicalRef = isPlainObject(row.canonical_product_ref)
    ? row.canonical_product_ref
    : isPlainObject(row.canonicalProductRef)
      ? row.canonicalProductRef
      : {};
  const matchState = String(metadata.match_state || metadata.matchState || '').trim().toLowerCase();
  const pdpPath = String(pdpOpen.path || '').trim().toLowerCase();
  const merchantId = pickFirstTrimmed(
    row.merchant_id,
    row.merchantId,
    sku.merchant_id,
    sku.merchantId,
    canonicalRef.merchant_id,
    canonicalRef.merchantId,
  );
  const productId = pickFirstTrimmed(row.product_id, row.productId, sku.product_id, sku.productId, canonicalRef.product_id, canonicalRef.productId);
  const source = String(pickFirstTrimmed(row.retrieval_source, row.source, sku.retrieval_source, sku.source) || '').trim().toLowerCase();
  return (
    matchState === 'llm_seed' ||
    pdpPath === 'external' ||
    merchantId === EXTERNAL_SEED_MERCHANT_ID ||
    source === 'external_seed' ||
    String(productId || '').trim().toLowerCase().startsWith('ext_')
  );
}

function buildExternalSeedCompareIdentity(productObj, productInput) {
  const row = isPlainObject(productObj) ? productObj : {};
  const metadata = isPlainObject(row.metadata) ? row.metadata : {};
  const llmSuggestion = isPlainObject(row.llm_suggestion)
    ? row.llm_suggestion
    : isPlainObject(metadata.llm_suggestion)
      ? metadata.llm_suggestion
      : {};
  const aliases = uniqCaseInsensitiveStrings(
    [
      ...asStringArray(row.search_aliases, 8),
      ...asStringArray(row.searchAliases, 8),
      ...asStringArray(llmSuggestion.search_aliases, 8),
      ...asStringArray(llmSuggestion.searchAliases, 8),
      pickFirstTrimmed(row.resolve_query, row.resolveQuery),
      String(productInput || '').trim(),
      buildProductInputText(row, null),
    ],
    8,
  );
  const langCode = normalizeRecoPromptLanguage(metadata.lang || row.lang || 'EN');
  const targetSignals = buildRecoAlternativesTargetSignals(row, {
    productInput: String(productInput || '').trim(),
    lang: langCode,
  });
  const anchorLabel = joinBrandAndName(targetSignals.brand, targetSignals.name || String(productInput || '').trim());
  const anchorNameTokens = tokenizeProductTextForSimilarity(anchorLabel);
  const ingredientTokens = uniqCaseInsensitiveStrings(
    [
      ...targetSignals.heroIngredients,
      ...targetSignals.knownActives,
    ],
    8,
  );
  const claimTokens = uniqCaseInsensitiveStrings(targetSignals.primaryClaims, 6);
  const textureTokens = uniqCaseInsensitiveStrings(targetSignals.textureHints, 5);
  return {
    aliases,
    targetSignals,
    anchorLabel,
    anchorNameTokens,
    ingredientTokens,
    claimTokens,
    textureTokens,
  };
}

function isExternalSeedFinishFitSunscreenTarget(targetSignals = null) {
  const target = isPlainObject(targetSignals) ? targetSignals : {};
  const roleScope = String(target.roleScope || '').trim().toLowerCase();
  const usageRole = String(target.usageRole || '').trim().toLowerCase();
  if (usageRole !== 'sunscreen') return false;
  if (roleScope === 'daily_sunscreen_finish_fit') return true;
  const signalText = [
    target.name,
    target.category,
    target.productType,
    target.notes,
    ...(Array.isArray(target.primaryClaims) ? target.primaryClaims : []),
    ...(Array.isArray(target.textureHints) ? target.textureHints : []),
  ]
    .map((value) => String(value || '').trim())
    .filter(Boolean)
    .join(' ')
    .toLowerCase();
  return /\b(makeup|under makeup|pilling|layering|fluid|lightweight|invisible|serum|water[-\s]?fit|matte|dewy|oil[-\s]?free|non[-\s]?greasy)\b/.test(
    signalText,
  );
}

function buildExternalSeedFinishFitSunscreenQueries(targetSignals = null) {
  const target = isPlainObject(targetSignals) ? targetSignals : {};
  if (!isExternalSeedFinishFitSunscreenTarget(target)) return [];
  const signalText = [
    target.name,
    target.category,
    target.productType,
    target.notes,
    ...(Array.isArray(target.primaryClaims) ? target.primaryClaims : []),
    ...(Array.isArray(target.textureHints) ? target.textureHints : []),
    ...(Array.isArray(target.heroIngredients) ? target.heroIngredients : []),
    ...(Array.isArray(target.knownActives) ? target.knownActives : []),
  ]
    .map((value) => String(value || '').trim())
    .filter(Boolean)
    .join(' ')
    .toLowerCase();
  const fluidSignal = /\b(fluid|invisible|water[-\s]?fit|serum sunscreen|watery|ultra[-\s]?light|light serum|sun serum|aqua)\b/.test(signalText);
  const oilySignal = /\b(oily|oil[-\s]?control|shine|matte|non[-\s]?greasy|oil[-\s]?free|sebum)\b/.test(signalText);
  return uniqCaseInsensitiveStrings(
    [
      oilySignal ? 'spf fluid oily skin' : 'spf fluid',
      'mineral sunscreen',
      oilySignal ? 'lightweight sunscreen oily skin' : 'sunscreen milk',
      'sunscreen under makeup',
    ],
    4,
  );
}

function buildExternalSeedCompareSearchQueries({ productObj, productInput = '', lang = 'EN' } = {}) {
  const identity = buildExternalSeedCompareIdentity(productObj, productInput);
  const target = identity.targetSignals;
  const out = [];
  const seen = new Set();
  const usageRole = inferRecoAlternativesSearchUsageRole(target);
  const finishFitSunscreenQueries = buildExternalSeedFinishFitSunscreenQueries(target);
  const isFinishFitSunscreen = finishFitSunscreenQueries.length > 0;
  const stepTerms = uniqCaseInsensitiveStrings(
    [
      target.productType,
      usageRole,
    ].filter((value) => {
      const token = String(value || '').trim().toLowerCase();
      return token && token !== 'unknown';
    }),
    2,
  ).join(' ');
  const pushQuery = (raw) => {
    const query = String(raw || '').trim().replace(/\s+/g, ' ');
    if (!query) return;
    const key = query.toLowerCase();
    if (seen.has(key)) return;
    seen.add(key);
    out.push(query.slice(0, 180));
  };

  const aliasQueries = identity.aliases.filter(
    (alias) => String(alias || '').trim().toLowerCase() !== String(identity.anchorLabel || '').trim().toLowerCase(),
  );
  if (isFinishFitSunscreen) {
    for (const query of finishFitSunscreenQueries) pushQuery(query);
  } else {
    pushQuery(identity.anchorLabel);
    for (const alias of aliasQueries.slice(0, 1)) pushQuery(alias);
  }

  if (usageRole && !isFinishFitSunscreen) {
    pushQuery(usageRole);
  }
  if (usageRole && usageRole !== 'sunscreen' && target.knownActives.length) {
    pushQuery(`${target.knownActives[0]} ${usageRole}`);
  } else if (target.knownActives.length) {
    pushQuery(target.knownActives[0]);
  }
  if (usageRole && usageRole !== 'unknown' && target.primaryClaims.length && target.textureHints.length) {
    pushQuery(`${target.textureHints[0]} ${target.primaryClaims[0]} ${usageRole}`);
  }
  if (usageRole && usageRole !== 'unknown' && target.primaryClaims.length) {
    pushQuery(`${target.primaryClaims[0]} ${usageRole}`);
  }
  if (usageRole && usageRole !== 'unknown' && target.textureHints.length) {
    pushQuery(`${target.textureHints[0]} ${usageRole}`);
  }
  if (stepTerms && !isFinishFitSunscreen) {
    pushQuery(stepTerms);
  }
  if (stepTerms && target.primaryClaims.length && !isFinishFitSunscreen) {
    pushQuery(`${stepTerms} ${target.primaryClaims[0]}`);
  }
  if (stepTerms && target.textureHints.length && !isFinishFitSunscreen) {
    pushQuery(`${stepTerms} ${target.textureHints[0]}`);
  }
  if (usageRole && usageRole !== 'unknown' && usageRole !== 'sunscreen' && target.knownActives.length) {
    pushQuery(`${target.knownActives[0]} ${usageRole}`);
  }
  if (!isFinishFitSunscreen) {
    for (const alias of aliasQueries.slice(1)) pushQuery(alias);
  }

  if (target.brand && target.name && usageRole && usageRole !== 'unknown' && !isFinishFitSunscreen) {
    pushQuery(`${target.brand} ${target.name} ${usageRole}`);
  }
  if (
    target.productType &&
    usageRole &&
    usageRole !== 'unknown' &&
    String(target.productType).trim().toLowerCase() !== usageRole.toLowerCase() &&
    !isFinishFitSunscreen
  ) {
    pushQuery(`${target.productType} ${usageRole}`);
  }
  if (target.productType && String(productInput || '').trim() && !isFinishFitSunscreen) {
    pushQuery(`${target.productType} ${String(productInput || '').trim()}`);
  }

  if (!out.length) {
    pushQuery(String(productInput || '').trim());
  }
  return out.slice(0, isFinishFitSunscreen ? 4 : 6);
}

function isExternalSeedPlaceholderCandidate(candidate) {
  const row = isPlainObject(candidate) ? candidate : {};
  const product = isPlainObject(row.product) ? row.product : {};
  const joined = [
    row.brand,
    row.name,
    row.display_name,
    product.brand,
    product.name,
    product.display_name,
  ]
    .map((value) => String(value || '').trim())
    .filter(Boolean)
    .join(' ');
  if (!joined) return true;
  return /\b(budget dupe|similar option|premium option|placeholder|candidate)\b/i.test(joined);
}

function computeExternalSeedSignalOverlap(tokens, sourceText) {
  const expected = (Array.isArray(tokens) ? tokens : [])
    .map((token) => String(token || '').trim().toLowerCase())
    .filter(Boolean);
  if (!expected.length) return 0;
  const haystack = String(sourceText || '').trim().toLowerCase();
  if (!haystack) return 0;
  let hits = 0;
  for (const token of expected) {
    if (haystack.includes(token)) hits += 1;
  }
  return clamp01Score(hits / Math.max(1, expected.length));
}

function computeRecoAlternativeTitleActiveMatchScore(tokens, candidateLabel) {
  const haystack = String(candidateLabel || '').trim().toLowerCase();
  if (!haystack) return 0;
  const expected = collectRecoAlternativeMeaningfulTokens(tokens)
    .filter((token) => !RECO_ALTERNATIVE_GROUNDING_GENERIC_TOKEN_SET.has(token));
  if (!expected.length) return 0;
  let hits = 0;
  for (const token of expected) {
    if (haystack.includes(token)) hits += 1;
  }
  return clamp01Score(hits / Math.max(1, expected.length));
}

function inferRecoAlternativeFormFactor(...values) {
  const text = values
    .flatMap((value) => Array.isArray(value) ? value : [value])
    .map((value) => String(value || '').trim().toLowerCase())
    .filter(Boolean)
    .join(' ');
  if (!text) return '';
  if (/\bbody\b/.test(text)) return 'body';
  if (/\bstick\b/.test(text)) return 'stick';
  if (/\b(?:spray|mist)\b/.test(text)) return 'spray';
  if (/\bfluid\b/.test(text)) return 'fluid';
  if (/\bmask\b/.test(text)) return 'mask';
  if (/\btinted\s+moisturi[sz]er\b/.test(text)) return 'tinted_moisturizer';
  if (/\bserum\b/.test(text)) return 'serum';
  if (/\b(?:gel cream|gel-cream|water cream|water-gel|gel)\b/.test(text)) return 'gel';
  if (/\blotion\b/.test(text)) return 'lotion';
  if (/\bcream\b/.test(text)) return 'cream';
  return '';
}

function isRecoAlternativeEyeAreaMismatch(candidateText, targetSignals = null) {
  const candidate = String(candidateText || '').trim();
  if (!/\beye(?:\s+(?:serum|cream|gel|treatment|mask|balm))?\b/i.test(candidate)) return false;
  const targetText = [
    targetSignals?.roleScope,
    targetSignals?.usageRole,
    targetSignals?.name,
    targetSignals?.productType,
    targetSignals?.category,
    targetSignals?.notes,
    ...(Array.isArray(targetSignals?.primaryClaims) ? targetSignals.primaryClaims : []),
  ]
    .map((value) => String(value || '').trim())
    .filter(Boolean)
    .join(' ');
  return !/\beye(?:\s+(?:serum|cream|gel|treatment|mask|balm))?\b/i.test(targetText);
}

function isRecoAlternativeFormFactorCompatible(candidate, { targetSignals = null } = {}) {
  const row = isPlainObject(candidate) ? candidate : {};
  const joined = [
    row.brand,
    row.name,
    row.display_name,
    row.category,
    row.product_type,
    row.short_description,
    row.description,
    ...(Array.isArray(row.texture_hints) ? row.texture_hints : []),
    ...(Array.isArray(row.key_features) ? row.key_features : []),
  ]
    .map((value) => String(value || '').trim())
    .filter(Boolean)
    .join(' ');
  if (!joined) return true;
  if (FACIAL_FRAMEWORK_SCOPE_BLOCK_RE.test(joined)) return false;
  if (isRecoAlternativeEyeAreaMismatch(joined, targetSignals)) return false;
  const candidateForm = inferRecoAlternativeFormFactor(joined);
  if (!candidateForm) return true;
  const targetForm = inferRecoAlternativeFormFactor(
    targetSignals?.name,
    targetSignals?.productType,
    targetSignals?.category,
    targetSignals?.notes,
    Array.isArray(targetSignals?.textureHints) ? targetSignals.textureHints : [],
  );
  if (candidateForm === 'tinted_moisturizer') {
    const targetText = [
      targetSignals?.roleScope,
      targetSignals?.name,
      targetSignals?.productType,
      targetSignals?.category,
      targetSignals?.notes,
      ...(Array.isArray(targetSignals?.textureHints) ? targetSignals.textureHints : []),
      ...(Array.isArray(targetSignals?.primaryClaims) ? targetSignals.primaryClaims : []),
    ]
      .map((value) => String(value || '').trim())
      .filter(Boolean)
      .join(' ');
    return /\b(tinted|coverage|makeup|base|primer)\b/i.test(targetText);
  }
  if (!targetForm) return candidateForm !== 'body';
  if (candidateForm === targetForm) return true;
  if (candidateForm === 'body') return false;
  if (candidateForm === 'mask') return false;
  if (['serum', 'fluid', 'gel', 'lotion', 'cream'].includes(targetForm) && ['stick', 'spray'].includes(candidateForm)) {
    return false;
  }
  return true;
}

const RECO_ALTERNATIVE_COSMETIC_FINISH_SIGNAL_RE = /\b(glow(?:screen)?|radiance|radiant|illuminat\w*|lumin(?:ous|izer)?|tinted|shimmer|pearlescent|soft[-\s]?radiance|bronz\w*|highlight\w*)\b/i;
const RECO_ALTERNATIVE_FINISH_DROPS_SIGNAL_RE = /\bdrops?\b/i;
const RECO_ALTERNATIVE_STRONG_TONE_INTENT_RE =
  /\b(dark\s*spots?|hyperpigmentation|uneven\s+tone|tone[-\s]?correct\w*|brighten(?:ing)?|radiance|radiant|glow(?:ing)?|txa|tranexamic|alpha[-\s]?arbutin|vitamin\s*c)\b/i;
const RECO_ALTERNATIVE_STRONG_AGING_INTENT_RE = /\b(wrinkles?|fine[-\s]?lines?|anti[-\s]?aging|retinol|retinoid|firm(?:ing)?)\b/i;
const RECO_ALTERNATIVE_STRONG_SENSITIVITY_INTENT_RE = /\b(redness|sensitive|sensitized|sooth(?:e|ing)?|calm(?:ing)?|irritat(?:e|ion)|stinging?|red[-\s]?prone)\b/i;
const RECO_ALTERNATIVE_STRONG_ACNE_INTENT_RE = /\b(acne|breakouts?|blemish(?:es)?|clog(?:ged)?|pores?|breakout[-\s]?prone)\b/i;
const RECO_ALTERNATIVE_STRONG_BARRIER_BRIDGE_RE =
  /\b(barrier|ceramides?|repair|cica|centella|panthenol|tamanu|lipids?|cholesterol|fatty\s+acids?|oat(?:meal)?|colloidal\s+oatmeal|beta[-\s]?glucan|ectoin|allantoin)\b/i;
const RECO_ALTERNATIVE_HYDRATION_SUPPORT_RE =
  /\b(hydrat\w*|moist\w*|glycerin|hyaluronic|squalane|beta[-\s]?glucan|oat(?:meal)?|colloidal\s+oatmeal|panthenol|ceramides?)\b/i;
const RECO_ALTERNATIVE_BARRIER_COMFORT_SIGNAL_RE =
  /\b(colloidal\s+oatmeal|oat(?:meal)?|sooth(?:e|ing)?|calm(?:ing)?|allantoin|centella|cica|redness|sensitive|reactive|irritat(?:e|ion)|stinging?)\b/i;

function buildRecoAlternativePoolCandidateText(normalized) {
  const row = isPlainObject(normalized) ? normalized : {};
  const shoppingCard = isPlainObject(row.shopping_card) ? row.shopping_card : {};
  const searchCard = isPlainObject(row.search_card) ? row.search_card : {};
  const pivotaInsights = isPlainObject(row.pivota_insights) ? row.pivota_insights : {};
  const productIntel = isPlainObject(row.product_intel) ? row.product_intel : {};
  return [
    joinBrandAndName(row.brand, pickFirstTrimmed(row.display_name, row.name)),
    row.category,
    row.product_type,
    ...(Array.isArray(row.ingredient_tokens) ? row.ingredient_tokens : []),
    ...(Array.isArray(row.skin_type_tags) ? row.skin_type_tags : []),
    ...(Array.isArray(row.search_aliases) ? row.search_aliases.slice(0, 4) : []),
    ...(Array.isArray(row.benefit_tokens) ? row.benefit_tokens.slice(0, 6) : []),
    ...(Array.isArray(row.description_tokens) ? row.description_tokens.slice(0, 4) : []),
    ...(Array.isArray(row.tag_tokens) ? row.tag_tokens.slice(0, 6) : []),
    row.short_description,
    row.description,
    row.best_for,
    row.why_this_one,
    ...(Array.isArray(row.key_features) ? row.key_features.slice(0, 6) : []),
    ...(Array.isArray(row.compare_highlights) ? row.compare_highlights.slice(0, 4) : []),
    pickFirstTrimmed(
      shoppingCard.intro,
      searchCard.intro,
      pivotaInsights.what_it_is,
      pivotaInsights.one_liner,
      productIntel.what_it_is,
      productIntel.one_liner,
    ),
  ]
    .map((value) => String(value || '').trim())
    .filter(Boolean)
    .join(' ');
}

function computeRecoAlternativeCosmeticFinishPenalty(targetSignals, candidateText, candidateLabel) {
  if (String(targetSignals?.usageRole || '').trim().toLowerCase() !== 'sunscreen') return 0;
  const targetText = [
    targetSignals?.name,
    targetSignals?.notes,
    ...(Array.isArray(targetSignals?.primaryClaims) ? targetSignals.primaryClaims : []),
    ...(Array.isArray(targetSignals?.textureHints) ? targetSignals.textureHints : []),
  ]
    .map((value) => String(value || '').trim())
    .filter(Boolean)
    .join(' ');
  if (RECO_ALTERNATIVE_COSMETIC_FINISH_SIGNAL_RE.test(targetText)) return 0;
  const candidateHaystack = [candidateLabel, candidateText]
    .map((value) => String(value || '').trim())
    .filter(Boolean)
    .join(' ');
  if (!RECO_ALTERNATIVE_COSMETIC_FINISH_SIGNAL_RE.test(candidateHaystack)) return 0;
  let penalty = 0.06;
  if (RECO_ALTERNATIVE_FINISH_DROPS_SIGNAL_RE.test(candidateHaystack)) penalty += 0.02;
  return Math.min(0.12, penalty);
}

function buildRecoAlternativeAnchorConcernText(targetSignals) {
  return [
    targetSignals?.roleScope,
    targetSignals?.usageRole,
    targetSignals?.productType,
    targetSignals?.category,
    targetSignals?.name,
    ...(Array.isArray(targetSignals?.explicitClaims) ? targetSignals.explicitClaims : []),
    ...(Array.isArray(targetSignals?.heroIngredients) ? targetSignals.heroIngredients : []),
    ...(Array.isArray(targetSignals?.knownActives) ? targetSignals.knownActives : []),
  ]
    .map((value) => String(value || '').trim())
    .filter(Boolean)
    .join(' ');
}

function computeRecoAlternativeConcernIntentPenalty(targetSignals, candidateText, candidateLabel) {
  const targetText = buildRecoAlternativeAnchorConcernText(targetSignals);
  const targetFamilies = collectRecoAssistantConcernFamilies(targetText);
  if (!targetFamilies.size) return 0;
  const targetRole = String(targetSignals?.usageRole || '').trim().toLowerCase();
  if (targetRole === 'sunscreen') return 0;
  const candidateHaystack = [candidateLabel, candidateText]
    .map((value) => String(value || '').trim())
    .filter(Boolean)
    .join(' ');
  if (!candidateHaystack) return 0;
  const candidateFamilies = collectRecoAssistantConcernFamilies(candidateHaystack);
  if (!candidateFamilies.size) return 0;
  const hasAllowedFamily = Array.from(candidateFamilies).some((family) => targetFamilies.has(family));
  let penalty = 0;

  if (
    targetRole === 'moisturizer' &&
    !targetFamilies.has('tone_brightening') &&
    RECO_ALTERNATIVE_STRONG_TONE_INTENT_RE.test(String(candidateLabel || ''))
  ) {
    penalty = Math.max(penalty, 0.3);
  }
  if (!targetFamilies.has('tone_brightening')) {
    if (RECO_ALTERNATIVE_STRONG_TONE_INTENT_RE.test(String(candidateLabel || ''))) {
      penalty = Math.max(penalty, hasAllowedFamily ? 0.18 : 0.28);
    } else if (RECO_ALTERNATIVE_STRONG_TONE_INTENT_RE.test(candidateHaystack)) {
      penalty = Math.max(penalty, hasAllowedFamily ? 0.12 : 0.22);
    }
  }
  if (!targetFamilies.has('aging_texture') && RECO_ALTERNATIVE_STRONG_AGING_INTENT_RE.test(candidateHaystack)) {
    penalty = Math.max(penalty, hasAllowedFamily ? 0.12 : 0.22);
  }
  if (!targetFamilies.has('sensitivity_redness') && RECO_ALTERNATIVE_STRONG_SENSITIVITY_INTENT_RE.test(candidateHaystack)) {
    const barrierMoisturizerContext = targetRole === 'moisturizer' && targetFamilies.has('hydration_barrier');
    if (barrierMoisturizerContext && candidateFamilies.has('hydration_barrier')) {
      penalty = Math.max(penalty, hasAllowedFamily ? 0 : 0.04);
    } else {
      penalty = Math.max(penalty, hasAllowedFamily ? 0.06 : 0.14);
    }
  }
  if (!targetFamilies.has('acne_pore') && RECO_ALTERNATIVE_STRONG_ACNE_INTENT_RE.test(candidateHaystack)) {
    penalty = Math.max(penalty, hasAllowedFamily ? 0.06 : 0.14);
  }
  if (!(penalty > 0) && !hasAllowedFamily) {
    penalty = 0.08;
  }
  return Math.min(0.3, penalty);
}

function computeRecoAlternativeSameRoleLabelMatchScore(targetRole, candidateLabel) {
  const role = String(targetRole || '').trim().toLowerCase();
  const label = String(candidateLabel || '').trim();
  if (!role || role === 'unknown' || !label) return 0;
  if (role === 'sunscreen') return /\b(?:sunscreen|spf|sun\s*(?:screen|cream|fluid|serum)?|uv)\b/i.test(label) ? 1 : 0;
  if (role === 'moisturizer') {
    return /\b(?:moisturi[sz]er|cream|lotion|gel[-\s]?cream|water[-\s]?(?:cream|gel)|emulsion|face lotion)\b/i.test(label) ? 1 : 0;
  }
  return 0;
}

function computeRecoAlternativeBarrierFitAdjustment(targetSignals, candidateText, candidateLabel) {
  const targetRole = String(targetSignals?.usageRole || '').trim().toLowerCase();
  if (targetRole !== 'moisturizer') {
    return {
      targetBarrierIntent: false,
      strongBarrierMatch: false,
      hydrationSupportMatch: false,
      comfortSignalMatch: false,
      bonus: 0,
      penalty: 0,
    };
  }
  const targetText = [
    targetSignals?.roleScope,
    targetSignals?.name,
    targetSignals?.productType,
    targetSignals?.category,
    targetSignals?.notes,
    ...(Array.isArray(targetSignals?.primaryClaims) ? targetSignals.primaryClaims : []),
    ...(Array.isArray(targetSignals?.heroIngredients) ? targetSignals.heroIngredients : []),
    ...(Array.isArray(targetSignals?.knownActives) ? targetSignals.knownActives : []),
  ]
    .map((value) => String(value || '').trim())
    .filter(Boolean)
    .join(' ');
  const targetBarrierIntent =
    RECO_ALTERNATIVE_STRONG_BARRIER_BRIDGE_RE.test(targetText) ||
    /\b(dry|tight|sensitive|redness|reactive|fragile|impaired|comfort|repair|sooth\w*|calm\w*)\b/i.test(targetText);
  if (!targetBarrierIntent) {
    return {
      targetBarrierIntent: false,
      strongBarrierMatch: false,
      hydrationSupportMatch: false,
      comfortSignalMatch: false,
      bonus: 0,
      penalty: 0,
    };
  }

  const candidateHaystack = [candidateLabel, candidateText]
    .map((value) => String(value || '').trim())
    .filter(Boolean)
    .join(' ');
  if (!candidateHaystack) {
    return {
      targetBarrierIntent: true,
      strongBarrierMatch: false,
      hydrationSupportMatch: false,
      comfortSignalMatch: false,
      bonus: 0,
      penalty: 0.06,
    };
  }

  const strongBarrierMatch = RECO_ALTERNATIVE_STRONG_BARRIER_BRIDGE_RE.test(candidateHaystack);
  const hydrationSupportMatch = RECO_ALTERNATIVE_HYDRATION_SUPPORT_RE.test(candidateHaystack);
  const comfortSensitiveTarget = /\b(dry|tight|sensitive|redness|reactive|fragile|impaired|irritat(?:e|ion)|stinging?)\b/i.test(targetText);
  const comfortSignalMatch = comfortSensitiveTarget && RECO_ALTERNATIVE_BARRIER_COMFORT_SIGNAL_RE.test(candidateHaystack);
  let bonus = 0;
  let penalty = 0;
  if (strongBarrierMatch) {
    bonus = 0.14;
  } else if (hydrationSupportMatch) {
    bonus = 0.05;
    penalty = 0.02;
  } else {
    penalty = 0.06;
  }
  if (strongBarrierMatch && comfortSignalMatch) bonus += 0.04;

  return {
    targetBarrierIntent,
    strongBarrierMatch,
    hydrationSupportMatch,
    comfortSignalMatch,
    bonus,
    penalty,
  };
}

function applyRecoAlternativeCosmeticFinishPenaltyToRow(row, {
  targetSignals,
  candidateText = '',
  candidateLabel = '',
} = {}) {
  const item = isPlainObject(row) ? row : null;
  if (!item) return row;
  const computedPenalty = computeRecoAlternativeCosmeticFinishPenalty(targetSignals, candidateText, candidateLabel);
  if (!(computedPenalty > 0)) return item;
  const metadata = isPlainObject(item.metadata) ? item.metadata : {};
  const priorPenalty = Math.max(0, Number(metadata.cosmetic_finish_penalty) || 0);
  const extraPenalty = Math.max(0, computedPenalty - priorPenalty);
  if (!(extraPenalty > 0)) return item;
  const baseScore = Number.isFinite(Number(item._mixed_score))
    ? clamp01Score(Number(item._mixed_score))
    : normalizeMaybePercentScore(item.similarity_score);
  if (!Number.isFinite(baseScore)) return item;
  const nextScore = clamp01Score(baseScore - extraPenalty);
  return {
    ...item,
    similarity_score: Math.max(1, Math.min(100, Math.round(nextScore * 100))),
    metadata: {
      ...metadata,
      raw_similarity_score: Number(nextScore.toFixed(3)),
      cosmetic_finish_penalty: Number(Math.max(priorPenalty, computedPenalty).toFixed(3)),
      ranking_signals_used: uniqCaseInsensitiveStrings([
        ...asStringArray(metadata.ranking_signals_used, 6),
        pickFirstTrimmed(metadata.ranking_signal),
        'cosmetic_finish_mismatch_penalty',
      ], 6),
    },
    _mixed_score: nextScore,
  };
}

function normalizePoolAlternativeRow(row, {
  targetSignals,
  anchorLabel = '',
  anchorNameTokens = [],
  ingredientTokens = [],
  claimTokens = [],
  textureTokens = [],
  anchorId = '',
} = {}) {
  const normalized = normalizeRecoCatalogProduct(row);
  if (!normalized) return null;
  const productId = pickFirstTrimmed(normalized.product_id, normalized.sku_id);
  const candidateLabel = joinBrandAndName(normalized.brand, pickFirstTrimmed(normalized.display_name, normalized.name));
  if (!candidateLabel) return null;
  if (!isSkincareCategory(normalized) || isBlacklistedCategoryOrTitle(normalized) || isExternalSeedPlaceholderCandidate(normalized)) {
    return null;
  }
  const anchorToken = String(anchorId || '').trim().toLowerCase();
  if (anchorToken && productId && productId.toLowerCase() === anchorToken) return null;
  if (anchorLabel && candidateLabel.trim().toLowerCase() === String(anchorLabel || '').trim().toLowerCase()) return null;

  const candidateText = buildRecoAlternativePoolCandidateText(normalized);
  const labelRole = inferRecoAlternativesUsageRole(
    normalized.display_name,
    normalized.name,
    candidateLabel,
  );
  const explicitCategoryRole = inferRecoAlternativesUsageRole(normalized.category, normalized.product_type);
  const candidateRole = labelRole === 'sunscreen'
    ? labelRole
    : explicitCategoryRole !== 'unknown'
      ? explicitCategoryRole
      : labelRole !== 'unknown'
        ? labelRole
        : inferRecoAlternativesUsageRole(
            normalized.category,
            normalized.product_type,
            candidateText,
          );
  const targetRole = String(targetSignals?.usageRole || '').trim().toLowerCase();
  const targetRoleScopeText = [
    targetSignals?.roleScope,
    ...(Array.isArray(targetSignals?.primaryClaims) ? targetSignals.primaryClaims : []),
  ]
    .map((value) => String(value || '').trim())
    .filter(Boolean)
    .join(' ');
  const allowBarrierSerumRoleBridge =
    targetRole === 'moisturizer' &&
    candidateRole === 'serum' &&
    RECO_ALTERNATIVE_STRONG_BARRIER_BRIDGE_RE.test(targetRoleScopeText) &&
    RECO_ALTERNATIVE_STRONG_BARRIER_BRIDGE_RE.test(candidateLabel);
  if (
    targetRole &&
    targetRole !== 'unknown' &&
    candidateRole &&
    candidateRole !== 'unknown' &&
    candidateRole !== targetRole &&
    !allowBarrierSerumRoleBridge
  ) {
    return null;
  }
  if (!isRecoAlternativeFormFactorCompatible(normalized, { targetSignals })) {
    return null;
  }

  const nameOverlap = computeTokenJaccardScore(anchorNameTokens, tokenizeProductTextForSimilarity(candidateLabel)) || 0;
  const ingredientOverlap = computeExternalSeedSignalOverlap(ingredientTokens, candidateText);
  const claimOverlap = computeExternalSeedSignalOverlap(claimTokens, candidateText);
  const textureOverlap = computeExternalSeedSignalOverlap(textureTokens, candidateText);
  const cosmeticFinishPenalty = computeRecoAlternativeCosmeticFinishPenalty(targetSignals, candidateText, candidateLabel);
  const concernIntentPenalty = computeRecoAlternativeConcernIntentPenalty(targetSignals, candidateText, candidateLabel);
  const barrierFit = computeRecoAlternativeBarrierFitAdjustment(targetSignals, candidateText, candidateLabel);
  const roleScore = !targetRole || targetRole === 'unknown'
    ? 0.72
    : candidateRole === targetRole
      ? 1
      : allowBarrierSerumRoleBridge
        ? 0.86
        : candidateRole === 'unknown'
          ? 0.58
          : 0.18;
  const titleActiveMatch = ['serum', 'treatment', 'sunscreen'].includes(targetRole)
    ? computeRecoAlternativeTitleActiveMatchScore(ingredientTokens, candidateLabel)
    : 0;
  const sameRoleLabelMatch = computeRecoAlternativeSameRoleLabelMatchScore(targetRole, candidateLabel);
  const stableIdBonus = normalized.canonical_product_ref || normalized.product_group_id ? 0.1 : productId ? 0.06 : 0;
  const retrievalBonus = normalized.retrieval_source === 'catalog' ? 0.06 : 0.03;
  const mixedScore = clamp01Score(
    roleScore * 0.44 +
    nameOverlap * 0.14 +
    ingredientOverlap * 0.18 +
    titleActiveMatch * 0.08 +
    sameRoleLabelMatch * 0.06 +
    claimOverlap * 0.12 +
    textureOverlap * 0.06 +
    stableIdBonus +
    retrievalBonus -
    cosmeticFinishPenalty -
    concernIntentPenalty +
    barrierFit.bonus -
    barrierFit.penalty,
  );
  const minimumPoolScore = targetRole === 'sunscreen' && candidateRole === 'sunscreen' ? 0.5 : 0.55;
  if (mixedScore < minimumPoolScore) return null;

  const pdpUrl = extractCandidateOpenUrl(normalized);
  const pdpOpen = normalized.canonical_product_ref
    ? { path: 'ref', product_ref: normalized.canonical_product_ref }
    : normalized.product_group_id
      ? { path: 'group', product_group_id: normalized.product_group_id }
      : pdpUrl
        ? { path: 'external', external: { url: pdpUrl, query: candidateLabel } }
        : productId
          ? {
              path: 'resolve',
              product_ref: {
                product_id: normalized.product_id,
                ...(normalized.merchant_id ? { merchant_id: normalized.merchant_id } : {}),
              },
              external: { query: candidateLabel },
            }
          : { path: 'external', external: { query: candidateLabel } };

  const sameStepReason =
    roleScore >= 0.9 && targetRole && targetRole !== 'unknown'
      ? (targetRole === 'moisturizer' && barrierFit.targetBarrierIntent
          ? 'Same barrier-friendly moisturizer step.'
          : `Same ${targetRole} step.`)
      : '';
  const barrierReason =
    barrierFit.targetBarrierIntent && barrierFit.strongBarrierMatch
      ? 'Barrier-support cues line up with the anchor instead of drifting into a more generic moisturizer compare.'
      : barrierFit.targetBarrierIntent && barrierFit.hydrationSupportMatch
        ? 'Keeps the compare inside the same hydration-first moisturizer lane.'
        : '';
  const barrierComfortReason =
    barrierFit.targetBarrierIntent && barrierFit.comfortSignalMatch
      ? 'Adds more calming barrier-comfort cues for dry, tight, or easily irritated skin.'
      : '';
  const barrierTradeoff =
    barrierFit.targetBarrierIntent && !barrierFit.strongBarrierMatch
      ? (barrierFit.hydrationSupportMatch
          ? 'More hydration-led than barrier-led compared with the anchor.'
          : 'Less explicit barrier-support evidence than the anchor.')
      : '';

  return applyGroundedAlternativeAuthorityExperience({
    kind: 'similar',
    candidate_origin: 'pool',
    grounding_status: 'catalog_verified',
    ranking_mode: 'best_score_mixed',
    product: {
      ...(normalized.product_id ? { product_id: normalized.product_id } : {}),
      ...(normalized.merchant_id ? { merchant_id: normalized.merchant_id } : {}),
      ...(normalized.product_group_id ? { product_group_id: normalized.product_group_id } : {}),
      ...(normalized.sku_id ? { sku_id: normalized.sku_id } : {}),
      ...(normalized.brand ? { brand: normalized.brand } : {}),
      name: pickFirstTrimmed(normalized.display_name, normalized.name),
      ...(normalized.category ? { category: normalized.category } : {}),
      ...(pdpUrl ? { pdp_url: pdpUrl, url: pdpUrl } : {}),
      ...(normalized.price && typeof normalized.price === 'object' ? { price: normalized.price } : {}),
    },
    ...(normalized.brand ? { brand: normalized.brand } : {}),
    name: pickFirstTrimmed(normalized.display_name, normalized.name),
    similarity_score: Math.max(1, Math.min(100, Math.round(mixedScore * 100))),
    reasons: uniqCaseInsensitiveStrings(
      [
        sameStepReason,
        barrierReason,
        barrierComfortReason,
        sameRoleLabelMatch >= 0.9 ? `Names the ${targetRole} role directly.` : '',
        titleActiveMatch >= 0.34 ? 'Names the anchor hero active directly.' : '',
        ingredientOverlap >= 0.34 ? 'Matches key active or ingredient signals from the anchor.' : '',
        claimOverlap >= 0.34 ? 'Overlaps the anchor use case and claims.' : '',
        textureOverlap >= 0.34 ? 'Texture profile is close to the anchor.' : '',
        stableIdBonus >= 0.1 ? 'Has stable product identifiers in the current pool.' : '',
      ],
      3,
    ),
    tradeoff_notes: uniqCaseInsensitiveStrings(
      [
        normalized.retrieval_source === 'external_seed'
          ? 'Pool hit is external-backed, so internal PDP coverage may vary.'
          : '',
        candidateRole === 'unknown' ? 'Exact usage role is inferred from sparse catalog text.' : '',
        barrierTradeoff,
        cosmeticFinishPenalty > 0
          ? 'Finish leans more cosmetic than the anchor, so it ranks lower for a straightforward sunscreen compare.'
          : '',
        concernIntentPenalty > 0
          ? 'Concern focus is less aligned with the anchor, so it ranks lower.'
          : '',
      ],
      2,
    ),
    best_use: targetRole && targetRole !== 'unknown'
      ? (targetRole === 'moisturizer' && barrierFit.targetBarrierIntent
          ? 'Comparable barrier-friendly moisturizer option.'
          : `Comparable ${targetRole} option.`)
      : null,
    pdp_open: pdpOpen,
    metadata: {
      compare_stage: 'pool_only',
      retrieval_source: normalized.retrieval_source || null,
      raw_similarity_score: Number(mixedScore.toFixed(3)),
      ...(sameRoleLabelMatch > 0 ? { same_role_label_match: Number(sameRoleLabelMatch.toFixed(3)) } : {}),
      ...(titleActiveMatch > 0 ? { title_active_match: Number(titleActiveMatch.toFixed(3)) } : {}),
      ...(cosmeticFinishPenalty > 0 ? { cosmetic_finish_penalty: Number(cosmeticFinishPenalty.toFixed(3)) } : {}),
      ...(concernIntentPenalty > 0 ? { concern_intent_penalty: Number(concernIntentPenalty.toFixed(3)) } : {}),
      ...(barrierFit.bonus > 0 ? { barrier_fit_bonus: Number(barrierFit.bonus.toFixed(3)) } : {}),
      ...(barrierFit.penalty > 0 ? { barrier_fit_penalty: Number(barrierFit.penalty.toFixed(3)) } : {}),
      ...(barrierFit.comfortSignalMatch ? { barrier_comfort_match: true } : {}),
      ...(
        sameRoleLabelMatch > 0 ||
        titleActiveMatch > 0 ||
        cosmeticFinishPenalty > 0 ||
        concernIntentPenalty > 0 ||
        barrierFit.bonus > 0 ||
        barrierFit.penalty > 0
          ? {
              ranking_signals_used: uniqCaseInsensitiveStrings([
                sameRoleLabelMatch > 0 ? 'same_role_label_match_bonus' : '',
                titleActiveMatch > 0 ? 'title_active_match_bonus' : '',
                cosmeticFinishPenalty > 0 ? 'cosmetic_finish_mismatch_penalty' : '',
                concernIntentPenalty > 0 ? 'concern_intent_mismatch_penalty' : '',
                barrierFit.bonus > 0 ? 'barrier_fit_bonus' : '',
                barrierFit.penalty > 0 ? 'barrier_fit_penalty' : '',
                barrierFit.comfortSignalMatch ? 'barrier_comfort_bonus' : '',
              ], 6),
            }
          : {}
      ),
    },
    _mixed_score: mixedScore,
  }, normalized);
}

function normalizeExternalSeedPoolCandidateRows(candidateRows, {
  identity,
  anchorId = '',
} = {}) {
  const deduped = [];
  const seen = new Set();
  for (const row of Array.isArray(candidateRows) ? candidateRows : []) {
    const normalized = normalizePoolAlternativeRow(row, {
      targetSignals: identity?.targetSignals,
      anchorLabel: identity?.anchorLabel,
      anchorNameTokens: Array.isArray(identity?.anchorNameTokens) ? identity.anchorNameTokens : [],
      ingredientTokens: Array.isArray(identity?.ingredientTokens) ? identity.ingredientTokens : [],
      claimTokens: Array.isArray(identity?.claimTokens) ? identity.claimTokens : [],
      textureTokens: Array.isArray(identity?.textureTokens) ? identity.textureTokens : [],
      anchorId,
    });
    if (!normalized) continue;
    const identityKeys = getRecoAlternativeIdentityKeys(normalized);
    const dedupeKey = identityKeys.find((key) => String(key || '').startsWith('pid:')) ||
      identityKeys.find((key) => String(key || '').startsWith('sku:')) ||
      identityKeys.find((key) => String(key || '').startsWith('url:')) ||
      identityKeys.find((key) => String(key || '').startsWith('name:'));
    if (!dedupeKey || seen.has(dedupeKey)) continue;
    seen.add(dedupeKey);
    deduped.push(normalized);
  }

  deduped.sort((left, right) => {
    const scoreDiff = Number(right?._mixed_score || 0) - Number(left?._mixed_score || 0);
    if (scoreDiff !== 0) return scoreDiff;
    return String(left?.product?.name || '').localeCompare(String(right?.product?.name || ''));
  });
  return deduped;
}

async function collectExternalSeedPoolAlternatives({
  ctx,
  productInput,
  productObj,
  maxTotal = 3,
  anchorId = '',
  logger,
} = {}) {
  const identity = buildExternalSeedCompareIdentity(productObj, productInput);
  const queryPlan = buildExternalSeedCompareSearchQueries({
    productObj,
    productInput,
    lang: ctx?.lang || 'EN',
  });
  const normalizedLimit = Math.max(3, Math.min(6, Number.isFinite(Number(maxTotal)) ? Math.trunc(Number(maxTotal)) : 3));
  const candidateRows = [];
  let localCandidateRowCount = 0;
  let backendCandidateRowCount = 0;
  let backendSearchSkipped = false;
  const embeddedPool = buildRecoAlternativesCandidatePool({
    sharedCandidates: [],
    productObj,
    anchorId,
    maxCandidates: 12,
  });
  for (const row of embeddedPool) candidateRows.push(row);

  const finishFitSunscreenCompare = isExternalSeedFinishFitSunscreenTarget(identity.targetSignals);
  const queriesToRun = queryPlan.slice(
    0,
    finishFitSunscreenCompare
      ? Math.min(3, queryPlan.length)
      : Math.max(2, Math.min(4, normalizedLimit)),
  );
  const localSeedSearchRole = buildRecoAlternativesLocalSeedSearchRole(identity.targetSignals);
  if (finishFitSunscreenCompare) {
    for (const query of queriesToRun) {
      // For finish-fit sunscreen alternatives, stop once the pool already spans
      // the main shopper-facing compare buckets instead of always exhausting
      // every local query.
      // eslint-disable-next-line no-await-in-loop
      const searched = await searchLocalExternalSeedProducts({
        query,
        limit: 12,
        logger,
        transportPolicyMode: 'reco_alternatives_pool',
        role: localSeedSearchRole,
        preferredStep: localSeedSearchRole.preferred_step,
      });
      const list = Array.isArray(searched?.products) ? searched.products : [];
      localCandidateRowCount += list.length;
      for (const row of list) candidateRows.push(row);
      const stagedDeduped = normalizeExternalSeedPoolCandidateRows(candidateRows, { identity, anchorId });
      const stagedCompetitiveRows = finalizeRecoAlternativesForCompetitiveQuality(stagedDeduped, { maxTotal: normalizedLimit });
      if (hasRecoAlternativeSunscreenTradeoffCoverage(stagedCompetitiveRows, {
        targetSignals: identity.targetSignals,
        maxTotal: normalizedLimit,
      })) {
        break;
      }
    }
  } else {
    const localSeedResults = await Promise.allSettled(
      queriesToRun.map((query) => searchLocalExternalSeedProducts({
        query,
        limit: 12,
        logger,
        transportPolicyMode: 'reco_alternatives_pool',
        role: localSeedSearchRole,
        preferredStep: localSeedSearchRole.preferred_step,
      })),
    );
    for (const result of localSeedResults) {
      const searched = result.status === 'fulfilled' ? result.value : null;
      const list = Array.isArray(searched?.products) ? searched.products : [];
      localCandidateRowCount += list.length;
      for (const row of list) candidateRows.push(row);
    }
  }

  let deduped = normalizeExternalSeedPoolCandidateRows(candidateRows, { identity, anchorId });
  const localCompetitiveRows = finalizeRecoAlternativesForCompetitiveQuality(deduped, { maxTotal: normalizedLimit });
  if (localCompetitiveRows.length >= Math.min(3, normalizedLimit)) {
    backendSearchSkipped = true;
  } else {
    const searchResults = await Promise.allSettled(
      queriesToRun.map((query) => searchPivotaBackendProducts({
        query,
        limit: 8,
        logger,
        timeoutMs: 1100,
        minTimeoutMs: 220,
        mode: 'main_path',
        allowExternalSeed: true,
        externalSeedStrategy: 'supplement_internal_first',
        fastMode: true,
        transportPolicy: {
          mode: 'reco_alternatives_pool_http_supplement',
          include_local_fallback: false,
          include_self_proxy: false,
          max_base_urls: 1,
          max_paths: 1,
          allow_secondary_base_failover: false,
          allow_secondary_path_failover: false,
          actual_http_attempt_limit_per_query: 1,
        },
      })),
    );
    for (const result of searchResults) {
      const searched = result.status === 'fulfilled' ? result.value : null;
      const list = Array.isArray(searched?.products) ? searched.products : [];
      backendCandidateRowCount += list.length;
      for (const row of list) candidateRows.push(row);
    }
    deduped = normalizeExternalSeedPoolCandidateRows(candidateRows, { identity, anchorId });
  }

  return {
    identity,
    queries: queryPlan,
    executed_queries: queriesToRun,
    local_authority_candidate_count: localCandidateRowCount,
    backend_authority_candidate_count: backendCandidateRowCount,
    backend_authority_search_skipped: backendSearchSkipped,
    local_authority_search_role: localSeedSearchRole,
    candidates: await hydrateRecoAlternativesAuthorityExperienceRows(
      deduped.slice(0, Math.max(normalizedLimit, 6)),
    ),
  };
}

function buildExternalSeedOpenWorldSchema() {
  return {
    type: 'object',
    additionalProperties: false,
    properties: {
      alternatives: {
        type: 'array',
        minItems: 0,
        maxItems: 3,
        items: {
          type: 'object',
          additionalProperties: false,
          properties: {
            brand: { type: 'string' },
            name: { type: 'string' },
            product_type: { type: 'string', nullable: true },
            similarity_score: { type: 'number', nullable: true },
            reasons: {
              type: 'array',
              minItems: 1,
              maxItems: 2,
              items: { type: 'string' },
            },
            tradeoff_notes: {
              type: 'array',
              minItems: 1,
              maxItems: 2,
              items: { type: 'string' },
            },
            best_use: { type: 'string', nullable: true },
          },
          required: ['brand', 'name', 'reasons', 'tradeoff_notes'],
        },
      },
    },
    required: ['alternatives'],
  };
}

function normalizeOpenWorldAlternativeRow(candidate, {
  targetSignals,
  anchorLabel = '',
  anchorNameTokens = [],
  ingredientTokens = [],
  claimTokens = [],
  textureTokens = [],
} = {}) {
  const row = isPlainObject(candidate) ? candidate : {};
  const brand = pickFirstTrimmed(row.brand);
  const name = pickFirstTrimmed(row.name, row.display_name, row.displayName);
  const productType = pickFirstTrimmed(row.product_type, row.productType, targetSignals?.productType, targetSignals?.category);
  if (!brand || !name) return null;
  const candidateLabel = joinBrandAndName(brand, name);
  if (!candidateLabel || candidateLabel.trim().toLowerCase() === String(anchorLabel || '').trim().toLowerCase()) return null;
  const categoryProbe = { brand, name, category: productType, product_type: productType };
  const explicitCategoryRole = inferRecoAlternativesUsageRole(productType);
  const candidateRole = explicitCategoryRole !== 'unknown'
    ? explicitCategoryRole
    : inferRecoAlternativesUsageRole(candidateLabel, productType);
  const targetRole = String(targetSignals?.usageRole || '').trim().toLowerCase();
  if (!isSkincareCategory(categoryProbe) && candidateRole !== targetRole) return null;
  if (isBlacklistedCategoryOrTitle(categoryProbe) || isExternalSeedPlaceholderCandidate(categoryProbe)) return null;
  if (!isRecoAlternativeFormFactorCompatible({
    brand,
    name,
    category: productType,
    product_type: productType,
  }, { targetSignals })) return null;

  const reasons = uniqCaseInsensitiveStrings(asStringArray(row.reasons, 2), 2);
  const tradeoffNotes = uniqCaseInsensitiveStrings(asStringArray(row.tradeoff_notes, 2), 2);
  if (!reasons.length || !tradeoffNotes.length) return null;

  const sourceText = [candidateLabel, productType, reasons.join(' '), tradeoffNotes.join(' ')].join(' ');
  const baseScoreRaw = Number(row.similarity_score);
  const baseScore = Number.isFinite(baseScoreRaw) ? clamp01Score(baseScoreRaw > 1 ? baseScoreRaw / 100 : baseScoreRaw) : 0.62;
  const nameOverlap = computeTokenJaccardScore(anchorNameTokens, tokenizeProductTextForSimilarity(candidateLabel)) || 0;
  const ingredientOverlap = computeExternalSeedSignalOverlap(ingredientTokens, sourceText);
  const claimOverlap = computeExternalSeedSignalOverlap(claimTokens, sourceText);
  const textureOverlap = computeExternalSeedSignalOverlap(textureTokens, sourceText);
  const roleScore = !targetRole || targetRole === 'unknown'
    ? 0.72
    : candidateRole === targetRole
      ? 1
      : candidateRole === 'unknown'
        ? 0.52
        : 0.14;
  const mixedScore = clamp01Score(
    baseScore * 0.34 +
    roleScore * 0.28 +
    ingredientOverlap * 0.14 +
    claimOverlap * 0.12 +
    textureOverlap * 0.06 +
    nameOverlap * 0.06,
  );

  return applyRecoAlternativeCosmeticFinishPenaltyToRow({
    kind: 'similar',
    candidate_origin: 'open_world',
    grounding_status: 'name_only',
    ranking_mode: 'best_score_mixed',
    product: {
      brand,
      name,
      ...(productType ? { category: productType } : {}),
    },
    brand,
    name,
    similarity_score: Math.max(1, Math.min(100, Math.round(mixedScore * 100))),
    reasons,
    tradeoff_notes: tradeoffNotes,
    best_use: pickFirstTrimmed(row.best_use, row.bestUse) || null,
    pdp_open: {
      path: 'external',
      external: {
        query: candidateLabel,
      },
    },
    metadata: {
      compare_stage: 'open_world',
      raw_similarity_score: Number(mixedScore.toFixed(3)),
    },
    _mixed_score: mixedScore,
  }, { targetSignals, candidateText: sourceText, candidateLabel });
}

const RECO_ALTERNATIVE_GROUNDING_GENERIC_TOKEN_SET = new Set([
  'spf',
  'sunscreen',
  'sun',
  'screen',
  'serum',
  'face',
  'daily',
  'fluid',
  'lotion',
  'cream',
  'gel',
  'oil',
  'free',
  'invisible',
  'ultra',
  'light',
  'broad',
  'spectrum',
  'protection',
  'protect',
  'filters',
  'uv',
]);

function extractRecoAlternativeSpfValue(text) {
  const match = String(text || '').match(/\bspf\s*(\d{1,3})\+?\b/i);
  const value = Number(match?.[1] || 0);
  return Number.isFinite(value) && value > 0 ? value : 0;
}

function collectRecoAlternativeMeaningfulTokens(tokens) {
  return uniqCaseInsensitiveStrings(
    (Array.isArray(tokens) ? tokens : [])
      .map((token) => String(token || '').trim().toLowerCase())
      .filter((token) => token && token.length >= 4 && !RECO_ALTERNATIVE_GROUNDING_GENERIC_TOKEN_SET.has(token)),
    12,
  );
}

function scoreRecoAlternativeCatalogGroundingMatch(openWorldRow, catalogRow) {
  const openProduct = getRecoAlternativeProductObject(openWorldRow);
  const candidate = normalizeRecoCatalogProduct(catalogRow);
  if (!candidate) return { ok: false, score: 0 };
  if (!isSkincareCategory(candidate) || isBlacklistedCategoryOrTitle(candidate) || isExternalSeedPlaceholderCandidate(candidate)) {
    return { ok: false, score: 0 };
  }
  const openBrand = normalizeRecoNameToken(pickFirstTrimmed(openProduct.brand, openWorldRow?.brand));
  const openName = normalizeRecoNameToken(pickFirstTrimmed(openProduct.name, openWorldRow?.name));
  const candidateBrand = normalizeRecoNameToken(candidate.brand);
  const candidateName = normalizeRecoNameToken(pickFirstTrimmed(candidate.display_name, candidate.name));
  if (!openBrand || !openName || !candidateBrand || !candidateName) return { ok: false, score: 0 };
  if (openBrand !== candidateBrand) return { ok: false, score: 0 };
  const openTokens = tokenizeProductTextForSimilarity(openName);
  const candidateTokens = tokenizeProductTextForSimilarity(candidateName);
  const tokenScore = computeTokenJaccardScore(openTokens, candidateTokens) || 0;
  const openSpf = extractRecoAlternativeSpfValue(openName);
  const candidateSpf = extractRecoAlternativeSpfValue(candidateName);
  const sharedMeaningfulTokens = collectRecoAlternativeMeaningfulTokens(openTokens)
    .filter((token) => collectRecoAlternativeMeaningfulTokens(candidateTokens).includes(token));
  const exactName = openName === candidateName;
  const containsName = openName.length >= 8 && candidateName.length >= 8 && (openName.includes(candidateName) || candidateName.includes(openName));
  const relaxedSpfVariantMatch =
    openSpf > 0 &&
    candidateSpf > 0 &&
    openSpf === candidateSpf &&
    tokenScore >= 0.46 &&
    (sharedMeaningfulTokens.length >= 2 || sharedMeaningfulTokens.some((token) => token.length >= 8));
  const ok = exactName || (containsName && tokenScore >= 0.72) || tokenScore >= 0.84 || relaxedSpfVariantMatch;
  return {
    ok,
    score: exactName
      ? 1
      : containsName
        ? Math.max(0.86, tokenScore)
        : relaxedSpfVariantMatch
          ? Math.max(0.76, tokenScore)
          : tokenScore,
    candidate,
    matchMode: relaxedSpfVariantMatch ? 'catalog_fuzzy_search' : 'catalog_exact_search',
  };
}

function classifyRecoAuthorityHitSource(candidate) {
  const normalized = normalizeRecoCatalogProduct(candidate);
  if (!normalized) return '';
  if (
    String(normalized.merchant_id || '').trim().toLowerCase() === String(EXTERNAL_SEED_MERCHANT_ID || '').trim().toLowerCase() ||
    String(normalized.retrieval_source || '').trim().toLowerCase() === 'external_seed' ||
    String(normalized.source || '').trim().toLowerCase().includes('external')
  ) {
    return 'external_seed_hit';
  }
  return 'internal_hit';
}

function summarizeResolverAuthoritySource(resolved) {
  const canonicalRef =
    normalizeCanonicalProductRef(resolved?.canonicalProductRef, {
      requireMerchant: true,
      allowOpaqueProductId: false,
    }) || null;
  if (
    String(canonicalRef?.merchant_id || '').trim().toLowerCase() === String(EXTERNAL_SEED_MERCHANT_ID || '').trim().toLowerCase()
  ) {
    return 'external_seed_hit';
  }
  const sources = Array.isArray(resolved?.metadata?.sources) ? resolved.metadata.sources : [];
  if (sources.some((entry) => String(entry?.source || '').trim().toLowerCase().includes('external'))) {
    return 'external_seed_hit';
  }
  return canonicalRef ? 'internal_hit' : '';
}

function buildOpenWorldAlternativeAuthorityQueryPack(row, { targetSignals = null } = {}) {
  const item = isPlainObject(row) ? row : {};
  const product = getRecoAlternativeProductObject(item);
  const brand = pickFirstTrimmed(product.brand, item.brand);
  const name = pickFirstTrimmed(product.display_name, product.displayName, product.name, item.name);
  const category = pickFirstTrimmed(product.category, product.product_type, item.product_type, targetSignals?.productType);
  const usageRole = pickFirstTrimmed(targetSignals?.usageRole);
  const searchAliases = uniqCaseInsensitiveStrings(
    [
      ...asStringArray(item.search_aliases, 8),
      ...asStringArray(product.search_aliases, 8),
      ...asStringArray(item.aliases, 8),
      ...asStringArray(product.aliases, 8),
      joinBrandAndName(brand, name),
      name,
    ].filter(Boolean),
    10,
  );
  return buildRecoAuthorityQueryVariants({
    brand,
    name,
    category,
    usageRole,
    searchAliases,
    maxVariants: 8,
  });
}

function isGenericGroundedAlternativeCopy(row) {
  const reasons = asStringArray(row?.reasons, 2);
  const tradeoffNotes = asStringArray(row?.tradeoff_notes, 2);
  const reasonText = reasons.join(' | ').toLowerCase();
  const tradeoffText = tradeoffNotes.join(' | ').toLowerCase();
  if (!reasons.length && !tradeoffNotes.length) return true;
  return (
    /same .* step as the anchor|distinct option for this compare|resolved to a live product entry/i.test(reasonText) ||
    /verify formula specifics before comparing actives or finish|key formula details still need verification/i.test(tradeoffText)
  );
}

function scoreGroundedAlternativeVisibleReasonLine(value) {
  const text = cleanRecoVisibleCopy(value).replace(/\s+/g, ' ').trim();
  if (!text) return Number.NEGATIVE_INFINITY;
  let score = 0;
  if (text.length >= 28) score += 1;
  if (text.length <= 140) score += 1;
  if (/^same\b/i.test(text)) score -= 6;
  if (/^names the\b/i.test(text)) score -= 6;
  if (/\bexternal-backed\b|\binternal pdp coverage may vary\b/i.test(text)) score -= 8;
  if (/\b(?:hydration-first|hydration-led|more\s+\w+(?:-\w+)?\s+than\s+\w+(?:-\w+)?|less\s+\w+(?:-\w+)?\s+than)\b/i.test(text)) {
    score += 3;
  }
  if (/\b(calming|comfort|dry|tight|irritated|hydration-first|hydration-led|barrier-support|matte|dewier|dewy|weightless|sheer|mineral|moisturizing|shine-controlling|less slip|under makeup|lighter|smoother)\b/i.test(text)) {
    score += 5;
  }
  if (/\banchor\b/i.test(text)) score -= 2;
  if (/\bgeneric moisturizer compare\b/i.test(text)) score -= 4;
  if (/\bcurrent pool|product pool|role directly\b/i.test(text)) score -= 3;
  return score;
}

function rewriteGroundedAlternativeVisibleShopperLine(row, value) {
  const item = isPlainObject(row) ? row : {};
  const text = cleanRecoVisibleCopy(value).replace(/\s+/g, ' ').trim();
  if (!text) return '';
  const candidateHaystack = buildRecoAlternativePoolCandidateText(item);
  const product = getRecoAlternativeProductObject(item);
  const sunscreenContextText = [
    item.best_use,
    item.best_for,
    item.role_scope,
    item.selected_target_id,
    product.category,
    product.product_type,
    item.name,
  ]
    .map((value) => String(value || '').trim())
    .filter(Boolean)
    .join(' ');
  const isSunscreenCompare =
    /\b(?:sunscreen|spf|daily_sunscreen_finish_fit)\b/i.test(sunscreenContextText) ||
    /\b(?:sunscreen|spf)\b/i.test(candidateHaystack);
  const hasMineralSunscreenCue = /\b(mineral|zinc oxide|titanium dioxide)\b/i.test(candidateHaystack);
  const hasSerumSunscreenCue = /\b(serum-like|sun serum|face serum|water-fit|watery|fresh finish|quick absorption|quick-absorbing|thin(?:ner)? feel)\b/i.test(candidateHaystack);
  const hasHydratingMilkCue = /\b(sunscreen milk|sun milk|hydrating sunscreen milk|cream-based|creamier|colloidal oatmeal|oatmeal|soft-focus|more moisture|cushion(?:ing)?|hydrating)\b/i.test(candidateHaystack);
  const hasMatteSunscreenCue = /\b(matte|mattifying|shine-control(?:ling)?|less slip)\b/i.test(candidateHaystack);
  const hasStrongComfortCue = /\b(colloidal\s+oatmeal|oat(?:meal)?|allantoin|ectoin|cica|centella|reactive|stinging?)\b/i.test(candidateHaystack);
  const hasLighterDewyCue = /\b(gel[-\s]?cream|water[-\s]?(?:cream|gel)|lightweight|ultra[-\s]?sheer|breathable|quick[-\s]?absorbing|dewy)\b/i.test(candidateHaystack);
  const hasOilControlCue = /\b(oil[-\s]?control|mattifying|matte|shine[-\s]?free|shine[-\s]?controlling|powder[-\s]?soft)\b/i.test(candidateHaystack);

  if (isSunscreenCompare) {
    if (/^same sunscreen step\.?$/i.test(text) || /^names the sunscreen role directly\.?$/i.test(text) || /overlaps the anchor use case and claims/i.test(text)) {
      return '';
    }
    if (/weightless sun protection with spf/i.test(text) && hasMineralSunscreenCue) {
      return 'Leans more mineral and weightless if you want a clear mineral sunscreen option.';
    }
    if (/serum-like spf|sunscreen that feels like a serum|serum texture/i.test(text) && hasSerumSunscreenCue) {
      return 'Leans more serum-like and fresh if you want a thinner sunscreen feel.';
    }
    if (/daily sunscreen built around humectants|comfortable daytime layering|am uv protection/i.test(text) && hasHydratingMilkCue) {
      return 'Leans more hydrating and creamier if you want a cushier sunscreen layer.';
    }
  }
  if (/adds more calming barrier-comfort cues for dry, tight, or easily irritated skin/i.test(text)) {
    if (hasOilControlCue) {
      return 'Leans lighter and more oil-controlling if you want less richness from a barrier moisturizer.';
    }
    if (hasLighterDewyCue && !hasStrongComfortCue) {
      return 'Leans lighter and dewier if you want hydration without a heavier cream feel.';
    }
    return text;
  }
  if (
    /keeps the compare inside the same hydration-first moisturizer lane/i.test(text) ||
    /more hydration-led than barrier-led compared with the anchor/i.test(text)
  ) {
    return 'Leans more hydration-first than barrier-first if you want a bit more moisture.';
  }
  if (/less explicit barrier-support evidence than the anchor/i.test(text)) {
    return 'Leans less barrier-focused than the anchor if you want a lighter hydration-first option.';
  }
  if (/barrier-support cues line up with the anchor instead of drifting into a more generic moisturizer compare/i.test(text)) {
    const metadata =
      item.metadata && typeof item.metadata === 'object' && !Array.isArray(item.metadata)
        ? item.metadata
        : {};
    if (hasOilControlCue) {
      return 'Leans lighter and more oil-controlling if you want less richness from a barrier moisturizer.';
    }
    if (hasLighterDewyCue && !hasStrongComfortCue) {
      return 'Leans lighter and dewier if you want hydration without a heavier cream feel.';
    }
    if (Number(metadata.barrier_fit_penalty || 0) > 0) {
      return 'Leans more hydration-first than barrier-first if you want a bit more moisture.';
    }
    return 'Stays closer to the anchor\'s barrier-support profile than a generic moisturizer.';
  }
  return text;
}

function buildGroundedAlternativeFallbackVisibleShopperCopy(row) {
  const item = isPlainObject(row) ? row : {};
  const metadata =
    item.metadata && typeof item.metadata === 'object' && !Array.isArray(item.metadata)
      ? item.metadata
      : {};
  const contextText = [
    ...(Array.isArray(item.reasons) ? item.reasons : []),
    ...(Array.isArray(item.tradeoff_notes) ? item.tradeoff_notes : []),
    item.best_use,
    item.best_for,
    item.role_scope,
    item.selected_target_id,
  ]
    .map((value) => String(value || '').trim())
    .filter(Boolean)
    .join(' ');
  const product = getRecoAlternativeProductObject(item);
  const candidateHaystack = buildRecoAlternativePoolCandidateText(item);
  const isSunscreenCompare =
    /\b(?:same sunscreen step|daily_sunscreen_finish_fit|sunscreen|spf)\b/i.test(contextText) ||
    /\b(?:sunscreen|spf)\b/i.test([product.category, product.product_type, item.name, candidateHaystack].filter(Boolean).join(' '));
  const mineralSunscreenSignal = /\b(mineral|zinc oxide|titanium dioxide)\b/i.test(candidateHaystack);
  const serumSunscreenSignal = /\b(serum-like|sun serum|face serum|water-fit|watery|fresh finish|quick absorption|quick-absorbing|thin(?:ner)? feel)\b/i.test(candidateHaystack);
  const hydratingMilkSignal = /\b(sunscreen milk|sun milk|hydrating sunscreen milk|cream-based|creamier|colloidal oatmeal|oatmeal|soft-focus|more moisture|cushion(?:ing)?|hydrating)\b/i.test(candidateHaystack);
  const matteSunscreenSignal = /\b(matte|mattifying|shine-control(?:ling)?|less slip)\b/i.test(candidateHaystack);
  if (isSunscreenCompare) {
    if (matteSunscreenSignal) {
      return 'Leans more matte and less slippery if you want less shine during the day.';
    }
    if (mineralSunscreenSignal) {
      return 'Leans more mineral and weightless if you want a clear mineral sunscreen option.';
    }
    if (hydratingMilkSignal) {
      return 'Leans more hydrating and creamier if you want a cushier sunscreen layer.';
    }
    if (serumSunscreenSignal) {
      return 'Leans more serum-like and fresh if you want a thinner sunscreen feel.';
    }
    return '';
  }
  const isBarrierMoisturizerCompare =
    /barrier-friendly moisturizer|hydrating_barrier_moisturizer|barrier-support|dry|tight|irritated|hydration-first|barrier-led/i.test(contextText) ||
    Number(metadata.barrier_fit_bonus || 0) > 0 ||
    Number(metadata.barrier_fit_penalty || 0) > 0 ||
    metadata.barrier_comfort_match === true;
  if (!isBarrierMoisturizerCompare) return '';

  const hydrationTradeoff =
    /hydration-first|hydration-led|dewy|plump|glycerin|hyaluronic|squalane/i.test(candidateHaystack) ||
    Number(metadata.barrier_fit_penalty || 0) > 0;
  const comfortSignal =
    metadata.barrier_comfort_match === true ||
    RECO_ALTERNATIVE_BARRIER_COMFORT_SIGNAL_RE.test(candidateHaystack);
  const strongComfortSignal = /\b(colloidal\s+oatmeal|oat(?:meal)?|allantoin|ectoin|cica|centella|reactive|stinging?)\b/i.test(candidateHaystack);
  const lighterDewySignal = /\b(gel[-\s]?cream|water[-\s]?(?:cream|gel)|lightweight|ultra[-\s]?sheer|breathable|quick[-\s]?absorbing|dewy)\b/i.test(candidateHaystack);
  const oilControlSignal = /\b(oil[-\s]?control|mattifying|matte|shine[-\s]?free|shine[-\s]?controlling|powder[-\s]?soft)\b/i.test(candidateHaystack);
  const strongBarrierSignal = RECO_ALTERNATIVE_STRONG_BARRIER_BRIDGE_RE.test(candidateHaystack);

  if (oilControlSignal) {
    return 'Leans lighter and more oil-controlling if you want less richness from a barrier moisturizer.';
  }
  if (comfortSignal) {
    if (lighterDewySignal && !strongComfortSignal) {
      return 'Leans lighter and dewier if you want hydration without a heavier cream feel.';
    }
    return 'Adds more calming barrier-comfort cues for dry, tight, or easily irritated skin.';
  }
  if (lighterDewySignal && hydrationTradeoff) {
    return 'Leans lighter and dewier if you want hydration without a heavier cream feel.';
  }
  if (hydrationTradeoff) {
    return 'Leans more hydration-first than barrier-first if you want a bit more moisture.';
  }
  if (strongBarrierSignal) {
    return 'Stays closer to the anchor\'s barrier-support profile than a generic moisturizer.';
  }
  return '';
}

function buildGroundedAlternativeVisibleShopperCopy(row) {
  const item = isPlainObject(row) ? row : {};
  const reasons = asStringArray(item.reasons, 4)
    .map((value) => rewriteGroundedAlternativeVisibleShopperLine(item, value))
    .filter(Boolean);
  const tradeoffNotes = asStringArray(item.tradeoff_notes, 3)
    .map((value) => rewriteGroundedAlternativeVisibleShopperLine(item, value))
    .filter(Boolean);
  const rankedReasons = reasons
    .map((text) => ({ text, score: scoreGroundedAlternativeVisibleReasonLine(text) }))
    .filter((entry) => Number.isFinite(entry.score) && entry.score >= 2)
    .sort((left, right) => Number(right.score || 0) - Number(left.score || 0));
  const rankedTradeoffs = tradeoffNotes
    .map((text) => ({ text, score: scoreGroundedAlternativeVisibleReasonLine(text) + 0.5 }))
    .filter((entry) => Number.isFinite(entry.score) && entry.score >= 2)
    .sort((left, right) => Number(right.score || 0) - Number(left.score || 0));
  const whyThisOne = pickFirstTrimmed(
    rankedReasons[0]?.text,
    rankedTradeoffs[0]?.text,
    buildGroundedAlternativeFallbackVisibleShopperCopy(item),
  );
  return {
    whyThisOne,
    shortDescription: whyThisOne ? truncateRecoNarrativeSnippet(whyThisOne, 110) : '',
  };
}

function collectGroundedAlternativeAuthorityExperience(candidate) {
  const normalized = normalizeRecoCatalogProduct(candidate);
  if (!normalized) {
    return {
      compareHighlights: [],
      productIntel: null,
      shoppingCard: null,
      searchCard: null,
      pivotaInsights: null,
    };
  }
  const compareHighlights = buildRecoCompareHighlightsFromInsightFields({
    row: normalized,
    pivotaInsights: normalized.pivota_insights,
    shoppingCard: normalized.shopping_card,
  });
  return {
    compareHighlights,
    productIntel: normalized.product_intel || null,
    shoppingCard: normalized.shopping_card || null,
    searchCard: normalized.search_card || null,
    pivotaInsights: normalized.pivota_insights || null,
    whyThisOne: pickFirstTrimmed(normalized.why_this_one),
    keyFeatures: asStringArray(normalized.key_features, 6),
    shortDescription: pickFirstTrimmed(normalized.short_description),
    description: pickFirstTrimmed(normalized.description),
    bestFor: pickFirstTrimmed(normalized.best_for),
  };
}

function extractRecoAlternativeProductIntelBundleFromKbEntry(entry) {
  const analysis = isPlainObject(entry?.analysis) ? entry.analysis : null;
  if (!analysis) return null;
  return pickRecoProductIntelBundle({ analysis });
}

function collectGroundedAlternativeAuthorityExperienceFromBundle(bundle, fallbackRow = null) {
  const sourceRow = {
    ...(isPlainObject(fallbackRow) ? fallbackRow : {}),
    product_intel: bundle,
    ...(isPlainObject(bundle?.shopping_card) ? { shopping_card: bundle.shopping_card } : {}),
    ...(isPlainObject(bundle?.search_card) ? { search_card: bundle.search_card } : {}),
  };
  const shoppingCard = pickRecoShoppingCardPayload(sourceRow);
  const searchCard = pickRecoSearchCardPayload(sourceRow);
  const pivotaInsights = pickRecoPivotaInsights(sourceRow);
  const bestForItems = Array.isArray(bundle?.product_intel_core?.best_for)
    ? bundle.product_intel_core.best_for.map((item) => pickFirstTrimmed(item?.label, item)).filter(Boolean)
    : [];
  return {
    compareHighlights: buildRecoCompareHighlightsFromInsightFields({
      row: sourceRow,
      pivotaInsights,
      shoppingCard,
    }),
    productIntel: bundle,
    shoppingCard,
    searchCard,
    pivotaInsights,
    whyThisOne: pickFirstTrimmed(
      fallbackRow?.why_this_one,
      shoppingCard?.intro,
      bundle?.product_intel_core?.what_it_is?.body,
    ),
    keyFeatures: asStringArray([
      ...(Array.isArray(fallbackRow?.key_features) ? fallbackRow.key_features : []),
      ...bestForItems,
    ], 6),
    shortDescription: pickFirstTrimmed(
      fallbackRow?.short_description,
      shoppingCard?.intro,
    ),
    description: pickFirstTrimmed(
      fallbackRow?.description,
      bundle?.product_intel_core?.what_it_is?.body,
    ),
    bestFor: pickFirstTrimmed(
      fallbackRow?.best_for,
      bestForItems[0],
    ),
  };
}

function applyGroundedAlternativeAuthorityExperience(row, candidate) {
  const item = isPlainObject(row) ? { ...row } : {};
  const experience = collectGroundedAlternativeAuthorityExperience(candidate);
  const derivedShopperCopy = buildGroundedAlternativeVisibleShopperCopy(item);
  const next = {
    ...item,
    ...(experience.compareHighlights.length ? { compare_highlights: experience.compareHighlights } : {}),
    ...(experience.productIntel ? { product_intel: experience.productIntel } : {}),
    ...(experience.shoppingCard ? { shopping_card: experience.shoppingCard } : {}),
    ...(experience.searchCard ? { search_card: experience.searchCard } : {}),
    ...(experience.pivotaInsights ? { pivota_insights: experience.pivotaInsights } : {}),
    ...(pickFirstTrimmed(derivedShopperCopy.whyThisOne, experience.whyThisOne) ? { why_this_one: pickFirstTrimmed(derivedShopperCopy.whyThisOne, experience.whyThisOne) } : {}),
    ...(experience.keyFeatures.length ? { key_features: experience.keyFeatures } : {}),
    ...(pickFirstTrimmed(derivedShopperCopy.shortDescription, experience.shortDescription) ? { short_description: pickFirstTrimmed(derivedShopperCopy.shortDescription, experience.shortDescription) } : {}),
    ...(experience.description ? { description: experience.description } : {}),
    ...(experience.bestFor ? { best_for: experience.bestFor } : {}),
  };
  if (isGenericGroundedAlternativeCopy(next) && experience.compareHighlights.length) {
    next.reasons = experience.compareHighlights.slice(0, 2);
  }
  return next;
}

function applyGroundedAlternativeAuthorityBundleExperience(row, bundle) {
  const item = isPlainObject(row) ? { ...row } : {};
  const experience = collectGroundedAlternativeAuthorityExperienceFromBundle(bundle, item);
  const derivedShopperCopy = buildGroundedAlternativeVisibleShopperCopy(item);
  const next = {
    ...item,
    ...(experience.compareHighlights.length ? { compare_highlights: experience.compareHighlights } : {}),
    ...(experience.productIntel ? { product_intel: experience.productIntel } : {}),
    ...(experience.shoppingCard ? { shopping_card: experience.shoppingCard } : {}),
    ...(experience.searchCard ? { search_card: experience.searchCard } : {}),
    ...(experience.pivotaInsights ? { pivota_insights: experience.pivotaInsights } : {}),
    ...(pickFirstTrimmed(derivedShopperCopy.whyThisOne, experience.whyThisOne) ? { why_this_one: pickFirstTrimmed(derivedShopperCopy.whyThisOne, experience.whyThisOne) } : {}),
    ...(experience.keyFeatures.length ? { key_features: experience.keyFeatures } : {}),
    ...(pickFirstTrimmed(derivedShopperCopy.shortDescription, experience.shortDescription) ? { short_description: pickFirstTrimmed(derivedShopperCopy.shortDescription, experience.shortDescription) } : {}),
    ...(experience.description ? { description: experience.description } : {}),
    ...(experience.bestFor ? { best_for: experience.bestFor } : {}),
    metadata: {
      ...(item.metadata && typeof item.metadata === 'object' && !Array.isArray(item.metadata) ? item.metadata : {}),
      product_intel_kb_used: true,
    },
  };
  if (isGenericGroundedAlternativeCopy(next) && experience.compareHighlights.length) {
    next.reasons = experience.compareHighlights.slice(0, 2);
  }
  return next;
}

async function hydrateRecoAlternativeAuthorityExperienceRow(row) {
  const item = isPlainObject(row) ? row : null;
  if (!item) return row;
  if (String(item.grounding_status || '').trim().toLowerCase() !== 'catalog_verified') return item;
  if (pickRecoProductIntelBundle(item)) return item;
  const product = getRecoAlternativeProductObject(item);
  const productId = pickFirstTrimmed(
    product.product_id,
    item.product_id,
    item.canonical_product_ref?.product_id,
    item.pdp_open?.product_ref?.product_id,
  );
  if (!productId) return item;
  let kbEntry = null;
  try {
    kbEntry = await getProductIntelKbEntry(`product:${productId}`);
  } catch {
    kbEntry = null;
  }
  const bundle = extractRecoAlternativeProductIntelBundleFromKbEntry(kbEntry);
  if (!bundle) return item;
  return applyGroundedAlternativeAuthorityBundleExperience(item, bundle);
}

async function hydrateRecoAlternativesAuthorityExperienceRows(rows) {
  const list = Array.isArray(rows) ? rows : [];
  if (!list.length) return [];
  const settled = await Promise.allSettled(list.map((row) => hydrateRecoAlternativeAuthorityExperienceRow(row)));
  return settled.map((result, index) => (result.status === 'fulfilled' ? result.value : list[index]));
}

function mapCatalogGroundedOpenWorldAlternative(
  openWorldRow,
  catalogRow,
  {
    matchScore = 0,
    query = '',
    groundingMode = 'catalog_exact_search',
    queryVariant = '',
    queryVariants = [],
    authorityPresence = '',
    searchHitCount = 0,
    targetSignals = null,
  } = {},
) {
  const normalized = normalizeRecoCatalogProduct(catalogRow);
  if (!normalized) return openWorldRow;
  const productId = pickFirstTrimmed(normalized.product_id, normalized.sku_id);
  const candidateLabel = joinBrandAndName(normalized.brand, pickFirstTrimmed(normalized.display_name, normalized.name));
  const pdpUrl = extractCandidateOpenUrl(normalized);
  const pdpOpen = normalized.canonical_product_ref
    ? { path: 'ref', product_ref: normalized.canonical_product_ref }
    : normalized.product_group_id
      ? { path: 'group', product_group_id: normalized.product_group_id }
      : pdpUrl
        ? { path: 'external', external: { url: pdpUrl, query: candidateLabel } }
        : productId
          ? {
              path: 'resolve',
              product_ref: {
                product_id: normalized.product_id,
                ...(normalized.merchant_id ? { merchant_id: normalized.merchant_id } : {}),
              },
              external: { query: candidateLabel },
            }
          : { path: 'external', external: { query: candidateLabel } };
  const grounded = applyGroundedAlternativeAuthorityExperience({
    ...openWorldRow,
    candidate_origin: 'pool',
    grounding_status: 'catalog_verified',
    product: {
      ...(normalized.product_id ? { product_id: normalized.product_id } : {}),
      ...(normalized.merchant_id ? { merchant_id: normalized.merchant_id } : {}),
      ...(normalized.product_group_id ? { product_group_id: normalized.product_group_id } : {}),
      ...(normalized.sku_id ? { sku_id: normalized.sku_id } : {}),
      ...(normalized.brand ? { brand: normalized.brand } : {}),
      name: pickFirstTrimmed(normalized.display_name, normalized.name),
      ...(normalized.category ? { category: normalized.category } : {}),
      ...(pdpUrl ? { pdp_url: pdpUrl, url: pdpUrl } : {}),
      ...(normalized.price && typeof normalized.price === 'object' ? { price: normalized.price } : {}),
    },
    ...(normalized.brand ? { brand: normalized.brand } : {}),
    name: pickFirstTrimmed(normalized.display_name, normalized.name),
    pdp_open: pdpOpen,
    metadata: {
      ...(openWorldRow?.metadata && typeof openWorldRow.metadata === 'object' && !Array.isArray(openWorldRow.metadata) ? openWorldRow.metadata : {}),
      compare_stage: 'open_world_grounded_catalog',
      catalog_grounding_query: String(query || '').trim() || null,
      catalog_grounding_mode: groundingMode,
      catalog_grounding_score: Number(matchScore.toFixed(3)),
      ...(queryVariant ? { catalog_grounding_query_variant: queryVariant } : {}),
      ...(Array.isArray(queryVariants) && queryVariants.length
        ? { catalog_grounding_query_variants: queryVariants.slice(0, 6) }
        : {}),
      ...(authorityPresence ? { authority_presence_class: authorityPresence } : {}),
      ...(searchHitCount > 0 ? { authority_hit_count: Math.max(0, Math.trunc(Number(searchHitCount) || 0)) } : {}),
      merged_candidate_origins: ['open_world', 'pool'],
    },
  }, normalized);
  return applyRecoAlternativeCosmeticFinishPenaltyToRow(grounded, {
    targetSignals,
    candidateText: buildRecoAlternativePoolCandidateText(normalized),
    candidateLabel,
  });
}

function buildOpenWorldAlternativeResolveHints(openWorldRow) {
  const row = isPlainObject(openWorldRow) ? openWorldRow : {};
  const product = getRecoAlternativeProductObject(row);
  const brand = pickFirstTrimmed(product.brand, row.brand);
  const name = pickFirstTrimmed(product.display_name, product.displayName, product.name, row.name);
  const displayName = pickFirstTrimmed(product.display_name, product.displayName, name);
  const aliasLabel = joinBrandAndName(brand, displayName || name);
  const authorityAliases = buildRecoAuthoritySearchAliases({
    brand,
    name: displayName || name,
    category: pickFirstTrimmed(product.category, product.product_type, row.product_type),
    usageRole: pickFirstTrimmed(row?.metadata?.usage_role),
    searchAliases: uniqCaseInsensitiveStrings(
      [
        ...asStringArray(row.search_aliases, 8),
        aliasLabel,
        displayName,
        name,
      ],
      8,
    ),
    maxAliases: 8,
  });
  const base = {
    ...row,
    ...(aliasLabel
      ? {
          search_aliases: authorityAliases,
        }
      : {}),
  };
  return buildRecoResolveHints({
    base,
    skuCandidate: product,
    rawProductId: null,
    rawMerchantId: null,
    brand,
    name,
    displayName,
  });
}

function sanitizeOpenWorldAlternativeVisibleCopy(row, {
  targetSignals = null,
  mode = 'name_only',
} = {}) {
  const item = isPlainObject(row) ? row : {};
  const product = getRecoAlternativeProductObject(item);
  const productType = pickFirstTrimmed(
    product.category,
    product.product_type,
    item.product_type,
    targetSignals?.productType,
    targetSignals?.category,
  );
  const targetRole = String(targetSignals?.usageRole || '').trim().toLowerCase();
  const roleLabel = targetRole && targetRole !== 'unknown' ? targetRole.replace(/_/g, ' ') : '';
  const reasonPrimary = roleLabel
    ? `Same ${roleLabel} step as the anchor.`
    : productType
      ? `Same ${String(productType).trim().toLowerCase()} step as the anchor.`
      : 'Same product step as the anchor.';
  const reasonSecondary = mode === 'resolved_ref'
    ? 'Resolved to a live product entry you can open for details.'
    : 'Presented as a distinct option for this compare.';
  const tradeoff = mode === 'resolved_ref'
    ? 'Open details to verify formula specifics before comparing actives or finish.'
    : 'Key formula details still need verification before comparing actives or finish.';
  return {
    ...item,
    reasons: uniqCaseInsensitiveStrings([reasonPrimary, reasonSecondary], 2),
    tradeoff_notes: [tradeoff],
    metadata: {
      ...(item.metadata && typeof item.metadata === 'object' && !Array.isArray(item.metadata) ? item.metadata : {}),
      name_only_copy_sanitized: true,
      visible_copy_mode: mode,
    },
  };
}

function markOpenWorldAlternativeVisibleCopy(row, { mode = 'name_only' } = {}) {
  const item = isPlainObject(row) ? row : {};
  return {
    ...item,
    metadata: {
      ...(item.metadata && typeof item.metadata === 'object' && !Array.isArray(item.metadata) ? item.metadata : {}),
      needs_conservative_copy: true,
      visible_copy_mode: mode,
    },
  };
}

function maybeApplyOpenWorldAlternativeVisibleCopy(row, { targetSignals = null } = {}) {
  const item = isPlainObject(row) ? row : row;
  if (!isPlainObject(item)) return row;
  const metadata = item.metadata && typeof item.metadata === 'object' && !Array.isArray(item.metadata)
    ? item.metadata
    : {};
  if (metadata.needs_conservative_copy !== true) return item;
  const origin = String(item.candidate_origin || '').trim().toLowerCase();
  const grounding = String(item.grounding_status || '').trim().toLowerCase();
  if (origin !== 'open_world' || grounding === 'catalog_verified') {
    const nextMetadata = { ...metadata };
    delete nextMetadata.needs_conservative_copy;
    return {
      ...item,
      metadata: nextMetadata,
    };
  }
  const sanitized = sanitizeOpenWorldAlternativeVisibleCopy(item, {
    targetSignals,
    mode: pickFirstTrimmed(metadata.visible_copy_mode, 'name_only') || 'name_only',
  });
  const nextMetadata =
    sanitized.metadata && typeof sanitized.metadata === 'object' && !Array.isArray(sanitized.metadata)
      ? { ...sanitized.metadata }
      : {};
  delete nextMetadata.needs_conservative_copy;
  return {
    ...sanitized,
    metadata: nextMetadata,
  };
}

function hasRecoAlternativeBareSkinToneCorrectionClaim(value) {
  const text = String(value || '').trim();
  if (!text) return false;
  if (!/\bskin\s+tone\b/i.test(text)) return false;
  return !/\b(?:all|any|every)\s+skin\s+tones?\b/i.test(text);
}

function shouldDropRecoAlternativeOffTargetVisibleClaim(value, { targetSignals = null } = {}) {
  const text = String(value || '').trim();
  if (!text) return false;
  const targetText = [
    targetSignals?.roleScope,
    targetSignals?.usageRole,
    targetSignals?.productType,
    targetSignals?.category,
    ...(Array.isArray(targetSignals?.explicitClaims) ? targetSignals.explicitClaims : []),
    ...(Array.isArray(targetSignals?.heroIngredients) ? targetSignals.heroIngredients : []),
    ...(Array.isArray(targetSignals?.knownActives) ? targetSignals.knownActives : []),
  ].filter(Boolean).join(' ');
  const allowedFamilies = collectRecoAssistantConcernFamilies(targetText);
  if (!allowedFamilies.size) return false;
  const claimFamilies = collectRecoAssistantConcernFamilies(text);
  if (!claimFamilies.size) return false;
  const hasUnallowedToneClaim =
    !allowedFamilies.has('tone_brightening') &&
    (
      /\b(dull(?:ness)?|uneven\s+tone|dark\s+spots?|hyperpigmentation|brighten(?:ing)?|radiance|radiant|glow(?:ing)?|improv(?:e|es|ing)\s+(?:the\s+look\s+of\s+)?skin\s+tone|even(?:s|ing)?\s+skin\s+tone)\b/i.test(text) ||
      hasRecoAlternativeBareSkinToneCorrectionClaim(text)
    );
  if (hasUnallowedToneClaim) return true;
  const hasUnallowedAgingClaim =
    !allowedFamilies.has('aging_texture') &&
    /\b(wrinkles?|fine[-\s]?lines?|aging|anti[-\s]?aging|roughness|retinol|retinoid)\b/i.test(text);
  if (hasUnallowedAgingClaim) return true;
  const hasAllowedFamily = Array.from(claimFamilies).some((family) => allowedFamilies.has(family));
  const hasUnallowedAcneOnlyClaim =
    !hasAllowedFamily &&
    !allowedFamilies.has('acne_pore') &&
    /\b(acne|breakouts?|blemish(?:es)?|clog(?:ged)?|pores?|breakout[-\s]?prone)\b/i.test(text);
  if (hasUnallowedAcneOnlyClaim) return true;
  const hasUnallowedSensitivityOnlyClaim =
    !hasAllowedFamily &&
    !allowedFamilies.has('sensitivity_redness') &&
    /\b(redness|sensitive|sensitized|irritat(?:e|ion)|stinging?|red[-\s]?prone)\b/i.test(text);
  return hasUnallowedSensitivityOnlyClaim;
}

function redactRecoAlternativeOffTargetVisibleClaim(value, { targetSignals = null } = {}) {
  const text = String(value || '').trim();
  if (!text) return '';
  const targetText = [
    targetSignals?.roleScope,
    targetSignals?.usageRole,
    targetSignals?.productType,
    targetSignals?.category,
    ...(Array.isArray(targetSignals?.explicitClaims) ? targetSignals.explicitClaims : []),
    ...(Array.isArray(targetSignals?.heroIngredients) ? targetSignals.heroIngredients : []),
    ...(Array.isArray(targetSignals?.knownActives) ? targetSignals.knownActives : []),
  ].filter(Boolean).join(' ');
  const allowedFamilies = collectRecoAssistantConcernFamilies(targetText);
  const claimFamilies = collectRecoAssistantConcernFamilies(text);
  const hasAllowedFamily = Array.from(claimFamilies).some((family) => allowedFamilies.has(family));
  if (!hasAllowedFamily) {
    return shouldDropRecoAlternativeOffTargetVisibleClaim(text, { targetSignals }) ? '' : text;
  }
  let next = text;
  if (!allowedFamilies.has('tone_brightening')) {
    const protectedSkinToneFitPhrases = [];
    next = next.replace(/\b(?:all|any|every)\s+skin\s+tones?\b/gi, (match) => {
      const token = `__reco_alt_skin_tone_fit_${protectedSkinToneFitPhrases.length}__`;
      protectedSkinToneFitPhrases.push({ token, match });
      return token;
    });
    const toneTerms = 'dull(?:ness)?|uneven\\s+tone|dark\\s+spots?|hyperpigmentation|brighten(?:ing)?|radiance|radiant|glow(?:ing)?(?:\\s+skin)?|improv(?:e|es|ing)\\s+(?:the\\s+look\\s+of\\s+)?skin\\s+tone|even(?:s|ing)?\\s+skin\\s+tone|skin\\s+tone';
    next = next
      .replace(new RegExp(`\\s+(?:and|or|plus)\\s+(?:${toneTerms})\\b`, 'gi'), '')
      .replace(new RegExp(`\\b(?:${toneTerms})\\s+(?:and|or|plus)\\s+`, 'gi'), '')
      .replace(new RegExp(`\\s+for\\s+(?:${toneTerms})\\b`, 'gi'), '')
      .replace(new RegExp(`\\s*,\\s*(?:${toneTerms})\\b`, 'gi'), '')
      .replace(new RegExp(`\\s+(?:${toneTerms})(?=\\s+with\\b|[.;:]|$)`, 'gi'), '');
    for (const item of protectedSkinToneFitPhrases) {
      next = next.replace(item.token, item.match);
    }
  }
  if (!allowedFamilies.has('aging_texture')) {
    const agingTerms = 'wrinkles?|fine[-\\s]?lines?(?:\\s+support)?|aging|anti[-\\s]?aging|roughness|retinol|retinoid';
    next = next
      .replace(new RegExp(`\\s+(?:and|or|plus)\\s+(?:${agingTerms})\\b`, 'gi'), '')
      .replace(new RegExp(`\\b(?:${agingTerms})\\s+(?:and|or|plus)\\s+`, 'gi'), '')
      .replace(new RegExp(`\\s*,\\s*(?:${agingTerms})\\b`, 'gi'), '');
  }
  if (!allowedFamilies.has('sensitivity_redness')) {
    const sensitivityTerms = 'redness|sensitive(?:\\s+skin(?:\\s+profiles?)?)?|sensitized|irritat(?:e|ion)|stinging?|red[-\\s]?prone';
    next = next
      .replace(new RegExp(`\\s+(?:and|or|plus)\\s+(?:${sensitivityTerms})\\b`, 'gi'), '')
      .replace(new RegExp(`\\b(?:${sensitivityTerms})\\s+(?:and|or|plus)\\s+`, 'gi'), '')
      .replace(new RegExp(`,?\\s+including\\s+(?:${sensitivityTerms})\\b`, 'gi'), '')
      .replace(/\s+which may increase (?:the )?(?:risk of )?(?:irritation|sensitivity)(?: risk)?\.?/gi, '')
      .replace(/\s+may increase (?:the )?(?:risk of )?(?:irritation|sensitivity)(?: risk)?\.?/gi, '')
      .replace(new RegExp(`\\s*,\\s*(?:${sensitivityTerms})\\b`, 'gi'), '');
  }
  next = next
    .replace(/\s+([.,;:!?])/g, '$1')
    .replace(/,\s*$/g, '')
    .replace(/\s{2,}/g, ' ')
    .trim();
  if (!next) return '';
  if (shouldDropRecoAlternativeOffTargetVisibleClaim(next, { targetSignals })) return '';
  const redactedFamilies = collectRecoAssistantConcernFamilies(next);
  const stillHasAllowedFamily = Array.from(redactedFamilies).some((family) => allowedFamilies.has(family));
  return stillHasAllowedFamily ? next : '';
}

function filterRecoAlternativeOffTargetVisibleCopy(row, { targetSignals = null } = {}) {
  const item = isPlainObject(row) ? row : null;
  if (!item) return row;
  const next = { ...item };
  let droppedCount = 0;
  const filterField = (field, max = 4) => {
    const original = asStringArray(next[field], max);
    if (!original.length) return;
    const filtered = [];
    let changedCount = 0;
    for (const value of original) {
      const redacted = redactRecoAlternativeOffTargetVisibleClaim(value, { targetSignals });
      if (!redacted) {
        changedCount += 1;
        continue;
      }
      if (redacted !== value) changedCount += 1;
      filtered.push(redacted);
    }
    droppedCount += changedCount;
    if (filtered.length) next[field] = filtered;
    else delete next[field];
  };
  filterField('reasons', 4);
  filterField('compare_highlights', 5);
  filterField('tradeoff_notes', 4);
  if (!Array.isArray(next.reasons) || !next.reasons.length) {
    const role = pickFirstTrimmed(targetSignals?.usageRole, targetSignals?.productType, targetSignals?.category);
    if (role) next.reasons = [`Same ${String(role).replace(/_/g, ' ').toLowerCase()} step as the anchor.`];
  }
  if (droppedCount <= 0) return item;
  return {
    ...next,
    metadata: {
      ...(item.metadata && typeof item.metadata === 'object' && !Array.isArray(item.metadata) ? item.metadata : {}),
      off_target_visible_claims_filtered: true,
      off_target_visible_claims_dropped: droppedCount,
    },
  };
}

function applyOpenWorldAlternativeVisibleCopy(rows, { targetSignals = null } = {}) {
  return (Array.isArray(rows) ? rows : []).map((row) =>
    filterRecoAlternativeOffTargetVisibleCopy(
      maybeApplyOpenWorldAlternativeVisibleCopy(row, { targetSignals }),
      { targetSignals },
    ));
}

function isCatalogVerifiedRecoAlternative(row) {
  const item = isPlainObject(row) ? row : {};
  return String(item.grounding_status || '').trim().toLowerCase() === 'catalog_verified';
}

function applyFinalRecoAlternativeVisibleShopperCopy(row) {
  const item = isPlainObject(row) ? { ...row } : row;
  if (!isPlainObject(item) || !isCatalogVerifiedRecoAlternative(item)) return item;
  const derived = buildGroundedAlternativeVisibleShopperCopy(item);
  const whyThisOne = pickFirstTrimmed(derived.whyThisOne, item.why_this_one, item.whyThisOne);
  const shortDescription = pickFirstTrimmed(derived.shortDescription, item.short_description, item.shortDescription);
  return {
    ...item,
    ...(whyThisOne ? { why_this_one: whyThisOne } : {}),
    ...(shortDescription ? { short_description: shortDescription } : {}),
  };
}

function filterRecoAlternativesVisibleAuthorityRows(rows, { minGrounded = 1 } = {}) {
  const list = Array.isArray(rows) ? rows.filter((row) => isPlainObject(row)) : [];
  const grounded = list.filter(isCatalogVerifiedRecoAlternative);
  const minimum = Math.max(1, Math.trunc(Number(minGrounded) || 2));
  if (grounded.length < minimum) {
    return {
      alternatives: list.map((row) => applyFinalRecoAlternativeVisibleShopperCopy(row)),
      hidden_unresolved_count: 0,
      visible_authority_only_filter_applied: false,
    };
  }
  return {
    alternatives: grounded.map((row) => applyFinalRecoAlternativeVisibleShopperCopy(row)),
    hidden_unresolved_count: Math.max(0, list.length - grounded.length),
    visible_authority_only_filter_applied: grounded.length !== list.length,
  };
}

function mapResolverGroundedOpenWorldAlternative(openWorldRow, {
  canonicalProductRef = null,
  canonicalProductGroupId = null,
  query = '',
  targetSignals = null,
  groundingMode = 'resolver_ref',
  queryVariant = '',
  queryVariants = [],
  authorityPresence = '',
  resolverSource = '',
} = {}) {
  const row = isPlainObject(openWorldRow) ? openWorldRow : {};
  const product = getRecoAlternativeProductObject(row);
  const normalizedGroupId = pickFirstTrimmed(canonicalProductGroupId);
  const normalizedRef =
    normalizeCanonicalProductRef(canonicalProductRef, {
      requireMerchant: true,
      allowOpaqueProductId: false,
    }) || extractCanonicalRefFromProductGroupId(normalizedGroupId);
  if (!normalizedRef && !normalizedGroupId) {
    return sanitizeOpenWorldAlternativeVisibleCopy(row, { targetSignals, mode: 'name_only' });
  }
  const brand = pickFirstTrimmed(product.brand, row.brand);
  const name = pickFirstTrimmed(product.display_name, product.displayName, product.name, row.name);
  const category = pickFirstTrimmed(product.category, product.product_type, row.product_type);
  const internalUrl = normalizedRef
    ? buildInternalPdpUrlFromTarget({
        productId: normalizedRef.product_id,
        merchantId: normalizedRef.merchant_id,
      })
    : '';
  const next = {
    ...row,
    candidate_origin: 'open_world',
    grounding_status: 'catalog_verified',
    product: {
      ...(product && typeof product === 'object' && !Array.isArray(product) ? product : {}),
      ...(normalizedRef?.product_id ? { product_id: normalizedRef.product_id } : {}),
      ...(normalizedRef?.merchant_id ? { merchant_id: normalizedRef.merchant_id } : {}),
      ...(normalizedGroupId ? { product_group_id: normalizedGroupId } : {}),
      ...(brand ? { brand } : {}),
      ...(name ? { name } : {}),
      ...(category ? { category } : {}),
      ...(internalUrl ? { pdp_url: internalUrl, url: internalUrl } : {}),
    },
    ...(brand ? { brand } : {}),
    ...(name ? { name } : {}),
    ...(normalizedRef ? { canonical_product_ref: normalizedRef } : {}),
    pdp_open: normalizedGroupId
      ? { path: 'group', product_group_id: normalizedGroupId }
      : normalizedRef
        ? { path: 'ref', product_ref: normalizedRef }
        : {
            path: 'external',
            external: {
              query: joinBrandAndName(brand, name),
            },
          },
    metadata: {
      ...(row.metadata && typeof row.metadata === 'object' && !Array.isArray(row.metadata) ? row.metadata : {}),
      compare_stage: groundingMode === 'catalog_search_ref'
        ? 'open_world_grounded_catalog_search'
        : 'open_world_grounded_resolver',
      catalog_grounding_query: String(query || '').trim() || null,
      catalog_grounding_mode: groundingMode,
      ...(queryVariant ? { catalog_grounding_query_variant: queryVariant } : {}),
      ...(Array.isArray(queryVariants) && queryVariants.length
        ? { catalog_grounding_query_variants: queryVariants.slice(0, 6) }
        : {}),
      ...(authorityPresence ? { authority_presence_class: authorityPresence } : {}),
      ...(resolverSource ? { catalog_grounding_resolver_source: resolverSource } : {}),
      merged_candidate_origins: ['open_world', 'pool'],
    },
  };
  return applyRecoAlternativeCosmeticFinishPenaltyToRow(next, {
    targetSignals,
    candidateText: [
      category,
      ...(Array.isArray(next.reasons) ? next.reasons : []),
      ...(Array.isArray(next.tradeoff_notes) ? next.tradeoff_notes : []),
    ].join(' '),
    candidateLabel: joinBrandAndName(brand, name),
  });
}

async function groundOpenWorldAlternativesToCatalog(rows, { logger, targetSignals = null } = {}) {
  const list = Array.isArray(rows) ? rows : [];
  if (!list.length) {
    return {
      alternatives: [],
      grounded_count: 0,
      attempted_count: 0,
      failure_class_counts: { coverage_miss: 0, recall_miss: 0 },
    };
  }
  const groundOne = async (row) => {
    const origin = String(row?.candidate_origin || '').trim().toLowerCase();
    const grounding = String(row?.grounding_status || '').trim().toLowerCase();
    if (origin !== 'open_world' || grounding === 'catalog_verified') {
      return { row, grounded: false, attempted: false, failureClass: null };
    }
    const product = getRecoAlternativeProductObject(row);
    const brand = pickFirstTrimmed(product.brand, row?.brand);
    const name = pickFirstTrimmed(product.name, row?.name);
    const queryPack = buildOpenWorldAlternativeAuthorityQueryPack(row, { targetSignals });
    const fallbackQuery = joinBrandAndName(brand, name);
    if ((!brand || !name || !fallbackQuery) && !queryPack.length) {
      return { row, grounded: false, attempted: false, failureClass: null };
    }
    const queries = queryPack.length
      ? queryPack
      : [{ query: fallbackQuery, normalized_query: fallbackQuery.toLowerCase(), kind: 'brand_name_exact' }];
    let best = null;
    const seenAuthorityCandidates = new Set();
    const queryVariants = queries.map((entry) => String(entry?.query || '').trim()).filter(Boolean);
    let searchHitCount = 0;
    let lastResolverSource = '';
    try {
      for (const variant of queries.slice(0, 4)) {
        // eslint-disable-next-line no-await-in-loop
        const searched = await searchPivotaBackendProducts({
          query: variant.query,
          limit: 5,
          logger,
          timeoutMs: 700,
          minTimeoutMs: 220,
          mode: 'main_path',
          allowExternalSeed: true,
          externalSeedStrategy: 'supplement_internal_first',
          fastMode: true,
        });
        for (const candidate of Array.isArray(searched?.products) ? searched.products : []) {
          const normalizedCandidate = normalizeRecoCatalogProduct(candidate);
          const candidateKey = normalizeRecoDedupeToken(
            pickFirstTrimmed(
              normalizedCandidate?.product_id,
              normalizedCandidate?.sku_id,
              normalizedCandidate?.merchant_id && normalizedCandidate?.name
                ? `${normalizedCandidate.merchant_id}:${normalizedCandidate.name}`
                : '',
            ),
          );
          if (candidateKey && !seenAuthorityCandidates.has(candidateKey)) {
            seenAuthorityCandidates.add(candidateKey);
            searchHitCount += 1;
          }
          const scored = scoreRecoAlternativeCatalogGroundingMatch(row, candidate);
          if (!scored.ok) continue;
          if (!best || scored.score > best.score) {
            best = {
              ...scored,
              raw: candidate,
              query: variant.query,
              queryVariant: variant.kind,
              authorityPresence: classifyRecoAuthorityHitSource(candidate),
            };
          }
        }
        if (best?.score >= 0.94) break;
      }
    } catch (err) {
      logger?.warn?.(
        { err: err?.message || String(err), query_variants: queryVariants.slice(0, 3) },
        'aurora bff: alternatives catalog grounding failed',
      );
    }
    if (best?.candidate) {
      return {
        row: mapCatalogGroundedOpenWorldAlternative(row, best.candidate, {
          matchScore: best.score,
          query: best.query || fallbackQuery,
          groundingMode: best.matchMode || 'catalog_exact_search',
          queryVariant: best.queryVariant,
          queryVariants,
          authorityPresence: best.authorityPresence,
          searchHitCount,
          targetSignals,
        }),
        grounded: true,
        attempted: true,
        failureClass: null,
      };
    }
    try {
      for (const variant of queries.slice(0, 3)) {
        const resolverHints = buildOpenWorldAlternativeResolveHints({
          ...row,
          search_aliases: buildRecoAuthoritySearchAliases({
            brand,
            name,
            category: pickFirstTrimmed(product.category, product.product_type, row.product_type, targetSignals?.productType),
            usageRole: pickFirstTrimmed(targetSignals?.usageRole),
            searchAliases: queryVariants,
            maxAliases: 8,
          }),
        });
        // eslint-disable-next-line no-await-in-loop
        const resolved = await resolveRecoPdpByLocalResolver({
          queryText: variant.query,
          hints: resolverHints,
          logger,
          timeoutMs: 650,
          allowExternalSeed: true,
          externalSeedStrategy: 'supplement_internal_first',
        });
        lastResolverSource = summarizeResolverAuthoritySource(resolved);
        if (resolved?.ok && resolved.canonicalProductRef) {
          return {
            row: mapResolverGroundedOpenWorldAlternative(row, {
              canonicalProductRef: resolved.canonicalProductRef,
              query: variant.query,
              targetSignals,
              groundingMode: 'resolver_ref',
              queryVariant: variant.kind,
              queryVariants,
              authorityPresence: lastResolverSource || (searchHitCount > 0 ? 'present_but_unresolved' : ''),
              resolverSource: lastResolverSource,
            }),
            grounded: true,
            attempted: true,
            failureClass: null,
          };
        }
      }
    } catch (err) {
      logger?.warn?.(
        { err: err?.message || String(err), query_variants: queryVariants.slice(0, 3) },
        'aurora bff: alternatives resolver grounding failed',
      );
    }
    const failureClass = searchHitCount > 0 ? 'recall_miss' : 'coverage_miss';
    return {
      row: markOpenWorldAlternativeVisibleCopy({
        ...row,
        metadata: {
          ...(row?.metadata && typeof row.metadata === 'object' && !Array.isArray(row.metadata) ? row.metadata : {}),
          authority_presence_class: searchHitCount > 0 ? 'present_but_unresolved' : 'missing_authority',
          grounding_failure_class: failureClass,
          ...(queryVariants.length ? { catalog_grounding_query_variants: queryVariants.slice(0, 6) } : {}),
          ...(lastResolverSource ? { catalog_grounding_resolver_source: lastResolverSource } : {}),
          ...(searchHitCount > 0 ? { authority_hit_count: searchHitCount } : {}),
        },
      }, { mode: 'name_only' }),
      grounded: false,
      attempted: true,
      failureClass,
    };
  };
  const settled = await Promise.allSettled(list.map((row) => groundOne(row)));
  const enriched = [];
  let groundedCount = 0;
  let attemptedCount = 0;
  const failureClassCounts = { coverage_miss: 0, recall_miss: 0 };
  for (let i = 0; i < settled.length; i += 1) {
    const result = settled[i];
    const value = result.status === 'fulfilled'
      ? result.value
      : { row: list[i], grounded: false, attempted: false, failureClass: null };
    if (value.grounded) groundedCount += 1;
    if (value.attempted) attemptedCount += 1;
    if (value.failureClass === 'coverage_miss') failureClassCounts.coverage_miss += 1;
    if (value.failureClass === 'recall_miss') failureClassCounts.recall_miss += 1;
    enriched.push(value.row || list[i]);
  }
  return {
    alternatives: enriched,
    grounded_count: groundedCount,
    attempted_count: attemptedCount,
    failure_class_counts: failureClassCounts,
  };
}

async function buildRecoAlternativesAuthorityBackfillLedger({
  ctx,
  alternatives,
  logger,
} = {}) {
  try {
    return await enqueueRecoAlternativesAuthorityBackfill({
      ctx,
      alternatives,
      logger,
    });
  } catch (err) {
    logger?.warn?.(
      {
        err: err?.message || String(err),
        request_id: ctx?.request_id || null,
        trace_id: ctx?.trace_id || null,
      },
      'aurora bff: alternatives authority backfill enqueue failed',
    );
    return {
      mode: 'async_external_seed_backfill',
      policy: 'open_world_coverage_repair',
      open_world_role: 'coverage_supplement',
      open_world_row_count: 0,
      coverage_gap_count: 0,
      recall_gap_count: 0,
      pending: false,
      status: 'enqueue_error',
      enqueued_brand_count: 0,
      enqueued_candidate_count: 0,
      brands: [],
    };
  }
}

function recordRecoAlternativesStageTiming(stageTimingsMs, name, startedAt) {
  if (!stageTimingsMs || typeof stageTimingsMs !== 'object' || !name || !Number.isFinite(Number(startedAt))) return;
  stageTimingsMs[name] = Math.max(0, Math.round(Date.now() - Number(startedAt)));
}

function buildRecoAlternativesTimingMeta(stageTimingsMs, requestStartedAt, extra = {}) {
  const timings =
    stageTimingsMs && typeof stageTimingsMs === 'object' && !Array.isArray(stageTimingsMs)
      ? Object.fromEntries(
          Object.entries(stageTimingsMs)
            .filter(([, value]) => Number.isFinite(Number(value)) && Number(value) >= 0)
            .map(([key, value]) => [key, Math.max(0, Math.round(Number(value)))]),
        )
      : {};
  return {
    ...extra,
    total_elapsed_ms: Math.max(0, Math.round(Date.now() - Number(requestStartedAt || Date.now()))),
    ...(Object.keys(timings).length ? { stage_timings_ms: timings } : {}),
  };
}

function normalizeRecoAlternativesOpenWorldModel(raw) {
  const model = pickFirstTrimmed(raw);
  const lower = String(model || '').trim().toLowerCase();
  if (!lower) return 'gemini-3-flash-preview';
  if (!lower.startsWith('gemini-')) return 'gemini-3-flash-preview';
  if (/^gemini-(?:1|2)(?:[.\-_]|$)/.test(lower)) return 'gemini-3-flash-preview';
  return model;
}

function getRecoAlternativesOpenWorldModel() {
  return normalizeRecoAlternativesOpenWorldModel(pickFirstTrimmed(
    process.env.AURORA_RECO_ALTERNATIVES_OPEN_WORLD_MODEL,
    process.env.AURORA_RUNTIME_QA_GEMINI_MODEL,
    ANALYSIS_STORY_MODEL_GEMINI,
    'gemini-3-flash-preview',
  ));
}

function getRecoAlternativesOpenWorldMaxOutputTokens() {
  const raw = Number(process.env.AURORA_RECO_ALTERNATIVES_OPEN_WORLD_MAX_OUTPUT_TOKENS);
  if (!Number.isFinite(raw)) return 3072;
  return Math.max(3072, Math.min(4096, Math.trunc(raw)));
}

function getRecoAlternativesOpenWorldTimeoutMs() {
  const raw = Number(process.env.AURORA_RECO_ALTERNATIVES_OPEN_WORLD_TIMEOUT_MS);
  if (!Number.isFinite(raw)) return 12000;
  return Math.max(3000, Math.min(20000, Math.trunc(raw)));
}

function getRecoAlternativesOpenWorldQueueTimeoutMs(timeoutMs = getRecoAlternativesOpenWorldTimeoutMs()) {
  const total = Math.max(3000, Math.min(20000, Number.isFinite(Number(timeoutMs)) ? Math.trunc(Number(timeoutMs)) : 12000));
  const raw = Number(process.env.AURORA_RECO_ALTERNATIVES_OPEN_WORLD_QUEUE_TIMEOUT_MS);
  if (Number.isFinite(raw)) {
    return Math.max(500, Math.min(Math.max(500, total - 1500), Math.trunc(raw)));
  }
  return Math.max(1000, Math.min(3500, Math.trunc(total * 0.25)));
}

function getRecoAlternativesOpenWorldUpstreamTimeoutMs(timeoutMs, queueTimeoutMs) {
  const total = Math.max(3000, Math.min(20000, Number.isFinite(Number(timeoutMs)) ? Math.trunc(Number(timeoutMs)) : 12000));
  const queue = Math.max(0, Math.min(total - 1, Number.isFinite(Number(queueTimeoutMs)) ? Math.trunc(Number(queueTimeoutMs)) : 0));
  return Math.max(1500, total - queue);
}

function buildRecoAlternativesOpenWorldUserPayload({ ctx, productInput, productObj, maxTotal } = {}) {
  const langCode = normalizeRecoPromptLanguage(ctx?.lang || 'EN');
  const targetSignals = buildRecoAlternativesTargetSignals(productObj, {
    productInput,
    lang: langCode,
  });
  const limit = Math.max(2, Math.min(3, Number.isFinite(Number(maxTotal)) ? Math.trunc(Number(maxTotal)) : 3));
  return {
    lang: langCode,
    anchor: {
      brand: targetSignals.brand,
      name: targetSignals.name,
      query: String(productInput || '').trim() || null,
      product_type: targetSignals.productType,
      usage_role: targetSignals.usageRole,
      hero_ingredients: Array.isArray(targetSignals.heroIngredients) ? targetSignals.heroIngredients.slice(0, 2) : [],
      known_actives: Array.isArray(targetSignals.knownActives) ? targetSignals.knownActives.slice(0, 2) : [],
      primary_claims: Array.isArray(targetSignals.primaryClaims) ? targetSignals.primaryClaims.slice(0, 2) : [],
      texture_hints: Array.isArray(targetSignals.textureHints) ? targetSignals.textureHints.slice(0, 1) : [],
    },
    task: {
      max_alternatives: limit,
      selection_rule: 'Return distinct real skincare alternatives anchored to the product context. For serum or treatment anchors with named actives or oil-control claims, every alternative must overlap on at least one named active or the same functional claim; do not return generic calming, repair, or same-category-only serums. Prefer the same product role and clear tradeoffs.',
    },
  };
}

function normalizeRecoAlternativesOpenWorldRows(rows, { productInput, productObj, ctx, maxTotal } = {}) {
  const langCode = normalizeRecoPromptLanguage(ctx?.lang || 'EN');
  const targetSignals = buildRecoAlternativesTargetSignals(productObj, {
    productInput,
    lang: langCode,
  });
  const limit = Math.max(1, Math.min(6, Number.isFinite(Number(maxTotal)) ? Math.trunc(Number(maxTotal)) : 3));
  const anchorLabel = joinBrandAndName(targetSignals.brand, targetSignals.name || String(productInput || '').trim());
  const anchorNameTokens = tokenizeProductTextForSimilarity(anchorLabel);
  const ingredientTokens = uniqCaseInsensitiveStrings(
    [
      ...(Array.isArray(targetSignals.heroIngredients) ? targetSignals.heroIngredients : []),
      ...(Array.isArray(targetSignals.knownActives) ? targetSignals.knownActives : []),
    ],
    8,
  );
  const claimTokens = uniqCaseInsensitiveStrings(targetSignals.primaryClaims, 6);
  const textureTokens = uniqCaseInsensitiveStrings(targetSignals.textureHints, 5);
  return (Array.isArray(rows) ? rows : [])
    .map((row) => {
      const candidate = isPlainObject(row) ? { ...row } : null;
      if (!candidate) return null;
      if (!Array.isArray(candidate.reasons) || !candidate.reasons.length) {
        const reason = pickFirstTrimmed(candidate.reason, candidate.why, candidate.rationale);
        if (reason) candidate.reasons = [reason];
      }
      if (!Array.isArray(candidate.tradeoff_notes) || !candidate.tradeoff_notes.length) {
        const tradeoff = pickFirstTrimmed(candidate.tradeoff_note, candidate.tradeoff, candidate.tradeoff_notes);
        candidate.tradeoff_notes = tradeoff ? [tradeoff] : ['Formula overlap remains uncertain.'];
      }
      return normalizeOpenWorldAlternativeRow(candidate, {
        targetSignals,
        anchorLabel,
        anchorNameTokens,
        ingredientTokens,
        claimTokens,
        textureTokens,
      });
    })
    .filter(Boolean)
    .slice(0, limit);
}

function recoverRecoAlternativesOpenWorldRowsFromTruncatedText(rawText) {
  const text = String(rawText || '');
  if (!text) return [];
  const rows = [];
  const seen = new Set();
  const decodeJsonString = (value) => {
    const raw = String(value || '');
    if (!raw) return '';
    try {
      return JSON.parse(`"${raw.replace(/\n/g, '\\n').replace(/\r/g, '\\r')}"`);
    } catch {
      return raw.replace(/\\"/g, '"').replace(/\\\\/g, '\\');
    }
  };
  const extractStringProp = (chunk, key) => {
    const pattern = new RegExp(`"${key}"\\s*:\\s*"((?:\\\\.|[^"\\\\])*)"`, 'i');
    const match = pattern.exec(chunk);
    return match ? decodeJsonString(match[1]).trim() : '';
  };
  const extractNumberProp = (chunk, key) => {
    const pattern = new RegExp(`"${key}"\\s*:\\s*([0-9]+(?:\\.[0-9]+)?)`, 'i');
    const match = pattern.exec(chunk);
    const parsed = match ? Number(match[1]) : NaN;
    return Number.isFinite(parsed) ? parsed : null;
  };
  const extractArrayStrings = (chunk, key, maxItems = 2) => {
    const pattern = new RegExp(`"${key}"\\s*:\\s*\\[([\\s\\S]*?)(?:\\]|$)`, 'i');
    const match = pattern.exec(chunk);
    if (!match) return [];
    const values = [];
    const stringPattern = /"((?:\\.|[^"\\])*)"/g;
    for (const item of match[1].matchAll(stringPattern)) {
      const decoded = decodeJsonString(item[1]).trim();
      if (decoded) values.push(decoded);
      if (values.length >= maxItems) break;
    }
    return values;
  };
  const brandMatches = Array.from(text.matchAll(/"brand"\s*:\s*"((?:\\.|[^"\\])*)"/gi));
  for (let i = 0; i < brandMatches.length; i += 1) {
    const match = brandMatches[i];
    const matchIndex = Number(match.index || 0);
    const objectStart = Math.max(0, text.lastIndexOf('{', matchIndex));
    const nextMatchIndex = brandMatches[i + 1] ? Number(brandMatches[i + 1].index || text.length) : text.length;
    const nextObjectStart = brandMatches[i + 1] ? Math.max(matchIndex + 1, text.lastIndexOf('{', nextMatchIndex)) : text.length;
    let objectEnd = text.indexOf('}', matchIndex);
    if (objectEnd < 0 || objectEnd > nextObjectStart) objectEnd = nextObjectStart - 1;
    const chunk = text.slice(objectStart, Math.max(objectStart + 1, objectEnd + 1));
    const brand = decodeJsonString(match[1]).trim();
    const name = extractStringProp(chunk, 'name');
    if (!brand || !name) continue;
    const dedupeKey = `${brand}:${name}`.toLowerCase();
    if (seen.has(dedupeKey)) continue;
    const reasons = extractArrayStrings(chunk, 'reasons', 2);
    const reason = extractStringProp(chunk, 'reason');
    const tradeoffNotes = extractArrayStrings(chunk, 'tradeoff_notes', 2);
    const tradeoffNote = extractStringProp(chunk, 'tradeoff_note');
    if (!reasons.length && !reason) continue;
    seen.add(dedupeKey);
    const productType = extractStringProp(chunk, 'product_type');
    const similarityScore = extractNumberProp(chunk, 'similarity_score');
    rows.push({
      brand,
      name,
      ...(productType ? { product_type: productType } : {}),
      ...(similarityScore != null ? { similarity_score: similarityScore } : {}),
      reasons: reasons.length ? reasons : [reason],
      tradeoff_notes: tradeoffNotes.length
        ? tradeoffNotes
        : [tradeoffNote || 'Formula overlap remains uncertain.'],
      ...(extractStringProp(chunk, 'best_use') ? { best_use: extractStringProp(chunk, 'best_use') } : {}),
    });
    if (rows.length >= 3) break;
  }
  return rows;
}

async function fetchRecoAlternativesForLocalGeminiOpenWorld({
  ctx,
  productInput,
  productObj,
  maxTotal,
  profileMode,
  logger,
} = {}) {
  const model = getRecoAlternativesOpenWorldModel();
  const maxOutputTokens = getRecoAlternativesOpenWorldMaxOutputTokens();
  const timeoutMs = getRecoAlternativesOpenWorldTimeoutMs();
  const queueTimeoutMs = getRecoAlternativesOpenWorldQueueTimeoutMs(timeoutMs);
  const upstreamTimeoutMs = getRecoAlternativesOpenWorldUpstreamTimeoutMs(timeoutMs, queueTimeoutMs);
  const systemPrompt = [
    'You are a strict skincare alternatives selector.',
    'Output STRICT JSON only.',
    'Return real skincare alternatives only. No makeup, tools, or placeholders.',
    'Do not invent URLs, product IDs, exact INCI lists, or internal references.',
    'Keep each reason grounded to the anchor product role and actives.',
    'Do not choose generic same-step products. For treatment/serum anchors, every alternative must share a named active or the same functional claim.',
    'For name-only open-world products, stay conservative: use product name, category, role, price, and availability tradeoffs only. Do not assert unseen ingredients, UV filter type, fragrance, alcohol, irritation, pilling, clinical claims, or exact finish unless supplied in the payload.',
    'Return at most 3 alternatives. Use 1 concise reason and 1 concise tradeoff note per item.',
  ].join('\n');
  const userPayload = buildRecoAlternativesOpenWorldUserPayload({ ctx, productInput, productObj, maxTotal });
  const targetSignals = buildRecoAlternativesTargetSignals(productObj, {
    productInput,
    lang: normalizeRecoPromptLanguage(ctx?.lang || 'EN'),
  });
  const startedAt = Date.now();
  let resp = null;
  try {
    resp = await callGeminiJsonObjectImpl({
      model,
      systemPrompt,
      userPrompt: JSON.stringify(userPayload, null, 2),
      timeoutMs,
      queueTimeoutMs,
      upstreamTimeoutMs,
      temperature: 0.2,
      maxOutputTokens,
      responseJsonSchema: buildExternalSeedOpenWorldSchema(),
      route: 'aurora_reco_alternatives_open_world',
      ignoreForceModel: true,
    });
  } catch (err) {
    resp = {
      ok: false,
      reason: err?.code || 'provider_error',
      detail: err?.message || String(err),
      meta: { result_reason: 'gemini_call_exception' },
    };
  }

  const llmTrace = {
    template_id: 'reco_alternatives_open_world_v1',
    source_mode: 'local_gemini_open_world',
    provider_route: 'aurora_reco_alternatives_open_world',
    provider_model: model,
    provider_reason: resp?.ok === false ? resp.reason || null : null,
    provider_detail: resp?.ok === false ? resp.detail || null : null,
    provider_timeout_stage: resp?.ok === false ? resp.timeout_stage || null : null,
    provider_total_ms: resp?.ok === false && Number.isFinite(Number(resp.total_ms)) ? Number(resp.total_ms) : null,
    provider_upstream_ms: resp?.ok === false && Number.isFinite(Number(resp.upstream_ms)) ? Number(resp.upstream_ms) : null,
    provider_result_reason: resp?.meta?.result_reason || null,
    finish_reason: resp?.finish_reason || null,
    parse_status: resp?.parse_status || null,
    latency_ms: Math.max(0, Date.now() - startedAt),
    cache_hit: false,
    error_class: resp?.ok === true ? null : classifyAlternativesFailureCode(resp?.reason),
  };

  const normalizedRows = normalizeRecoAlternativesOpenWorldRows(resp?.json?.alternatives, {
    productInput,
    productObj,
    ctx,
    maxTotal,
  });
  if (normalizedRows.length) {
    const grounded = await groundOpenWorldAlternativesToCatalog(normalizedRows, { logger, targetSignals });
    llmTrace.catalog_grounding_attempted_count = grounded.attempted_count;
    llmTrace.catalog_grounded_count = grounded.grounded_count;
    llmTrace.catalog_grounding_failure_class_counts = grounded.failure_class_counts;
    const hydratedAlternatives = await hydrateRecoAlternativesAuthorityExperienceRows(grounded.alternatives);
    const finalAlternatives = applyOpenWorldAlternativeVisibleCopy(
      sortRecoAlternativesByMixedScore(hydratedAlternatives, { useExperienceQualityBonus: true }),
      { targetSignals },
    );
    const visibleAlternatives = filterRecoAlternativesVisibleAuthorityRows(finalAlternatives, { minGrounded: 2 });
    const backfillLedger = await buildRecoAlternativesAuthorityBackfillLedger({
      ctx,
      alternatives: finalAlternatives,
      logger,
    });
    return {
      ok: true,
      alternatives: visibleAlternatives.alternatives.slice(0, Math.max(1, Math.min(6, Number(maxTotal) || 1))),
      field_missing: [],
      source_mode: 'open_world_only',
      fallback_source: null,
      refresh_pending: Boolean(backfillLedger?.pending),
      refresh_after_ms: 0,
      failure_class: null,
      attempt_count: 1,
      recommendation_mode: 'open_world_only',
      profile_mode: normalizeAlternativesProfileMode(profileMode),
      template_id: 'reco_alternatives_open_world_v1',
      raw_output_summary: summarizeRecoAlternativesRaw(resp?.json?.alternatives),
      llm_trace: llmTrace,
      compare_meta: {
        open_world_status: 'success',
        open_world_candidate_count: normalizedRows.length,
        open_world_selected_count: visibleAlternatives.alternatives.filter((row) => String(row?.candidate_origin || '') === 'open_world').length,
        open_world_grounding_attempted_count: grounded.attempted_count,
        open_world_grounded_count: grounded.grounded_count,
        visible_authority_only_filter_applied: visibleAlternatives.visible_authority_only_filter_applied,
        hidden_unresolved_count: visibleAlternatives.hidden_unresolved_count,
        authority_backfill: backfillLedger,
      },
    };
  }

  const recoveredRows = resp?.ok === false
    ? normalizeRecoAlternativesOpenWorldRows(
        recoverRecoAlternativesOpenWorldRowsFromTruncatedText(resp?.raw_text),
        { productInput, productObj, ctx, maxTotal },
      )
    : [];
  if (recoveredRows.length) {
    const grounded = await groundOpenWorldAlternativesToCatalog(recoveredRows, { logger, targetSignals });
    llmTrace.catalog_grounding_attempted_count = grounded.attempted_count;
    llmTrace.catalog_grounded_count = grounded.grounded_count;
    llmTrace.catalog_grounding_failure_class_counts = grounded.failure_class_counts;
    llmTrace.recovered_from_truncated_raw = true;
    llmTrace.recovered_row_count = recoveredRows.length;
    const hydratedAlternatives = await hydrateRecoAlternativesAuthorityExperienceRows(grounded.alternatives);
    const finalAlternatives = applyOpenWorldAlternativeVisibleCopy(
      sortRecoAlternativesByMixedScore(hydratedAlternatives, { useExperienceQualityBonus: true }),
      { targetSignals },
    );
    const visibleAlternatives = filterRecoAlternativesVisibleAuthorityRows(finalAlternatives, { minGrounded: 2 });
    const backfillLedger = await buildRecoAlternativesAuthorityBackfillLedger({
      ctx,
      alternatives: finalAlternatives,
      logger,
    });
    return {
      ok: true,
      alternatives: visibleAlternatives.alternatives.slice(0, Math.max(1, Math.min(6, Number(maxTotal) || 1))),
      field_missing: [],
      source_mode: 'open_world_only',
      fallback_source: null,
      refresh_pending: Boolean(backfillLedger?.pending),
      refresh_after_ms: 0,
      failure_class: null,
      attempt_count: 1,
      recommendation_mode: 'open_world_only',
      profile_mode: normalizeAlternativesProfileMode(profileMode),
      template_id: 'reco_alternatives_open_world_v1',
      raw_output_summary: summarizeRecoAlternativesRaw(recoveredRows),
      llm_trace: llmTrace,
      compare_meta: {
        open_world_status: 'success',
        open_world_candidate_count: recoveredRows.length,
        open_world_selected_count: visibleAlternatives.alternatives.filter((row) => String(row?.candidate_origin || '') === 'open_world').length,
        open_world_grounding_attempted_count: grounded.attempted_count,
        open_world_grounded_count: grounded.grounded_count,
        visible_authority_only_filter_applied: visibleAlternatives.visible_authority_only_filter_applied,
        hidden_unresolved_count: visibleAlternatives.hidden_unresolved_count,
        authority_backfill: backfillLedger,
      },
    };
  }

  return {
    ok: true,
    alternatives: [],
    field_missing: [{ field: 'alternatives', reason: 'upstream_error' }],
    source_mode: 'open_world_only',
    fallback_source: 'none',
    refresh_pending: false,
    refresh_after_ms: 0,
    failure_class: classifyAlternativesFailureCode(resp?.reason),
    attempt_count: 1,
    no_result_reason: 'no_viable_results_after_open_world',
    recommendation_mode: 'open_world_only',
    profile_mode: normalizeAlternativesProfileMode(profileMode),
    template_id: 'reco_alternatives_open_world_v1',
    raw_output_summary: summarizeRecoAlternativesRaw([]),
    llm_trace: llmTrace,
  };
}

async function fetchRecoAlternativesForExternalSeedProduct({
  ctx,
  productInput,
  productObj,
  anchorId = '',
  maxTotal = 3,
  logger,
} = {}) {
  const requestStartedAt = Date.now();
  const stageTimingsMs = {};
  const limit = Math.max(1, Math.min(6, Number.isFinite(Number(maxTotal)) ? Math.trunc(Number(maxTotal)) : 3));
  const openWorldModel = getRecoAlternativesOpenWorldModel();
  const maxOutputTokens = getRecoAlternativesOpenWorldMaxOutputTokens();
  const timeoutMs = getRecoAlternativesOpenWorldTimeoutMs();
  const queueTimeoutMs = getRecoAlternativesOpenWorldQueueTimeoutMs(timeoutMs);
  const upstreamTimeoutMs = getRecoAlternativesOpenWorldUpstreamTimeoutMs(timeoutMs, queueTimeoutMs);
  const poolStageStartedAt = Date.now();
  const pool = await collectExternalSeedPoolAlternatives({
    ctx,
    productInput,
    productObj,
    maxTotal: limit,
    anchorId,
    logger,
  });
  recordRecoAlternativesStageTiming(stageTimingsMs, 'pool_search', poolStageStartedAt);
  const targetSignals = pool.identity.targetSignals;
  const embeddedSelectorPool = buildRecoAlternativesCandidatePool({
    productObj,
    anchorId,
    maxCandidates: Math.max(8, limit * 3),
  });
  const embeddedPoolCandidates = mapSelectorCandidatesToAlternatives(embeddedSelectorPool, {
    maxTotal: limit,
    lang: ctx.lang,
    reasonLine: ctx.lang === 'CN'
      ? '基于本次推荐已召回的同角色候选。'
      : 'Grounded alternative from the same-role candidate pool already recalled for this recommendation.',
  }).map((row) => ({
    ...row,
    candidate_origin: 'pool',
    grounding_status: row?.grounding_status || 'catalog_verified',
  }));
  const searchedPoolCandidates = Array.isArray(pool.candidates) ? pool.candidates : [];
  const poolCandidates = mergeRecoAlternativesForHybrid(
    embeddedPoolCandidates,
    searchedPoolCandidates,
    { maxTotal: limit },
  );
  let openWorldRows = [];
  let openWorldStatus = 'empty';
  let openWorldGroundingAttemptedCount = 0;
  let openWorldGroundedCount = 0;
  let openWorldFailureClassCounts = { coverage_miss: 0, recall_miss: 0 };
  let llmTrace = null;

  const poolSummary = poolCandidates.slice(0, 4).map((row) => {
    const product = isPlainObject(row.product) ? row.product : {};
    return {
      brand: pickFirstTrimmed(product.brand),
      name: pickFirstTrimmed(product.name),
      similarity_score: Number.isFinite(Number(row.similarity_score)) ? Number(row.similarity_score) : null,
      reasons: asStringArray(row.reasons, 2),
    };
  });

  const systemPrompt = [
    'You are a strict skincare compare assistant.',
    'Output STRICT JSON only that matches the schema.',
    'Suggest 2 to 3 real skincare alternatives for the anchor product.',
    'Never invent URLs, product IDs, SKUs, exact INCI lists, or internal catalog references.',
    'Each alternative must include a real brand, a real product name, anchor-linked reasons, and at least one concrete tradeoff or uncertainty.',
    'Reject makeup, tools, fragrance, body-only items, haircare, and placeholder products.',
    'Do not choose generic same-step products. For treatment/serum anchors, every alternative must share a named active or the same functional claim.',
    'If pool_summary is present, do not return a product whose brand and name duplicate or lightly reformat any pool_summary item; open-world suggestions must add new candidates.',
    'For name-only open-world products, stay conservative: use product name, category, role, price, and availability tradeoffs only. Do not assert unseen ingredients, UV filter type, fragrance, alcohol, irritation, pilling, clinical claims, or exact finish unless supplied in the payload.',
    'Return at most 3 alternatives. Use 1 concise reason and 1 concise tradeoff note per item.',
  ].join('\n');
  const userPayload = {
    lang: normalizeRecoPromptLanguage(ctx?.lang || 'EN'),
    anchor: {
      brand: targetSignals.brand,
      name: targetSignals.name,
      query: String(productInput || '').trim() || null,
      product_type: targetSignals.productType,
      usage_role: targetSignals.usageRole,
      hero_ingredients: targetSignals.heroIngredients,
      known_actives: targetSignals.knownActives,
      primary_claims: targetSignals.primaryClaims,
      texture_hints: targetSignals.textureHints,
      notes: targetSignals.notes,
    },
    pool_summary: poolSummary,
    excluded_pool_products: poolSummary.map((row) => ({
      brand: row.brand || null,
      name: row.name || null,
    })).filter((row) => row.brand || row.name),
    task: {
      max_alternatives: Math.min(3, Math.max(2, limit)),
      selection_rule: 'Prefer Pivota product-pool candidates when they are already strong; use open-world suggestions only to add unique non-duplicate candidates for any remaining slots.',
    },
  };

  if (poolCandidates.length >= Math.min(3, limit)) {
    openWorldStatus = 'skipped_sufficient_pool';
    llmTrace = {
      template_id: 'reco_alternatives_grounded_pool_v1',
      source_mode: 'grounded_pool',
      provider_route: null,
      provider_model: null,
      latency_ms: 0,
      error_class: null,
      cache_hit: false,
    };
  } else {
    const openWorldStageStartedAt = Date.now();
    try {
      const resp = await callGeminiJsonObjectImpl({
        model: openWorldModel,
        systemPrompt,
        userPrompt: JSON.stringify(userPayload, null, 2),
        timeoutMs,
        queueTimeoutMs,
        upstreamTimeoutMs,
        temperature: 0.2,
        maxOutputTokens,
        responseJsonSchema: buildExternalSeedOpenWorldSchema(),
        route: 'aurora_reco_alternatives_open_world',
        ignoreForceModel: true,
      });
      llmTrace = {
        template_id: 'reco_alternatives_open_world_v1',
        source_mode: 'local_gemini_open_world',
        provider_route: 'aurora_reco_alternatives_open_world',
        provider_model: openWorldModel,
        provider_reason: resp?.ok === false ? resp.reason || null : null,
        provider_detail: resp?.ok === false ? resp.detail || null : null,
        provider_timeout_stage: resp?.ok === false ? resp.timeout_stage || null : null,
        provider_total_ms: resp?.ok === false && Number.isFinite(Number(resp.total_ms)) ? Number(resp.total_ms) : null,
        provider_upstream_ms: resp?.ok === false && Number.isFinite(Number(resp.upstream_ms)) ? Number(resp.upstream_ms) : null,
        provider_result_reason: resp?.meta?.result_reason || null,
        finish_reason: resp?.finish_reason || null,
        parse_status: resp?.parse_status || null,
        latency_ms: Math.max(0, Date.now() - openWorldStageStartedAt),
        error_class: resp?.ok === true ? null : classifyAlternativesFailureCode(resp?.reason),
      };
      const recoveredRawRows = resp?.ok === false
        ? recoverRecoAlternativesOpenWorldRowsFromTruncatedText(resp?.raw_text)
        : [];
      const rawOpenWorldRows = resp?.ok === true && isPlainObject(resp.json) && Array.isArray(resp.json.alternatives)
        ? resp.json.alternatives
        : recoveredRawRows;
      if (Array.isArray(rawOpenWorldRows) && rawOpenWorldRows.length) {
        openWorldRows = rawOpenWorldRows
          .map((row) => normalizeOpenWorldAlternativeRow(row, {
            targetSignals,
            anchorLabel: pool.identity.anchorLabel,
            anchorNameTokens: pool.identity.anchorNameTokens,
            ingredientTokens: pool.identity.ingredientTokens,
            claimTokens: pool.identity.claimTokens,
            textureTokens: pool.identity.textureTokens,
          }))
          .filter(Boolean);
        if (openWorldRows.length) {
          const grounded = await groundOpenWorldAlternativesToCatalog(openWorldRows, { logger, targetSignals });
          openWorldRows = grounded.alternatives;
          openWorldGroundingAttemptedCount = grounded.attempted_count;
          openWorldGroundedCount = grounded.grounded_count;
          openWorldFailureClassCounts = grounded.failure_class_counts || openWorldFailureClassCounts;
          llmTrace.catalog_grounding_attempted_count = grounded.attempted_count;
          llmTrace.catalog_grounded_count = grounded.grounded_count;
          llmTrace.catalog_grounding_failure_class_counts = grounded.failure_class_counts;
        }
        if (recoveredRawRows.length) {
          llmTrace.recovered_from_truncated_raw = true;
          llmTrace.recovered_row_count = openWorldRows.length;
        }
        openWorldStatus = openWorldRows.length ? 'success' : 'empty';
      } else {
        openWorldStatus = resp?.ok === false ? 'provider_error' : 'empty';
      }
    } catch (err) {
      logger?.warn?.(
        { err: err?.message || String(err), request_id: ctx?.request_id, trace_id: ctx?.trace_id },
        'aurora bff: external seed compare open-world stage failed',
      );
      llmTrace = {
        template_id: 'reco_alternatives_open_world_v1',
        source_mode: 'local_gemini_open_world',
        provider_route: 'aurora_reco_alternatives_open_world',
        provider_model: openWorldModel,
        provider_reason: err?.code || 'provider_error',
        provider_detail: err?.message || String(err),
        provider_timeout_stage: null,
        provider_total_ms: null,
        provider_upstream_ms: null,
        provider_result_reason: 'gemini_call_exception',
        finish_reason: null,
        parse_status: null,
        latency_ms: 0,
        error_class: classifyAlternativesFailureCode(err?.code || err?.message),
      };
      openWorldStatus = 'provider_error';
    }
    recordRecoAlternativesStageTiming(stageTimingsMs, 'open_world', openWorldStageStartedAt);
  }

  const merged = mergeRecoAlternativesForHybrid(poolCandidates, openWorldRows, {
    maxTotal: limit,
    preferBestScore: true,
  });

  const finalizeStageStartedAt = Date.now();
  const hydratedAlternatives = await hydrateRecoAlternativesAuthorityExperienceRows(merged);
  const rankedHydratedAlternatives = sortRecoAlternativesByMixedScore(hydratedAlternatives, { useExperienceQualityBonus: true });
  const cleanedAlternatives = applyOpenWorldAlternativeVisibleCopy(rankedHydratedAlternatives.map((row) => {
    const next = { ...(row || {}) };
    delete next._mixed_score;
    return next;
  }), { targetSignals });
  const visibleAlternatives = filterRecoAlternativesVisibleAuthorityRows(cleanedAlternatives, { minGrounded: 2 });
  recordRecoAlternativesStageTiming(stageTimingsMs, 'finalize_visible_rows', finalizeStageStartedAt);
  const backfillStageStartedAt = Date.now();
  const backfillLedger = await buildRecoAlternativesAuthorityBackfillLedger({
    ctx,
    alternatives: cleanedAlternatives.length ? cleanedAlternatives : openWorldRows,
    logger,
  });
  recordRecoAlternativesStageTiming(stageTimingsMs, 'authority_backfill_ledger', backfillStageStartedAt);
  const visibleAlternativeRows = visibleAlternatives.alternatives;
  const poolSelectedCount = visibleAlternativeRows.filter((row) => String(row?.candidate_origin || '') === 'pool').length;
  const openWorldSelectedCount = visibleAlternativeRows.filter((row) => String(row?.candidate_origin || '') === 'open_world').length;
  const compareMeta = {
    embedded_candidate_count: embeddedPoolCandidates.length,
    pool_candidate_count: poolCandidates.length,
    search_query_count: Array.isArray(pool?.queries) ? pool.queries.length : 0,
    executed_query_count: Array.isArray(pool?.executed_queries) ? pool.executed_queries.length : 0,
    pool_selected_count: poolSelectedCount,
    open_world_candidate_count: openWorldRows.length,
    open_world_selected_count: openWorldSelectedCount,
    open_world_grounding_attempted_count: openWorldGroundingAttemptedCount,
    open_world_grounded_count: openWorldGroundedCount,
    open_world_grounding_failure_class_counts: openWorldFailureClassCounts,
    visible_authority_only_filter_applied: visibleAlternatives.visible_authority_only_filter_applied,
    hidden_unresolved_count: visibleAlternatives.hidden_unresolved_count,
    ranking_mode: 'best_score_mixed',
    pool_recall_status: poolCandidates.length >= 3 ? 'full' : poolCandidates.length > 0 ? 'partial' : 'empty',
    pool_local_authority_candidate_count: Number(pool?.local_authority_candidate_count) || 0,
    pool_backend_authority_candidate_count: Number(pool?.backend_authority_candidate_count) || 0,
    pool_backend_authority_search_skipped: pool?.backend_authority_search_skipped === true,
    pool_local_authority_preferred_step: pickFirstTrimmed(pool?.local_authority_search_role?.preferred_step) || null,
    open_world_status: openWorldStatus,
    open_world_role: 'coverage_supplement',
    authority_backfill: backfillLedger,
  };
  Object.assign(compareMeta, buildRecoAlternativesTimingMeta(stageTimingsMs, requestStartedAt));

  if (!visibleAlternativeRows.length) {
    return {
      ok: true,
      alternatives: [],
      field_missing: [{ field: 'alternatives', reason: 'no_viable_compare_candidates' }],
      source_mode: 'pool_open_world_mixed',
      fallback_source: 'none',
      refresh_pending: Boolean(backfillLedger?.pending),
      refresh_after_ms: 0,
      failure_class: openWorldStatus === 'provider_error' ? 'provider_error' : null,
      attempt_count: 1,
      no_result_reason: openWorldStatus === 'provider_error'
        ? 'open_world_provider_error_after_pool_empty'
        : 'pool_and_open_world_empty',
      llm_trace: llmTrace,
      elapsed_ms: Math.max(0, Math.round(Date.now() - requestStartedAt)),
      compare_meta: compareMeta,
    };
  }

  return {
    ok: true,
    alternatives: visibleAlternativeRows,
    field_missing: [],
    source_mode: 'pool_open_world_mixed',
    fallback_source: null,
    refresh_pending: Boolean(backfillLedger?.pending),
    refresh_after_ms: 0,
    failure_class: openWorldStatus === 'provider_error' && poolSelectedCount === 0 ? 'provider_error' : null,
    attempt_count: 1,
    llm_trace: llmTrace,
    elapsed_ms: Math.max(0, Math.round(Date.now() - requestStartedAt)),
    compare_meta: compareMeta,
  };
}

async function fetchRecoAlternativesForProduct({
  ctx,
  profileSummary,
  recentLogs,
  productInput,
  productObj,
  anchorId,
  maxTotal,
  candidatePool = [],
  budget = null,
  debug,
  logger,
  options,
}) {
  const requestStartedAt = Date.now();
  const stageTimingsMs = {};
  const opts = options && typeof options === 'object' && !Array.isArray(options) ? options : {};
  const recommendationMode = normalizeRecoAlternativesMode(opts.recommendation_mode);
  const profileMode = normalizeAlternativesProfileMode(opts.profile_mode);
  const disableFallback = opts.disable_fallback === true;
  const disableAsyncRefresh = opts.disable_async_refresh === true;
  const skipAnchorPrecheck = opts.skip_anchor_precheck === true;
  const preferRefreshCache = opts.prefer_refresh_cache !== false;
  const disableSyntheticLocalFallback = opts.disable_synthetic_local_fallback === true;
  const ignoreSelectorCandidates = opts.ignore_selector_candidates === true;
  const allowAnchorlessOpenWorld = recommendationMode !== 'pool_only';
  const usesOpenWorldPrompt = recommendationMode === 'pool_open_world_mixed' || recommendationMode === 'open_world_only';

  const inputText = String(productInput || '').trim();
  let effectiveProductObj = productObj && typeof productObj === 'object' && !Array.isArray(productObj) ? productObj : null;
  const serializeRecoAlternativesProductJson = (product) => (
    product && typeof product === 'object' && !Array.isArray(product)
      ? JSON.stringify(product).slice(0, 1400)
      : ''
  );
  const shouldAdoptResolvedAnchorProduct = (currentProduct, resolvedProduct) => {
    const current = currentProduct && typeof currentProduct === 'object' && !Array.isArray(currentProduct) ? currentProduct : null;
    const resolved = resolvedProduct && typeof resolvedProduct === 'object' && !Array.isArray(resolvedProduct) ? resolvedProduct : null;
    if (!resolved) return false;
    if (!current) return true;
    return !pickFirstTrimmed(
      current.product_id,
      current.sku_id,
      current.canonical_product_ref?.product_id,
      current.brand,
      current.name,
      current.display_name,
    );
  };
  const buildSelectorCandidatePoolForProduct = (activeProductObj, activeAnchorId) => (
    ignoreSelectorCandidates
      ? []
      : buildRecoAlternativesCandidatePool({
        sharedCandidates: candidatePool,
        productObj: activeProductObj,
        anchorId: activeAnchorId,
        maxCandidates: Math.max(8, Math.min(24, (Number.isFinite(Number(maxTotal)) ? Math.trunc(Number(maxTotal)) : 6) * 3)),
      })
  );
  const hydrateSelectorGroundedAlternativesForPool = async (pool) => (
    ignoreSelectorCandidates
      ? []
      : hydrateRecoAlternativesAuthorityExperienceRows(
        mapSelectorCandidatesToAlternatives(pool, {
          maxTotal,
          lang: ctx.lang,
          reasonLine: ctx.lang === 'CN'
            ? '基于已解析商品候选给出 grounded alternatives。'
            : 'Grounded alternatives derived from resolved candidate pool.',
        }),
      )
  );
  let anchor = anchorId ? String(anchorId).trim() : '';
  const bestInput = inputText || anchor;
  let selectorCandidatePool = buildSelectorCandidatePoolForProduct(effectiveProductObj, anchor);
  let selectorGroundedAlternatives = await hydrateSelectorGroundedAlternativesForPool(selectorCandidatePool);
  const emptyRawOutputSummary = summarizeRecoAlternativesRaw([]);
  let refreshKey = makeRecoAlternativesRefreshKey({
    anchorId: anchor || null,
    productInput: bestInput,
    lang: ctx.lang,
    maxTotal,
    recommendationMode,
    profileMode,
  });

  if (preferRefreshCache && refreshKey) {
    const cached = getRecoAlternativesRefreshCache(refreshKey);
    if (cached && Array.isArray(cached.alternatives) && cached.alternatives.length) {
      return {
        ok: true,
        alternatives: cached.alternatives.slice(0, Math.max(1, Math.min(8, Number(maxTotal) || 6))),
        field_missing: [],
        source_mode: recommendationMode === 'pool_only' ? 'llm' : recommendationMode,
        fallback_source: 'refresh_cache',
        refresh_pending: false,
        refresh_after_ms: 0,
        failure_class: null,
        attempt_count: 0,
        recommendation_mode: recommendationMode,
        profile_mode: profileMode,
        template_id: cached.llm_trace && cached.llm_trace.template_id ? cached.llm_trace.template_id : null,
        raw_output_summary: null,
        ...(cached.llm_trace ? { llm_trace: cached.llm_trace } : {}),
      };
    }
  }

  if (!bestInput) {
    recordAuroraRecoLlmCall({ stage: 'alternatives', outcome: 'precheck_fail' });
    return {
      ok: false,
      alternatives: [],
      field_missing: [{ field: 'alternatives', reason: 'product_identity_missing' }],
      source_mode: recommendationMode === 'pool_only' ? 'local_fallback' : recommendationMode,
      fallback_source: 'none',
      refresh_pending: false,
      refresh_after_ms: 0,
      failure_class: 'precheck_fail',
      attempt_count: 0,
      recommendation_mode: recommendationMode,
      profile_mode: profileMode,
      raw_output_summary: emptyRawOutputSummary,
    };
  }

  const budgetDeadlineMs = budget && Number.isFinite(Number(budget.deadline_ms))
    ? Number(budget.deadline_ms)
    : null;
  const remainingBudgetMs = Number.isFinite(budgetDeadlineMs)
    ? Math.max(0, Math.trunc(budgetDeadlineMs - Date.now()))
    : null;
  if (Number.isFinite(remainingBudgetMs) && remainingBudgetMs <= RECO_ALTERNATIVES_OVERHEAD_MS + 200) {
    recordAuroraRecoLlmCall({ stage: 'alternatives', outcome: 'budget_exhausted' });
    recordRecoAlternativesBudgetExhausted();
    return {
      ok: true,
      alternatives: [],
      field_missing: [{ field: 'alternatives', reason: 'alternatives_budget_exhausted' }],
      source_mode: recommendationMode === 'pool_only' ? 'local_fallback' : recommendationMode,
      fallback_source: 'none',
      refresh_pending: false,
      refresh_after_ms: 0,
      failure_class: 'budget_exhausted',
      attempt_count: 0,
      no_result_reason: 'alternatives_budget_exhausted',
      timeout_root_cause: 'budget_exceeded',
      recommendation_mode: recommendationMode,
      profile_mode: profileMode,
      raw_output_summary: emptyRawOutputSummary,
    };
  }

  const mapFallbackCandidateToAlternative = (row, kind = 'similar') => {
    const candidate = row && typeof row === 'object' && !Array.isArray(row) ? row : null;
    if (!candidate) return null;
    const displayName = pickFirstTrimmed(candidate.display_name, candidate.displayName, candidate.name);
    if (!displayName) return null;
    const product = {
      brand: pickFirstTrimmed(candidate.brand) || null,
      name: displayName,
      product_id: pickFirstTrimmed(candidate.product_id, candidate.productId, candidate.sku_id, candidate.skuId) || null,
      sku_id: pickFirstTrimmed(candidate.sku_id, candidate.skuId, candidate.product_id, candidate.productId) || null,
    };
    const scoreRaw = Number.isFinite(Number(candidate.similarity_score))
      ? Number(candidate.similarity_score)
      : Number.isFinite(Number(candidate.similarity))
        ? Number(candidate.similarity)
        : null;
    const score = scoreRaw == null ? null : scoreRaw > 1 ? Math.max(0, Math.min(100, Math.round(scoreRaw))) : Math.round(scoreRaw * 100);
    const reasons = Array.isArray(candidate.why_candidate?.reasons_user_visible)
      ? candidate.why_candidate.reasons_user_visible
      : Array.isArray(candidate.reasons)
        ? candidate.reasons
        : [];
    return {
      kind: kind === 'dupe' || kind === 'premium' ? kind : 'similar',
      product,
      ...(score != null ? { similarity: score } : {}),
      reasons: reasons.slice(0, 2).map((x) => String(x || '').trim()).filter(Boolean),
      tradeoffs: Array.isArray(candidate.compare_highlights) ? candidate.compare_highlights.slice(0, 2) : [],
      evidence: {
        science: { key_ingredients: [], mechanisms: [], fit_notes: [], risk_notes: [] },
        social_signals: { typical_positive: [], typical_negative: [], risk_for_groups: [] },
        expert_notes: [],
        confidence: score == null ? null : Math.max(0, Math.min(1, score / 100)),
        missing_info: ['local_fallback_seed'],
      },
      missing_info: ['local_fallback_seed'],
    };
  };

  const buildLocalFallbackAlternatives = async ({ failureClass }) => {
    const maxItems = Number.isFinite(Number(maxTotal)) ? Math.max(1, Math.min(8, Math.trunc(Number(maxTotal)))) : 6;
    const out = [];
    let fallbackSource = 'synthetic';
    if (anchor) {
      try {
        const kbKey = normalizeDupeKbKey(`id:${anchor}`);
        const kbEntry = kbKey ? await getDupeKbEntry(kbKey) : null;
        if (kbEntry && kbEntry.verified === true) {
          for (const row of Array.isArray(kbEntry.dupes) ? kbEntry.dupes : []) {
            const mappedAlt = mapFallbackCandidateToAlternative(row, 'dupe');
            if (!mappedAlt) continue;
            out.push(mappedAlt);
            if (out.length >= maxItems) break;
          }
          if (out.length < maxItems) {
            for (const row of Array.isArray(kbEntry.comparables) ? kbEntry.comparables : []) {
              const mappedAlt = mapFallbackCandidateToAlternative(row, 'similar');
              if (!mappedAlt) continue;
              out.push(mappedAlt);
              if (out.length >= maxItems) break;
            }
          }
          if (out.length) fallbackSource = 'kb';
        }
      } catch {
        // ignore kb fallback errors
      }
    }
    if (!out.length && !disableSyntheticLocalFallback) {
      const base = effectiveProductObj && typeof effectiveProductObj === 'object' && !Array.isArray(effectiveProductObj) ? effectiveProductObj : {};
      const brand = pickFirstTrimmed(base.brand, base.manufacturer) || null;
      const name = pickFirstTrimmed(base.display_name, base.displayName, base.name, inputText, anchor) || null;
      const prefixName = name || (ctx.lang === 'CN' ? '护肤替代候选' : 'Skincare alternative candidate');
      const templates = [
        { kind: 'dupe', score: 78, title: ctx.lang === 'CN' ? `${prefixName}（平替）` : `${prefixName} (budget dupe)` },
        { kind: 'similar', score: 74, title: ctx.lang === 'CN' ? `${prefixName}（相似）` : `${prefixName} (similar option)` },
        { kind: 'premium', score: 70, title: ctx.lang === 'CN' ? `${prefixName}（升级）` : `${prefixName} (premium option)` },
      ];
      for (const row of templates) {
        out.push({
          kind: row.kind,
          product: { brand, name: row.title, product_id: null, sku_id: null },
          similarity: row.score,
          reasons: [ctx.lang === 'CN' ? '先给出可用替代项，后台继续刷新更完整结果。' : 'Returning immediate alternatives while richer results refresh in background.'],
          tradeoffs: [`fallback_reason: ${failureClass || 'upstream_unavailable'}`],
          evidence: {
            science: { key_ingredients: [], mechanisms: [], fit_notes: [], risk_notes: [] },
            social_signals: { typical_positive: [], typical_negative: [], risk_for_groups: [] },
            expert_notes: [],
            confidence: Math.max(0, Math.min(1, row.score / 100)),
            missing_info: ['local_fallback_seed'],
          },
          missing_info: ['local_fallback_seed'],
        });
        if (out.length >= maxItems) break;
      }
    }
    return { alternatives: out.slice(0, maxItems), fallback_source: fallbackSource };
  };
  const describeLocalFallbackVisibility = (localFallback) => {
    const hasVisibleAlternatives = Array.isArray(localFallback?.alternatives) && localFallback.alternatives.length > 0;
    return {
      hasVisibleAlternatives,
      source_mode: hasVisibleAlternatives ? 'local_fallback' : 'llm',
      fallback_source: hasVisibleAlternatives
        ? pickFirstTrimmed(localFallback?.fallback_source) || 'synthetic'
        : 'none',
    };
  };

  let anchorPrecheck = null;
  if (!anchor && !skipAnchorPrecheck) {
    try {
      const startedAt = Date.now();
      const resolved = await resolveAvailabilityProductByLocalResolver({
        query: bestInput,
        lang: String(ctx.lang || '').toLowerCase() === 'cn' ? 'cn' : 'en',
        timeoutMs: RECO_ALTERNATIVES_ANCHOR_PRECHECK_TIMEOUT_MS,
        logger,
      });
      const resolvedAnchor = extractAnchorIdFromProductLike(resolved && resolved.product);
      const resolvedAnchorProduct = shouldAdoptResolvedAnchorProduct(
        effectiveProductObj,
        resolved && resolved.product,
      )
        ? (
          mapCatalogProductToAnchorProduct(resolved && resolved.product, { fallbackName: bestInput }) ||
          (resolved && resolved.product && typeof resolved.product === 'object' && !Array.isArray(resolved.product)
            ? resolved.product
            : null)
        )
        : null;
      const precheckReasonCode =
        resolved && resolved.resolve_reason_code ? normalizeResolveReasonCode(resolved.resolve_reason_code, null) : null;
      const canProceedWithoutAnchor =
        Boolean(bestInput) && (
          allowAnchorlessOpenWorld ||
          (
            RECO_ALTERNATIVES_ANCHORLESS_ON_PRECHECK_FAILURE_ENABLED &&
            (precheckReasonCode === 'db_error' ||
              precheckReasonCode === 'upstream_timeout' ||
              precheckReasonCode === 'rate_limited')
          )
        );
      anchorPrecheck = {
        resolved: Boolean(resolvedAnchor),
        reason: precheckReasonCode,
        latency_ms: Date.now() - startedAt,
        continue_without_anchor: Boolean(!resolvedAnchor && canProceedWithoutAnchor),
        resolved_product_hydrated: Boolean(resolvedAnchorProduct),
      };
      recordRecoAlternativesStageTiming(stageTimingsMs, 'anchor_precheck', startedAt);
      if (resolvedAnchor) {
        anchor = resolvedAnchor;
        if (resolvedAnchorProduct) {
          effectiveProductObj = resolvedAnchorProduct;
          selectorCandidatePool = buildSelectorCandidatePoolForProduct(effectiveProductObj, anchor);
          selectorGroundedAlternatives = await hydrateSelectorGroundedAlternativesForPool(selectorCandidatePool);
        }
        refreshKey = makeRecoAlternativesRefreshKey({
          anchorId: anchor || null,
          productInput: bestInput,
          lang: ctx.lang,
          maxTotal,
          recommendationMode,
          profileMode,
        });
      } else if (canProceedWithoutAnchor) {
        refreshKey = makeRecoAlternativesRefreshKey({
          anchorId: null,
          productInput: bestInput,
          lang: ctx.lang,
          maxTotal,
          recommendationMode,
          profileMode,
        });
      } else {
        recordAuroraRecoLlmCall({ stage: 'alternatives', outcome: 'precheck_fail' });
        if (selectorGroundedAlternatives.length) {
          return {
            ok: true,
            alternatives: selectorGroundedAlternatives,
            field_missing: [],
            source_mode: recommendationMode === 'pool_open_world_mixed' ? 'pool_open_world_mixed' : 'selector_grounded',
            fallback_source: null,
            refresh_pending: false,
            refresh_after_ms: 0,
            failure_class: null,
            attempt_count: 0,
            recommendation_mode: recommendationMode,
            profile_mode: profileMode,
            raw_output_summary: emptyRawOutputSummary,
            ...(debug ? { debug: { anchor_precheck: anchorPrecheck, selector_grounded: true } } : {}),
          };
        }
        if (disableFallback) {
          return {
            ok: false,
            alternatives: [],
            field_missing: [{ field: 'alternatives', reason: 'anchor_missing_precheck' }],
            source_mode: 'llm',
            fallback_source: 'none',
            refresh_pending: false,
            refresh_after_ms: 0,
            failure_class: 'anchor_missing_precheck',
            attempt_count: 0,
            recommendation_mode: recommendationMode,
            profile_mode: profileMode,
            raw_output_summary: emptyRawOutputSummary,
          };
        }
        const localFallback = await buildLocalFallbackAlternatives({ failureClass: 'anchor_missing_precheck' });
        const localFallbackMeta = describeLocalFallbackVisibility(localFallback);
        return {
          ok: true,
          alternatives: localFallback.alternatives,
          field_missing: localFallback.alternatives.length ? [] : [{ field: 'alternatives', reason: 'anchor_missing_precheck' }],
          source_mode: localFallbackMeta.source_mode,
          fallback_source: localFallbackMeta.fallback_source,
          refresh_pending: false,
          refresh_after_ms: 0,
          failure_class: 'anchor_missing_precheck',
          attempt_count: 0,
          no_result_reason: localFallback.alternatives.length ? null : (recommendationMode === 'open_world_only' ? 'anchor_insufficient_for_open_world' : null),
          recommendation_mode: recommendationMode,
          profile_mode: profileMode,
          raw_output_summary: emptyRawOutputSummary,
          ...(debug ? { debug: { anchor_precheck: anchorPrecheck } } : {}),
        };
      }
    } catch (err) {
      anchorPrecheck = {
        resolved: false,
        reason: 'anchor_precheck_error',
        error: err && err.message ? err.message : String(err),
        continue_without_anchor: Boolean(bestInput),
      };
      if (bestInput && (allowAnchorlessOpenWorld || RECO_ALTERNATIVES_ANCHORLESS_ON_PRECHECK_FAILURE_ENABLED)) {
        refreshKey = makeRecoAlternativesRefreshKey({
          anchorId: null,
          productInput: bestInput,
          lang: ctx.lang,
          maxTotal,
          recommendationMode,
          profileMode,
        });
      } else {
        recordAuroraRecoLlmCall({ stage: 'alternatives', outcome: 'precheck_fail' });
      }
      if (bestInput && (allowAnchorlessOpenWorld || RECO_ALTERNATIVES_ANCHORLESS_ON_PRECHECK_FAILURE_ENABLED)) {
        // Continue with anchorless LLM path when local precheck is unavailable.
      } else if (selectorGroundedAlternatives.length) {
        return {
          ok: true,
          alternatives: selectorGroundedAlternatives,
          field_missing: [],
          source_mode: recommendationMode === 'pool_open_world_mixed' ? 'pool_open_world_mixed' : 'selector_grounded',
          fallback_source: null,
          refresh_pending: false,
          refresh_after_ms: 0,
          failure_class: null,
          attempt_count: 0,
          recommendation_mode: recommendationMode,
          profile_mode: profileMode,
          raw_output_summary: emptyRawOutputSummary,
          ...(debug ? { debug: { anchor_precheck: anchorPrecheck, selector_grounded: true } } : {}),
        };
      } else if (!disableFallback) {
        const localFallback = await buildLocalFallbackAlternatives({ failureClass: 'anchor_missing_precheck' });
        const localFallbackMeta = describeLocalFallbackVisibility(localFallback);
        return {
          ok: true,
          alternatives: localFallback.alternatives,
          field_missing: localFallback.alternatives.length ? [] : [{ field: 'alternatives', reason: 'anchor_missing_precheck' }],
          source_mode: localFallbackMeta.source_mode,
          fallback_source: localFallbackMeta.fallback_source,
          refresh_pending: false,
          refresh_after_ms: 0,
          failure_class: 'anchor_missing_precheck',
          attempt_count: 0,
          no_result_reason: localFallback.alternatives.length ? null : (recommendationMode === 'open_world_only' ? 'anchor_insufficient_for_open_world' : null),
          recommendation_mode: recommendationMode,
          profile_mode: profileMode,
          raw_output_summary: emptyRawOutputSummary,
          ...(debug ? { debug: { anchor_precheck: anchorPrecheck } } : {}),
        };
      } else {
        return {
          ok: false,
          alternatives: [],
          field_missing: [{ field: 'alternatives', reason: 'anchor_missing_precheck' }],
          source_mode: 'llm',
          fallback_source: 'none',
          refresh_pending: false,
          refresh_after_ms: 0,
          failure_class: 'anchor_missing_precheck',
          attempt_count: 0,
          recommendation_mode: recommendationMode,
          profile_mode: profileMode,
          raw_output_summary: emptyRawOutputSummary,
          ...(debug ? { debug: { anchor_precheck: anchorPrecheck } } : {}),
        };
      }
    }
  }

  const profileSnapshot = buildAlternativesProfileSnapshot(
    profileSummary && typeof profileSummary === 'object' && !Array.isArray(profileSummary) ? profileSummary : {},
  );
  let groundedPoolAlternatives = selectorGroundedAlternatives;
  let groundedPoolMeta = null;
  if (recommendationMode === 'pool_open_world_mixed' && !ignoreSelectorCandidates) {
    try {
      const poolStageStartedAt = Date.now();
      const pool = await collectExternalSeedPoolAlternatives({
        ctx,
        productInput: bestInput,
        productObj: effectiveProductObj,
        maxTotal,
        anchorId: anchor,
        logger,
      });
      recordRecoAlternativesStageTiming(stageTimingsMs, 'pool_search', poolStageStartedAt);
      const searchedPoolAlternatives = Array.isArray(pool?.candidates) ? pool.candidates : [];
      const finalizeGroundedPoolStartedAt = Date.now();
      groundedPoolAlternatives = mergeRecoAlternativesForHybrid(
        selectorGroundedAlternatives,
        searchedPoolAlternatives,
        { maxTotal: Math.max(1, Math.min(8, Number(maxTotal) || 6)) },
      );
      groundedPoolAlternatives = await hydrateRecoAlternativesAuthorityExperienceRows(groundedPoolAlternatives);
      groundedPoolAlternatives = sortRecoAlternativesByMixedScore(groundedPoolAlternatives, { useExperienceQualityBonus: true });
      recordRecoAlternativesStageTiming(stageTimingsMs, 'finalize_visible_rows', finalizeGroundedPoolStartedAt);
      groundedPoolMeta = {
        selector_candidate_count: selectorCandidatePool.length,
        selector_grounded_count: selectorGroundedAlternatives.length,
        search_query_count: Array.isArray(pool?.queries) ? pool.queries.length : 0,
        executed_query_count: Array.isArray(pool?.executed_queries) ? pool.executed_queries.length : 0,
        searched_pool_candidate_count: searchedPoolAlternatives.length,
        pool_recall_status: searchedPoolAlternatives.length >= 3 ? 'full' : searchedPoolAlternatives.length > 0 ? 'partial' : 'empty',
        pool_local_authority_candidate_count: Number(pool?.local_authority_candidate_count) || 0,
        pool_backend_authority_candidate_count: Number(pool?.backend_authority_candidate_count) || 0,
        pool_backend_authority_search_skipped: pool?.backend_authority_search_skipped === true,
        pool_local_authority_preferred_step: pickFirstTrimmed(pool?.local_authority_search_role?.preferred_step) || null,
      };
    } catch (err) {
      groundedPoolMeta = {
        selector_candidate_count: selectorCandidatePool.length,
        selector_grounded_count: selectorGroundedAlternatives.length,
        search_query_count: 0,
        executed_query_count: 0,
        searched_pool_candidate_count: 0,
        pool_recall_status: selectorGroundedAlternatives.length > 0 ? 'embedded_only' : 'search_error',
        search_error: err?.message || String(err),
      };
    }
  }
  if (recommendationMode === 'pool_open_world_mixed') {
    const limit = Math.max(1, Math.min(8, Number.isFinite(Number(maxTotal)) ? Math.trunc(Number(maxTotal)) : 6));
    const sufficientGroundedCount = Math.min(3, limit);
    if (groundedPoolAlternatives.length >= sufficientGroundedCount) {
      return {
        ok: true,
        alternatives: groundedPoolAlternatives.slice(0, limit),
        field_missing: [],
        source_mode: 'pool_open_world_mixed',
        fallback_source: null,
        refresh_pending: false,
        refresh_after_ms: 0,
        failure_class: null,
        attempt_count: 0,
        recommendation_mode: recommendationMode,
        profile_mode: profileMode,
        template_id: 'reco_alternatives_grounded_pool_v1',
        raw_output_summary: emptyRawOutputSummary,
        llm_trace: {
          template_id: 'reco_alternatives_grounded_pool_v1',
          source_mode: 'grounded_pool',
          latency_ms: 0,
          cache_hit: false,
          error_class: null,
        },
        compare_meta: {
          ...(groundedPoolMeta || {}),
          pool_selected_count: Math.min(groundedPoolAlternatives.length, limit),
          open_world_candidate_count: 0,
          open_world_selected_count: 0,
          open_world_status: 'skipped_sufficient_pool',
          ranking_mode: 'grounded_pool_first',
          open_world_role: 'coverage_supplement',
          authority_backfill: {
            mode: 'async_external_seed_backfill',
            policy: 'open_world_coverage_repair',
            open_world_role: 'coverage_supplement',
            open_world_row_count: 0,
            coverage_gap_count: 0,
            recall_gap_count: 0,
            pending: false,
            status: 'not_needed',
            enqueued_brand_count: 0,
            enqueued_candidate_count: 0,
            brands: [],
          },
          ...buildRecoAlternativesTimingMeta(stageTimingsMs, requestStartedAt),
        },
        elapsed_ms: Math.max(0, Math.round(Date.now() - requestStartedAt)),
        ...(debug ? { debug: { anchor_precheck: anchorPrecheck, grounded_pool: groundedPoolMeta } } : {}),
      };
    }

    let openWorldOut = null;
    try {
      const openWorldStageStartedAt = Date.now();
      openWorldOut = await fetchRecoAlternativesForLocalGeminiOpenWorld({
        ctx,
        productInput: bestInput,
        productObj: effectiveProductObj,
        maxTotal: Math.max(1, limit - groundedPoolAlternatives.length),
        profileMode,
        logger,
      });
      recordRecoAlternativesStageTiming(stageTimingsMs, 'open_world', openWorldStageStartedAt);
    } catch (err) {
      openWorldOut = {
        ok: true,
        alternatives: [],
        field_missing: [{ field: 'alternatives', reason: 'upstream_error' }],
        source_mode: 'open_world_only',
        fallback_source: 'none',
        failure_class: classifyAlternativesFailureCode(err?.code || err?.message),
        attempt_count: 1,
        no_result_reason: 'open_world_provider_exception',
        template_id: 'reco_alternatives_open_world_v1',
        raw_output_summary: emptyRawOutputSummary,
        llm_trace: {
          template_id: 'reco_alternatives_open_world_v1',
          source_mode: 'local_gemini_open_world',
          provider_route: 'aurora_reco_alternatives_open_world',
          provider_model: getRecoAlternativesOpenWorldModel(),
          provider_reason: err?.code || 'provider_error',
          provider_detail: err?.message || String(err),
          latency_ms: 0,
          cache_hit: false,
          error_class: classifyAlternativesFailureCode(err?.code || err?.message),
        },
      };
    }
    const openWorldAlternatives = Array.isArray(openWorldOut?.alternatives) ? openWorldOut.alternatives : [];
    const alternatives = mergeRecoAlternativesForHybrid(
      groundedPoolAlternatives,
      openWorldAlternatives,
      { maxTotal: limit },
    );
    const finalizeVisibleRowsStartedAt = Date.now();
    const hydratedAlternatives = await hydrateRecoAlternativesAuthorityExperienceRows(alternatives);
    const visibleAlternatives = filterRecoAlternativesVisibleAuthorityRows(
      sortRecoAlternativesByMixedScore(hydratedAlternatives, { useExperienceQualityBonus: true }),
      { minGrounded: 2 },
    );
    recordRecoAlternativesStageTiming(stageTimingsMs, 'finalize_visible_rows', finalizeVisibleRowsStartedAt);
    const openWorldStatus = openWorldAlternatives.length
      ? 'success'
      : openWorldOut?.failure_class
        ? 'provider_error'
        : 'empty';
    const openWorldBackfill =
      openWorldOut?.compare_meta && typeof openWorldOut.compare_meta === 'object'
        ? openWorldOut.compare_meta.authority_backfill || null
        : null;
    return {
      ok: true,
      alternatives: visibleAlternatives.alternatives,
      field_missing: visibleAlternatives.alternatives.length
        ? []
        : mergeFieldMissing(openWorldOut?.field_missing, [{ field: 'alternatives', reason: 'no_viable_compare_candidates' }]),
      source_mode: 'pool_open_world_mixed',
      fallback_source: visibleAlternatives.alternatives.length ? null : 'none',
      refresh_pending: Boolean(openWorldOut?.refresh_pending),
      refresh_after_ms: 0,
      failure_class: visibleAlternatives.alternatives.length ? null : (openWorldOut?.failure_class || 'empty_structured'),
      attempt_count: Math.max(1, Number(openWorldOut?.attempt_count) || 1),
      no_result_reason: visibleAlternatives.alternatives.length
        ? null
        : (openWorldOut?.no_result_reason || 'pool_and_open_world_empty'),
      recommendation_mode: recommendationMode,
      profile_mode: profileMode,
      template_id: 'reco_alternatives_hybrid_v1',
      raw_output_summary: openWorldOut?.raw_output_summary || emptyRawOutputSummary,
      llm_trace: openWorldOut?.llm_trace || null,
      compare_meta: {
        ...(groundedPoolMeta || {}),
        pool_selected_count: visibleAlternatives.alternatives.filter((row) => String(row?.candidate_origin || '') === 'pool').length,
        open_world_candidate_count: openWorldAlternatives.length,
        open_world_selected_count: visibleAlternatives.alternatives.filter((row) => String(row?.candidate_origin || '') === 'open_world').length,
        open_world_grounding_attempted_count: Number(openWorldOut?.llm_trace?.catalog_grounding_attempted_count || 0),
        open_world_grounded_count: Number(openWorldOut?.llm_trace?.catalog_grounded_count || 0),
        open_world_status: openWorldStatus,
        visible_authority_only_filter_applied: visibleAlternatives.visible_authority_only_filter_applied,
        hidden_unresolved_count: visibleAlternatives.hidden_unresolved_count,
        ranking_mode: 'grounded_pool_then_local_open_world',
        open_world_role: 'coverage_supplement',
        authority_backfill: openWorldBackfill || {
          mode: 'async_external_seed_backfill',
          policy: 'open_world_coverage_repair',
          open_world_role: 'coverage_supplement',
          open_world_row_count: openWorldAlternatives.length,
          coverage_gap_count: 0,
          recall_gap_count: 0,
          pending: false,
          status: 'not_needed',
          enqueued_brand_count: 0,
          enqueued_candidate_count: 0,
          brands: [],
        },
        ...buildRecoAlternativesTimingMeta(stageTimingsMs, requestStartedAt),
      },
      elapsed_ms: Math.max(0, Math.round(Date.now() - requestStartedAt)),
      ...(debug ? { debug: { anchor_precheck: anchorPrecheck, grounded_pool: groundedPoolMeta } } : {}),
    };
  }
  if (recommendationMode === 'open_world_only') {
    return fetchRecoAlternativesForLocalGeminiOpenWorld({
      ctx,
      productInput: bestInput,
      productObj: effectiveProductObj,
      maxTotal,
      profileMode,
      logger,
    });
  }
  const prefix = buildContextPrefix({
    profile: profileSummary || null,
    recentLogs: Array.isArray(recentLogs) ? recentLogs : [],
    lang: ctx.lang,
    trigger_source: ctx.trigger_source,
    intent: 'alternatives',
    action_id: pickFirstTrimmed(opts.context_action_id, 'chip.action.dupe_compare'),
  });
  const queryPack = buildAuroraRecoAlternativesQuery({
    lang: ctx.lang,
    profileSnapshot,
    productInput: bestInput,
    productObj: effectiveProductObj,
    maxTotal,
    region: normalizeRecoPromptRegion(profileSummary),
    candidates: selectorCandidatePool,
    anchorId: anchor,
    mode: recommendationMode,
    profileMode,
  });
  const query = `${prefix}${queryPack.query}`;

  const traceSeed = buildRecoPromptTrace({
    templateId: queryPack.templateId,
    query,
    latencyMs: null,
    cacheHit: false,
    provider: 'aurora',
    model: null,
    coverage: {
      has_anchor_id: Boolean(anchor),
      has_product_json: Boolean(serializeRecoAlternativesProductJson(effectiveProductObj)),
      has_recent_logs: Array.isArray(recentLogs) && recentLogs.length > 0,
    },
  });

  const startedAtMs = Date.now();
  let upstream = null;
  let llmFailureClass = null;
  try {
    upstream = await auroraChat({
      baseUrl: AURORA_DECISION_BASE_URL,
      query,
      timeoutMs: RECO_ALTERNATIVES_TIMEOUT_MS,
      retries: RECO_ALTERNATIVES_UPSTREAM_RETRIES,
      trace_id: ctx.trace_id,
      request_id: ctx.request_id,
      prompt_hash: traceSeed.prompt_hash,
      prompt_template_id: traceSeed.template_id,
      ...(anchor ? { anchor_product_id: anchor } : {}),
      intent_hint: 'alternatives',
      disallow_clarify: true,
      required_structured_keys: ['alternatives'],
      allow_recommendations: true,
    });
  } catch (err) {
    const transientCode = classifyRecoUpstreamFailureCode(err);
    llmFailureClass =
      err && err.code === 'AURORA_NOT_CONFIGURED'
        ? 'precheck_fail'
        : isTransientRecoUpstreamFailureCode(transientCode)
          ? 'timeout'
          : 'provider_error';
    recordAuroraRecoLlmCall({ stage: 'alternatives', outcome: llmFailureClass });
    if (selectorGroundedAlternatives.length) {
      const alternatives = recommendationMode === 'pool_open_world_mixed'
        ? mergeRecoAlternativesForHybrid([], selectorGroundedAlternatives, { maxTotal })
        : selectorGroundedAlternatives;
      return {
        ok: true,
        alternatives,
        field_missing: [],
        source_mode: recommendationMode === 'pool_open_world_mixed' ? 'pool_open_world_mixed' : 'selector_grounded',
        fallback_source: null,
        refresh_pending: false,
        refresh_after_ms: 0,
        failure_class: null,
        attempt_count: 1,
        recommendation_mode: recommendationMode,
        profile_mode: profileMode,
        template_id: queryPack.templateId,
        raw_output_summary: emptyRawOutputSummary,
        llm_trace: {
          ...traceSeed,
          latency_ms: Date.now() - startedAtMs,
          cache_hit: false,
          error_class: llmFailureClass,
        },
        ...(debug ? { debug: { anchor_precheck: anchorPrecheck, selector_grounded: true } } : {}),
      };
    }
    if (usesOpenWorldPrompt) {
      return {
        ok: true,
        alternatives: [],
        field_missing: [{ field: 'alternatives', reason: 'upstream_error' }],
        source_mode: recommendationMode,
        fallback_source: 'none',
        refresh_pending: false,
        refresh_after_ms: 0,
        failure_class: llmFailureClass,
        attempt_count: 1,
        no_result_reason: recommendationMode === 'open_world_only'
          ? 'no_viable_results_after_open_world'
          : null,
        recommendation_mode: recommendationMode,
        profile_mode: profileMode,
        template_id: queryPack.templateId,
        raw_output_summary: emptyRawOutputSummary,
        llm_trace: {
          ...traceSeed,
          latency_ms: Date.now() - startedAtMs,
          cache_hit: false,
          error_class: llmFailureClass,
        },
      };
    }
    const localFallback = disableFallback ? { alternatives: [], fallback_source: 'none' } : await buildLocalFallbackAlternatives({ failureClass: llmFailureClass });
    const localFallbackMeta = describeLocalFallbackVisibility(localFallback);
    return {
      ok: !disableFallback,
      alternatives: localFallback.alternatives,
      field_missing: localFallback.alternatives.length ? [] : [{ field: 'alternatives', reason: 'upstream_error' }],
      source_mode: disableFallback ? 'llm' : localFallbackMeta.source_mode,
      fallback_source: disableFallback ? 'none' : localFallbackMeta.fallback_source,
      refresh_pending: !disableFallback && Boolean(anchor) && Boolean(refreshKey),
      refresh_after_ms: !disableFallback && Boolean(anchor) && Boolean(refreshKey) ? RECO_ALTERNATIVES_REFRESH_DELAY_MS : 0,
      failure_class: llmFailureClass,
      attempt_count: 1,
      recommendation_mode: recommendationMode,
      profile_mode: profileMode,
      template_id: queryPack.templateId,
      raw_output_summary: emptyRawOutputSummary,
      llm_trace: {
        ...traceSeed,
        latency_ms: Date.now() - startedAtMs,
        cache_hit: false,
        error_class: llmFailureClass,
      },
    };
  }

  const answerJson =
    upstream && typeof upstream.answer === 'string' ? extractJsonObjectByKeys(upstream.answer, ['alternatives']) : null;
  const structuredFallback = getUpstreamStructuredOrJson(upstream);
  const structured =
    answerJson && typeof answerJson === 'object' && !Array.isArray(answerJson) && Array.isArray(answerJson.alternatives)
      ? answerJson
      : structuredFallback || answerJson;
  const alternativesRaw = Array.isArray(structured?.alternatives) ? structured.alternatives : [];
  const rawOutputSummary = summarizeRecoAlternativesRaw(alternativesRaw);
  let mapped = mapAuroraAlternativesToRecoAlternatives(alternativesRaw, {
    lang: ctx.lang,
    maxTotal: maxTotal ?? 3,
  });
  if (recommendationMode === 'pool_open_world_mixed') {
    mapped = mergeRecoAlternativesForHybrid(mapped, selectorGroundedAlternatives, { maxTotal });
  }
  const upstreamNoResultReason = pickFirstTrimmed(
    structured && structured.no_result_reason,
    structured && structured.result_meta && structured.result_meta.no_result_reason,
  );
  let llmOutcome = 'success';
  if (!mapped.length) {
    llmOutcome = String(upstream && upstream.intent || '').trim().toLowerCase() === 'clarify' ? 'empty_structured_clarify' : 'empty_structured';
  }
  recordAuroraRecoLlmCall({ stage: 'alternatives', outcome: llmOutcome });
  const llmTrace = {
    ...traceSeed,
    latency_ms: Date.now() - startedAtMs,
    cache_hit: false,
    ...(llmOutcome === 'success' ? {} : { error_class: llmOutcome === 'empty_structured_clarify' ? 'policy_skip' : 'empty_structured' }),
  };

  if (mapped.length) {
    writeRecoAlternativesCache(
      buildRecoAlternativesCacheKey({
        inputText: bestInput,
        anchorId: anchor,
        productObj,
        lang: ctx.lang,
        recommendationMode,
        profileMode,
      }),
      mapped,
      llmTrace,
    );
    return {
      ok: true,
      alternatives: mapped,
      field_missing: [],
      source_mode: recommendationMode === 'pool_only' ? 'llm' : recommendationMode,
      fallback_source: null,
      refresh_pending: false,
      refresh_after_ms: 0,
      failure_class: null,
      attempt_count: 1,
      recommendation_mode: recommendationMode,
      profile_mode: profileMode,
      template_id: queryPack.templateId,
      raw_output_summary: rawOutputSummary,
      llm_trace: llmTrace,
      ...(debug ? { debug: { anchor_precheck: anchorPrecheck, upstream_intent: upstream && upstream.intent ? upstream.intent : null } } : {}),
    };
  }

  if (selectorGroundedAlternatives.length) {
    const alternatives = recommendationMode === 'pool_open_world_mixed'
      ? mergeRecoAlternativesForHybrid([], selectorGroundedAlternatives, { maxTotal })
      : selectorGroundedAlternatives;
    return {
      ok: true,
      alternatives,
      field_missing: [],
      source_mode: recommendationMode === 'pool_open_world_mixed' ? 'pool_open_world_mixed' : 'selector_grounded',
      fallback_source: null,
      refresh_pending: false,
      refresh_after_ms: 0,
      failure_class: null,
      attempt_count: 1,
      recommendation_mode: recommendationMode,
      profile_mode: profileMode,
      template_id: queryPack.templateId,
      raw_output_summary: rawOutputSummary,
      llm_trace: llmTrace,
      ...(debug ? { debug: { anchor_precheck: anchorPrecheck, upstream_intent: upstream && upstream.intent ? upstream.intent : null, selector_grounded: true } } : {}),
    };
  }

  if (usesOpenWorldPrompt) {
    return {
      ok: true,
      alternatives: [],
      field_missing: [{ field: 'alternatives', reason: 'upstream_missing_or_empty' }],
      source_mode: recommendationMode,
      fallback_source: 'none',
      refresh_pending: false,
      refresh_after_ms: 0,
      failure_class: llmOutcome === 'empty_structured_clarify' ? 'empty_structured_clarify' : 'empty_structured',
      attempt_count: 1,
      no_result_reason: upstreamNoResultReason || 'no_viable_results_after_open_world',
      recommendation_mode: recommendationMode,
      profile_mode: profileMode,
      template_id: queryPack.templateId,
      raw_output_summary: rawOutputSummary,
      llm_trace: llmTrace,
      ...(debug ? { debug: { anchor_precheck: anchorPrecheck, upstream_intent: upstream && upstream.intent ? upstream.intent : null } } : {}),
    };
  }

  const localFallback = disableFallback ? { alternatives: [], fallback_source: 'none' } : await buildLocalFallbackAlternatives({
    failureClass: llmOutcome === 'empty_structured_clarify' ? 'policy_skip' : 'empty_structured',
  });
  const localFallbackMeta = describeLocalFallbackVisibility(localFallback);
  const shouldRefresh = !disableFallback && !disableAsyncRefresh && Boolean(anchor) && Boolean(refreshKey);
  if (shouldRefresh && !recoAlternativesRefreshInFlight.has(refreshKey)) {
    recoAlternativesRefreshInFlight.add(refreshKey);
    const refreshHandle = setTimeout(async () => {
      try {
        const refreshed = await fetchRecoAlternativesForProduct({
          ctx,
          profileSummary,
          recentLogs,
          productInput: bestInput,
          productObj,
          anchorId: anchor,
          maxTotal,
          debug: false,
          logger,
          options: {
            disable_fallback: true,
            disable_async_refresh: true,
            skip_anchor_precheck: true,
            prefer_refresh_cache: false,
            recommendation_mode: recommendationMode,
            profile_mode: profileMode,
            context_action_id: pickFirstTrimmed(opts.context_action_id, 'chip.action.dupe_compare'),
            disable_synthetic_local_fallback: disableSyntheticLocalFallback,
          },
        });
        if (refreshed && Array.isArray(refreshed.alternatives) && refreshed.alternatives.length) {
          setRecoAlternativesRefreshCache(refreshKey, {
            alternatives: refreshed.alternatives.slice(0, Math.max(1, Math.min(8, Number(maxTotal) || 6))),
            llm_trace: refreshed.llm_trace || null,
          });
        }
      } catch {
        // ignore refresh worker failure
      } finally {
        recoAlternativesRefreshInFlight.delete(refreshKey);
      }
    }, RECO_ALTERNATIVES_REFRESH_DELAY_MS);
    if (refreshHandle && typeof refreshHandle.unref === 'function') refreshHandle.unref();
  }

  return {
    ok: !disableFallback,
    alternatives: localFallback.alternatives,
    field_missing: localFallback.alternatives.length ? [] : [{ field: 'alternatives', reason: 'upstream_missing_or_empty' }],
    source_mode: disableFallback ? 'llm' : localFallbackMeta.source_mode,
    fallback_source: disableFallback ? 'none' : localFallbackMeta.fallback_source,
    refresh_pending: shouldRefresh,
    refresh_after_ms: shouldRefresh ? RECO_ALTERNATIVES_REFRESH_DELAY_MS : 0,
    failure_class: llmOutcome === 'empty_structured_clarify' ? 'empty_structured_clarify' : 'empty_structured',
    attempt_count: 1,
    recommendation_mode: recommendationMode,
    profile_mode: profileMode,
    template_id: queryPack.templateId,
    raw_output_summary: rawOutputSummary,
    llm_trace: llmTrace,
    ...(debug ? { debug: { anchor_precheck: anchorPrecheck, upstream_intent: upstream && upstream.intent ? upstream.intent : null } } : {}),
  };
}

async function enrichRecommendationsWithAlternatives({ ctx, profileSummary, recentLogs, recommendations, debug, logger }) {
  const recos = Array.isArray(recommendations) ? recommendations : [];
  const maxProducts = RECO_ALTERNATIVES_MAX_PRODUCTS;
  if (!recos.length || maxProducts <= 0) return { recommendations: recos, field_missing: [] };
  const alternativesBudget = {
    deadline_ms: Date.now() + AURORA_BFF_CHAT_RECO_BUDGET_MS,
  };

  const firstBySlot = { am: null, pm: null, other: null };
  for (let i = 0; i < recos.length; i += 1) {
    const item = recos[i];
    const slot = item && typeof item === 'object' ? String(item.slot || '').trim().toLowerCase() : '';
    const key = slot === 'am' ? 'am' : slot === 'pm' ? 'pm' : 'other';
    if (firstBySlot[key] == null) firstBySlot[key] = i;
  }

  const orderedIdx = [];
  const seenIdx = new Set();
  for (const key of ['am', 'pm', 'other']) {
    const idx = firstBySlot[key];
    if (typeof idx !== 'number') continue;
    if (seenIdx.has(idx)) continue;
    seenIdx.add(idx);
    orderedIdx.push(idx);
  }
  for (let i = 0; i < recos.length; i += 1) {
    if (seenIdx.has(i)) continue;
    orderedIdx.push(i);
  }

  const sharedCandidatePool = [];
  for (let i = 0; i < recos.length; i += 1) {
    const item = recos[i];
    const base = item && typeof item === 'object' ? item : null;
    const candidate =
      base && base.sku && typeof base.sku === 'object'
        ? base.sku
        : base && base.product && typeof base.product === 'object'
          ? base.product
          : base;
    const normalized = normalizeAlternativesSelectorCandidate(
      {
        ...(candidate && typeof candidate === 'object' ? candidate : {}),
        ...(typeof base?.url === 'string' ? { pdp_url: base.url, url: base.url } : {}),
        ...(Array.isArray(base?.reasons) ? { why_candidate: base.reasons } : {}),
      },
      { index: i },
    );
    if (normalized) sharedCandidatePool.push(normalized);
  }

  const targets = [];
  for (const idx of orderedIdx) {
    if (targets.length >= maxProducts) break;
    const item = recos[idx];
    const base = item && typeof item === 'object' ? item : null;
    const candidate =
      base && base.sku && typeof base.sku === 'object'
        ? base.sku
        : base && base.product && typeof base.product === 'object'
          ? base.product
          : base;

    const inputText = buildProductInputText(candidate, base && typeof base.url === 'string' ? base.url : null);
    const anchorId = extractAnchorIdFromProductLike(candidate) || extractAnchorIdFromProductLike(base);
    if (!inputText && !anchorId) continue;
    const anchorToken = String(anchorId || '').trim().toLowerCase();
    const candidatePool = sharedCandidatePool.filter((row) => {
      if (!row || typeof row !== 'object') return false;
      const idToken = String(row.id || '').trim().toLowerCase();
      const pidToken = String(row.product_id || row.sku_id || '').trim().toLowerCase();
      if (!anchorToken) return true;
      return idToken !== anchorToken && pidToken !== anchorToken;
    });
    targets.push({ idx, inputText, anchorId, productObj: candidate, candidatePool });
  }

  if (!targets.length) {
    return { recommendations: recos, field_missing: [{ field: 'recommendations[].alternatives', reason: 'recommendations_missing_product_identity' }] };
  }

  const results = await mapWithConcurrency(targets, RECO_ALTERNATIVES_CONCURRENCY, async (t) => {
    const out = await fetchRecoAlternativesForProduct({
      ctx,
      profileSummary,
      recentLogs,
      productInput: t.inputText,
      productObj: t.productObj,
      anchorId: t.anchorId,
      candidatePool: t.candidatePool,
      budget: alternativesBudget,
      debug,
      logger,
      options: {
        disable_fallback: true,
        disable_synthetic_local_fallback: true,
      },
    });
    return { ...out, idx: t.idx };
  });

  const enriched = recos.slice();
  let anyEmpty = false;
  let mergedFieldMissing = [];
  for (const r of results) {
    if (!r || typeof r !== 'object' || typeof r.idx !== 'number') continue;
    const base = enriched[r.idx];
    const next = base && typeof base === 'object' ? { ...base } : {};
    next.alternatives = Array.isArray(r.alternatives) ? r.alternatives : [];
    if (Array.isArray(r.alternatives) && r.alternatives.length > 0) {
      next.reco_reason_codes = uniqCaseInsensitiveStrings([
        ...asStringArray(next.reco_reason_codes),
        'matched_candidate',
      ], 8);
    }
    enriched[r.idx] = next;
    if (!next.alternatives.length) anyEmpty = true;
    mergedFieldMissing = mergeFieldMissing(mergedFieldMissing, r.field_missing);
  }

  let field_missing = mergedFieldMissing;
  if (anyEmpty) {
    field_missing = mergeFieldMissing(field_missing, [{ field: 'recommendations[].alternatives', reason: 'alternatives_partial' }]);
  }
  const debugInfo = debug
    ? results
      .map((r) => (r && typeof r === 'object' && r.debug ? { idx: r.idx, ...r.debug } : null))
      .filter(Boolean)
      .slice(0, 8)
    : null;
  return { recommendations: enriched, field_missing, ...(debugInfo ? { debug: debugInfo } : {}) };
}

async function generateRoutineReco({ ctx, profile, recentLogs, focus, constraints, includeAlternatives, logger }) {
  const profileSummary = summarizeProfileForContext(profile);
  const query = buildAuroraRoutineQuery({
    profile: { ...profileSummary, ...(profile && profile.currentRoutine ? { currentRoutine: profile.currentRoutine } : {}) },
    focus,
    constraints: constraints || {},
    lang: ctx.lang,
  });

  let upstream = null;
  try {
    upstream = await auroraChat({
      baseUrl: AURORA_DECISION_BASE_URL,
      query,
      timeoutMs: RECO_ROUTINE_UPSTREAM_TIMEOUT_MS,
      retries: 0,
    });
  } catch (err) {
    if (err && err.code !== 'AURORA_NOT_CONFIGURED') {
      logger?.warn({ err: err.message }, 'aurora bff: routine upstream failed');
    }
  }

  const contextObj = upstream && upstream.context && typeof upstream.context === 'object' ? upstream.context : null;
  const routine = contextObj ? contextObj.routine : null;
  const contextMeta = contextObj && typeof contextObj === 'object' && !Array.isArray(contextObj) ? { ...contextObj } : {};
  if (profileSummary && profileSummary.budgetTier && !contextMeta.budget && !contextMeta.budget_cny) {
    contextMeta.budget = profileSummary.budgetTier;
  }
  const mapped = mapAuroraRoutineToRecoGenerate(routine, contextMeta);
  const norm = normalizeRecoGenerate(mapped);
  norm.payload = { ...norm.payload, intent: 'routine', profile: profileSummary || null };

  if (includeAlternatives) {
    try {
      const alt = await enrichRecommendationsWithAlternatives({
        ctx,
        profileSummary,
        recentLogs,
        recommendations: norm.payload.recommendations,
        logger,
      });
      norm.payload = { ...norm.payload, recommendations: alt.recommendations };
      norm.field_missing = mergeFieldMissing(norm.field_missing, alt.field_missing);
    } catch (altErr) {
      logger?.warn({ err: altErr?.message, code: altErr?.code }, 'aurora bff: routine enrichRecommendationsWithAlternatives failed, continuing without alternatives');
    }
  }

  const budgetKnown = normalizeBudgetHint(profileSummary && profileSummary.budgetTier);
  if (budgetKnown && Array.isArray(norm.payload?.missing_info)) {
    norm.payload.missing_info = norm.payload.missing_info.filter((code) => String(code) !== 'budget_unknown');
  }

  try {
    const pdpOpenOut = await enrichRecommendationsWithPdpOpenContract({
      recommendations: norm.payload.recommendations,
      logger,
      lightEnrich: RECO_PDP_LIGHT_ENRICH_ENABLED,
    });
    norm.payload = {
      ...norm.payload,
      recommendations: pdpOpenOut.recommendations,
      metadata: {
        ...(isPlainObject(norm.payload?.metadata) ? norm.payload.metadata : {}),
        pdp_open_path_stats: pdpOpenOut.path_stats,
        resolve_fail_reason_counts: pdpOpenOut.fail_reason_counts,
        time_to_pdp_ms_stats: pdpOpenOut.time_to_pdp_ms_stats,
      },
    };
  } catch (pdpErr) {
    logger?.warn({ err: pdpErr?.message, code: pdpErr?.code }, 'aurora bff: routine enrichRecommendationsWithPdpOpenContract failed, continuing without PDP enrichment');
  }

  const suggestedChips = [];
  const nextActions = upstream && Array.isArray(upstream.next_actions) ? upstream.next_actions : [];
  if ((!norm.payload.recommendations || norm.payload.recommendations.length === 0) && nextActions.length) {
    for (const act of nextActions.slice(0, 8)) {
      if (!act || typeof act !== 'object') continue;
      const label = typeof act.label === 'string' ? act.label.trim() : typeof act.text === 'string' ? act.text.trim() : '';
      const text = typeof act.text === 'string' ? act.text.trim() : label;
      const id = typeof act.id === 'string' ? act.id.trim() : '';
      if (!label) continue;
      suggestedChips.push({
        chip_id: `chip.aurora.next_action.${id || label.replace(/\\s+/g, '_')}`.slice(0, 80),
        label,
        kind: 'quick_reply',
        data: { reply_text: text, aurora_action_id: id || null },
      });
    }
  }

  return { norm, suggestedChips };
}

function buildRecoLlmPromptState({
  prefix = '',
  profileSummary = null,
  recentLogs = [],
  requestText = '',
  lang = 'EN',
  globalStatus = null,
  ingredientContext = null,
  candidates = [],
} = {}) {
  const promptBundle = buildAuroraProductRecommendationsPromptBundle({
    profile: profileSummary || {},
    requestText,
    lang,
    globalStatus: isPlainObject(globalStatus) ? globalStatus : {},
    candidates: Array.isArray(candidates) ? candidates : [],
    ingredientContext,
  });
  const query = `${prefix}${promptBundle.query}`;
  const llmTraceCoverage = buildRecoInputCoverage({
    profileSummary,
    recentLogs,
    requestText,
  });
  const llmTraceSeed = buildRecoPromptTrace({
    templateId: promptBundle.prompt_spec.template_id,
    query,
    latencyMs: null,
    cacheHit: false,
    provider: 'aurora',
    model: null,
    coverage: llmTraceCoverage,
  });
  llmTraceSeed.schema_chars = Number(promptBundle.schema_chars || 0);
  llmTraceSeed.llm_mode = String(promptBundle.prompt_spec.llm_mode || '').trim() || null;
  llmTraceSeed.candidate_count = Array.isArray(candidates) ? candidates.length : 0;
  const promptContractBase = validateRecoPromptContract({
    query,
    expectedTemplateId: promptBundle.prompt_spec.template_id,
    expectedPromptHash: llmTraceSeed.prompt_hash,
  });
  const promptContract = AURORA_RECO_FORCE_PROMPT_CONTRACT_MISMATCH
    ? {
      ...promptContractBase,
      ok: false,
      issues: Array.from(new Set([...(Array.isArray(promptContractBase.issues) ? promptContractBase.issues : []), 'forced_mismatch'])),
    }
    : promptContractBase;
  return {
    promptBundle,
    query,
    llmTraceSeed,
    promptContract,
  };
}

async function runRecoLlmPrimary({
  ctx,
  logger,
  promptState,
  profileSummary = null,
} = {}) {
  const state = isPlainObject(promptState) ? promptState : {};
  const promptBundle = isPlainObject(state.promptBundle) ? state.promptBundle : { prompt_spec: {}, schema_chars: 0 };
  const query = typeof state.query === 'string' ? state.query : '';
  const promptContract = isPlainObject(state.promptContract) ? state.promptContract : { ok: true, issues: [] };
  const llmTraceSeed = isPlainObject(state.llmTraceSeed) ? state.llmTraceSeed : {};
  let upstream = null;
  let contextMeta = {};
  let upstreamFailureCode = '';
  let llmFailureClass = '';
  let llmLatencyMs = null;
  let answerJson = null;
  let llmStructured = null;
  let llmStructuredSource = null;
  let initialLlmOutcome = promptContract.ok ? 'not_invoked' : 'prompt_contract_mismatch';
  let llmInvoked = false;

  if (!promptContract.ok) {
    llmLatencyMs = 0;
    upstreamFailureCode = 'PROMPT_CONTRACT_MISMATCH';
    llmFailureClass = 'precheck_fail';
    recordAuroraRecoLlmCall({ stage: 'main', outcome: 'prompt_contract_mismatch' });
    recordPromptContractMismatch();
    recordAuroraSkinFlowMetric({ stage: 'reco_prompt_contract_mismatch', hit: true });
    logger?.warn(
      {
        request_id: ctx?.request_id,
        trace_id: ctx?.trace_id,
        prompt_contract_issues: promptContract.issues,
        expected_template_id: promptBundle.prompt_spec?.template_id,
        actual_template_id: promptContract.template_id,
        expected_prompt_hash: promptContract.prompt_hash_expected,
        actual_prompt_hash: promptContract.prompt_hash_actual,
      },
      'aurora bff: reco prompt contract mismatch; skip upstream call',
    );
  } else {
    const llmStartedAtMs = Date.now();
    try {
      llmInvoked = true;
      upstream = await auroraChat({
        baseUrl: AURORA_DECISION_BASE_URL,
        query,
        timeoutMs: RECO_UPSTREAM_TIMEOUT_MS,
        trace_id: ctx?.trace_id,
        request_id: ctx?.request_id,
        prompt_hash: llmTraceSeed.prompt_hash,
        prompt_template_id: llmTraceSeed.template_id,
      });
      llmLatencyMs = Date.now() - llmStartedAtMs;
    } catch (err) {
      llmLatencyMs = Date.now() - llmStartedAtMs;
      upstreamFailureCode = classifyRecoUpstreamFailureCode(err);
      initialLlmOutcome = isTransientRecoUpstreamFailureCode(upstreamFailureCode) ? 'upstream_timeout' : 'upstream_dependency_failure';
      if (isTransientRecoUpstreamFailureCode(upstreamFailureCode)) {
        llmFailureClass = 'timeout';
      }
      if (err && err.code !== 'AURORA_NOT_CONFIGURED') {
        logger?.warn(
          {
            err: err && err.message ? err.message : String(err),
            code: err && err.code ? err.code : null,
            normalized_code: upstreamFailureCode || null,
          },
          'aurora bff: product reco upstream failed',
        );
      }
    }

    const contextObj = upstream && upstream.context && typeof upstream.context === 'object' ? upstream.context : null;
    const routine = contextObj ? contextObj.routine : null;
    contextMeta = contextObj && typeof contextObj === 'object' && !Array.isArray(contextObj) ? { ...contextObj } : {};
    if (profileSummary && profileSummary.budgetTier && !contextMeta.budget && !contextMeta.budget_cny) {
      contextMeta.budget = profileSummary.budgetTier;
    }
    answerJson = upstream && typeof upstream.answer === 'string' ? extractJsonObjectByKeys(upstream.answer, ['recommendations']) : null;
    const structuredFallback = getUpstreamStructuredOrJson(upstream);
    llmStructured = answerJson;
    llmStructuredSource = answerJson ? 'llm_answer_json' : null;
    if (!llmStructured && routine) {
      llmStructured = mapAuroraRoutineToRecoGenerate(routine, contextMeta);
      llmStructuredSource = 'llm_context_routine';
    }
    if (!llmStructured) {
      llmStructured = structuredFallback;
      llmStructuredSource = structuredFallback ? 'llm_structured_fallback' : null;
    }
    const llmStructuredRecoEmpty = hasEmptyStructuredRecommendations(llmStructured);
    if (
      promptContract.ok &&
      !llmFailureClass &&
      llmStructured &&
      typeof llmStructured === 'object' &&
      !Array.isArray(llmStructured) &&
      !Array.isArray(llmStructured.recommendations)
    ) {
      llmFailureClass = 'schema_invalid';
      initialLlmOutcome = 'schema_invalid';
      recordAuroraRecoLlmCall({ stage: 'main', outcome: 'schema_invalid' });
    } else if (!llmFailureClass && llmStructuredRecoEmpty) {
      llmFailureClass = 'empty_structured';
      initialLlmOutcome = 'empty_structured';
      recordAuroraRecoLlmCall({ stage: 'main', outcome: 'empty_structured' });
    } else if (!llmFailureClass && llmStructured) {
      initialLlmOutcome = 'success';
      recordAuroraRecoLlmCall({ stage: 'main', outcome: 'success' });
    } else if (!llmFailureClass && llmInvoked) {
      initialLlmOutcome = 'empty_structured';
      llmFailureClass = 'empty_structured';
      recordAuroraRecoLlmCall({ stage: 'main', outcome: 'empty_structured' });
    }
  }

  const llmTrace = {
    ...llmTraceSeed,
    latency_ms: llmLatencyMs,
    cache_hit: false,
    prompt_contract_ok: promptContract.ok,
    ...(promptContract.ok ? {} : { prompt_contract_issues: promptContract.issues.slice(0, 6) }),
    ...(llmFailureClass ? { error_class: llmFailureClass } : {}),
  };

  return {
    promptBundle,
    query,
    promptContract,
    llmTrace,
    upstream,
    contextMeta,
    upstreamFailureCode,
    llmFailureClass,
    llmLatencyMs,
    answerJson,
    llmStructured,
    llmStructuredSource,
    initialLlmOutcome,
    llmInvoked,
  };
}

