  app.post('/v1/photos/presign', async (req, res) => {
    const ctx = buildRequestContext(req, {});
    try {
      requireAuroraUid(ctx);
      const parsed = PhotosPresignRequestSchema.safeParse(req.body || {});
      if (!parsed.success) {
        const envelope = buildEnvelope(ctx, {
          assistant_message: makeAssistantMessage('Invalid request.'),
          suggested_chips: [],
          cards: [{ card_id: `err_${ctx.request_id}`, type: 'error', payload: { error: 'BAD_REQUEST', details: parsed.error.format() } }],
          session_patch: {},
          events: [makeEvent(ctx, 'error', { code: 'BAD_REQUEST' })],
        });
        return res.status(400).json(envelope);
      }

      if (USE_AURORA_BFF_MOCK) {
        // Stub: real storage/QC should be wired via pivota-backend photos endpoints.
        const photoId = `photo_${ctx.request_id}_${Date.now()}`;
        const payload = {
          photo_id: photoId,
          slot_id: parsed.data.slot_id,
          upload: {
            method: 'PUT',
            url: null,
            headers: {},
            expires_in_seconds: 600,
          },
        };

        const envelope = buildEnvelope(ctx, {
          assistant_message: null,
          suggested_chips: [],
          cards: [
            {
              card_id: `presign_${ctx.request_id}`,
              type: 'photo_presign',
              payload,
              field_missing: [{ field: 'upload.url', reason: 'mock_mode' }],
            },
          ],
          session_patch: {},
          events: [makeEvent(ctx, 'value_moment', { kind: 'photo_presign' })],
        });
        return res.json(envelope);
      }

      if (!PIVOTA_BACKEND_BASE_URL) {
        const photoId = `photo_${ctx.request_id}_${Date.now()}`;
        const payload = {
          photo_id: photoId,
          slot_id: parsed.data.slot_id,
          upload: {
            method: 'PUT',
            url: null,
            headers: {},
            expires_in_seconds: 600,
          },
        };

        const envelope = buildEnvelope(ctx, {
          assistant_message: null,
          suggested_chips: [],
          cards: [
            {
              card_id: `presign_${ctx.request_id}`,
              type: 'photo_presign',
              payload,
              field_missing: [{ field: 'upload.url', reason: 'pivota_backend_not_configured' }],
            },
          ],
          session_patch: {},
          events: [makeEvent(ctx, 'value_moment', { kind: 'photo_presign' })],
        });
        return res.json(envelope);
      }

      const authHeaders = buildPivotaBackendAuthHeaders(req);
      if (!Object.keys(authHeaders).length) {
        const photoId = `photo_${ctx.request_id}_${Date.now()}`;
        const payload = {
          photo_id: photoId,
          slot_id: parsed.data.slot_id,
          upload: {
            method: 'PUT',
            url: null,
            headers: {},
            expires_in_seconds: 600,
          },
        };

        const envelope = buildEnvelope(ctx, {
          assistant_message: null,
          suggested_chips: [],
          cards: [
            {
              card_id: `presign_${ctx.request_id}`,
              type: 'photo_presign',
              payload,
              field_missing: [{ field: 'upload.url', reason: 'pivota_backend_auth_not_configured' }],
            },
          ],
          session_patch: {},
          events: [makeEvent(ctx, 'value_moment', { kind: 'photo_presign' })],
        });
        return res.json(envelope);
      }

      const contentType =
        typeof parsed.data.content_type === 'string' && parsed.data.content_type.trim()
          ? parsed.data.content_type.trim()
          : 'image/jpeg';
      const byteSize = typeof parsed.data.bytes === 'number' && Number.isFinite(parsed.data.bytes) ? parsed.data.bytes : null;

      const upstreamResp = await axios.post(
        `${PIVOTA_BACKEND_BASE_URL}/photos/presign`,
        {
          content_type: contentType,
          ...(byteSize ? { byte_size: byteSize } : {}),
          consent: true,
          user_id: ctx.aurora_uid,
        },
        {
          timeout: 12000,
          validateStatus: () => true,
          headers: { 'Content-Type': 'application/json', ...authHeaders },
        },
      );

      if (upstreamResp.status !== 200 || !upstreamResp.data || !upstreamResp.data.upload_id || !upstreamResp.data.upload) {
        const detail = pickUpstreamErrorDetail(upstreamResp.data);
        const envelope = buildEnvelope(ctx, {
          assistant_message: makeAssistantMessage('Failed to presign upload.'),
          suggested_chips: [],
          cards: [
            {
              card_id: `err_${ctx.request_id}`,
              type: 'error',
              payload: {
                error: 'PHOTO_PRESIGN_UPSTREAM_FAILED',
                status: upstreamResp.status,
                detail: detail || null,
              },
            },
          ],
          session_patch: {},
          events: [makeEvent(ctx, 'error', { code: 'PHOTO_PRESIGN_UPSTREAM_FAILED', status: upstreamResp.status })],
        });
        return res.status(upstreamResp.status >= 400 ? upstreamResp.status : 502).json(envelope);
      }

      const uploadId = String(upstreamResp.data.upload_id);
      const upstreamUpload = upstreamResp.data.upload || {};
      const expiresInSeconds = secondsUntilIso(upstreamResp.data.expires_at) ?? 900;

      const payload = {
        photo_id: uploadId,
        slot_id: parsed.data.slot_id,
        upload: {
          method: upstreamUpload.method || 'PUT',
          url: upstreamUpload.url || null,
          headers: upstreamUpload.headers || {},
          expires_in_seconds: expiresInSeconds,
        },
        ...(typeof upstreamResp.data.max_bytes === 'number' ? { max_bytes: upstreamResp.data.max_bytes } : {}),
        ...(upstreamResp.data.tips ? { tips: upstreamResp.data.tips } : {}),
      };

      const fieldMissing = [];
      if (!payload.upload.url) fieldMissing.push({ field: 'upload.url', reason: 'upstream_missing_upload_url' });

      const envelope = buildEnvelope(ctx, {
        assistant_message: null,
        suggested_chips: [],
        cards: [
          {
            card_id: `presign_${ctx.request_id}`,
            type: 'photo_presign',
            payload,
            ...(fieldMissing.length ? { field_missing: fieldMissing } : {}),
          },
        ],
        session_patch: {},
        events: [makeEvent(ctx, 'value_moment', { kind: 'photo_presign' })],
      });
      return res.json(envelope);
    } catch (err) {
      const status = err.status || 500;
      const envelope = buildEnvelope(ctx, {
        assistant_message: makeAssistantMessage('Failed to presign upload.'),
        suggested_chips: [],
        cards: [{ card_id: `err_${ctx.request_id}`, type: 'error', payload: { error: err.code || 'PHOTO_PRESIGN_FAILED' } }],
        session_patch: {},
        events: [makeEvent(ctx, 'error', { code: err.code || 'PHOTO_PRESIGN_FAILED' })],
      });
      return res.status(status).json(envelope);
    }
  });

  // Proxy upload to avoid browser-to-storage CORS issues.
  // Request: multipart/form-data with fields:
  // - slot_id (required)
  // - consent=true (required)
  // - file field: photo (required)
  app.post('/v1/photos/upload', async (req, res) => {
    const ctx = buildRequestContext(req, {});
    let tmpDir = null;
    let uploadStage = 'initialize';
    try {
      requireAuroraUid(ctx);

      if (USE_AURORA_BFF_MOCK) {
        const photoId = `photo_${ctx.request_id}_${Date.now()}`;
        const payload = {
          photo_id: photoId,
          slot_id: 'daylight',
          qc_status: 'passed',
          qc: { state: 'done', qc_status: 'passed', advice: { summary: 'Mock: photo looks good.', suggestions: [] } },
        };
        const envelope = buildEnvelope(ctx, {
          assistant_message: null,
          suggested_chips: [],
          cards: [
            {
              card_id: `confirm_${ctx.request_id}`,
              type: 'photo_confirm',
              payload,
              field_missing: [{ field: 'upload.url', reason: 'mock_mode' }],
            },
          ],
          session_patch: {},
          events: [makeEvent(ctx, 'value_moment', { kind: 'photo_upload', qc_status: 'passed' })],
        });
        return res.json(envelope);
      }

      const authHeaders = buildPivotaBackendAuthHeaders(req);
      if (!PIVOTA_BACKEND_BASE_URL) {
        const payload = { photo_id: null, slot_id: null, qc_status: null };
        const envelope = buildEnvelope(ctx, {
          assistant_message: makeAssistantMessage('Photo upload is not configured.'),
          suggested_chips: [],
          cards: [
            {
              card_id: `confirm_${ctx.request_id}`,
              type: 'photo_confirm',
              payload,
              field_missing: [{ field: 'photo_id', reason: 'pivota_backend_not_configured' }],
            },
          ],
          session_patch: {},
          events: [makeEvent(ctx, 'error', { code: 'PHOTO_UPLOAD_NOT_CONFIGURED' })],
        });
        return res.status(501).json(envelope);
      }
      if (!Object.keys(authHeaders).length) {
        const payload = { photo_id: null, slot_id: null, qc_status: null };
        const envelope = buildEnvelope(ctx, {
          assistant_message: makeAssistantMessage('Photo upload auth is not configured.'),
          suggested_chips: [],
          cards: [
            {
              card_id: `confirm_${ctx.request_id}`,
              type: 'photo_confirm',
              payload,
              field_missing: [{ field: 'photo_id', reason: 'pivota_backend_auth_not_configured' }],
            },
          ],
          session_patch: {},
          events: [makeEvent(ctx, 'error', { code: 'PHOTO_UPLOAD_AUTH_NOT_CONFIGURED' })],
        });
        return res.status(501).json(envelope);
      }

      const reqContentType = String(req.headers['content-type'] || '').toLowerCase();
      if (!reqContentType.includes('multipart/form-data') || !reqContentType.includes('boundary=')) {
        const envelope = buildEnvelope(ctx, {
          assistant_message: makeAssistantMessage('Invalid request.'),
          suggested_chips: [],
          cards: [{ card_id: `err_${ctx.request_id}`, type: 'error', payload: { error: 'BAD_REQUEST', detail: 'multipart_required' } }],
          session_patch: {},
          events: [makeEvent(ctx, 'error', { code: 'BAD_REQUEST' })],
        });
        return res.status(400).json(envelope);
      }

      uploadStage = 'parse_multipart';
      const { fields, files, tmpDir: parsedTmpDir } = await parseMultipart(req, {
        maxBytes: PHOTO_UPLOAD_PROXY_MAX_BYTES,
        parseTimeoutMs: PHOTO_UPLOAD_PARSE_TIMEOUT_MS,
        allowedContentTypes: new Set(['image/jpeg', 'image/png', 'image/webp', 'image/heic', 'image/heif']),
        requiredFields: ['slot_id', 'consent'],
      });
      tmpDir = parsedTmpDir;

      const slotId = String(fields.slot_id || '').trim();
      if (!slotId) {
        const envelope = buildEnvelope(ctx, {
          assistant_message: makeAssistantMessage('Missing slot_id.'),
          suggested_chips: [],
          cards: [{ card_id: `err_${ctx.request_id}`, type: 'error', payload: { error: 'BAD_REQUEST', detail: 'slot_id_required' } }],
          session_patch: {},
          events: [makeEvent(ctx, 'error', { code: 'BAD_REQUEST' })],
        });
        return res.status(400).json(envelope);
      }

      const consentRaw = String(fields.consent || '').trim().toLowerCase();
      const consent = consentRaw === 'true' || consentRaw === '1' || consentRaw === 'yes';
      if (!consent) {
        const envelope = buildEnvelope(ctx, {
          assistant_message: makeAssistantMessage('User consent is required.'),
          suggested_chips: [],
          cards: [{ card_id: `err_${ctx.request_id}`, type: 'error', payload: { error: 'USER_CONSENT_REQUIRED' } }],
          session_patch: {},
          events: [makeEvent(ctx, 'error', { code: 'USER_CONSENT_REQUIRED' })],
        });
        return res.status(400).json(envelope);
      }

      const fileEntry = files.photo || files.file || files.image || Object.values(files || {})[0];
      if (!fileEntry || !fileEntry.path) {
        const envelope = buildEnvelope(ctx, {
          assistant_message: makeAssistantMessage('Missing photo file.'),
          suggested_chips: [],
          cards: [{ card_id: `err_${ctx.request_id}`, type: 'error', payload: { error: 'BAD_REQUEST', detail: 'photo_file_required' } }],
          session_patch: {},
          events: [makeEvent(ctx, 'error', { code: 'BAD_REQUEST' })],
        });
        return res.status(400).json(envelope);
      }

      const stat = fs.statSync(fileEntry.path);
      const byteSize = Number.isFinite(stat.size) ? stat.size : null;
      const contentType = fileEntry.contentType || 'image/jpeg';

      uploadStage = 'presign_request';
      const presignResp = await axios.post(
        `${PIVOTA_BACKEND_BASE_URL}/photos/presign`,
        {
          content_type: contentType,
          ...(byteSize ? { byte_size: byteSize } : {}),
          consent: true,
          user_id: ctx.aurora_uid,
        },
        {
          timeout: 12000,
          validateStatus: () => true,
          headers: { 'Content-Type': 'application/json', ...authHeaders },
        },
      );

      if (presignResp.status !== 200 || !presignResp.data || !presignResp.data.upload_id || !presignResp.data.upload) {
        const detail = pickUpstreamErrorDetail(presignResp.data);
        const envelope = buildEnvelope(ctx, {
          assistant_message: makeAssistantMessage('Failed to start photo upload.'),
          suggested_chips: [],
          cards: [
            {
              card_id: `err_${ctx.request_id}`,
              type: 'error',
              payload: { error: 'PHOTO_PRESIGN_UPSTREAM_FAILED', status: presignResp.status, detail: detail || null },
            },
          ],
          session_patch: {},
          events: [makeEvent(ctx, 'error', { code: 'PHOTO_PRESIGN_UPSTREAM_FAILED', status: presignResp.status })],
        });
        return res.status(presignResp.status >= 400 ? presignResp.status : 502).json(envelope);
      }

      const uploadId = String(presignResp.data.upload_id);
      const upstreamUpload = presignResp.data.upload || {};
      const uploadUrl = typeof upstreamUpload.url === 'string' ? upstreamUpload.url.trim() : '';
      const uploadMethod = typeof upstreamUpload.method === 'string' && upstreamUpload.method.trim()
        ? upstreamUpload.method.trim().toUpperCase()
        : 'PUT';
      const uploadHeaders = upstreamUpload.headers && typeof upstreamUpload.headers === 'object' ? upstreamUpload.headers : {};

      if (!uploadUrl) {
        const envelope = buildEnvelope(ctx, {
          assistant_message: makeAssistantMessage('Upload URL is missing from upstream.'),
          suggested_chips: [],
          cards: [{ card_id: `err_${ctx.request_id}`, type: 'error', payload: { error: 'UPSTREAM_MISSING_UPLOAD_URL' } }],
          session_patch: {},
          events: [makeEvent(ctx, 'error', { code: 'UPSTREAM_MISSING_UPLOAD_URL' })],
        });
        return res.status(502).json(envelope);
      }

      const hasHeader = (headersObj, key) => {
        const wanted = String(key || '').toLowerCase();
        for (const k of Object.keys(headersObj || {})) {
          if (String(k).toLowerCase() === wanted) return true;
        }
        return false;
      };

      const finalUploadHeaders = { ...uploadHeaders };
      // Some S3-compatible providers require a Content-Length (otherwise 411 Length Required).
      if (byteSize && !hasHeader(finalUploadHeaders, 'content-length')) {
        finalUploadHeaders['Content-Length'] = String(byteSize);
      }
      // Ensure Content-Type is present if upstream didn't include it.
      if (contentType && !hasHeader(finalUploadHeaders, 'content-type')) {
        finalUploadHeaders['Content-Type'] = contentType;
      }

      uploadStage = 'upload_bytes';
      const uploadResp = await axios.request({
        method: uploadMethod,
        url: uploadUrl,
        headers: finalUploadHeaders,
        data: fs.createReadStream(fileEntry.path),
        timeout: 120000,
        maxBodyLength: 30 * 1024 * 1024,
        maxContentLength: 30 * 1024 * 1024,
        validateStatus: () => true,
      });

      if (uploadResp.status < 200 || uploadResp.status >= 300) {
        const detail =
          typeof uploadResp.data === 'string'
            ? uploadResp.data.slice(0, 4000)
            : uploadResp.data && typeof uploadResp.data === 'object'
              ? JSON.stringify(uploadResp.data).slice(0, 4000)
              : null;
        const envelope = buildEnvelope(ctx, {
          assistant_message: makeAssistantMessage('Failed to upload photo bytes.'),
          suggested_chips: [],
          cards: [
            {
              card_id: `err_${ctx.request_id}`,
              type: 'error',
              payload: { error: 'PHOTO_UPLOAD_BYTES_FAILED', status: uploadResp.status, detail },
            },
          ],
          session_patch: {},
          events: [makeEvent(ctx, 'error', { code: 'PHOTO_UPLOAD_BYTES_FAILED', status: uploadResp.status })],
        });
        return res.status(502).json(envelope);
      }

      uploadStage = 'confirm_request';
      const confirmResp = await axios.post(
        `${PIVOTA_BACKEND_BASE_URL}/photos/confirm`,
        { upload_id: uploadId, ...(byteSize ? { byte_size: byteSize } : {}) },
        {
          timeout: 12000,
          validateStatus: () => true,
          headers: { 'Content-Type': 'application/json', ...authHeaders },
        },
      );

      if (confirmResp.status !== 200 || !confirmResp.data) {
        const detail = pickUpstreamErrorDetail(confirmResp.data);
        const envelope = buildEnvelope(ctx, {
          assistant_message: makeAssistantMessage('Failed to confirm upload.'),
          suggested_chips: [],
          cards: [
            {
              card_id: `err_${ctx.request_id}`,
              type: 'error',
              payload: { error: 'PHOTO_CONFIRM_UPSTREAM_FAILED', status: confirmResp.status, detail: detail || null },
            },
          ],
          session_patch: {},
          events: [makeEvent(ctx, 'error', { code: 'PHOTO_CONFIRM_UPSTREAM_FAILED', status: confirmResp.status })],
        });
        return res.status(confirmResp.status >= 400 ? confirmResp.status : 502).json(envelope);
      }

      let qcStatus = resolvePhotoQcStatus(confirmResp.data);
      let qc = confirmResp.data.qc && typeof confirmResp.data.qc === 'object' ? confirmResp.data.qc : null;
      let nextPollMs = typeof confirmResp.data.next_poll_ms === 'number' ? confirmResp.data.next_poll_ms : null;

      const deadlineMs = Date.now() + 6000;
      let lastQcData = null;
      while (!qcStatus && Date.now() < deadlineMs) {
        const waitMs = Math.min(1200, Math.max(400, nextPollMs || 1000));
        await sleep(waitMs);

        uploadStage = 'qc_poll';
        const qcResp = await axios.get(`${PIVOTA_BACKEND_BASE_URL}/photos/qc`, {
          timeout: 12000,
          validateStatus: () => true,
          headers: authHeaders,
          params: { upload_id: uploadId },
        });

        if (qcResp.status !== 200 || !qcResp.data) break;
        lastQcData = qcResp.data;
        const resolvedPollStatus = resolvePhotoQcStatus(qcResp.data);
        if (resolvedPollStatus) qcStatus = resolvedPollStatus;
        qc = qcResp.data.qc && typeof qcResp.data.qc === 'object' ? qcResp.data.qc : qc;
        nextPollMs = typeof qcResp.data.next_poll_ms === 'number' ? qcResp.data.next_poll_ms : nextPollMs;
      }

      const normalizedQcPayload = harmonizePhotoQcCardPayload({
        qcStatus,
        qc,
        nextPollMs,
        language: ctx.lang,
      });
      qcStatus = normalizedQcPayload.qcStatus;
      qc = normalizedQcPayload.qc;
      nextPollMs = normalizedQcPayload.nextPollMs;

      const payload = {
        photo_id: uploadId,
        slot_id: slotId,
        qc_status: qcStatus,
        ...(qc ? { qc } : {}),
        ...(typeof nextPollMs === 'number' ? { next_poll_ms: nextPollMs } : {}),
        ...(!qcStatus && lastQcData ? { qc_pending: true } : {}),
      };

      try {
        const uploadBuffer = fs.readFileSync(fileEntry.path);
        setPhotoBytesCache({
          photoId: uploadId,
          auroraUid: ctx.aurora_uid,
          buffer: uploadBuffer,
          contentType,
        });
      } catch (cacheErr) {
        logger?.warn({ err: cacheErr && cacheErr.message ? cacheErr.message : String(cacheErr) }, 'aurora bff: failed to cache upload bytes');
      }

      const fieldMissing = [];
      if (!qcStatus) fieldMissing.push({ field: 'qc_status', reason: 'qc_pending' });

      const photoConfirmCard = {
        card_id: `confirm_${ctx.request_id}`,
        type: 'photo_confirm',
        payload,
        ...(fieldMissing.length ? { field_missing: fieldMissing } : {}),
      };
      if (isPassedPhotoQcStatus(qcStatus)) {
        setRecentConfirmedPhoto({
          photoId: uploadId,
          auroraUid: ctx.aurora_uid,
          slotId,
          qcStatus,
        });
      }
      const autoAnalysis = await safeBuildAutoAnalysisFromConfirmedPhoto({
        req,
        ctx,
        photoId: uploadId,
        slotId,
        qcStatus,
        logger,
      });

      const envelope = buildEnvelope(ctx, {
        assistant_message: null,
        suggested_chips: [],
        cards: [photoConfirmCard, ...(autoAnalysis && Array.isArray(autoAnalysis.cards) ? autoAnalysis.cards : [])],
        session_patch: autoAnalysis && autoAnalysis.session_patch ? autoAnalysis.session_patch : {},
        events: [
          makeEvent(ctx, 'value_moment', { kind: 'photo_upload', qc_status: qcStatus }),
          ...(autoAnalysis && autoAnalysis.event ? [autoAnalysis.event] : []),
        ],
      });
      return res.json(envelope);
    } catch (err) {
      const status = Number(err?.statusCode || err?.status || 500);
      const code = derivePhotoIoStageFailureCode({
        flow: 'photo_upload',
        stage: uploadStage,
        err,
        fallbackCode: 'PHOTO_UPLOAD_FAILED',
      });
      logger?.error(
        {
          err: err && err.message ? err.message : String(err),
          code,
          stage: uploadStage,
          request_id: ctx.request_id,
          trace_id: ctx.trace_id,
          aurora_uid: ctx.aurora_uid,
        },
        'aurora bff: /v1/photos/upload failed',
      );
      const envelope = buildEnvelope(ctx, {
        assistant_message: makeAssistantMessage('Failed to upload photo.'),
        suggested_chips: [],
        cards: [{ card_id: `err_${ctx.request_id}`, type: 'error', payload: { error: code, stage: uploadStage } }],
        session_patch: {},
        events: [makeEvent(ctx, 'error', { code, stage: uploadStage })],
      });
      return res.status(status).json(envelope);
    } finally {
      if (tmpDir) rmrf(tmpDir);
    }
  });

  app.post('/v1/photos/confirm', async (req, res) => {
    const ctx = buildRequestContext(req, {});
    let confirmStage = 'initialize';
    try {
      requireAuroraUid(ctx);
      const parsed = PhotosConfirmRequestSchema.safeParse(req.body || {});
      if (!parsed.success) {
        const envelope = buildEnvelope(ctx, {
          assistant_message: makeAssistantMessage('Invalid request.'),
          suggested_chips: [],
          cards: [{ card_id: `err_${ctx.request_id}`, type: 'error', payload: { error: 'BAD_REQUEST', details: parsed.error.format() } }],
          session_patch: {},
          events: [makeEvent(ctx, 'error', { code: 'BAD_REQUEST' })],
        });
        return res.status(400).json(envelope);
      }

      if (USE_AURORA_BFF_MOCK) {
        const qcStatus = 'passed';
        const payload = { ...parsed.data, qc_status: qcStatus };

        const envelope = buildEnvelope(ctx, {
          assistant_message: null,
          suggested_chips: [],
          cards: [{ card_id: `confirm_${ctx.request_id}`, type: 'photo_confirm', payload }],
          session_patch: {},
          events: [makeEvent(ctx, 'value_moment', { kind: 'photo_confirm', qc_status: qcStatus })],
        });
        return res.json(envelope);
      }

      if (!PIVOTA_BACKEND_BASE_URL) {
        const payload = { ...parsed.data, qc_status: null };
        const envelope = buildEnvelope(ctx, {
          assistant_message: null,
          suggested_chips: [],
          cards: [
            {
              card_id: `confirm_${ctx.request_id}`,
              type: 'photo_confirm',
              payload,
              field_missing: [{ field: 'qc_status', reason: 'pivota_backend_not_configured' }],
            },
          ],
          session_patch: {},
          events: [makeEvent(ctx, 'value_moment', { kind: 'photo_confirm', qc_status: null })],
        });
        return res.json(envelope);
      }

      const authHeaders = buildPivotaBackendAuthHeaders(req);
      if (!Object.keys(authHeaders).length) {
        const payload = { ...parsed.data, qc_status: null };
        const envelope = buildEnvelope(ctx, {
          assistant_message: null,
          suggested_chips: [],
          cards: [
            {
              card_id: `confirm_${ctx.request_id}`,
              type: 'photo_confirm',
              payload,
              field_missing: [{ field: 'qc_status', reason: 'pivota_backend_auth_not_configured' }],
            },
          ],
          session_patch: {},
          events: [makeEvent(ctx, 'value_moment', { kind: 'photo_confirm', qc_status: null })],
        });
        return res.json(envelope);
      }

      const uploadId = parsed.data.photo_id;
      confirmStage = 'confirm_request';
      const confirmResp = await axios.post(
        `${PIVOTA_BACKEND_BASE_URL}/photos/confirm`,
        { upload_id: uploadId },
        {
          timeout: 12000,
          validateStatus: () => true,
          headers: { 'Content-Type': 'application/json', ...authHeaders },
        },
      );

      if (confirmResp.status !== 200 || !confirmResp.data) {
        const detail = pickUpstreamErrorDetail(confirmResp.data);
        const envelope = buildEnvelope(ctx, {
          assistant_message: makeAssistantMessage('Failed to confirm upload.'),
          suggested_chips: [],
          cards: [
            {
              card_id: `err_${ctx.request_id}`,
              type: 'error',
              payload: {
                error: 'PHOTO_CONFIRM_UPSTREAM_FAILED',
                status: confirmResp.status,
                detail: detail || null,
              },
            },
          ],
          session_patch: {},
          events: [makeEvent(ctx, 'error', { code: 'PHOTO_CONFIRM_UPSTREAM_FAILED', status: confirmResp.status })],
        });
        return res.status(confirmResp.status >= 400 ? confirmResp.status : 502).json(envelope);
      }

      let qcStatus = resolvePhotoQcStatus(confirmResp.data);
      let qc = confirmResp.data.qc && typeof confirmResp.data.qc === 'object' ? confirmResp.data.qc : null;
      let nextPollMs = typeof confirmResp.data.next_poll_ms === 'number' ? confirmResp.data.next_poll_ms : null;

      const deadlineMs = Date.now() + 6000;
      let lastQcData = null;
      while (!qcStatus && Date.now() < deadlineMs) {
        const waitMs = Math.min(1200, Math.max(400, nextPollMs || 1000));
        await sleep(waitMs);

        confirmStage = 'qc_poll';
        const qcResp = await axios.get(`${PIVOTA_BACKEND_BASE_URL}/photos/qc`, {
          timeout: 12000,
          validateStatus: () => true,
          headers: authHeaders,
          params: { upload_id: uploadId },
        });

        if (qcResp.status !== 200 || !qcResp.data) break;

        lastQcData = qcResp.data;
        const resolvedPollStatus = resolvePhotoQcStatus(qcResp.data);
        if (resolvedPollStatus) qcStatus = resolvedPollStatus;
        qc = qcResp.data.qc && typeof qcResp.data.qc === 'object' ? qcResp.data.qc : qc;
        nextPollMs = typeof qcResp.data.next_poll_ms === 'number' ? qcResp.data.next_poll_ms : nextPollMs;
      }

      const normalizedQcPayload = harmonizePhotoQcCardPayload({
        qcStatus,
        qc,
        nextPollMs,
        language: ctx.lang,
      });
      qcStatus = normalizedQcPayload.qcStatus;
      qc = normalizedQcPayload.qc;
      nextPollMs = normalizedQcPayload.nextPollMs;

      const payload = {
        ...parsed.data,
        qc_status: qcStatus,
        ...(qc ? { qc } : {}),
        ...(typeof nextPollMs === 'number' ? { next_poll_ms: nextPollMs } : {}),
        ...(!qcStatus && lastQcData ? { qc_pending: true } : {}),
      };

      const fieldMissing = [];
      if (!qcStatus) fieldMissing.push({ field: 'qc_status', reason: 'qc_pending' });

      const photoConfirmCard = {
        card_id: `confirm_${ctx.request_id}`,
        type: 'photo_confirm',
        payload,
        ...(fieldMissing.length ? { field_missing: fieldMissing } : {}),
      };
      if (isPassedPhotoQcStatus(qcStatus)) {
        setRecentConfirmedPhoto({
          photoId: uploadId,
          auroraUid: ctx.aurora_uid,
          slotId: parsed.data.slot_id || null,
          qcStatus,
        });
      }
      const autoAnalysis = await safeBuildAutoAnalysisFromConfirmedPhoto({
        req,
        ctx,
        photoId: uploadId,
        slotId: parsed.data.slot_id || null,
        qcStatus,
        logger,
      });

      const envelope = buildEnvelope(ctx, {
        assistant_message: null,
        suggested_chips: [],
        cards: [photoConfirmCard, ...(autoAnalysis && Array.isArray(autoAnalysis.cards) ? autoAnalysis.cards : [])],
        session_patch: autoAnalysis && autoAnalysis.session_patch ? autoAnalysis.session_patch : {},
        events: [
          makeEvent(ctx, 'value_moment', { kind: 'photo_confirm', qc_status: qcStatus }),
          ...(autoAnalysis && autoAnalysis.event ? [autoAnalysis.event] : []),
        ],
      });
      return res.json(envelope);
    } catch (err) {
      const status = Number(err?.statusCode || err?.status || 500);
      const code = derivePhotoIoStageFailureCode({
        flow: 'photo_confirm',
        stage: confirmStage,
        err,
        fallbackCode: 'PHOTO_CONFIRM_FAILED',
      });
      logger?.error(
        {
          err: err && err.message ? err.message : String(err),
          code,
          stage: confirmStage,
          request_id: ctx.request_id,
          trace_id: ctx.trace_id,
          aurora_uid: ctx.aurora_uid,
        },
        'aurora bff: /v1/photos/confirm failed',
      );
      const envelope = buildEnvelope(ctx, {
        assistant_message: makeAssistantMessage('Failed to confirm upload.'),
        suggested_chips: [],
        cards: [{ card_id: `err_${ctx.request_id}`, type: 'error', payload: { error: code, stage: confirmStage } }],
        session_patch: {},
        events: [makeEvent(ctx, 'error', { code, stage: confirmStage })],
      });
      return res.status(status).json(envelope);
    }
  });

  app.post('/v1/analysis/skin', async (req, res) => {
    const ctx = buildRequestContext(req, {});
    const rollout = getDiagRolloutDecision({ requestId: ctx.request_id });
    const outputPipelineVersion = rollout.shadowMode ? 'legacy' : rollout.selectedVersion;
    const shadowRunV2 = rollout.shadowMode && rollout.selectedVersion === 'v2';

    logger?.info(
      {
        kind: 'diag_rollout',
        request_id: ctx.request_id,
        trace_id: ctx.trace_id,
        output_pipeline_version: outputPipelineVersion,
        selected_pipeline_version: rollout.selectedVersion,
        reason: rollout.reason,
        shadow_mode: rollout.shadowMode,
        canary_percent: rollout.canaryPercent,
        canary_bucket: rollout.canaryBucket,
        llm_kill_switch: rollout.llmKillSwitch,
      },
      'aurora bff: diag rollout decision',
    );
    try {
      requireAuroraUid(ctx);
      const parsed = SkinAnalysisRequestSchema.safeParse(req.body || {});
      if (!parsed.success) {
        const envelope = buildEnvelope(ctx, {
          assistant_message: makeAssistantMessage('Invalid request.'),
          suggested_chips: [],
          cards: [{ card_id: `err_${ctx.request_id}`, type: 'error', payload: { error: 'BAD_REQUEST', details: parsed.error.format() } }],
          session_patch: {},
          events: [makeEvent(ctx, 'error', { code: 'BAD_REQUEST' })],
        });
        return res.status(400).json(envelope);
      }

      recordAuroraSkinFlowMetric({ stage: 'analysis_request', hit: true });

      const identity = await resolveIdentity(req, ctx);
      const runOnce = async ({ pipelineVersion, persistLastAnalysis, shadowRun } = {}) => {
        const profiler = createStageProfiler();
        profiler.skip('face', 'not_implemented');
        profiler.skip('skin_roi', 'not_implemented');

        const experiments = assignExperiments({ requestId: ctx.request_id });
        const experimentsSlim = Array.isArray(experiments.assignments)
          ? experiments.assignments
              .map((a) => ({
                experiment_id: a.experiment_id,
                kind: a.kind,
                variant: a.variant,
                ...(typeof a.bucket === 'number' ? { bucket: a.bucket } : {}),
                ...(a.reason ? { reason: a.reason } : {}),
              }))
              .slice(0, 8)
          : [];
        if (experiments.error) {
          logger?.warn(
            { err: String(experiments.error), request_id: ctx.request_id, trace_id: ctx.trace_id },
            'aurora bff: experiments config invalid',
          );
        }

        const qualityGateConfig =
          experiments.byKind && experiments.byKind.quality_gate && experiments.byKind.quality_gate.params
            ? experiments.byKind.quality_gate.params
            : null;
        const severityThresholdsOverrides =
          experiments.byKind && experiments.byKind.severity_mapping && experiments.byKind.severity_mapping.params
            ? experiments.byKind.severity_mapping.params
            : null;
        const promptParams =
          experiments.byKind && experiments.byKind.llm_prompt && experiments.byKind.llm_prompt.params
            ? experiments.byKind.llm_prompt.params
            : null;
        const promptVersionFromParams =
          promptParams && typeof promptParams.prompt_version === 'string' && promptParams.prompt_version.trim()
            ? promptParams.prompt_version.trim()
            : null;
        const promptVersion =
          promptVersionFromParams ||
          (experiments.byKind &&
          experiments.byKind.llm_prompt &&
          typeof experiments.byKind.llm_prompt.variant === 'string' &&
          experiments.byKind.llm_prompt.variant &&
          experiments.byKind.llm_prompt.variant !== 'holdout'
            ? experiments.byKind.llm_prompt.variant
            : null);

        let profile = null;
        let recentLogs = [];
        let pregnancyPolicyEvents = [];
        let qualityPolicyPatchDeferred = false;
        const photos = Array.isArray(parsed.data.photos) ? parsed.data.photos : [];
        const routineOnlyMemoryFastPath = shouldUseRoutineOnlyAnalysisMemoryFastPath({
          parsedBody: parsed.data,
          rawBody: req.body || {},
          summaryFirstEnabled: AURORA_ROUTINE_SUMMARY_FIRST_ENABLED,
        });
        const routineOnlyArtifactFastPath = shouldUseRoutineOnlyAnalysisArtifactFastPath({
          parsedBody: parsed.data,
          rawBody: req.body || {},
          summaryFirstEnabled: AURORA_ROUTINE_SUMMARY_FIRST_ENABLED,
        });
        const requestProfileOverlay = extractProfilePatchFromRequestContextPayload(parsed.data);
        const requestProfileOverlayKeys = requestProfileOverlay && typeof requestProfileOverlay === 'object'
          ? Object.keys(requestProfileOverlay).sort()
          : [];
        const requestProfileContextSource = requestProfileOverlayKeys.length ? 'request_overlay_applied' : 'db_only_profile';
        const qualityProfileTimeoutMs = routineOnlyMemoryFastPath
          ? resolveAnalysisProfileFastTimeoutMs({
              identity,
              requestProfileOverlayApplied: requestProfileOverlayKeys.length > 0,
            })
          : null;
        let qualityMemoryMode = routineOnlyMemoryFastPath ? 'routine_only_profile_only' : 'default';
        let qualityProfileTimedOut = false;
        let qualityLogsSkipped = false;
        profiler.start('quality', { kind: 'memory' });
        try {
          if (routineOnlyMemoryFastPath) {
            qualityLogsSkipped = true;
            try {
              profile = await withTimeout(
                getProfileForIdentity({ auroraUid: identity.auroraUid, userId: identity.userId }),
                qualityProfileTimeoutMs,
                'AURORA_ANALYSIS_PROFILE_FAST_PATH_TIMEOUT',
              );
            } catch (err) {
              qualityProfileTimedOut = err && err.code === 'AURORA_ANALYSIS_PROFILE_FAST_PATH_TIMEOUT';
              logger?.warn(
                { err: err && (err.code || err.message) ? String(err.code || err.message) : String(err) },
                'aurora bff: routine summary fast path profile load skipped or timed out',
              );
            }
          } else {
            const [profileRes, logsRes] = await Promise.allSettled([
              getProfileForIdentity({ auroraUid: identity.auroraUid, userId: identity.userId }),
              getRecentSkinLogsForIdentity({ auroraUid: identity.auroraUid, userId: identity.userId }, 7),
            ]);
            if (profileRes.status === 'fulfilled') profile = profileRes.value;
            else {
              const r = profileRes.reason;
              logger?.warn(
                { err: r && (r.code || r.message) ? String(r.code || r.message) : String(r) },
                'aurora bff: failed to load profile',
              );
            }
            if (logsRes.status === 'fulfilled') recentLogs = logsRes.value;
            else {
              const r = logsRes.reason;
              logger?.warn(
                { err: r && (r.code || r.message) ? String(r.code || r.message) : String(r) },
                'aurora bff: failed to load recent logs',
              );
            }
          }
        } catch (err) {
          logger?.warn({ err: err.code || err.message }, 'aurora bff: failed to load memory context');
        }

        const pregnancyPolicyForDiagnosis = derivePregnancyPolicyPatch({
          profile,
          message: '',
          todayUtc: utcTodayIsoDate(),
        });
        if (pregnancyPolicyForDiagnosis && Array.isArray(pregnancyPolicyForDiagnosis.events)) {
          pregnancyPolicyEvents = pregnancyPolicyForDiagnosis.events
            .filter((evt) => evt && typeof evt === 'object' && evt.event_name)
            .map((evt) => makeEvent(ctx, evt.event_name, evt.data && typeof evt.data === 'object' ? evt.data : {}));
        }
        if (pregnancyPolicyForDiagnosis && pregnancyPolicyForDiagnosis.patch) {
          profile = { ...(profile || {}), ...pregnancyPolicyForDiagnosis.patch };
          if (persistLastAnalysis) {
            qualityPolicyPatchDeferred = deferProfilePatchPersistence({
              identity,
              patch: pregnancyPolicyForDiagnosis.patch,
              logger,
              requestId: ctx.request_id,
              traceId: ctx.trace_id,
            });
          }
        }
        const snapshotProfileBase =
          profile && typeof profile === 'object' && !Array.isArray(profile)
            ? { ...profile }
            : profile;

        const photoQcParts = [];
        const passedPhotos = [];
        const degradedPhotos = [];
        const failedPhotos = [];
        let photosSubmittedCount = 0;
        for (const p of photos) {
          const slot = String(p.slot_id || '').trim();
          const qc = String(p.qc_status || '').trim().toLowerCase();
          const photoId = typeof p.photo_id === 'string' ? p.photo_id.trim() : '';
          if (slot && qc) photoQcParts.push(`${slot}:${qc}`);
          if (!slot || !photoId) continue;
          photosSubmittedCount += 1;
          const entry = { slot_id: slot, photo_id: photoId, qc_status: qc || 'unknown' };
          if (qc === 'passed' || qc === 'pass' || qc === 'ok') passedPhotos.push(entry);
          else if (qc === 'degraded' || qc === 'warn' || qc === 'warning' || qc === 'low' || !qc) degradedPhotos.push(entry);
          else if (qc === 'fail' || qc === 'failed' || qc === 'reject' || qc === 'rejected' || qc === 'bad') failedPhotos.push(entry);
          else degradedPhotos.push(entry);
        }
        const photosProvided = photosSubmittedCount > 0;
        let photoQuality = classifyPhotoQuality(photos);

        const applyRequestProfileOverlay = (profileValue, { fillOnly = false } = {}) => {
          if (!requestProfileOverlay || typeof requestProfileOverlay !== 'object') return profileValue;
          const base = profileValue && typeof profileValue === 'object' && !Array.isArray(profileValue)
            ? { ...profileValue }
            : {};
          return fillOnly ? mergeMissingProfilePatchFields(base, requestProfileOverlay) : { ...base, ...requestProfileOverlay };
        };
        profile = applyRequestProfileOverlay(profile);
        let profileSummary = summarizeProfileForContext(profile);
        const previousRoutineState = normalizeRoutineStateFromProfile(profile);
        const previousRoutine = previousRoutineState.current_routine_struct;
        const recentLogsSummary = Array.isArray(recentLogs) ? recentLogs.slice(0, 7) : [];
        const routineRequestInput = resolveSkinAnalysisRoutineInput({
          parsedBody: parsed.data,
          rawBody: req.body || {},
        });
        const routineInputRaw = routineRequestInput.found ? routineRequestInput.value : undefined;
        const routineFromRequest =
          routineInputRaw !== undefined
            ? normalizeRoutineInputWithPmShortcut(routineInputRaw)
            : undefined;
        const requestedRoutineState =
          routineFromRequest !== undefined ? normalizeRoutineStateValue(routineFromRequest) : null;
        const routineDerivedProfilePatch = extractProfilePatchFromRoutinePayload(routineInputRaw);

        if (routineFromRequest !== undefined) {
          const routinePersistencePatch = {
            ...(routineDerivedProfilePatch && typeof routineDerivedProfilePatch === 'object' ? routineDerivedProfilePatch : {}),
          };
          const normalizedRoutine =
            (requestedRoutineState && requestedRoutineState.current_routine_struct) ||
            (requestedRoutineState && requestedRoutineState.current_routine_text) ||
            normalizeCurrentRoutineToV2(routineFromRequest);
          // Best-effort persistence. Analysis should still proceed even if storage is unavailable.
          profile = {
            ...(profile || {}),
            ...routinePersistencePatch,
            currentRoutine: normalizedRoutine,
          };
          if (persistLastAnalysis) {
            void upsertProfileForIdentity(
              { auroraUid: identity.auroraUid, userId: identity.userId },
              {
                ...routinePersistencePatch,
                currentRoutine: normalizedRoutine,
              },
            ).catch((err) => {
              logger?.warn({ err: err.code || err.message }, 'aurora bff: failed to persist current routine for analysis');
            });
          }
          profile = applyRequestProfileOverlay(profile, { fillOnly: true });
          profileSummary = summarizeProfileForContext(profile);
        }

        const effectiveRoutineState =
          routineFromRequest !== undefined ? normalizeRoutineStateValue(profile && profile.currentRoutine) : previousRoutineState;
        const routineCandidate = routineRequestInput.found ? routineInputRaw : effectiveRoutineState.routine_candidate;
        const routinePayloadShape = detectRoutinePayloadShape(routineCandidate);
        const hasRoutine = routineRequestInput.found
          ? Boolean(
              routineCandidate != null &&
                (typeof routineCandidate === 'string'
                  ? String(routineCandidate).trim()
                  : Array.isArray(routineCandidate)
                    ? routineCandidate.length > 0
                    : isPlainObject(routineCandidate)
                      ? Object.keys(routineCandidate).length > 0
                      : false),
            )
          : Boolean(effectiveRoutineState.has_current_routine);
        const routineStateMeta = {
          source_shape: routineRequestInput.found
            ? routinePayloadShape
            : effectiveRoutineState.source_shape,
          missing_routine_fields:
            routineRequestInput.found
              ? Array.isArray(requestedRoutineState && requestedRoutineState.missing_routine_fields)
                ? requestedRoutineState.missing_routine_fields.slice(0, 4)
                : []
              : Array.isArray(effectiveRoutineState.missing_routine_fields)
                ? effectiveRoutineState.missing_routine_fields.slice(0, 4)
                : [],
        };
        const analysisFieldMissing = [];
        const qualityReportReasons = [];
        const photoFailureCodes = [];
        const analysisSubstageEvents = [];
        const recordAnalysisSubstageFailure = (stage, err, extra = {}) => {
          const failureMeta = classifyRoutineFitUpstreamFailure(err);
          const failureClass = String(failureMeta.failure_class || 'substage_error');
          analysisFieldMissing.push({ field: `analysis.${stage}`, reason: failureClass });
          analysisSubstageEvents.push(
            makeEvent(ctx, 'analysis_substage_failed', {
              stage,
              failure_class: failureClass,
              upstream_status: failureMeta.upstream_status,
              upstream_error_code: failureMeta.upstream_error_code,
              routine_source_shape: routineStateMeta.source_shape,
              missing_routine_fields: routineStateMeta.missing_routine_fields,
              ...extra,
            }),
          );
          logger?.warn(
            {
              err: err && err.message ? err.message : String(err),
              request_id: ctx.request_id,
              stage,
              failure_class: failureClass,
              upstream_status: failureMeta.upstream_status,
              upstream_error_code: failureMeta.upstream_error_code,
              routine_source_shape: routineStateMeta.source_shape,
              missing_routine_fields: routineStateMeta.missing_routine_fields,
            },
            'aurora bff: analysis substage degraded after failure',
          );
        };
        let routineProductCandidates = [];
        if (hasRoutine) {
          try {
            routineProductCandidates = extractRoutineProductCandidatesForDeepScan(routineCandidate, {
              maxTotal: AURORA_ROUTINE_PRODUCT_AUTOSCAN_TOTAL_LIMIT,
            });
          } catch (err) {
            recordAnalysisSubstageFailure('routine_product_candidate_extract', err, {
              candidate_count: 0,
            });
            routineProductCandidates = [];
          }
        }
        profiler.end('quality', {
          kind: 'memory',
          has_routine: hasRoutine,
          logs_n: recentLogsSummary.length,
          memory_mode: qualityMemoryMode,
          logs_skipped: qualityLogsSkipped,
          profile_timed_out: qualityProfileTimedOut,
          profile_timeout_ms: qualityProfileTimeoutMs,
          policy_patch_deferred: qualityPolicyPatchDeferred,
        });
        logger?.info(
          {
            event: 'aurora_analysis_skin_routine_intake',
            request_id: ctx.request_id,
            trace_id: ctx.trace_id,
            routine_payload_shape: routinePayloadShape,
            analysis_skin_has_routine: hasRoutine,
            analysis_skin_routine_preview_items_count: routineProductCandidates.length,
            routine_product_enrichment_deferred: routineProductCandidates.length > 0,
            routine_request_source: routineRequestInput.source,
            config_snapshot: {
              analysis_budget_ms: AURORA_BFF_ANALYSIS_BUDGET_MS,
              routine_product_autoscan_enabled: AURORA_ROUTINE_PRODUCT_AUTOSCAN_ENABLED,
              routine_product_autoscan_sync_limit: AURORA_ROUTINE_PRODUCT_AUTOSCAN_SYNC_LIMIT,
              routine_product_autoscan_total_limit: AURORA_ROUTINE_PRODUCT_AUTOSCAN_TOTAL_LIMIT,
              diag_pipeline_version: outputPipelineVersion,
              diag_shadow_mode: rollout.shadowMode,
              diag_canary_percent: rollout.canaryPercent,
              routine_summary_first_enabled: AURORA_ROUTINE_SUMMARY_FIRST_ENABLED,
              routine_audit_v1_enabled: AURORA_ROUTINE_AUDIT_V1_ENABLED,
            },
          },
          'aurora bff: analysis skin routine intake snapshot',
        );

        // "Dual input" policy:
        // - routine/recent logs are primary for personalization
        // - when photos are explicitly provided, allow a photo-first path so LLM/photo analysis is not blocked
        const hasPrimaryInput = hasRoutine || recentLogsSummary.length > 0;

        const userRequestedPhoto =
          parsed.data.use_photo === true || (parsed.data.use_photo == null && photosProvided);
        const hasPhotoPrimaryInput = Boolean(userRequestedPhoto && photosProvided);
        const hasLlmPrimaryInput = hasPrimaryInput || hasPhotoPrimaryInput;
        const forceVisionCall = Boolean(SKIN_VISION_FORCE_CALL && userRequestedPhoto && photosProvided && hasLlmPrimaryInput);
        const explicitPhotoFirstRequested = parsed.data.use_photo === true;
        const routineAuditFastPathEligible =
          AURORA_ROUTINE_AUDIT_V1_ENABLED &&
          AURORA_ROUTINE_ANALYSIS_V2_ENABLED &&
          hasRoutine &&
          !explicitPhotoFirstRequested &&
          !hasPhotoPrimaryInput &&
          routineProductCandidates.length > 0;

        if (routineAuditFastPathEligible) {
          const expectedRoutineAuditCardTypes = [
            'routine_verdict_v1',
            'routine_product_audit_v1',
            'routine_user_fit_v1',
            'routine_adjustment_plan_v1',
          ];
          const fastPathEvents = [
            makeEvent(ctx, 'routine_audit_fast_path_started', {
              candidate_count: routineProductCandidates.length,
              routine_source_shape: routineStateMeta.source_shape,
              missing_routine_fields: routineStateMeta.missing_routine_fields,
              profile_context_source: requestProfileContextSource,
            }),
          ];
          let fastPathFailureStage = 'routine_context_build';
          try {
            const routineExpert = buildRoutineExpertV1({
              routineCandidate,
              profileSummary,
              recentLogs: recentLogsSummary,
              language: ctx.lang,
            });
            const routineLifecycleStage = detectRoutineLifecycleStage({
              routineCandidate,
              previousRoutine,
              routineExpertIssues: Array.isArray(routineExpert && routineExpert.key_issues) ? routineExpert.key_issues : [],
              intent: 'analysis_review_products',
            });
            const routineLifecycleContext = routineLifecycleStage
              ? buildRoutineLifecycleContext({
                stage: routineLifecycleStage,
                routineCandidate,
                previousRoutine,
                profileSummary,
                routineExpert,
                language: ctx.lang,
              })
              : null;

            fastPathFailureStage = 'routine_analysis_v2';
            const routineAnalysisV2Result = await runRoutineAnalysisV2({
              requestId: ctx.request_id,
              language: ctx.lang,
              profile,
              profileSummary,
              routineProductCandidates,
              ingredientPlan: null,
              analysisContextSnapshot: null,
              requestProfileOverride: requestProfileOverlay,
              surfaceMode: 'routine_audit_v1',
              routineExpert,
              routineLifecycleContext,
              logger,
            });

            fastPathFailureStage = 'response_contract';
            const fastPathCards = Array.isArray(routineAnalysisV2Result && routineAnalysisV2Result.cards)
              ? routineAnalysisV2Result.cards
              : [];
            const fastPathCardTypes = fastPathCards
              .map((card) => String(card && card.type || '').trim())
              .filter(Boolean);
            const hasExpectedRoutineAuditSurface =
              fastPathCardTypes.length === expectedRoutineAuditCardTypes.length &&
              expectedRoutineAuditCardTypes.every((type, index) => fastPathCardTypes[index] === type);
            if (!hasExpectedRoutineAuditSurface) {
              const err = new Error('ROUTINE_AUDIT_FAST_PATH_INVALID_SURFACE');
              err.code = 'ROUTINE_AUDIT_FAST_PATH_INVALID_SURFACE';
              throw err;
            }

            let diagnosisArtifact = null;
            let latestArtifactId = null;
            let artifactGate = null;
            if (AURORA_DIAG_ARTIFACT_ENABLED && persistLastAnalysis) {
              fastPathFailureStage = 'diagnosis_artifact_handoff';
              try {
                const artifactCandidate = buildDiagnosisArtifactV1({
                  ctx,
                  identity,
                  profileSummary,
                  recentLogsSummary,
                  analysis: buildRoutineAuditFastPathArtifactAnalysis({
                    routineAnalysisResult: routineAnalysisV2Result,
                  }),
                  analysisSource: 'rule_based',
                  usePhoto: false,
                  usedPhotos: false,
                  photos: [],
                  photoQuality,
                });
                const savedArtifact = await saveDiagnosisArtifact({
                  auroraUid: identity.auroraUid,
                  userId: identity.userId,
                  sessionId: ctx.brief_id || null,
                  artifact: artifactCandidate,
                  artifactId: artifactCandidate && artifactCandidate.artifact_id ? artifactCandidate.artifact_id : undefined,
                });
                diagnosisArtifact = savedArtifact && savedArtifact.artifact_json && typeof savedArtifact.artifact_json === 'object'
                  ? {
                      ...savedArtifact.artifact_json,
                      artifact_id: savedArtifact.artifact_id,
                      created_at: savedArtifact.created_at || savedArtifact.artifact_json.created_at,
                    }
                  : artifactCandidate;
                latestArtifactId = diagnosisArtifact && diagnosisArtifact.artifact_id
                  ? String(diagnosisArtifact.artifact_id).trim()
                  : null;
                artifactGate = hasUsableArtifactForRecommendations(diagnosisArtifact);
              } catch (err) {
                logger?.warn(
                  {
                    err: err && err.message ? err.message : String(err),
                    request_id: ctx.request_id,
                    candidate_count: routineProductCandidates.length,
                  },
                  'aurora bff: routine audit fast path artifact handoff failed',
                );
              }
            }

            const analysisMeta = {
              detector_source: 'rule_based',
              llm_vision_called: false,
              llm_report_called: false,
              artifact_usable: Boolean(artifactGate && artifactGate.ok),
              artifact_gate: buildArtifactGateMeta(artifactGate),
              routine_analysis_version: 'v2',
              routine_preview_items_count: routineProductCandidates.length,
              analysis_mode: 'routine_audit_v1',
              execution_path: 'routine_audit_fast_path',
              profile_context_source: requestProfileContextSource,
              request_profile_overlay_applied: requestProfileOverlayKeys.length > 0,
              ...(requestProfileOverlayKeys.length ? { request_profile_overlay_keys: requestProfileOverlayKeys } : {}),
              gate_relax_mode: AURORA_RULE_RELAX_MODE,
              low_quality_tolerated: false,
              reco_artifact_eligible:
                Boolean(artifactGate && artifactGate.ok)
                || (Array.isArray(routineAnalysisV2Result && routineAnalysisV2Result.recommendation_groups)
                  ? routineAnalysisV2Result.recommendation_groups.some(
                      (group) => Array.isArray(group && group.candidate_pool) && group.candidate_pool.length > 0,
                    )
                  : false),
            };

            const sessionPatch = {
              next_state: 'ROUTINE_REVIEW',
              meta: {
                routine_analysis_v2: {
                  ...(isPlainObject(routineAnalysisV2Result.debug_meta) ? routineAnalysisV2Result.debug_meta : {}),
                  profile_context_source: requestProfileContextSource,
                  request_profile_overlay_applied: requestProfileOverlayKeys.length > 0,
                  ...(requestProfileOverlayKeys.length ? { request_profile_overlay_keys: requestProfileOverlayKeys } : {}),
                },
                routine_analysis_legacy_compat: routineAnalysisV2Result.legacy_compat,
                analysis_contract: {
                  analysis_mode: 'routine_audit_v1',
                  card_contract: 'aurora.routine_audit_v1',
                  execution_path: 'routine_audit_fast_path',
                  card_types: fastPathCardTypes.slice(0, 6),
                },
                ...(routineExpert ? { routine_expert: routineExpert } : {}),
                ...(routineLifecycleContext ? { routine_lifecycle_context: routineLifecycleContext } : {}),
              },
            };
            if (profileSummary) {
              sessionPatch.profile = profileSummary;
            }
            appendLatestArtifactToSessionPatch(sessionPatch, latestArtifactId);
            const routineLatestRecoContext = buildLatestRecoContextFromAnalysisArtifacts({
              routineAnalysisResult: routineAnalysisV2Result,
              profileSummary,
              artifactId: latestArtifactId,
              contextOrigin: 'routine_audit_v1',
              analysisSource: 'routine_audit_v1',
              usePhoto: false,
              usedPhotos: false,
              photoQualityGrade: '',
            });
            appendLatestRecoContextToSessionPatch(
              sessionPatch,
              routineLatestRecoContext,
            );
            const persistableRoutineFastPathAnalysis = buildPersistableLastAnalysisSnapshot({
              analysis: null,
              ingredientPlan: null,
              routineFitCard: null,
              routineAnalysisV2Result,
              latestRecoContext: routineLatestRecoContext,
              profileSummary,
            });

            const analysisChips = buildAnalysisSuggestedChips({
              language: ctx.lang,
              lowConfidence: false,
              hasIngredientPlan: false,
              hasRoutineFit: false,
            });
            const analysisAssistantText =
              typeof routineAnalysisV2Result.assistant_text === 'string' && routineAnalysisV2Result.assistant_text.trim()
                ? routineAnalysisV2Result.assistant_text
                : buildAnalysisAssistantMessage({
                    language: ctx.lang,
                    skinProfile: {
                      skin_type_tendency: profileSummary && profileSummary.skinType ? profileSummary.skinType : null,
                      sensitivity_tendency: profileSummary && profileSummary.sensitivity ? profileSummary.sensitivity : null,
                    },
                    lowConfidence: false,
                    ingredientPlan: null,
                    routineFit: null,
                  });

            profiler.start('render', { kind: 'routine_audit_fast_path' });
            const envelope = buildEnvelope(ctx, {
              assistant_message: makeAssistantMessage(analysisAssistantText),
              suggested_chips: analysisChips,
              cards: fastPathCards,
              session_patch: sessionPatch,
              events: [
                ...fastPathEvents,
                makeEvent(ctx, 'routine_analysis_v2_completed', {
                  audited_product_count:
                    routineAnalysisV2Result &&
                    routineAnalysisV2Result.audit &&
                    Array.isArray(routineAnalysisV2Result.audit.products)
                      ? routineAnalysisV2Result.audit.products.length
                      : 0,
                  recommendation_group_count: Array.isArray(routineAnalysisV2Result && routineAnalysisV2Result.recommendation_groups)
                    ? routineAnalysisV2Result.recommendation_groups.length
                    : 0,
                  deferred_product_count:
                    routineAnalysisV2Result &&
                    routineAnalysisV2Result.debug_meta &&
                    routineAnalysisV2Result.debug_meta.stage_a &&
                    Number.isFinite(Number(routineAnalysisV2Result.debug_meta.stage_a.deferred_product_count))
                      ? Number(routineAnalysisV2Result.debug_meta.stage_a.deferred_product_count)
                      : 0,
                }),
                makeEvent(ctx, 'routine_audit_fast_path_completed', {
                  candidate_count: routineProductCandidates.length,
                  card_count: fastPathCards.length,
                  lifecycle_stage: routineLifecycleStage || null,
                  expert_issue_count: Array.isArray(routineExpert && routineExpert.key_issues) ? routineExpert.key_issues.length : 0,
                }),
                ...pregnancyPolicyEvents,
                makeEvent(ctx, 'value_moment', {
                  kind: 'skin_analysis',
                  used_photos: false,
                  analysis_source: 'rule_based',
                }),
              ],
              analysis_meta: analysisMeta,
            });
            profiler.end('render', { kind: 'routine_audit_fast_path' });
            recordAuroraSkinFlowMetric({ stage: 'routine_audit_fast_path_completed', hit: true });
            if (persistLastAnalysis && persistableRoutineFastPathAnalysis) {
              try {
                await saveLastAnalysisForIdentity(
                  { auroraUid: identity.auroraUid, userId: identity.userId },
                  { analysis: persistableRoutineFastPathAnalysis, lang: ctx.lang },
                );
              } catch (err) {
                logger?.warn(
                  {
                    err: err && err.message ? err.message : String(err),
                    request_id: ctx.request_id,
                    trace_id: ctx.trace_id,
                  },
                  'aurora bff: routine audit fast path last analysis persistence failed',
                );
              }
            }

            return {
              envelope,
              report: profiler.report(),
              profile_for_guardrails: profile,
              analysis_for_persist: null,
              photo_refs: [],
              skip_product_intel_guardrails: true,
            };
          } catch (err) {
            analysisSubstageEvents.push(
              makeEvent(ctx, 'routine_audit_fast_path_failed', {
                failure_stage: fastPathFailureStage,
                fallback_path: 'preview_or_routine_v2',
                candidate_count: routineProductCandidates.length,
                routine_source_shape: routineStateMeta.source_shape,
                missing_routine_fields: routineStateMeta.missing_routine_fields,
                error_code: err && err.code ? String(err.code) : null,
              }),
            );
            recordAuroraSkinFlowMetric({ stage: 'routine_audit_fast_path_failed', hit: true });
            logger?.warn(
              {
                err: err && err.message ? err.message : String(err),
                code: err && err.code ? err.code : null,
                request_id: ctx.request_id,
                candidate_count: routineProductCandidates.length,
                failure_stage: fastPathFailureStage,
              },
              'aurora bff: routine audit fast path failed, falling back to legacy routine path',
            );
          }
        }

        const detectorConfidence = inferDetectorConfidence({ profileSummary, recentLogsSummary, routineCandidate });
        const selectedVisionProvider = {
          provider: 'gemini',
          requested: 'gemini_locked_mainline',
          apiKeyConfigured: isGeminiSkinGatewayAvailable(),
        };
        const visionAvailability = classifyVisionAvailability({
          enabled: SKIN_VISION_ENABLED,
          apiKeyConfigured: selectedVisionProvider.apiKeyConfigured,
        });
        const visionAvailable = visionAvailability.available && !rollout.llmKillSwitch;
        const reportAvailable = Boolean(selectedVisionProvider.apiKeyConfigured) && !rollout.llmKillSwitch;

        let usedPhotos = false;
        let analysisSource = 'rule_based';
        let visionRuntime = null;
        let visionDecisionForReport = null;
        let visionLayer = null;
        let reportLayer = null;
        let reportCanonical = null;
        let deepeningRuntime = null;
        let llmInputHash = null;
        let llmInputHashPrefix = null;
        let deterministicFallbackReason = null;
        let reportModelCalled = false;
        let reportModelErrored = false;
        let reportModelErrorReason = null;
        let reportStageBudgetMs = 0;
        let reportStageBudgetProfile = 'default';
        let reportStageElapsedMs = 0;
        let reportStageOutcome = 'not_requested';
        let reportStageAttempts = 0;
        let reportStageRecovered = false;
        let reportStageRecoveryMode = null;
        let reportStagePrimaryFailureReason = null;
        let reportStagePrimaryFailureDetail = null;
        let budgetAbortStage = null;

        let diagnosisPhoto = null;
        let diagnosisPhotoBytes = null;
        let shadowVerifyPhotoBytes = null;
        let photoModulesSourcePhoto = null;
        let diagnosisV1 = null;
        let diagnosisV1Internal = null;
        let diagnosisPolicy = null;
        function recordPhotoFailure(code, detail) {
          const failureCode = String(code || '').trim().toUpperCase() || 'DOWNLOAD_URL_GENERATE_FAILED';
          if (!photoFailureCodes.includes(failureCode)) photoFailureCodes.push(failureCode);
          analysisFieldMissing.push({ field: 'analysis.used_photos', reason: failureCode });
          if (detail) {
            logger?.warn({ code: failureCode, detail }, 'aurora bff: photo fetch failure');
          }
        }

        if (rollout.llmKillSwitch) {
          if (ctx.lang === 'CN') qualityReportReasons.push('系统已开启 LLM 总开关：本次会强制跳过所有模型调用。');
          else qualityReportReasons.push('LLM kill switch is enabled: skipping all model calls for this request.');
        }

        function mergePhotoQuality(baseQuality, extraQuality, { extraPrefix } = {}) {
          const base = baseQuality && typeof baseQuality === 'object' ? baseQuality : { grade: 'unknown', reasons: [] };
          const extra = extraQuality && typeof extraQuality === 'object' ? extraQuality : null;
          if (!extra) return base;
          const order = { unknown: 0, pass: 1, degraded: 2, fail: 3 };
          const g0 = String(base.grade || 'unknown').trim().toLowerCase();
          const g1 = String(extra.grade || 'unknown').trim().toLowerCase();
          const grade0 = order[g0] != null ? g0 : 'unknown';
          const grade1 = order[g1] != null ? g1 : 'unknown';
          const mergedGrade = order[grade1] > order[grade0] ? grade1 : grade0;
          const r0 = Array.isArray(base.reasons) ? base.reasons : [];
          const r1raw = Array.isArray(extra.reasons) ? extra.reasons : [];
          const r1 = extraPrefix ? r1raw.map((r) => `${extraPrefix}${r}`) : r1raw;
          const mergedReasons = Array.from(new Set([...r0, ...r1])).slice(0, 10);
          return { grade: mergedGrade, reasons: mergedReasons };
        }

        if (hasPhotoPrimaryInput && (photoQuality.grade !== 'fail' || AURORA_RULE_RELAX_AGGRESSIVE)) {
          const candidates = photoQuality.grade === 'pass' ? passedPhotos : degradedPhotos.length ? degradedPhotos : passedPhotos;
          diagnosisPhoto = chooseVisionPhoto(candidates);
          if (!diagnosisPhoto) {
            analysisFieldMissing.push({ field: 'analysis.used_photos', reason: 'no_usable_photo' });
            if (ctx.lang === 'CN') qualityReportReasons.push('没有可用的照片（缺少 photo_id 或未通过质量门槛）；我会跳过照片检测。');
            else qualityReportReasons.push('No usable photo (missing photo_id or failed quality gate); skipping photo checks.');
          } else {
            photoModulesSourcePhoto = {
              slot_id: diagnosisPhoto.slot_id,
              photo_id: diagnosisPhoto.photo_id,
            };
            try {
              profiler.start('decode', { kind: 'photo_fetch', slot: diagnosisPhoto.slot_id, purpose: 'diagnosis_v1' });
              const diagnosisAttempt = await runPhotoDiagnosisWithReadinessRetry({
                req,
                photoId: diagnosisPhoto.photo_id,
                language: ctx.lang,
                profileSummary,
                recentLogsSummary,
                profiler,
                qualityGateConfig,
                severityThresholdsOverrides,
                freshnessHint: { enabled: true, source: 'analysis_skin_photo' },
              });
              if (diagnosisAttempt && diagnosisAttempt.ok) {
                diagnosisPhotoBytes = diagnosisAttempt.photoBytes;
                shadowVerifyPhotoBytes = diagnosisPhotoBytes;
                const diag = diagnosisAttempt.diagResult;
                if (diag && diag.ok && diag.diagnosis) {
                  diagnosisV1 = diag.diagnosis;
                  diagnosisV1Internal = diag.internal || null;
                  diagnosisPolicy = summarizeDiagnosisForPolicy(diagnosisV1);
                  usedPhotos = true;
                  shadowVerifyPhotoBytes = diagnosisPhotoBytes;
                  const dq = diagnosisV1 && diagnosisV1.quality && typeof diagnosisV1.quality === 'object' ? diagnosisV1.quality : null;
                  if (dq && typeof dq.grade === 'string') photoQuality = mergePhotoQuality(photoQuality, dq, { extraPrefix: 'pixel_' });
                  if (dq && dq.grade === 'fail') {
                    if (ctx.lang === 'CN') qualityReportReasons.push('照片像素质量未通过（模糊/光照/白平衡/覆盖不足等）；为避免误判我会建议重拍。');
                    else {
                      qualityReportReasons.push(
                        'Pixel-level photo quality did not pass (blur/lighting/WB/coverage); recommending a retake to avoid wrong guesses.',
                      );
                    }
                  } else if (dq && dq.grade === 'degraded') {
                    if (ctx.lang === 'CN') qualityReportReasons.push('照片质量一般：我会更保守，并减少/避免无效模型调用。');
                    else {
                      qualityReportReasons.push('Photo quality is degraded: keeping conclusions conservative and reducing unnecessary model calls.');
                    }
                  }
                } else if (diag && !diag.ok) {
                  const reason = String(diag.reason || 'diagnosis_failed');
                  photoQuality = mergePhotoQuality(photoQuality, { grade: 'fail', reasons: [reason] }, { extraPrefix: 'pixel_' });
                  if (ctx.lang === 'CN') qualityReportReasons.push(`照片检测未能稳定完成（${reason}）；为避免误判建议重拍。`);
                  else qualityReportReasons.push(`Photo checks could not complete reliably (${reason}); recommending a retake to avoid wrong guesses.`);
                  if (!analysisFieldMissing.some((f) => f && f.field === 'analysis.used_photos' && f.reason === 'diagnosis_failed')) {
                    analysisFieldMissing.push({ field: 'analysis.used_photos', reason: 'diagnosis_failed' });
                  }
                } else {
                  recordPhotoFailure('PHOTO_DIAGNOSIS_THROWN', null);
                }
              } else {
                recordPhotoFailure(
                  diagnosisAttempt && (diagnosisAttempt.failure_code || diagnosisAttempt.reason),
                  diagnosisAttempt && diagnosisAttempt.detail,
                );
              }
              profiler.end('decode', {
                kind: 'photo_fetch',
                slot: diagnosisPhoto.slot_id,
                purpose: 'diagnosis_v1',
                ok: Boolean(diagnosisPhotoBytes),
                bytes: diagnosisPhotoBytes ? diagnosisPhotoBytes.length : 0,
              });
            } catch (err) {
              recordPhotoFailure('DOWNLOAD_URL_FETCH_5XX', err && err.message ? err.message : null);
              profiler.fail('decode', err, { kind: 'photo_fetch', slot: diagnosisPhoto.slot_id, purpose: 'diagnosis_v1' });
              logger?.warn({ err: err.message }, 'aurora bff: failed to fetch photo bytes for diagnosis');
            }
          }
        }

        const qualityForReport = userRequestedPhoto && photosProvided ? photoQuality : { grade: 'pass', reasons: ['no_photo'] };
        const policyDetectorConfidenceLevel = diagnosisPolicy ? diagnosisPolicy.detector_confidence_level : detectorConfidence.level;
        const policyUncertainty = diagnosisPolicy ? diagnosisPolicy.uncertainty : null;

        const visionDecision = rollout.llmKillSwitch
          ? { decision: 'skip', reasons: ['llm_kill_switch'], downgrade_confidence: true }
          : forceVisionCall
            ? { decision: 'call', reasons: ['force_vision_call'], downgrade_confidence: true }
            : shouldCallLlm({
                kind: 'vision',
                quality: photoQuality,
                hasPrimaryInput: hasLlmPrimaryInput,
                userRequestedPhoto,
                detectorConfidenceLevel: policyDetectorConfidenceLevel,
                uncertainty: policyUncertainty,
                visionAvailable,
                visionUnavailabilityReason: visionAvailability.reason,
                reportAvailable,
                degradedMode: SKIN_DEGRADED_MODE,
              });
        let reportDecision = rollout.llmKillSwitch
          ? { decision: 'skip', reasons: ['llm_kill_switch'], downgrade_confidence: true }
          : shouldCallLlm({
              kind: 'report',
              quality: qualityForReport,
              hasPrimaryInput: hasLlmPrimaryInput,
              userRequestedPhoto,
              detectorConfidenceLevel: policyDetectorConfidenceLevel,
              uncertainty: policyUncertainty,
              visionAvailable,
              reportAvailable,
              degradedMode: SKIN_DEGRADED_MODE,
            });
        reportStageBudgetProfile = deriveAnalysisReportBudgetProfile({
          summaryFirst: AURORA_ROUTINE_SUMMARY_FIRST_ENABLED,
          hasRoutine,
          hasPhotoPrimaryInput,
        });
        const forceReportOnPhotoFetchFailure = Boolean(
            !rollout.llmKillSwitch &&
            userRequestedPhoto &&
            photosProvided &&
            hasLlmPrimaryInput &&
            reportAvailable &&
            photoFailureCodes.length > 0 &&
            reportDecision.decision !== 'call',
        );
        if (forceReportOnPhotoFetchFailure) {
          reportDecision = {
            decision: 'call',
            reasons: ['photo_fetch_failed_force_report'],
            downgrade_confidence: true,
          };
          if (ctx.lang === 'CN') {
            qualityReportReasons.push('照片上传已通过但读取失败：强制调用报告模型给出保守解释与下一步。');
          } else {
            qualityReportReasons.push(
              'Photo upload passed but image bytes could not be read: forcing report model for conservative guidance.',
            );
          }
        }
        if (
          AURORA_ANALYSIS_REPORT_SKIP_ROUTINE_ONLY &&
          reportDecision &&
          reportDecision.decision === 'call' &&
          reportStageBudgetProfile === 'routine_only'
        ) {
          reportDecision = {
            ...reportDecision,
            decision: 'skip',
            reasons: Array.from(
              new Set([
                ...(Array.isArray(reportDecision.reasons) ? reportDecision.reasons : []),
                'routine_summary_first_fast_path',
              ]),
            ),
          };
          if (ctx.lang === 'CN') {
            qualityReportReasons.push('当前是 routine summary-first 快速路径：跳过报告模型，直接返回确定性总结以保证主链稳定。');
          } else {
            qualityReportReasons.push(
              'Routine summary-first fast path active: skipping report model and returning deterministic summary to keep the main path stable.',
            );
          }
        }
        let analysis = null;
        let retakeFallbackAnalysis = null;
        if (hasPhotoPrimaryInput && !hasPrimaryInput) {
          if (ctx.lang === 'CN') {
            qualityReportReasons.push('缺少 routine/recent logs：本次改为“照片优先 + 保守解释”，并建议补充日常流程提升准确性。');
          } else {
            qualityReportReasons.push(
              'Routine/recent logs are missing: proceeding with photo-first analysis and conservative interpretation.',
            );
          }
        }

        if (userRequestedPhoto && photosProvided && photoQuality.grade === 'fail' && !forceVisionCall && !AURORA_RULE_RELAX_AGGRESSIVE) {
          retakeFallbackAnalysis = profiler.timeSync('detector', () => buildRetakeSkinAnalysis({ language: ctx.lang, photoQuality }), {
            kind: 'retake',
          });
          if (ctx.lang === 'CN') qualityReportReasons.push('照片质量未通过：我不会调用 AI 做皮肤结论，避免误判；建议按提示重拍。');
          else qualityReportReasons.push('Photo quality failed: skipping all AI analysis to avoid guessy results; please retake.');
        } else if (userRequestedPhoto && photosProvided && photoQuality.grade === 'fail' && forceVisionCall) {
          if (ctx.lang === 'CN') qualityReportReasons.push('已开启调试强制：即使质量判定失败也会尝试继续调用照片模型。');
          else qualityReportReasons.push('Force-vision debug enabled: attempting photo model call despite fail-grade quality.');
        }

        if (!analysis && visionDecision.decision === 'call') {
          const allowLowQualityVision = AURORA_RULE_RELAX_AGGRESSIVE && userRequestedPhoto && photosProvided;
          const candidates = photoQuality.grade === 'pass'
            ? passedPhotos
            : degradedPhotos.length
              ? degradedPhotos
              : forceVisionCall || allowLowQualityVision
                ? [...passedPhotos, ...degradedPhotos, ...failedPhotos]
                : passedPhotos;
          const chosen = chooseVisionPhoto(candidates);
          if (!chosen) {
            analysisFieldMissing.push({ field: 'photos', reason: photosProvided ? 'no_usable_photo' : 'no_photo_uploaded' });
            if (ctx.lang === 'CN') qualityReportReasons.push('没有可用的照片（缺少 photo_id 或未通过质量门槛）；我会跳过照片解析。');
            else qualityReportReasons.push('No usable photo (missing photo_id or failed quality gate); skipping photo analysis.');
          } else {
            let photoBytes = null;
            photoModulesSourcePhoto = { slot_id: chosen.slot_id, photo_id: chosen.photo_id };
            if (diagnosisPhotoBytes && diagnosisPhoto && diagnosisPhoto.photo_id === chosen.photo_id) {
              photoBytes = diagnosisPhotoBytes;
            } else {
              try {
                profiler.start('decode', { kind: 'photo_fetch', slot: chosen.slot_id, purpose: 'vision' });
                const resp = await fetchPhotoBytesFromPivotaBackend({ req, photoId: chosen.photo_id });
                if (resp && resp.ok) photoBytes = resp.buffer;
                else {
                  recordPhotoFailure(resp && (resp.failure_code || resp.reason), resp && resp.detail);
                }
                profiler.end('decode', {
                  kind: 'photo_fetch',
                  slot: chosen.slot_id,
                  purpose: 'vision',
                  ok: Boolean(photoBytes),
                  bytes: photoBytes ? photoBytes.length : 0,
                });
              } catch (err) {
                recordPhotoFailure('DOWNLOAD_URL_FETCH_5XX', err && err.message ? err.message : null);
                profiler.fail('decode', err, { kind: 'photo_fetch', slot: chosen.slot_id, purpose: 'vision' });
                logger?.warn({ err: err.message }, 'aurora bff: failed to fetch photo bytes');
              }
            }

            if (photoBytes) {
              const deterministicSeedForVisionDto =
                userRequestedPhoto && photosProvided && diagnosisV1 && diagnosisV1.quality
                  ? buildSkinAnalysisFromDiagnosisV1(diagnosisV1, { language: ctx.lang, profileSummary })
                  : buildRuleBasedSkinAnalysis({ profile: profileSummary || profile, recentLogs, language: ctx.lang });
              const factLayerSeed = buildFactLayer({
                deterministicAnalysis: deterministicSeedForVisionDto,
                visionLayer: null,
              });
              const visionDto = buildVisionSignalsDto({
                lang: ctx.lang,
                photoQuality,
                profileSummary,
                diagnosisPolicy,
                factLayer: factLayerSeed,
                imageBuffer: photoBytes,
              });
              llmInputHash = visionDto.input_hash || llmInputHash;
              llmInputHashPrefix = buildInputHashPrefix(llmInputHash);
              recordAuroraSkinMainlineProvider({ provider: 'gemini' });
              const visionStep = await executeAuroraOptionalStep({
                logger,
                route: '/v1/analysis/skin',
                stepId: 'analysis_skin.vision_mainline',
                criticality: 'optional',
                metricStage: 'analysis_optional_step',
                fn: async () =>
                  runGeminiVisionStrategyImpl({
                    imageBuffer: photoBytes,
                    visionDto,
                    language: ctx.lang,
                    promptVersion,
                    profiler,
                  }),
              });
              const vision = visionStep.ok
                ? visionStep.value
                : {
                    ok: false,
                    provider: 'gemini',
                    reason: 'OPTIONAL_STEP_FAILED',
                    schema_violation: false,
                    semantic_violation: false,
                    upstream_status_code: null,
                    latency_ms: 0,
                    retry: { attempted: 0, final: 'fail', last_reason: 'OPTIONAL_STEP_FAILED' },
                    optional_step_error_class: visionStep.error_class,
                  };
              visionRuntime = vision;
              if (vision && vision.ok && vision.analysis) {
                visionLayer = vision.analysis;
                usedPhotos = true;
                shadowVerifyPhotoBytes = photoBytes;
                analysisSource = 'vision_gemini';
                recordAuroraSkinSemanticGuard({
                  stage: 'vision',
                  outcome: vision.semantic && vision.semantic.useful_output ? 'pass' : 'limited',
                  reason: 'none',
                  promptVersion: vision.prompt_version,
                  locale: ctx.lang,
                });
                recordAuroraSkinUsefulOutput({
                  stage: 'vision',
                  useful: Boolean(vision.semantic ? vision.semantic.useful_output : !vision.analysis.insufficient_visual_detail),
                  insufficientReason: vision.canonical && vision.canonical.insufficient_reason ? vision.canonical.insufficient_reason : 'none',
                  promptVersion: vision.prompt_version,
                  locale: ctx.lang,
                });
                logger?.info(
                  {
                    kind: 'metric',
                    name: 'aurora.skin.analysis.provider_success.count',
                    value: 1,
                    provider: 'gemini',
                    analysis_source: analysisSource,
                  },
                  'metric',
                );
                if (vision.retry && Number(vision.retry.attempted || 0) > 0) {
                  recordAuroraSkinLlmRetry({
                    stage: 'vision',
                    provider: 'gemini',
                    inputHashPrefix: llmInputHashPrefix,
                  });
                  if (vision.retry.final === 'success') {
                    recordAuroraSkinLlmRetrySuccess({
                      stage: 'vision',
                      provider: 'gemini',
                      inputHashPrefix: llmInputHashPrefix,
                    });
                  }
                }
              } else if (vision && !vision.ok) {
                const gatewayReasonMap = {
                  TIMEOUT: VisionUnavailabilityReason.VISION_TIMEOUT,
                  RATE_LIMIT: VisionUnavailabilityReason.VISION_RATE_LIMITED,
                  UPSTREAM_5XX: VisionUnavailabilityReason.VISION_UPSTREAM_5XX,
                  UPSTREAM_4XX: VisionUnavailabilityReason.VISION_UPSTREAM_4XX,
                  IMAGE_INVALID: VisionUnavailabilityReason.VISION_IMAGE_INVALID,
                  VISION_IMAGE_INVALID: VisionUnavailabilityReason.VISION_IMAGE_INVALID,
                  SCHEMA_INVALID: VisionUnavailabilityReason.VISION_SCHEMA_INVALID,
                  SEMANTIC_EMPTY: VisionUnavailabilityReason.VISION_SEMANTIC_INVALID,
                  SEMANTIC_INVALID: VisionUnavailabilityReason.VISION_SEMANTIC_INVALID,
                  IMAGE_FETCH_FAILED: VisionUnavailabilityReason.VISION_IMAGE_FETCH_FAILED,
                  MISSING_GEMINI_KEY: VisionUnavailabilityReason.VISION_MISSING_KEY,
                };
                const normalizedReason = normalizeVisionReason(gatewayReasonMap[String(vision.reason || '').trim().toUpperCase()] || vision.reason);
                visionRuntime = { ...vision, reason: normalizedReason || vision.reason };
                deterministicFallbackReason = normalizedReason || deterministicFallbackReason || 'vision_failed';
                analysisFieldMissing.push({
                  field: 'analysis.used_photos',
                  reason: normalizedReason || 'VISION_UNKNOWN',
                });
                if (ctx.lang === 'CN') qualityReportReasons.push(`照片解析失败（${normalizedReason || 'VISION_UNKNOWN'}）；我会退回到确定性基线。`);
                else qualityReportReasons.push(`Photo analysis failed (${normalizedReason || 'VISION_UNKNOWN'}); falling back to deterministic baseline.`);
                if (vision.schema_violation) {
                  recordAuroraSkinLlmSchemaViolation({
                    stage: 'vision',
                    provider: 'gemini',
                    reason: normalizedReason || 'VISION_SCHEMA_INVALID',
                    inputHashPrefix: llmInputHashPrefix,
                  });
                }
                if (vision.semantic_violation) {
                  recordAuroraSkinSemanticGuard({
                    stage: 'vision',
                    outcome: 'fail',
                    reason: normalizedReason || 'VISION_SEMANTIC_INVALID',
                    promptVersion: vision.prompt_version,
                    locale: ctx.lang,
                  });
                  recordAuroraSkinUsefulOutput({
                    stage: 'vision',
                    useful: false,
                    insufficientReason: vision.canonical && vision.canonical.insufficient_reason ? vision.canonical.insufficient_reason : 'none',
                    promptVersion: vision.prompt_version,
                    locale: ctx.lang,
                  });
                }
                logger?.info(
                  {
                    kind: 'metric',
                    name: 'aurora.skin.analysis.provider_failure.count',
                    value: 1,
                    provider: 'gemini',
                    reason: normalizedReason || 'VISION_UNKNOWN',
                    fallback_from: null,
                  },
                  'metric',
                );
                logger?.warn(
                  {
                    reason: normalizedReason || 'VISION_UNKNOWN',
                    provider: 'gemini',
                    upstream_status_code: toNullableInt(vision.upstream_status_code),
                    error_code: vision.error || null,
                  },
                  'aurora bff: vision skin analysis failed',
                );
              }
            }
          }
        } else if (!analysis && visionDecision.decision === 'skip' && userRequestedPhoto && photosProvided) {
          const r = humanizeLlmReasons(visionDecision.reasons, { language: ctx.lang });
          if (ctx.lang === 'CN') qualityReportReasons.push(`已跳过照片解析：${r.join('；') || '原因未知'}`);
          else qualityReportReasons.push(`Skipped photo analysis: ${r.join('; ') || 'unknown reason'}`);
        }

        if (!analysis && reportDecision.decision === 'call' && hasPrimaryInput && reportAvailable) {
          const reportBudget = resolveAnalysisReportStageBudget({
            startedAtMs: analysisBudgetStartedAtMs,
            analysisBudgetMs: effectiveBudgetMs,
            summaryFirst: AURORA_ROUTINE_SUMMARY_FIRST_ENABLED,
            hasRoutine,
            hasPhotoPrimaryInput,
          });
          reportStageBudgetMs = Number.isFinite(Number(reportBudget.budget_ms)) ? Math.trunc(Number(reportBudget.budget_ms)) : 0;
          reportStageBudgetProfile = String(reportBudget.budget_profile || 'default').trim() || 'default';
          if (!reportBudget.ok) {
            reportStageOutcome = 'skipped_low_budget';
            reportModelErrored = true;
            reportModelErrorReason = String(reportBudget.reason || 'REPORT_STAGE_BUDGET_LOW');
            budgetAbortStage = 'report';
            reportDecision = {
              ...reportDecision,
              decision: 'skip',
              reasons: Array.from(new Set([...(Array.isArray(reportDecision.reasons) ? reportDecision.reasons : []), 'analysis_budget_low_skip_report'])),
            };
            profiler.skip('report', 'report_stage_budget_low', {
              remaining_budget_ms: reportBudget.remaining_ms,
              stage_budget_ms: reportStageBudgetMs,
              budget_profile: reportStageBudgetProfile,
            });
            logger?.info({ kind: 'metric', name: 'aurora.skin.analysis.report_stage_budget_skip_rate', value: 1 }, 'metric');
            recordAuroraSkinFlowMetric({ stage: 'analysis_report_budget_skip', hit: true });
            if (ctx.lang === 'CN') qualityReportReasons.push('报告模型阶段因剩余预算不足被跳过；已直接回退到保守基线。');
            else qualityReportReasons.push('Report stage skipped because remaining analysis budget was too low; falling back immediately.');
          } else {
            reportModelCalled = true;
            const reportStageStartedAtMs = Date.now();
            profiler.start('report', {
              remaining_budget_ms: reportBudget.remaining_ms,
              stage_budget_ms: reportStageBudgetMs,
              budget_profile: reportStageBudgetProfile,
            });
          const deterministicSeedForReportDto =
            userRequestedPhoto && photosProvided && diagnosisV1 && diagnosisV1.quality
              ? buildSkinAnalysisFromDiagnosisV1(diagnosisV1, { language: ctx.lang, profileSummary })
              : buildRuleBasedSkinAnalysis({ profile: profileSummary || profile, recentLogs, language: ctx.lang });
          const factLayerForReport = buildFactLayer({
            deterministicAnalysis: deterministicSeedForReportDto,
            visionLayer,
          });
	          const reportDto = buildReportSignalsDto({
	            lang: ctx.lang,
            diagnosisV1,
            diagnosisPolicy,
            profileSummary,
            routineCandidate: hasRoutine ? routineCandidate : null,
            photoQuality: qualityForReport,
            factLayer: factLayerForReport,
            visionCanonical: visionRuntime && visionRuntime.canonical ? visionRuntime.canonical : null,
            imageBuffer: diagnosisPhotoBytes || shadowVerifyPhotoBytes || null,
          });
          llmInputHash = reportDto.input_hash || llmInputHash;
          llmInputHashPrefix = buildInputHashPrefix(llmInputHash);
          recordAuroraSkinMainlineProvider({ provider: 'gemini' });
          let reportStep;
          try {
            const remainingAnalysisBudgetMs = getRemainingBudgetMs({
              startedAtMs: analysisBudgetStartedAtMs,
              budgetMs: effectiveBudgetMs,
            });
            const remainingStageBudgetMs = Math.max(0, reportStageBudgetMs - Math.max(0, Date.now() - reportStageStartedAtMs));
            const callTimeoutMs = Math.max(
              0,
              Math.min(
                remainingStageBudgetMs,
                Number.isFinite(remainingAnalysisBudgetMs) ? remainingAnalysisBudgetMs : remainingStageBudgetMs,
              ),
            );
            if (callTimeoutMs < AURORA_ANALYSIS_REPORT_STAGE_TIMEOUT_FLOOR_MS) {
              throw Object.assign(new Error('AURORA_ANALYSIS_REPORT_STAGE_TIMEOUT'), { code: 'AURORA_ANALYSIS_REPORT_STAGE_TIMEOUT' });
            }
            reportStageAttempts += 1;
            reportStep = await withTimeout(
              executeAuroraOptionalStep({
                logger,
                route: '/v1/analysis/skin',
                stepId: 'analysis_skin.report_mainline',
                criticality: 'optional',
                metricStage: 'analysis_optional_step',
                fn: async () => {
                  const previousRoutine = null;
                  let lifecycleInstructions = '';
                  try {
                    const lifecycleStage = detectRoutineLifecycleStage({
                      routineCandidate: hasRoutine ? routineCandidate : null,
                      previousRoutine,
                      intent: parsed.data.intent || null,
                    });
                    if (lifecycleStage) {
                      const lifecycleCtx = buildRoutineLifecycleContext({
                        stage: lifecycleStage,
                        routineCandidate: hasRoutine ? routineCandidate : null,
                        previousRoutine,
                        profileSummary,
                        language: ctx.lang,
                      });
                      lifecycleInstructions = buildLifecyclePromptInstructions(lifecycleCtx, ctx.lang);
                    }
                  } catch (err) {
                    recordAnalysisSubstageFailure('routine_lifecycle_context', err, {
                      llm_stage: 'report',
                    });
                    lifecycleInstructions = '';
                  }
                  const supplementaryInstructions = buildSupplementaryPromptInstructions({
                    routineCandidate: hasRoutine ? routineCandidate : null,
                    profileSummary,
                    language: ctx.lang,
                  });
                  let kbGrounding = '';
                  if (hasRoutine && routineCandidate) {
                    const { actives } = parseRoutineForSupplementary(routineCandidate);
                    const activeConcepts = actives.map((a) => a.toUpperCase());
                    if (profileSummary && profileSummary.barrierStatus === 'impaired') activeConcepts.push('BARRIER_COMPROMISED');
                    if (profileSummary && profileSummary.sensitivity === 'high') activeConcepts.push('SENSITIVE_SKIN');
                    kbGrounding = buildKbGroundingForPrompt({
                      activeConcepts,
                      profileSummary,
                      language: ctx.lang,
                    });
                  }
                  lifecycleInstructions += supplementaryInstructions + kbGrounding;
                  return runGeminiReportStrategyImpl({
                    reportDto,
                    language: ctx.lang,
                    promptVersion,
                    profiler,
                    lifecycleInstructions,
                  });
                },
              }),
              callTimeoutMs,
              'AURORA_ANALYSIS_REPORT_STAGE_TIMEOUT',
            );
          } catch (err) {
            reportStep = {
              ok: false,
              error_class: err && err.code === 'AURORA_ANALYSIS_REPORT_STAGE_TIMEOUT' ? 'timeout' : 'exception',
              timed_out: Boolean(err && err.code === 'AURORA_ANALYSIS_REPORT_STAGE_TIMEOUT'),
            };
          } finally {
            reportStageElapsedMs = Math.max(0, Date.now() - reportStageStartedAtMs);
          }
          const reportResult = reportStep && reportStep.ok
            ? reportStep.value
            : {
                ok: false,
                provider: 'gemini',
                reason:
                  reportStep && reportStep.timed_out
                    ? 'REPORT_STAGE_BUDGET_TIMEOUT'
                    : 'OPTIONAL_STEP_FAILED',
                schema_violation: false,
                semantic_violation: false,
                layer: null,
                retry: {
                  attempted: reportStageAttempts,
                  final: 'fail',
                  last_reason:
                    reportStep && reportStep.timed_out
                      ? 'REPORT_STAGE_BUDGET_TIMEOUT'
                      : 'OPTIONAL_STEP_FAILED',
                },
                upstream_status_code: null,
                latency_ms: reportStageElapsedMs,
                prompt_version: promptVersion,
                input_hash: reportDto && reportDto.input_hash ? String(reportDto.input_hash) : null,
                optional_step_error_class: reportStep && reportStep.error_class ? reportStep.error_class : 'unknown',
              };
          if (reportResult.retry && Number(reportResult.retry.attempted || 0) > 0) {
            recordAuroraSkinLlmRetry({
              stage: 'report',
              provider: 'gemini',
              inputHashPrefix: llmInputHashPrefix,
            });
            if (reportResult.retry.final === 'success') {
              recordAuroraSkinLlmRetrySuccess({
                stage: 'report',
                provider: 'gemini',
                inputHashPrefix: llmInputHashPrefix,
              });
            }
          }
          if (reportResult.ok && reportResult.layer) {
            reportLayer = reportResult.layer;
            reportCanonical = reportResult.canonical || reportCanonical;
            analysisSource = visionLayer ? 'gemini_vision_report' : 'gemini_report';
            if (reportResult.__deterministic_fallback) {
              reportStageOutcome = 'deterministic_fallback';
              reportStageRecovered = true;
              reportStageRecoveryMode = 'deterministic_fallback';
              reportStagePrimaryFailureReason = normalizeReportFailureReason(reportResult.fallback_reason) || 'UNKNOWN';
              reportStagePrimaryFailureDetail =
                typeof reportResult.fallback_detail === 'string' && reportResult.fallback_detail.trim()
                  ? reportResult.fallback_detail.trim()
                  : null;
            } else if (reportResult.__semantic_fallback) {
              reportStageOutcome = 'semantic_fallback';
              reportStageRecovered = true;
              reportStageRecoveryMode = 'semantic_fallback';
              reportStagePrimaryFailureReason = 'SEMANTIC_INVALID';
              reportStagePrimaryFailureDetail =
                Array.isArray(reportResult.semantic && reportResult.semantic.issues) && reportResult.semantic.issues.length
                  ? reportResult.semantic.issues.join('; ').slice(0, 240)
                  : null;
            } else {
              reportStageOutcome = 'success';
            }
            recordAuroraSkinSemanticGuard({
              stage: 'report',
              outcome: reportResult.semantic && reportResult.semantic.useful_output ? 'pass' : 'limited',
              reason: 'none',
              promptVersion: reportResult.prompt_version,
              locale: ctx.lang,
            });
            recordAuroraSkinUsefulOutput({
              stage: 'report',
              useful: Boolean(reportResult.semantic ? reportResult.semantic.useful_output : !reportResult.layer.insufficient_visual_detail),
              insufficientReason: reportResult.layer && reportResult.layer.insufficient_visual_detail ? 'insufficient_visual_detail' : 'none',
              promptVersion: reportResult.prompt_version,
              locale: ctx.lang,
            });
	            const deepeningContext = buildMainlineDeepeningDto({
              language: ctx.lang,
              promptVersion,
              userRequestedPhoto,
              photosProvided,
              hasRoutine,
              routineCandidate,
              profileSummary,
              recentLogsSummary,
              qualityObject: reportDto && reportDto.quality,
              reportCanonical,
              visionCanonical: visionRuntime && visionRuntime.canonical ? visionRuntime.canonical : null,
            });
            if (deepeningContext && deepeningContext.dto) {
              if (!(reportResult.__semantic_fallback || reportResult.__deterministic_fallback)) {
                const deepeningStep = await executeAuroraOptionalStep({
                  logger,
                  route: '/v1/analysis/skin',
                  stepId: 'analysis_skin.deepening_child',
                  criticality: 'optional',
                  metricStage: 'analysis_optional_step',
                  fn: async () =>
                    runGeminiDeepeningStrategyImpl({
                      deepeningDto: deepeningContext.dto,
                      language: ctx.lang,
                      promptVersion: deepeningContext.promptVersion,
                      profiler,
                    }),
                });
                deepeningRuntime = deepeningStep.ok
                  ? deepeningStep.value
                  : {
                      ok: false,
                      provider: 'deterministic',
                      reason: 'OPTIONAL_STEP_FAILED',
                      optional_step_error_class: deepeningStep.error_class,
                      layer: null,
                    };
              }
              if (deepeningRuntime && deepeningRuntime.ok && deepeningRuntime.layer) {
                reportLayer = {
                  ...reportLayer,
                  deepening: deepeningRuntime.layer,
                };
              } else {
                const fallbackDeepeningCanonical = adjudicateDeepeningCanonicalLayer(
                  {
                    phase: deepeningContext.phasePlan.phase,
                    summary_priority:
                      reportCanonical && reportCanonical.summary_focus
                        ? reportCanonical.summary_focus.priority
                        : 'mixed',
                    question_intent: deepeningContext.phasePlan.question_intent,
                  },
                  {
                    inheritedPriority:
                      reportCanonical && reportCanonical.summary_focus
                        ? reportCanonical.summary_focus.priority
                        : 'mixed',
                    deepeningContext: deepeningContext.dto,
                  },
                );
                reportLayer = {
                  ...reportLayer,
                  deepening: renderDeepeningCanonicalLayer(fallbackDeepeningCanonical, { lang: ctx.lang }),
                };
              }
            }
            profiler.end('report', {
              outcome: reportStageOutcome,
              attempts: reportStageAttempts,
              elapsed_ms: reportStageElapsedMs,
              stage_budget_ms: reportStageBudgetMs,
              budget_profile: reportStageBudgetProfile,
            });
          } else {
            const reportFailureRaw = reportResult.reason || 'report_output_invalid';
            const reportFailureReason = normalizeReportFailureReason(reportFailureRaw) || 'UNKNOWN';
            reportStagePrimaryFailureDetail =
              typeof reportResult.error_detail === 'string' && reportResult.error_detail.trim()
                ? reportResult.error_detail.trim()
                : reportStagePrimaryFailureDetail;
            deterministicFallbackReason = deterministicFallbackReason || reportFailureRaw;
            reportModelErrored = true;
            reportModelErrorReason = reportFailureReason;
            if (reportFailureReason === 'REPORT_STAGE_BUDGET_TIMEOUT') {
              reportStageOutcome = 'budget_timeout';
              budgetAbortStage = 'report';
              logger?.info({ kind: 'metric', name: 'aurora.skin.analysis.report_stage_timeout_rate', value: 1 }, 'metric');
            } else if (reportFailureReason === 'SCHEMA_INVALID') {
              reportStageOutcome = 'schema_invalid';
            } else {
              reportStageOutcome = 'upstream_error';
            }
            if (reportResult.schema_violation) {
              recordAuroraSkinLlmSchemaViolation({
                stage: 'report',
                provider: 'gemini',
                reason: reportFailureReason,
                inputHashPrefix: llmInputHashPrefix,
              });
            }
            if (reportResult.semantic_violation) {
              recordAuroraSkinSemanticGuard({
                stage: 'report',
                outcome: 'fail',
                reason: reportFailureReason,
                promptVersion: reportResult.prompt_version,
                locale: ctx.lang,
              });
              recordAuroraSkinUsefulOutput({
                stage: 'report',
                useful: false,
                insufficientReason: 'semantic_invalid',
                promptVersion: reportResult.prompt_version,
                locale: ctx.lang,
              });
            }
            profiler.end('report', {
              outcome: reportStageOutcome,
              failure_reason: reportFailureReason,
              attempts: reportStageAttempts,
              elapsed_ms: reportStageElapsedMs,
              stage_budget_ms: reportStageBudgetMs,
              budget_profile: reportStageBudgetProfile,
            });
            if (ctx.lang === 'CN') qualityReportReasons.push(`报告模型未能稳定输出（${reportFailureReason}）；我会退回到确定性基线。`);
            else qualityReportReasons.push(`Report model output was unstable (${reportFailureReason}); falling back to deterministic baseline.`);
          }
          }
        }
        if (!analysis && reportDecision.decision === 'skip' && hasPrimaryInput) {
          if (reportStageOutcome === 'not_requested') {
            reportStageOutcome = 'skipped_policy';
            profiler.skip('report', 'policy_skip', {
              reasons: Array.isArray(reportDecision.reasons) ? reportDecision.reasons.slice(0, 4).join('|') : '',
              budget_profile: reportStageBudgetProfile,
            });
          }
          const r = humanizeLlmReasons(reportDecision.reasons, { language: ctx.lang });
          if (ctx.lang === 'CN') qualityReportReasons.push(`已跳过报告模型：${r.join('；') || '原因未知'}`);
          else qualityReportReasons.push(`Skipped report model: ${r.join('; ') || 'unknown reason'}`);
        }
        if (!analysis && retakeFallbackAnalysis) {
          analysis = retakeFallbackAnalysis;
          analysisSource = 'retake';
        }

        if (!analysis) {
          if (!hasPrimaryInput && !hasPhotoPrimaryInput) {
            analysis = profiler.timeSync(
              'detector',
              () => buildLowConfidenceBaselineSkinAnalysis({ profile: profileSummary || profile, language: ctx.lang }),
              { kind: 'baseline_low_confidence' },
            );
            analysisSource = 'baseline_low_confidence';
          } else {
            if (
              userRequestedPhoto &&
              photosProvided &&
              diagnosisV1 &&
              diagnosisV1.quality &&
              String(diagnosisV1.quality.grade || '').trim().toLowerCase() !== 'fail'
            ) {
              analysis = profiler.timeSync(
                'postprocess',
                () => buildSkinAnalysisFromDiagnosisV1(diagnosisV1, { language: ctx.lang, profileSummary }),
                { kind: 'diagnosis_v1_template' },
              );
              if (analysis) analysisSource = 'diagnosis_v1_template';
            }
            if (!analysis) {
              analysis = profiler.timeSync(
                'detector',
                () => buildRuleBasedSkinAnalysis({ profile: profileSummary || profile, recentLogs, language: ctx.lang }),
                { kind: 'rule_based' },
              );
            }
          }
        }
        if (
          analysis &&
          deterministicFallbackReason &&
          analysisSource !== 'gemini_vision_report' &&
          analysisSource !== 'gemini_report' &&
          analysisSource !== 'vision_gemini'
        ) {
          recordAuroraSkinFallbackDeterministic({ reason: deterministicFallbackReason });
        }
        if (analysis && reportLayer && analysisSource !== 'retake') {
          analysisSource = visionLayer ? 'gemini_vision_report' : 'gemini_report';
        }

        const baseVisionReasons = Array.isArray(visionDecision.reasons) ? visionDecision.reasons.filter(Boolean) : [];
        const firstVisionFailureReason = pickPrimaryVisionReason(baseVisionReasons);
        const unavailabilityOnSkip = Boolean(visionDecision.decision === 'skip' && firstVisionFailureReason);
        const visionRetryDefault = {
          attempted: 0,
          final: 'fail',
          last_reason: firstVisionFailureReason || null,
        };
        visionDecisionForReport = {
          ...visionDecision,
          reasons: baseVisionReasons,
          provider: selectedVisionProvider.provider || 'gemini',
          upstream_status_code: null,
          latency_ms: null,
          retry: visionRetryDefault,
        };

        if (visionRuntime && visionRuntime.ok) {
          const runtimeReasons = Array.isArray(visionDecisionForReport.reasons)
            ? visionDecisionForReport.reasons.filter(Boolean)
            : [];
          const normalizedQualityGrade = String(photoQuality && photoQuality.grade ? photoQuality.grade : '')
            .trim()
            .toLowerCase();
          const qualityReasonFallback =
            normalizedQualityGrade === 'degraded' || normalizedQualityGrade === 'unknown'
              ? ['degraded_mode_vision']
              : ['quality_pass'];
          visionDecisionForReport = {
            ...visionDecisionForReport,
            decision: 'call',
            // Preserve policy reasons so report metadata stays consistent with degrade decisions.
            reasons: runtimeReasons.length ? runtimeReasons : qualityReasonFallback,
            provider: visionRuntime.provider || visionDecisionForReport.provider,
            retry: visionRuntime.retry || { attempted: 0, final: 'success', last_reason: null },
            upstream_status_code: null,
            latency_ms: toNullableNumber(visionRuntime.latency_ms),
          };
        } else if (visionRuntime && !visionRuntime.ok) {
          const runtimeReason = normalizeVisionReason(visionRuntime.reason);
          const runtimeReasons = [runtimeReason];
          if (usedPhotos) runtimeReasons.push(VisionUnavailabilityReason.VISION_CV_FALLBACK_USED);
          visionDecisionForReport = {
            ...visionDecisionForReport,
            decision: 'fallback',
            reasons: Array.from(new Set(runtimeReasons)),
            provider: visionRuntime.provider || visionDecisionForReport.provider,
            retry: visionRuntime.retry || { attempted: 0, final: 'fail', last_reason: runtimeReason },
            upstream_status_code: toNullableInt(visionRuntime.upstream_status_code),
            latency_ms: toNullableNumber(visionRuntime.latency_ms),
          };
        } else if (visionDecision.decision === 'call' && photoFailureCodes.length) {
          const reasons = [VisionUnavailabilityReason.VISION_IMAGE_FETCH_FAILED];
          if (usedPhotos) reasons.push(VisionUnavailabilityReason.VISION_CV_FALLBACK_USED);
          visionDecisionForReport = {
            ...visionDecisionForReport,
            decision: 'fallback',
            reasons,
            retry: { attempted: 0, final: 'fail', last_reason: VisionUnavailabilityReason.VISION_IMAGE_FETCH_FAILED },
          };
        } else if (unavailabilityOnSkip && userRequestedPhoto && photosProvided && usedPhotos) {
          visionDecisionForReport = {
            ...visionDecisionForReport,
            decision: 'fallback',
            reasons: Array.from(new Set([...baseVisionReasons, VisionUnavailabilityReason.VISION_CV_FALLBACK_USED])),
          };
        }

        const visionNoticeReason = pickPrimaryVisionReason(visionDecisionForReport.reasons);
        const visionPhotoNoticeMessage = buildVisionPhotoNotice({
          reason: visionNoticeReason,
          language: ctx.lang,
        });

        recordVisionDecision({
          provider: visionDecisionForReport.provider || 'gemini',
          decision: visionDecisionForReport.decision,
          reasons: visionDecisionForReport.reasons,
          latencyMs: visionDecisionForReport.latency_ms,
        });

        const mustDowngrade =
          userRequestedPhoto &&
          photosProvided &&
          (photoQuality.grade === 'degraded' || photoQuality.grade === 'unknown') &&
          analysisSource !== 'retake';
        if (analysis && mustDowngrade) analysis = downgradeSkinAnalysisConfidence(analysis, { language: ctx.lang, qualityObject: buildQualityObject(photoQuality) });
        if (analysis && diagnosisV1 && usedPhotos) {
          analysis = mergePhotoFindingsIntoAnalysis({
            analysis,
            diagnosisV1,
            language: ctx.lang,
            profileSummary,
          });
        }
        let finalContract = null;
        let geometrySanitizer = null;
        let photoNotice = null;
        const photoNotUsed = Boolean(userRequestedPhoto && photosProvided && !usedPhotos);
        const photoFailureCode =
          photoFailureCodes[0] || (photoNotUsed && hasPhotoPrimaryInput && !hasPrimaryInput ? 'MISSING_PRIMARY_INPUT' : null);
        profiler.start('postprocess', { kind: 'analysis_finalize' });
        try {
          if (analysis) {
            const factLayer = buildFactLayer({
              deterministicAnalysis: analysis,
              visionLayer,
            });
            finalContract = finalizeSkinAnalysisContract({
              factLayer,
              reportLayer,
              quality: photoQuality,
              lang: ctx.lang,
              deterministicFallback: analysis,
            });
            if (finalContract && finalContract.__contract_fallback) {
              deterministicFallbackReason = deterministicFallbackReason || 'contract_invalid';
              recordAuroraSkinFallbackDeterministic({ reason: deterministicFallbackReason });
            }
            analysis = mergeFinalContractIntoAnalysis({ analysis, finalContract });
          }
          if (photoNotUsed && photoFailureCode) {
            photoNotice = {
              failure_code: photoFailureCode,
              message:
                ctx.lang === 'CN'
                  ? `本次未能读取并分析照片（原因：${photoFailureCode}），以下结果仅基于你的问卷/历史信息。请重传后重试。`
                  : `We couldn't analyze your photo this time (reason: ${photoFailureCode}). Results below are based on your answers/history only. Please re-upload and retry.`,
            };
          }
          if (analysis) {
            analysis = buildExecutablePlanForAnalysis({
              analysis,
              language: ctx.lang,
              usedPhotos,
              photoQuality,
              profileSummary,
              photoNoticeOverride:
                photoNotice && typeof photoNotice.message === 'string' && photoNotice.message.trim()
                  ? photoNotice.message
                  : visionPhotoNoticeMessage,
              photoFailureCode,
              photosProvided,
            });
            analysis = attachRoutineExpertToAnalysis({
              analysis,
              routineCandidate: hasRoutine ? routineCandidate : null,
              profileSummary,
              recentLogs: recentLogsSummary,
              language: ctx.lang,
            });
            geometrySanitizer =
              analysis && analysis.__geometry_sanitizer && typeof analysis.__geometry_sanitizer === 'object'
                ? analysis.__geometry_sanitizer
                : null;
            if (analysis && Object.prototype.hasOwnProperty.call(analysis, '__geometry_sanitizer')) {
              delete analysis.__geometry_sanitizer;
            }
            if (finalContract) {
              const locked = finalizeSkinAnalysisContract({
                factLayer: buildFactLayer({ deterministicAnalysis: analysis, visionLayer }),
                reportLayer,
                quality: photoQuality,
                lang: ctx.lang,
                deterministicFallback: analysis,
              });
              analysis = mergeFinalContractIntoAnalysis({ analysis, finalContract: locked });
            }
          }
        } catch (err) {
          profiler.fail('postprocess', err, { kind: 'analysis_finalize', has_analysis: Boolean(analysis) });
          throw err;
        }
        profiler.end('postprocess', {
          kind: 'analysis_finalize',
          has_analysis: Boolean(analysis),
          analysis_source: analysisSource || 'none',
          used_photos: Boolean(usedPhotos),
        });

        let renderedAnalysisSource = analysisSource;
        if (photoNotUsed && analysisSource !== 'retake') {
          renderedAnalysisSource = 'rule_based_with_photo_qc';
        }
        const qualityGradeForMetrics = normalizeQualityGradeForMetrics(photoQuality && photoQuality.grade);
        const pipelineVersionForMetrics = normalizePipelineVersionForMetrics(pipelineVersion || 'unknown');
        const deviceClassForMetrics = inferDeviceClassForMetrics(req);
        const sanitizerTotals = geometrySanitizer || { checked_n: 0, dropped_n: 0, clipped_n: 0 };
        recordAnalyzeRequest({
          issueType: 'all',
          qualityGrade: qualityGradeForMetrics,
          pipelineVersion: pipelineVersionForMetrics,
          deviceClass: deviceClassForMetrics,
        });
        recordGeometrySanitizerTotals({
          issueType: 'all',
          qualityGrade: qualityGradeForMetrics,
          pipelineVersion: pipelineVersionForMetrics,
          deviceClass: deviceClassForMetrics,
          dropped: sanitizerTotals.dropped_n,
          clipped: sanitizerTotals.clipped_n,
        });
        const sanitizerByIssue =
          geometrySanitizer && geometrySanitizer.by_issue && typeof geometrySanitizer.by_issue === 'object'
            ? geometrySanitizer.by_issue
            : {};
        for (const [issueType, issueStatsRaw] of Object.entries(sanitizerByIssue)) {
          const issueStats = issueStatsRaw && typeof issueStatsRaw === 'object' ? issueStatsRaw : {};
          const checkedN = Number(issueStats.checked_n || 0);
          if (checkedN <= 0) continue;
          recordAnalyzeRequest({
            issueType,
            qualityGrade: qualityGradeForMetrics,
            pipelineVersion: pipelineVersionForMetrics,
            deviceClass: deviceClassForMetrics,
          });
          recordGeometrySanitizerTotals({
            issueType,
            qualityGrade: qualityGradeForMetrics,
            pipelineVersion: pipelineVersionForMetrics,
            deviceClass: deviceClassForMetrics,
            dropped: issueStats.dropped_n,
            clipped: issueStats.clipped_n,
          });
        }

        let photoModulesCard = null;
        let photoQualitySoftenedReason = null;
        let photoModulesConfidenceSoftenedReason = null;
        profiler.start('photo_modules', { kind: 'analysis_photo_modules' });
        try {
          const photoModulesSkinMask = await maybeInferSkinMaskForPhotoModules({
            imageBuffer: diagnosisPhotoBytes,
            diagnosisInternal: diagnosisV1Internal,
            logger,
            requestId: ctx.request_id,
          });

          const photoModulesSourceResolved = (() => {
            const normalizeSourcePhoto = (candidate) => {
              if (!candidate || typeof candidate !== 'object') return null;
              const slotId = String(candidate.slot_id || '').trim();
              const photoId = String(candidate.photo_id || '').trim();
              if (!slotId || !photoId) return null;
              return { slot_id: slotId, photo_id: photoId };
            };

            const direct = normalizeSourcePhoto(photoModulesSourcePhoto);
            if (direct) return direct;

            const diagnosisFallback = normalizeSourcePhoto(diagnosisPhoto);
            if (diagnosisFallback) return diagnosisFallback;

            const bestEffort = chooseVisionPhoto([
              ...(Array.isArray(passedPhotos) ? passedPhotos : []),
              ...(Array.isArray(degradedPhotos) ? degradedPhotos : []),
              ...(Array.isArray(failedPhotos) ? failedPhotos : []),
            ]);
            return normalizeSourcePhoto(bestEffort);
          })();

          photoModulesCard = maybeBuildPhotoModulesCardForAnalysis({
            requestId: ctx.request_id,
            analysis,
            usedPhotos,
            photoQuality,
            photoNotice:
              photoNotice && typeof photoNotice.message === 'string' && photoNotice.message.trim()
                ? photoNotice.message
                : visionPhotoNoticeMessage,
            diagnosisInternal: diagnosisV1Internal,
            sourcePhoto: photoModulesSourceResolved,
            profileSummary,
            language: ctx.lang,
            skinMask: photoModulesSkinMask,
          });
          if (photoModulesCard) {
            const softenedPhotoQuality = softenPhotoQualityFailFromUsablePhotoModules({
              photoQuality,
              photoModulesCard,
            });
            photoQuality = softenedPhotoQuality.photoQuality || photoQuality;
            photoModulesCard = softenedPhotoQuality.photoModulesCard || photoModulesCard;
            photoQualitySoftenedReason = softenedPhotoQuality.applied ? softenedPhotoQuality.reason : null;
          }
          if (photoModulesCard && photoModulesSourceResolved) {
            const payloadObj =
              photoModulesCard.payload && typeof photoModulesCard.payload === 'object' && !Array.isArray(photoModulesCard.payload)
                ? photoModulesCard.payload
                : null;
            const faceCropObj =
              payloadObj && payloadObj.face_crop && typeof payloadObj.face_crop === 'object' && !Array.isArray(payloadObj.face_crop)
                ? payloadObj.face_crop
                : null;

            const hasRenderablePhoto = Boolean(
              faceCropObj &&
                (
                  String(faceCropObj.crop_image_url || '').trim() ||
                  String(faceCropObj.original_image_url || '').trim() ||
                  String(faceCropObj.face_crop_url || '').trim() ||
                  String(faceCropObj.source_image_url || '').trim() ||
                  String(faceCropObj.image_url || '').trim() ||
                  String(faceCropObj.src || '').trim()
                ),
            );

            if (!hasRenderablePhoto) {
              const authHeaders = buildPivotaBackendAuthHeaders(req);
              if (PIVOTA_BACKEND_BASE_URL && Object.keys(authHeaders).length) {
                const generated = await requestPhotoDownloadUrlOnce({
                  photoId: photoModulesSourceResolved.photo_id,
                  authHeaders,
                });
                const fallbackImageUrl =
                  generated && generated.ok && typeof generated.downloadUrl === 'string' ? generated.downloadUrl.trim() : '';
                if (fallbackImageUrl) {
                  const nextFaceCrop = {
                    ...(faceCropObj && typeof faceCropObj === 'object' ? faceCropObj : {}),
                    original_image_url:
                      (faceCropObj && typeof faceCropObj.original_image_url === 'string' && faceCropObj.original_image_url.trim()) ||
                      fallbackImageUrl,
                  };
                  if (!String(nextFaceCrop.source_image_url || '').trim()) nextFaceCrop.source_image_url = fallbackImageUrl;
                  if (!String(nextFaceCrop.image_url || '').trim()) nextFaceCrop.image_url = fallbackImageUrl;
                  photoModulesCard.payload = {
                    ...(payloadObj || {}),
                    face_crop: nextFaceCrop,
                  };
                }
              }
            }
          }
          if (photoModulesCard) {
            photoModulesCard = await enrichPhotoModulesCardWithIngredientProductsBounded({
              photoModulesCard,
              profileSummary,
              language: ctx.lang,
              logger,
            });
            const softenedPhotoModulesConfidence = softenPhotoModulesLowConfidenceFromUsableOnnxFallback({
              photoModulesCard,
              language: ctx.lang,
            });
            photoModulesCard = softenedPhotoModulesConfidence.photoModulesCard || photoModulesCard;
            photoModulesConfidenceSoftenedReason = softenedPhotoModulesConfidence.applied
              ? softenedPhotoModulesConfidence.reason
              : null;
          }
        } catch (err) {
          profiler.fail('photo_modules', err, { kind: 'analysis_photo_modules', has_analysis: Boolean(analysis) });
          throw err;
        }
        profiler.end('photo_modules', {
          kind: 'analysis_photo_modules',
          emitted: Boolean(photoModulesCard),
          used_photos: Boolean(usedPhotos),
        });

        let diagnosisArtifact = null;
        let ingredientPlan = null;
        let analysisContextSnapshot = null;
        let recommendationReady = false;
        let latestArtifactId = null;
        let artifactGate = null;
        if (analysis && AURORA_DIAG_ARTIFACT_ENABLED && persistLastAnalysis) {
          let artifactStageFailed = false;
          profiler.start('artifact', { kind: 'diagnosis_artifact_plan' });
          try {
            const artifactCandidate = buildDiagnosisArtifactV1({
              ctx,
              identity,
              profileSummary,
              recentLogsSummary,
              analysis,
              analysisSource: renderedAnalysisSource,
              usePhoto: Boolean(userRequestedPhoto),
              usedPhotos,
              photos,
              photoQuality,
            });
            let ingredientPlanPersistPayload = null;
            let ingredientPlanPersistId = null;
            if (routineOnlyArtifactFastPath) {
              diagnosisArtifact = artifactCandidate;
            } else {
              const savedArtifact = await saveDiagnosisArtifact({
                auroraUid: identity.auroraUid,
                userId: identity.userId,
                sessionId: ctx.brief_id || null,
                artifact: artifactCandidate,
                artifactId: artifactCandidate && artifactCandidate.artifact_id ? artifactCandidate.artifact_id : undefined,
              });
              diagnosisArtifact = savedArtifact && savedArtifact.artifact_json && typeof savedArtifact.artifact_json === 'object'
                ? {
                    ...savedArtifact.artifact_json,
                    artifact_id: savedArtifact.artifact_id,
                    created_at: savedArtifact.created_at || savedArtifact.artifact_json.created_at,
                  }
                : artifactCandidate;
            }
            logger?.info({ kind: 'metric', name: 'aurora.skin.artifact_created_rate', value: diagnosisArtifact ? 1 : 0 }, 'metric');
            recordAuroraSkinFlowMetric({ stage: 'artifact_created', hit: Boolean(diagnosisArtifact) });
            latestArtifactId = diagnosisArtifact && diagnosisArtifact.artifact_id
              ? String(diagnosisArtifact.artifact_id).trim()
              : null;

            if (diagnosisArtifact && AURORA_INGREDIENT_PLAN_ENABLED && latestArtifactId) {
              const planBuilt = buildIngredientPlan({
                artifact: diagnosisArtifact,
                profile: profileSummary || profile || {},
              });
              if (routineOnlyArtifactFastPath) {
                ingredientPlanPersistPayload = planBuilt && typeof planBuilt === 'object' ? { ...planBuilt } : null;
                ingredientPlanPersistId = createPlanId();
                ingredientPlan = ingredientPlanPersistPayload
                  ? {
                      ...ingredientPlanPersistPayload,
                      plan_id: ingredientPlanPersistId,
                      created_at: new Date().toISOString(),
                    }
                  : planBuilt;
              } else {
                const savedPlan = await saveIngredientPlan({
                  artifactId: latestArtifactId,
                  auroraUid: identity.auroraUid,
                  userId: identity.userId,
                  plan: planBuilt,
                });
                ingredientPlan = savedPlan && savedPlan.plan_json && typeof savedPlan.plan_json === 'object'
                  ? {
                      ...savedPlan.plan_json,
                      plan_id: savedPlan.plan_id,
                      created_at: savedPlan.created_at || savedPlan.plan_json.created_at,
                    }
                  : planBuilt;
              }
              logger?.info({ kind: 'metric', name: 'aurora.skin.ingredient_plan_rate', value: ingredientPlan ? 1 : 0 }, 'metric');
              recordAuroraSkinFlowMetric({ stage: 'ingredient_plan', hit: Boolean(ingredientPlan) });
            }

            artifactGate = hasUsableArtifactForRecommendations(diagnosisArtifact);
            recommendationReady = Boolean(artifactGate && artifactGate.ok && artifactGate.confidence_level !== 'low');

            analysisContextSnapshot = buildAnalysisContextSnapshotForRoute({
              latestArtifact: diagnosisArtifact,
              profile: snapshotProfileBase,
              recentLogs: recentLogsSummary,
              lastAnalysis: ingredientPlan && analysis
                ? {
                    ...analysis,
                    ingredient_plan: {
                      targets: Array.isArray(ingredientPlan.targets) ? ingredientPlan.targets : [],
                      avoid: Array.isArray(ingredientPlan.avoid) ? ingredientPlan.avoid : [],
                    },
                  }
                : analysis,
            });

            if (routineOnlyArtifactFastPath && diagnosisArtifact) {
              deferDiagnosisArtifactPersistence({
                identity,
                sessionId: ctx.brief_id || null,
                diagnosisArtifact,
                ingredientPlanPayload: ingredientPlanPersistPayload,
                ingredientPlanId: ingredientPlanPersistId,
                logger,
                requestId: ctx.request_id,
                traceId: ctx.trace_id,
              });
            }
          } catch (err) {
            artifactStageFailed = true;
            profiler.fail('artifact', err, {
              kind: 'diagnosis_artifact_plan',
              artifact_created: Boolean(diagnosisArtifact),
              ingredient_plan_created: Boolean(ingredientPlan),
            });
            logger?.warn(
              { err: err && err.message ? err.message : String(err), request_id: ctx.request_id },
              'aurora bff: diagnosis artifact/plan generation failed',
            );
          }
          if (!artifactStageFailed) {
            profiler.end('artifact', {
              kind: 'diagnosis_artifact_plan',
              artifact_created: Boolean(diagnosisArtifact),
              ingredient_plan_created: Boolean(ingredientPlan),
              recommendation_ready: Boolean(recommendationReady),
              persistence_mode: routineOnlyArtifactFastPath ? 'deferred_async' : 'sync',
            });
          }
        } else {
          profiler.skip('artifact', 'artifact_not_requested', {
            has_analysis: Boolean(analysis),
            artifact_enabled: Boolean(AURORA_DIAG_ARTIFACT_ENABLED),
            persist_last_analysis: Boolean(persistLastAnalysis),
          });
        }

        const visionModelCalled = Boolean(visionRuntime);
        const visionLlmOutcome =
          visionModelCalled
            ? visionRuntime && visionRuntime.ok
              ? 'call'
              : 'provider_error'
            : visionDecision && visionDecision.decision === 'call'
              ? 'precheck_fail'
              : 'policy_skip';
        const reportLlmOutcome = reportModelCalled
          ? (reportModelErrored ? 'provider_error' : 'call')
          : reportDecision && reportDecision.decision === 'call'
            ? 'precheck_fail'
            : 'policy_skip';
        if (!shadowRun) {
          recordAuroraSkinAnalysisRealModel({ source: renderedAnalysisSource });
          recordAuroraSkinLlmCall({ stage: 'vision', outcome: visionLlmOutcome });
          recordAuroraSkinLlmCall({ stage: 'report', outcome: reportLlmOutcome });
        }

        const degradeMeta = deriveSkinDegradeMeta({
          renderedAnalysisSource,
          photoFailureCode,
          visionDecisionForReport,
          reportModelErrored,
          reportModelErrorReason,
        });
        const degradeReason = degradeMeta.degradeReason;
        let routineAnalysisV2Result = null;
        let routineAnalysisV2Attempted = false;
        let routineAnalysisV2FailureClass = null;
        const analysisMeta = {
          detector_source: String(renderedAnalysisSource || '').trim() || 'unknown',
          llm_vision_called: visionModelCalled,
          llm_report_called: reportModelCalled,
          routine_analysis_version:
            AURORA_ROUTINE_ANALYSIS_V2_ENABLED &&
            hasRoutine &&
            routineProductCandidates.length > 0
              ? 'v2_attempted'
              : 'legacy',
          routine_payload_shape: routinePayloadShape,
          routine_preview_items_count: routineProductCandidates.length,
          routine_product_enrichment_deferred: routineProductCandidates.length > 0,
          analysis_mode: 'analysis_summary',
          profile_context_source: requestProfileContextSource,
          request_profile_overlay_applied: requestProfileOverlayKeys.length > 0,
          quality_memory_mode: qualityMemoryMode,
          quality_logs_skipped: qualityLogsSkipped,
          ...(qualityProfileTimeoutMs != null ? { quality_profile_timeout_ms: qualityProfileTimeoutMs } : {}),
          quality_policy_patch_deferred: qualityPolicyPatchDeferred,
          ...(qualityProfileTimedOut ? { quality_profile_timed_out: true } : {}),
          ...(requestProfileOverlayKeys.length ? { request_profile_overlay_keys: requestProfileOverlayKeys } : {}),
          artifact_usable: Boolean(artifactGate && artifactGate.ok),
          artifact_gate: buildArtifactGateMeta(artifactGate),
          reco_artifact_eligible: Boolean(artifactGate && artifactGate.ok && artifactGate.confidence_level !== 'low'),
          ...(reportModelCalled || reportStageOutcome !== 'not_requested' || reportStageAttempts > 0
            ? {
                report_stage_budget_ms: Math.max(0, Math.trunc(Number(reportStageBudgetMs) || 0)),
                report_stage_budget_profile: reportStageBudgetProfile,
                report_stage_elapsed_ms: Math.max(0, Number(reportStageElapsedMs) || 0),
                report_stage_outcome: reportStageOutcome,
                report_stage_attempts: Math.max(0, Math.trunc(Number(reportStageAttempts) || 0)),
                ...(reportStageRecovered ? { report_stage_recovered: true } : {}),
                ...(reportStageRecoveryMode ? { report_stage_recovery_mode: reportStageRecoveryMode } : {}),
                ...(reportStagePrimaryFailureReason ? { report_stage_primary_failure_reason: reportStagePrimaryFailureReason } : {}),
                ...(reportStagePrimaryFailureDetail ? { report_stage_primary_failure_detail: reportStagePrimaryFailureDetail } : {}),
              }
            : {}),
          ...(budgetAbortStage ? { budget_abort_stage: budgetAbortStage } : {}),
          gate_relax_mode: AURORA_RULE_RELAX_MODE,
          low_quality_tolerated: Boolean(
            AURORA_RULE_RELAX_AGGRESSIVE &&
              userRequestedPhoto &&
              photosProvided &&
              String(photoQuality && photoQuality.grade || '').trim().toLowerCase() === 'fail',
          ),
          ...(photoQualitySoftenedReason ? { photo_quality_softened_reason: photoQualitySoftenedReason } : {}),
          ...(photoModulesConfidenceSoftenedReason ? { photo_modules_confidence_softened_reason: photoModulesConfidenceSoftenedReason } : {}),
          ...(degradeReason ? { degrade_reason: degradeReason } : {}),
          ...(degradeMeta.visionFailureReason ? { vision_failure_reason: degradeMeta.visionFailureReason } : {}),
          ...(degradeMeta.reportFailureReason ? { report_failure_reason: degradeMeta.reportFailureReason } : {}),
        };
        const artifactConfidence = diagnosisArtifact && diagnosisArtifact.overall_confidence && typeof diagnosisArtifact.overall_confidence === 'object'
          ? diagnosisArtifact.overall_confidence
          : null;
        if (photoModulesCard && ingredientPlan) {
          const softenedPhotoModulesConfidenceLate = softenPhotoModulesLowConfidenceFromUsableOnnxFallback({
            photoModulesCard,
            ingredientPlanPayload: ingredientPlan,
            language: ctx.lang,
          });
          photoModulesCard = softenedPhotoModulesConfidenceLate.photoModulesCard || photoModulesCard;
          if (softenedPhotoModulesConfidenceLate.applied) {
            photoModulesConfidenceSoftenedReason = softenedPhotoModulesConfidenceLate.reason;
          }
        }
        const lowConfidenceFromPhotoQuality = Boolean(
          userRequestedPhoto &&
            photosProvided &&
            ['fail', 'unknown'].includes(String(photoQuality && photoQuality.grade || '').trim().toLowerCase()),
        );
        const lowConfidenceArtifact = Boolean(
          artifactConfidence &&
          String(artifactConfidence.level || '').toLowerCase() === 'low',
        );
        const lowConfidencePhotoCard = Boolean(photoModulesCard && photoModulesCard.payload && photoModulesCard.payload.low_confidence === true);
        const softenedAnalysisSummaryLowConfidence = shouldSoftenAnalysisSummaryLowConfidence({
          analysisSource: renderedAnalysisSource,
          usePhoto: Boolean(userRequestedPhoto),
          photosProvided,
          photos,
          usedPhotos,
          photoQualityGrade: photoQuality && photoQuality.grade,
          degradeReason,
          ingredientPlan,
          profileSummary,
          photoModulesCard,
        });
        const analysisSummaryConfidenceSoftenedReason = softenedAnalysisSummaryLowConfidence
          ? (
              photoModulesConfidenceSoftenedReason === 'skinmask_onnx_fail_target_stable'
                ? 'skinmask_onnx_fail_target_stable'
                : 'photo_artifact_limited_target_stable'
            )
          : '';
        if (analysisSummaryConfidenceSoftenedReason) {
          analysisMeta.confidence_softened_reason = analysisSummaryConfidenceSoftenedReason;
        }
        const lowConfidenceSummary =
          !softenedAnalysisSummaryLowConfidence && (
            analysisSource === 'baseline_low_confidence'
            || lowConfidenceFromPhotoQuality
            || lowConfidenceArtifact
            || lowConfidencePhotoCard
          );

        profiler.start('render', { kind: 'envelope' });
        const chatQualityObj = buildQualityObject(photoQuality);
        const chatCappedAnalysis = analysis ? applyConfidenceCaps(analysis, chatQualityObj.grade) : analysis;
        const chatDedupedAnalysis = chatCappedAnalysis ? dedupeAndCapOutput(chatCappedAnalysis) : chatCappedAnalysis;
        let chatEnrichedAnalysis = chatDedupedAnalysis ? {
          ...chatDedupedAnalysis,
          quality: chatQualityObj,
          findings: Array.isArray(chatDedupedAnalysis.findings) ? chatDedupedAnalysis.findings : [],
          guidance_brief: Array.isArray(chatDedupedAnalysis.guidance_brief) ? chatDedupedAnalysis.guidance_brief : [],
          insufficient_visual_detail: Boolean(chatDedupedAnalysis.insufficient_visual_detail) || detectInsufficientVisualDetail(Array.isArray(chatDedupedAnalysis.findings) ? chatDedupedAnalysis.findings : []),
        } : chatDedupedAnalysis;
        if (softenedAnalysisSummaryLowConfidence && isPlainObject(chatEnrichedAnalysis)) {
          const existingConfidence = isPlainObject(chatEnrichedAnalysis.confidence) ? chatEnrichedAnalysis.confidence : {};
          const rationale = Array.isArray(existingConfidence.rationale) ? existingConfidence.rationale.slice() : [];
          if (analysisSummaryConfidenceSoftenedReason && !rationale.includes(analysisSummaryConfidenceSoftenedReason)) {
            rationale.push(analysisSummaryConfidenceSoftenedReason);
          }
          chatEnrichedAnalysis = {
            ...chatEnrichedAnalysis,
            confidence: {
              ...existingConfidence,
              level: 'medium',
              rationale,
            },
          };
        }
        if (renderedAnalysisSource === 'retake') {
          chatEnrichedAnalysis = ensureRetakeFeatureObservation(chatEnrichedAnalysis, { language: ctx.lang });
        }
        const analysisSummaryPayload = {
          analysis: chatEnrichedAnalysis,
          low_confidence: lowConfidenceSummary,
          photos_provided: photosProvided,
          photo_qc: photoQcParts,
          used_photos: usedPhotos,
          analysis_source: renderedAnalysisSource,
          ...(photoNotice ? { photo_notice: photoNotice } : {}),
          quality_report: {
            photo_quality: { grade: photoQuality.grade, reasons: photoQuality.reasons },
            detector_confidence: detectorConfidence,
            ...(diagnosisPolicy ? { detector_policy: diagnosisPolicy } : {}),
            degraded_mode: SKIN_DEGRADED_MODE,
            llm: { vision: visionDecisionForReport || visionDecision, report: reportDecision },
            ...(llmInputHashPrefix ? { input_hash_prefix: llmInputHashPrefix } : {}),
            reasons: qualityReportReasons.slice(0, 8),
          },
          ...(diagnosisArtifact ? { diagnosis_artifact: diagnosisArtifact } : {}),
          ...(ingredientPlan ? { ingredient_plan: ingredientPlan } : {}),
          recommendation_ready: Boolean(recommendationReady),
          photo_pipeline_enabled: AURORA_AURORAAPP_PHOTO_PIPELINE_ENABLED,
          analysis_meta: {
            analysis_mode: 'analysis_summary',
            routine_preview_items_count: routineProductCandidates.length,
            ...(!routineAnalysisV2Attempted ? { routine_payload_shape: routinePayloadShape } : {}),
            ...(!routineAnalysisV2Attempted
              ? { routine_product_enrichment_deferred: routineProductCandidates.length > 0 }
              : {}),
            artifact_usable: Boolean(artifactGate && artifactGate.ok),
            artifact_gate: buildArtifactGateMeta(artifactGate),
            reco_artifact_eligible: Boolean(artifactGate && artifactGate.ok && artifactGate.confidence_level !== 'low'),
            gate_relax_mode: AURORA_RULE_RELAX_MODE,
            low_quality_tolerated: Boolean(
              AURORA_RULE_RELAX_AGGRESSIVE &&
                userRequestedPhoto &&
                photosProvided &&
                String(photoQuality && photoQuality.grade || '').trim().toLowerCase() === 'fail',
            ),
            ...(analysisSummaryConfidenceSoftenedReason
              ? { confidence_softened_reason: analysisSummaryConfidenceSoftenedReason }
              : {}),
            ...(photoQualitySoftenedReason ? { photo_quality_softened_reason: photoQualitySoftenedReason } : {}),
          },
        };
        if (!shadowRun && persistLastAnalysis) {
          scheduleSkinAnalysisKbBackfill({
            ctx,
            identity,
            analysisSummaryPayload,
            analysisMeta,
            logger,
          });
        }

        const sessionPatch = { next_state: 'S5_ANALYSIS_SUMMARY' };
        appendLatestArtifactToSessionPatch(sessionPatch, latestArtifactId);

        const lowConfidenceRuleBased =
          artifactConfidence &&
          String(artifactConfidence.level || '').toLowerCase() === 'low' &&
          (renderedAnalysisSource === 'rule_based' || renderedAnalysisSource === 'baseline_low_confidence');

        const extraCards = [];
        const routineProductEvents = [];
        const routineAuditV1Enabled = false;
        const routineExpert = routineAuditV1Enabled
          ? buildRoutineExpertV1({
            routineCandidate,
            profileSummary,
            recentLogs: recentLogsSummary,
            language: ctx.lang,
          })
          : null;
        const routineLifecycleStage = routineAuditV1Enabled
          ? detectRoutineLifecycleStage({
            routineCandidate,
            previousRoutine,
            routineExpertIssues: Array.isArray(routineExpert && routineExpert.key_issues) ? routineExpert.key_issues : [],
            intent: 'analysis_review_products',
          })
          : null;
        const routineLifecycleContext = routineLifecycleStage
          ? buildRoutineLifecycleContext({
            stage: routineLifecycleStage,
            routineCandidate,
            previousRoutine,
            profileSummary,
            routineExpert,
            language: ctx.lang,
          })
          : null;
        const routineProductsPreviewCard = routineAuditV1Enabled
          ? null
          : buildRoutineProductsPreviewCard({
            ctx,
            language: ctx.lang,
            candidates: routineProductCandidates,
            payloadShape: routinePayloadShape,
            profileSummary,
            ingredientPlan,
          });
        if (routineProductsPreviewCard) {
          routineProductEvents.push(
            makeEvent(ctx, 'routine_products_preview_ready', {
              payload_shape: routinePayloadShape,
              total_candidates: routineProductCandidates.length,
            }),
          );
          routineProductEvents.push(
            makeEvent(ctx, 'routine_product_enrichment_deferred', {
              deferred: true,
              total_candidates: routineProductCandidates.length,
              source: 'routine_intake',
            }),
          );
        }
        if (AURORA_ROUTINE_ANALYSIS_V2_ENABLED && hasRoutine && routineProductCandidates.length > 0) {
          routineAnalysisV2Attempted = true;
          try {
            routineAnalysisV2Result = await runRoutineAnalysisV2({
              requestId: ctx.request_id,
              language: ctx.lang,
              profile,
              profileSummary,
              routineProductCandidates,
              ingredientPlan,
              analysisContextSnapshot,
              requestProfileOverride: requestProfileOverlay,
              surfaceMode: routineAuditV1Enabled ? 'routine_audit_v1' : 'routine_v2',
              routineExpert,
              routineLifecycleContext,
              logger,
            });
            analysisMeta.routine_analysis_version = 'v2';
            analysisMeta.analysis_mode = routineAuditV1Enabled ? 'routine_audit_v1' : 'routine_v2';
            analysisMeta.reco_artifact_eligible = Array.isArray(routineAnalysisV2Result && routineAnalysisV2Result.recommendation_groups)
              ? routineAnalysisV2Result.recommendation_groups.some((group) => Array.isArray(group && group.candidate_pool) && group.candidate_pool.length > 0)
              : false;
            routineProductEvents.push(
              makeEvent(ctx, 'routine_analysis_v2_completed', {
                audited_product_count:
                  routineAnalysisV2Result &&
                  routineAnalysisV2Result.audit &&
                  Array.isArray(routineAnalysisV2Result.audit.products)
                    ? routineAnalysisV2Result.audit.products.length
                    : 0,
                recommendation_group_count: Array.isArray(routineAnalysisV2Result && routineAnalysisV2Result.recommendation_groups)
                  ? routineAnalysisV2Result.recommendation_groups.length
                  : 0,
                deferred_product_count:
                  routineAnalysisV2Result &&
                  routineAnalysisV2Result.debug_meta &&
                  routineAnalysisV2Result.debug_meta.stage_a &&
                  Number.isFinite(Number(routineAnalysisV2Result.debug_meta.stage_a.deferred_product_count))
                    ? Number(routineAnalysisV2Result.debug_meta.stage_a.deferred_product_count)
                    : 0,
              }),
            );
          } catch (err) {
            const failureMeta = classifyRoutineFitUpstreamFailure(err);
            routineAnalysisV2FailureClass = failureMeta.failure_class || 'substage_error';
            recordAnalysisSubstageFailure('routine_analysis_v2', err, {
              candidate_count: routineProductCandidates.length,
            });
            analysisMeta.routine_analysis_version = 'v2_failed';
            analysisMeta.routine_analysis_v2_failure_class = routineAnalysisV2FailureClass;
            routineAnalysisV2Result = null;
          }
        }
        if (routineAnalysisV2Attempted) {
          delete analysisMeta.routine_payload_shape;
          delete analysisMeta.routine_product_enrichment_deferred;
        }

        if (!routineAnalysisV2Result && ingredientPlan && photoModulesCard) {
          ingredientPlan = annotateIngredientPlanForPhotoLed(ingredientPlan, photoModulesCard, ctx.lang);
        }

        const suppressPhotoFailureIngredientPlan = shouldSuppressPhotoFailureIngredientPlanAndRecoHandoff({
          analysisSource: renderedAnalysisSource,
          userRequestedPhoto,
          photosProvided,
          usedPhotos,
          photoQuality,
          photoModulesCard,
          ingredientPlan,
        });
        if (suppressPhotoFailureIngredientPlan && ingredientPlan) {
          ingredientPlan = buildPhotoQualityFailedIngredientPlanV2(ingredientPlan, profileSummary || profile || null);
          analysisMeta.reco_artifact_eligible = false;
        }

        if (!routineAnalysisV2Result && ingredientPlan) {
          extraCards.push(buildIngredientPlanCard(ingredientPlan, ctx.request_id));
        }
        if (routineAnalysisV2Result) {
          sessionPatch.meta = {
            ...(isPlainObject(sessionPatch.meta) ? sessionPatch.meta : {}),
            ...(analysisContextSnapshot ? { analysis_context_snapshot: analysisContextSnapshot } : {}),
            routine_analysis_v2: {
              ...(isPlainObject(routineAnalysisV2Result.debug_meta) ? routineAnalysisV2Result.debug_meta : {}),
              profile_context_source: requestProfileContextSource,
              request_profile_overlay_applied: requestProfileOverlayKeys.length > 0,
              ...(requestProfileOverlayKeys.length ? { request_profile_overlay_keys: requestProfileOverlayKeys } : {}),
            },
            routine_analysis_legacy_compat: routineAnalysisV2Result.legacy_compat,
            analysis_contract: {
              analysis_mode: routineAuditV1Enabled ? 'routine_audit_v1' : 'routine_v2',
              card_contract: routineAuditV1Enabled ? 'aurora.routine_audit_v1' : 'aurora.routine_analysis_v2',
              card_types: Array.isArray(routineAnalysisV2Result.cards)
                ? routineAnalysisV2Result.cards.map((card) => String(card && card.type || '')).filter(Boolean).slice(0, 6)
                : [],
            },
            ...(routineExpert ? { routine_expert: routineExpert } : {}),
            ...(routineLifecycleContext ? { routine_lifecycle_context: routineLifecycleContext } : {}),
          };
        } else if (routineAnalysisV2Attempted) {
          sessionPatch.meta = {
            ...(isPlainObject(sessionPatch.meta) ? sessionPatch.meta : {}),
            ...(analysisContextSnapshot ? { analysis_context_snapshot: analysisContextSnapshot } : {}),
            routine_analysis_v2: {
              attempted: true,
              enabled: false,
              failed: true,
              guardrail_bypass: true,
              failure_class: routineAnalysisV2FailureClass || 'substage_error',
              profile_context_source: requestProfileContextSource,
              request_profile_overlay_applied: requestProfileOverlayKeys.length > 0,
              ...(requestProfileOverlayKeys.length ? { request_profile_overlay_keys: requestProfileOverlayKeys } : {}),
            },
            ...(routineExpert ? { routine_expert: routineExpert } : {}),
            ...(routineLifecycleContext ? { routine_lifecycle_context: routineLifecycleContext } : {}),
          };
        } else if (analysisContextSnapshot) {
          sessionPatch.meta = {
            ...(isPlainObject(sessionPatch.meta) ? sessionPatch.meta : {}),
            analysis_context_snapshot: analysisContextSnapshot,
          };
        }

        const routineFitPlan = resolveRoutineFitAnalysisPlan({
          routineProductCandidates,
          lowConfidenceRuleBased,
        });
        const routineFitEvaluationMode = AURORA_ROUTINE_SUMMARY_FIRST_ENABLED
          ? (routineFitPlan.shouldQueueKbBackfill ? 'deterministic_summary_first' : 'off')
          : (routineFitPlan.shouldEvaluateRoutineFit ? 'llm_with_fallback' : 'off');
        let routineFitCard = null;
        let routineFitFailureReason = null;
        let routineFitRetryCount = 0;
        let routineFitPartialStructured = false;
        let routineFitPartialDimensions = [];
        let routineFitFallbackUsed = false;
        let routineFitFallbackReason = null;
        if (!routineAnalysisV2Result && !routineAnalysisV2Attempted && routineFitEvaluationMode !== 'off') {
          try {
            routineProductEvents.push(
              makeEvent(ctx, 'routine_fit_evaluation_started', {
                total_candidates: routineProductCandidates.length,
                routine_source_shape: routineStateMeta.source_shape,
                missing_routine_fields: routineStateMeta.missing_routine_fields,
                evaluation_mode: routineFitEvaluationMode,
              }),
            );

            const routineSkinProfile = {
              skin_type_tendency: profileSummary && profileSummary.skinType ? profileSummary.skinType : null,
              sensitivity_tendency: profileSummary && profileSummary.sensitivity ? profileSummary.sensitivity : null,
            };

            if (routineFitEvaluationMode === 'deterministic_summary_first') {
              const localFit = buildDeterministicRoutineFitSummary({
                routineProducts: routineProductCandidates,
                ingredientPlan,
                skinProfile: routineSkinProfile,
                profileSummary,
                language: ctx.lang,
              });
              if (localFit) {
                routineFitCard = buildRoutineFitSummaryCard(localFit, ctx.request_id);
                recordAuroraSkinFlowMetric({ stage: 'routine_fit_deterministic_summary_first', hit: true });
              } else {
                routineFitFailureReason = 'deterministic_empty';
              }
            } else {
              const fitPrefix = buildContextPrefix({
                profile: isPlainObject(profileSummary) ? profileSummary : {},
                lang: ctx.lang,
                state: 'S4_ANALYSIS_LOADING',
                trigger_source: 'routine_fit_evaluation',
                intent: 'routine_fit_summary',
                action_id: 'routine.fit.evaluate',
              });
              const fitPrompt = buildRoutineFitSummaryPrompt({
                prefix: fitPrefix,
                skinProfile: routineSkinProfile,
                ingredientPlan,
                routineProducts: routineProductCandidates.slice(0, 8),
                language: ctx.lang,
              });
              const fitPromptHash = crypto.createHash('sha1').update(fitPrompt).digest('hex').slice(0, 16);

              for (let attempt = 0; attempt < 2 && !routineFitCard; attempt += 1) {
                const attemptPrompt = attempt === 0 ? fitPrompt : buildRoutineFitRetryPrompt(fitPrompt, ctx.lang);
                try {
                  const fitUpstream = await auroraChat({
                    baseUrl: AURORA_DECISION_BASE_URL,
                    query: attemptPrompt,
                    timeoutMs: AURORA_ROUTINE_FIT_TIMEOUT_MS,
                    llm_provider: 'gemini',
                    llm_model: ROUTINE_FIT_MODEL_GEMINI || 'gemini-3-flash-preview',
                    intent_hint: 'routine_fit_summary',
                    disallow_clarify: true,
                    required_structured_keys: ROUTINE_FIT_REQUIRED_STRUCTURED_KEYS,
                    prompt_hash: fitPromptHash,
                    prompt_template_id: 'routine_fit_summary_v1',
                    trace_id: ctx.trace_id,
                    request_id: ctx.request_id,
                  });

                  const parsedFit = parseRoutineFitUpstreamResult(fitUpstream);
                  if (parsedFit.ok && parsedFit.value) {
                    routineFitCard = buildRoutineFitSummaryCard(parsedFit.value, ctx.request_id);
                    routineFitFailureReason = null;
                    routineFitRetryCount = attempt;
                    routineFitPartialStructured = Boolean(parsedFit.partial_structured);
                    routineFitPartialDimensions = Array.isArray(parsedFit.partial_dimensions)
                      ? parsedFit.partial_dimensions.slice(0, ROUTINE_FIT_DIMENSION_KEYS.length)
                      : [];
                    break;
                  }

                  routineFitFailureReason = parsedFit.failure_reason || 'json_parse_failed';
                  routineFitRetryCount = attempt;
                  if (attempt === 0) {
                    logger?.warn(
                      {
                        request_id: ctx.request_id,
                        failure_reason: routineFitFailureReason,
                        missing_keys: parsedFit.missing_keys,
                      },
                      'aurora bff: routine fit evaluation retrying after invalid structured output',
                    );
                  }
                } catch (err) {
                  const failureMeta = classifyRoutineFitUpstreamFailure(err);
                  routineFitFailureReason = failureMeta.failure_class || 'upstream_error';
                  routineFitRetryCount = attempt;
                  logger?.warn(
                    {
                      err: err && err.message ? err.message : String(err),
                      request_id: ctx.request_id,
                      attempt: attempt + 1,
                      failure_class: failureMeta.failure_class,
                      upstream_status: failureMeta.upstream_status,
                      upstream_error_code: failureMeta.upstream_error_code,
                      timeout_ms: AURORA_ROUTINE_FIT_TIMEOUT_MS,
                    },
                    'aurora bff: routine fit evaluation failed',
                  );
                  routineProductEvents.push(
                    makeEvent(ctx, 'routine_fit_upstream_failure', {
                      attempt: attempt + 1,
                      failure_class: failureMeta.failure_class,
                      upstream_status: failureMeta.upstream_status,
                      upstream_error_code: failureMeta.upstream_error_code,
                      timeout_ms: AURORA_ROUTINE_FIT_TIMEOUT_MS,
                      llm_model: ROUTINE_FIT_MODEL_GEMINI || 'gemini-3-flash-preview',
                    }),
                  );
                }
              }

              if (!routineFitCard) {
                const fallbackFit = buildDeterministicRoutineFitSummary({
                  routineProducts: routineProductCandidates,
                  ingredientPlan,
                  skinProfile: routineSkinProfile,
                  profileSummary,
                  language: ctx.lang,
                });
                if (fallbackFit) {
                  routineFitCard = buildRoutineFitSummaryCard(fallbackFit, ctx.request_id);
                  routineFitFallbackUsed = true;
                  routineFitFallbackReason = routineFitFailureReason || 'unknown';
                  recordAuroraSkinFlowMetric({ stage: 'routine_fit_fallback', hit: true });
                  logger?.info(
                    {
                      request_id: ctx.request_id,
                      failure_reason: routineFitFallbackReason,
                      fallback_source: 'deterministic_local',
                      timeout_ms: AURORA_ROUTINE_FIT_TIMEOUT_MS,
                      llm_model: ROUTINE_FIT_MODEL_GEMINI || 'gemini-3-flash-preview',
                    },
                    'aurora bff: routine fit fallback applied after upstream failure',
                  );
                }
              }
            }

            if (!routineFitCard) {
              recordAuroraSkinFlowMetric({
                stage: `routine_fit_${String(routineFitFailureReason || 'failed').slice(0, 48)}`,
                hit: true,
              });
            }
            recordAuroraSkinFlowMetric({ stage: 'routine_fit_evaluated', hit: true });
            recordAuroraSkinFlowMetric({ stage: 'routine_fit_emitted', hit: Boolean(routineFitCard) });
            logger?.info(
              { kind: 'metric', name: 'aurora.skin.routine_fit.emitted_rate', value: routineFitCard ? 1 : 0 },
              'metric',
            );
            if (routineFitCard && routineFitPartialStructured) {
              logger?.info(
                { kind: 'metric', name: 'aurora.skin.routine_fit.partial_structured_rate', value: 1 },
                'metric',
              );
            }

            routineProductEvents.push(
              makeEvent(ctx, 'routine_fit_evaluation_completed', {
                candidate_count: routineProductCandidates.length,
                fit_card_emitted: Boolean(routineFitCard),
                overall_fit: routineFitCard && routineFitCard.payload ? routineFitCard.payload.overall_fit : null,
                failure_reason: routineFitCard ? null : routineFitFailureReason || 'unknown',
                retry_count: routineFitRetryCount,
                partial_structured: routineFitPartialStructured,
                partial_dimensions: routineFitPartialDimensions,
                fallback_used: routineFitFallbackUsed,
                fallback_reason: routineFitFallbackUsed ? routineFitFallbackReason : null,
                fallback_source: routineFitFallbackUsed ? 'deterministic_local' : null,
                evaluation_mode: routineFitEvaluationMode,
                local_only: routineFitEvaluationMode === 'deterministic_summary_first',
                timeout_ms: AURORA_ROUTINE_FIT_TIMEOUT_MS,
                llm_model: routineFitEvaluationMode === 'llm_with_fallback'
                  ? (ROUTINE_FIT_MODEL_GEMINI || 'gemini-3-flash-preview')
                  : null,
              }),
            );
          } catch (err) {
            routineFitFailureReason = routineFitFailureReason || 'substage_exception';
            recordAnalysisSubstageFailure('routine_fit_summary', err, {
              candidate_count: routineProductCandidates.length,
              timeout_ms: AURORA_ROUTINE_FIT_TIMEOUT_MS,
              llm_model: routineFitEvaluationMode === 'llm_with_fallback'
                ? (ROUTINE_FIT_MODEL_GEMINI || 'gemini-3-flash-preview')
                : null,
              evaluation_mode: routineFitEvaluationMode,
            });
          }
        }

        if (routineFitCard && analysisSummaryPayload && typeof analysisSummaryPayload === 'object') {
          analysisSummaryPayload.routine_fit = routineFitCard.payload;
        }
        if (routineAnalysisV2Result && analysisSummaryPayload && typeof analysisSummaryPayload === 'object') {
          analysisSummaryPayload.routine_analysis_v2 = routineAnalysisV2Result.persist_payload;
          analysisSummaryPayload.routine_analysis_legacy_compat = routineAnalysisV2Result.legacy_compat;
        }

        if (routineFitPlan.shouldQueueKbBackfill) {
          setImmediate(async () => {
            let asyncCompleted = 0;
            let asyncBackfilled = 0;
            for (const candidate of routineProductCandidates) {
              try {
                const result = await deepScanRoutineProductCandidate({
                  candidate,
                  ctx,
                  profileSummary,
                  recentLogsSummary,
                  logger,
                  includeCard: false,
                });
                asyncCompleted += 1;
                if (result && result.backfilled) asyncBackfilled += 1;
              } catch {
                // non-critical: KB backfill for on-demand deep dive
              }
            }
            logger?.info(
              {
                request_id: ctx.request_id,
                trace_id: ctx.trace_id,
                queued: routineProductCandidates.length,
                completed: asyncCompleted,
                backfilled: asyncBackfilled,
              },
              'aurora bff: routine product async KB backfill finished',
            );
          });
        }

        if (
          artifactConfidence &&
          String(artifactConfidence.level || '').toLowerCase() === 'low' &&
          !softenedAnalysisSummaryLowConfidence &&
          !(routineAuditV1Enabled && routineAnalysisV2Result)
        ) {
          logger?.info({ kind: 'metric', name: 'aurora.skin.low_confidence_rate', value: 1 }, 'metric');
          extraCards.push({
            card_id: `conf_${ctx.request_id}`,
            type: 'confidence_notice',
            payload: buildConfidenceNoticeCardPayload({
              language: ctx.lang,
              reason: 'low_confidence',
              confidence: artifactConfidence,
              actions: ['upload_daylight_and_indoor_white', 'update_current_routine'],
            }),
          });
        }

        const analysisSkinProfile = {
          skin_type_tendency: profileSummary && profileSummary.skinType ? profileSummary.skinType : null,
          sensitivity_tendency: profileSummary && profileSummary.sensitivity ? profileSummary.sensitivity : null,
        };
        const analysisChips = buildAnalysisSuggestedChips({
          language: ctx.lang,
          lowConfidence: lowConfidenceSummary,
          hasIngredientPlan: Boolean(ingredientPlan) && !(routineAuditV1Enabled && routineAnalysisV2Result),
          hasRoutineFit: Boolean(routineFitCard || (routineAnalysisV2Result && !routineAuditV1Enabled)),
        });
        const analysisAssistantText = routineAnalysisV2Result && typeof routineAnalysisV2Result.assistant_text === 'string'
          ? routineAnalysisV2Result.assistant_text
          : buildAnalysisAssistantMessage({
              language: ctx.lang,
              skinProfile: analysisSkinProfile,
              lowConfidence: lowConfidenceSummary,
              ingredientPlan,
              routineFit: routineFitCard && routineFitCard.payload ? routineFitCard.payload : null,
            });
        if (profileSummary) {
          sessionPatch.profile = profileSummary;
        }
        const analysisLatestRecoContext = buildLatestRecoContextFromAnalysisArtifacts({
          routineAnalysisResult: routineAnalysisV2Result,
          ingredientPlan,
          photoModulesCard,
          profileSummary,
          artifactId: latestArtifactId,
          contextOrigin: String(analysisMeta.analysis_mode || 'analysis_summary').trim().toLowerCase() || 'analysis_summary',
          analysisSource: renderedAnalysisSource,
          usePhoto: userRequestedPhoto,
          usedPhotos,
          photoQualityGrade: photoQuality && photoQuality.grade,
        });
        if (suppressPhotoFailureIngredientPlan && !analysisLatestRecoContext) {
          clearLatestRecoContextInSessionPatch(sessionPatch);
        } else {
          appendLatestRecoContextToSessionPatch(sessionPatch, analysisLatestRecoContext);
        }
        const persistableLastAnalysis = buildPersistableLastAnalysisSnapshot({
          analysis,
          ingredientPlan,
          routineFitCard,
          routineAnalysisV2Result,
          latestRecoContext: analysisLatestRecoContext,
          profileSummary,
        });
        const routineAnalysisCards = Array.isArray(routineAnalysisV2Result && routineAnalysisV2Result.cards)
          ? routineAnalysisV2Result.cards
          : [];
        const routineAnalysisHasStructuredStory = routineAnalysisCards.some((card) => {
          if (!isPlainObject(card)) return false;
          const type = String(card.type || '').trim().toLowerCase();
          return type === 'analysis_summary' || type === 'analysis_story_v2';
        });
        const shouldSurfacePhotoAnalysisSummaryAlongsideRoutineCards = Boolean(
          routineAnalysisV2Result &&
          photoModulesCard &&
          !routineAuditV1Enabled &&
          AURORA_ANALYSIS_STORY_V2_ENABLED &&
          !routineAnalysisHasStructuredStory,
        );
        const envelope = buildEnvelope(ctx, {
          assistant_message: makeAssistantMessage(analysisAssistantText),
          suggested_chips: analysisChips,
          cards: routineAnalysisV2Result
            ? [
                ...(shouldSurfacePhotoAnalysisSummaryAlongsideRoutineCards
                  ? [
                      {
                        card_id: `analysis_${ctx.request_id}`,
                        type: 'analysis_summary',
                        payload: analysisSummaryPayload,
                        ...(analysisFieldMissing.length ? { field_missing: analysisFieldMissing } : {}),
                      },
                    ]
                  : []),
                ...routineAnalysisCards,
                ...(routineProductsPreviewCard ? [routineProductsPreviewCard] : []),
                ...((photoModulesCard && !routineAuditV1Enabled) ? [photoModulesCard] : []),
                ...extraCards,
              ]
            : [
                {
                  card_id: `analysis_${ctx.request_id}`,
                  type: 'analysis_summary',
                  payload: analysisSummaryPayload,
                  ...(analysisFieldMissing.length ? { field_missing: analysisFieldMissing } : {}),
                },
                ...(routineProductsPreviewCard ? [routineProductsPreviewCard] : []),
                ...(routineFitCard ? [routineFitCard] : []),
                ...(photoModulesCard ? [photoModulesCard] : []),
                ...extraCards,
              ],
          session_patch: sessionPatch,
          events: [
            ...routineProductEvents,
            ...analysisSubstageEvents,
            ...pregnancyPolicyEvents,
            makeEvent(ctx, 'value_moment', { kind: 'skin_analysis', used_photos: usedPhotos, analysis_source: renderedAnalysisSource }),
          ],
          analysis_meta: analysisMeta,
        });
        profiler.end('render', { kind: 'envelope' });
        if (persistLastAnalysis && persistableLastAnalysis) {
          profiler.skip('persist', 'deferred_async', {
            has_ingredient_plan: Boolean(ingredientPlan),
            has_routine_fit: Boolean(routineFitCard),
            has_routine_analysis_v2: Boolean(routineAnalysisV2Result),
          });
          deferLastAnalysisPersistence({
            identity,
            analysisSnapshot: persistableLastAnalysis,
            lang: ctx.lang,
            logger,
            requestId: ctx.request_id,
            traceId: ctx.trace_id,
          });
        } else {
          profiler.skip('persist', persistLastAnalysis ? 'persist_payload_missing' : 'persist_not_requested', {
            has_analysis: Boolean(analysis),
          });
        }

        const report = profiler.report();
        const stageTimingMeta = buildAnalysisStageTimingMeta(report);
        const llmTimingMeta = buildAnalysisLlmMeta(report);
        const stageTimings = stageTimingMeta && stageTimingMeta.stage_timings_ms && typeof stageTimingMeta.stage_timings_ms === 'object'
          ? stageTimingMeta.stage_timings_ms
          : {};
        const qualityStageMs = Number(stageTimings.quality);
        const artifactStageMs = Number(stageTimings.artifact);
        if (envelope && envelope.analysis_meta && typeof envelope.analysis_meta === 'object') {
          envelope.analysis_meta = {
            ...envelope.analysis_meta,
            ...stageTimingMeta,
            ...llmTimingMeta,
          };
        }
        if (!shadowRun) {
          if (reportStageRecovered) {
            recordAuroraSkinFlowMetric({ stage: 'analysis_report_recovered', hit: true });
            recordAuroraSkinFlowMetric({
              stage: buildAnalysisReportRecoveredMetricStage(reportStagePrimaryFailureReason),
              hit: true,
            });
            logger?.info({ kind: 'metric', name: 'aurora.skin.analysis_report_recovered_rate', value: 1 }, 'metric');
          }
          if (Number.isFinite(qualityStageMs) && qualityStageMs >= AURORA_ANALYSIS_QUALITY_SLOW_MS) {
            recordAuroraSkinFlowMetric({ stage: 'analysis_quality_slow', hit: true });
            logger?.info({ kind: 'metric', name: 'aurora.skin.analysis_quality_slow_rate', value: 1 }, 'metric');
          }
          if (Number.isFinite(artifactStageMs) && artifactStageMs >= AURORA_ANALYSIS_ARTIFACT_SLOW_MS) {
            recordAuroraSkinFlowMetric({ stage: 'analysis_artifact_slow', hit: true });
            logger?.info({ kind: 'metric', name: 'aurora.skin.analysis_artifact_slow_rate', value: 1 }, 'metric');
          }
        }
        logger?.info(
          {
            kind: shadowRun ? 'skin_analysis_profile_shadow' : 'skin_analysis_profile',
            request_id: ctx.request_id,
            trace_id: ctx.trace_id,
            pipeline_version: pipelineVersion || null,
            shadow_run: Boolean(shadowRun),
            experiments: experimentsSlim,
            analysis_source: renderedAnalysisSource,
            user_requested_photo: Boolean(userRequestedPhoto),
            photos_provided: Boolean(photosProvided),
            used_photos: Boolean(usedPhotos),
            photo_quality_grade: photoQuality && typeof photoQuality.grade === 'string' ? photoQuality.grade : 'unknown',
            profile_context_source: requestProfileContextSource,
            request_profile_overlay_keys: requestProfileOverlayKeys,
            routine_payload_shape: routinePayloadShape,
            routine_preview_items_count: routineProductCandidates.length,
            routine_product_enrichment_deferred: Boolean(routineProductsPreviewCard),
            report_failure_reason: reportModelErrorReason || null,
            report_stage_budget_ms: reportStageBudgetMs,
            report_stage_budget_profile: reportStageBudgetProfile,
            report_stage_elapsed_ms: reportStageElapsedMs,
            report_stage_outcome: reportStageOutcome,
            report_stage_attempts: reportStageAttempts,
            report_stage_recovered: reportStageRecovered,
            report_stage_recovery_mode: reportStageRecoveryMode,
            report_stage_primary_failure_reason: reportStagePrimaryFailureReason,
            report_stage_primary_failure_detail: reportStagePrimaryFailureDetail,
            quality_stage_ms: Number.isFinite(qualityStageMs) ? qualityStageMs : null,
            artifact_stage_ms: Number.isFinite(artifactStageMs) ? artifactStageMs : null,
            budget_abort_stage: budgetAbortStage || null,
            total_ms: report.total_ms,
            llm_summary: report.llm_summary,
            stages: report.stages,
            ...stageTimingMeta,
            ...llmTimingMeta,
          },
          'aurora bff: skin analysis profile',
        );
        logger?.info(
          { kind: 'metric', name: `aurora.skin_analysis.${pipelineVersion || 'unknown'}.total_ms`, value: report.total_ms },
          'metric',
        );
	        if (!shadowRun) {
	          logger?.info({ kind: 'metric', name: 'aurora.skin_analysis.total_ms', value: report.total_ms }, 'metric');
	          logger?.info({ kind: 'metric', name: 'aurora.skin.analysis_skin_mainpath_ms', value: report.total_ms }, 'metric');
	        }

        if (experimentsSlim.length) {
          const llmCalls = report && report.llm_summary && typeof report.llm_summary.calls === 'number' ? report.llm_summary.calls : 0;
          const qualityGrade = photoQuality && typeof photoQuality.grade === 'string' ? photoQuality.grade : 'unknown';
          const pv = pipelineVersion || 'unknown';

          for (const exp of experimentsSlim) {
            const expId = exp && typeof exp.experiment_id === 'string' ? exp.experiment_id : null;
            const variant = exp && typeof exp.variant === 'string' ? exp.variant : null;
            if (!expId || !variant) continue;

            logger?.info({ kind: 'metric', name: `aurora.skin_experiment.${expId}.${variant}.${pv}.requests`, value: 1 }, 'metric');
            logger?.info(
              { kind: 'metric', name: `aurora.skin_experiment.${expId}.${variant}.${pv}.total_ms`, value: report.total_ms },
              'metric',
            );
            logger?.info(
              { kind: 'metric', name: `aurora.skin_experiment.${expId}.${variant}.${pv}.llm_calls`, value: llmCalls },
              'metric',
            );
            logger?.info(
              { kind: 'metric', name: `aurora.skin_experiment.${expId}.${variant}.${pv}.quality_grade.${qualityGrade}`, value: 1 },
              'metric',
            );
          }
        }

	        setImmediate(() => {
	          sampleHardCase({
	            req,
	            ctx,
	            identity: { auroraUid: identity.auroraUid, userId: identity.userId },
	            pipelineVersion,
	            shadowRun,
	            profileSummary,
	            photoQuality,
	            diagnosisPolicy,
	            diagnosisV1,
	            analysis,
	            analysisSource,
	            geometrySanitizer,
	            diagnosisPhotoBytes,
	            diagnosisV1Internal,
	            logger,
	          }).catch((err) => {
	            logger?.warn({ err: err && err.message ? err.message : String(err) }, 'hard case sampler: failed');
	          });
	        });

	        if (!shadowRun) {
	          const verifyRuntimeLimits = (() => {
	            if (!DIAG_VERIFY_ALLOW_GUARD_TEST) return null;

	            const headerPerMin = Number(req.get('x-diag-verify-max-calls-per-min'));
	            const headerPerDay = Number(req.get('x-diag-verify-max-calls-per-day'));
	            const queryPerMin = Number(req.query && req.query.diag_verify_max_calls_per_min);
	            const queryPerDay = Number(req.query && req.query.diag_verify_max_calls_per_day);
	            const bodyLimits =
	              (isPlainObject(req.body) && isPlainObject(req.body.diag_verify_runtime_limits) && req.body.diag_verify_runtime_limits) ||
	              (isPlainObject(req.body) &&
	                isPlainObject(req.body.debug) &&
	                isPlainObject(req.body.debug.diag_verify_runtime_limits) &&
	                req.body.debug.diag_verify_runtime_limits) ||
	              null;
	            const bodyPerMin = Number(
	              bodyLimits &&
	                (bodyLimits.maxCallsPerMin != null ? bodyLimits.maxCallsPerMin : bodyLimits.max_calls_per_min),
	            );
	            const bodyPerDay = Number(
	              bodyLimits &&
	                (bodyLimits.maxCallsPerDay != null ? bodyLimits.maxCallsPerDay : bodyLimits.max_calls_per_day),
	            );

	            const pickFirstFinite = (...values) => {
	              for (const value of values) {
	                if (Number.isFinite(value) && value >= 0) return Math.trunc(value);
	              }
	              return null;
	            };

	            const maxCallsPerMin = pickFirstFinite(headerPerMin, bodyPerMin, queryPerMin);
	            const maxCallsPerDay = pickFirstFinite(headerPerDay, bodyPerDay, queryPerDay);
	            if (maxCallsPerMin == null && maxCallsPerDay == null) return null;
	            return {
	              ...(maxCallsPerMin != null ? { maxCallsPerMin } : {}),
	              ...(maxCallsPerDay != null ? { maxCallsPerDay } : {}),
	            };
	          })();
	          setImmediate(() => {
	            runGeminiShadowVerify({
	              imageBuffer: shadowVerifyPhotoBytes || diagnosisPhotoBytes || null,
	              language: ctx.lang,
	              photoQuality,
	              usedPhotos,
	              diagnosisV1,
	              diagnosisInternal: diagnosisV1Internal,
	              profileSummary,
	              recentLogsSummary,
	              inferenceId: ctx.request_id || ctx.trace_id || null,
	              traceId: ctx.trace_id || null,
	              assetId: diagnosisPhoto && typeof diagnosisPhoto.photo_id === 'string' ? diagnosisPhoto.photo_id : null,
	              runtimeLimits: verifyRuntimeLimits || undefined,
	              skinToneBucket:
	                diagnosisV1Internal && typeof diagnosisV1Internal.skin_tone_bucket === 'string'
	                  ? diagnosisV1Internal.skin_tone_bucket
	                  : 'unknown',
	              lightingBucket:
	                diagnosisV1Internal && typeof diagnosisV1Internal.lighting_bucket === 'string'
	                  ? diagnosisV1Internal.lighting_bucket
	                  : 'unknown',
	              logger,
	              metricsHooks: {
	                onProviderResult: (stat) =>
	                  recordEnsembleProviderResult({
	                    provider: stat.provider,
	                    ok: stat.ok,
	                    latencyMs: stat.latency_ms,
	                    failureReason: stat.failure_reason,
	                    schemaFailed: stat.schema_failed,
	                  }),
	                onAgreement: (score) => recordEnsembleAgreementScore(score),
	                onVerifyCall: ({ status }) => recordVerifyCall({ status }),
	                onVerifyFail: ({
	                  reason,
	                  provider,
	                  http_status_class: httpStatusClass,
	                  timeout_stage: timeoutStage,
	                  retry_count: retryCount,
	                  error_class: errorClass,
	                }) =>
	                  recordVerifyFail({
	                    reason,
	                    provider,
	                    httpStatusClass,
	                    timeoutStage,
	                    retryCount,
	                    errorClass,
	                  }),
	                onVerifyRetry: ({ attempts }) => recordVerifyRetry({ attempts }),
	                onVerifyBudgetGuard: () => recordVerifyBudgetGuard(),
	                onVerifyCircuitOpen: () => recordVerifyCircuitOpen(),
	                onVerifyAgreement: (score) => recordVerifyAgreementScore(score),
	                onVerifyHardCase: () => recordVerifyHardCase(),
	              },
		            })
		              .then(async (verify) => {
		                if (!verify || !verify.called) return;
		                logger?.info(
		                  {
		                    request_id: ctx.request_id,
		                    trace_id: ctx.trace_id,
		                    used_photos: usedPhotos,
		                    verify_ok: Boolean(verify.ok),
		                    verify_provider_status_code:
		                      Number.isFinite(Number(verify.provider_status_code)) ? Number(verify.provider_status_code) : null,
		                    verify_final_reason: verify.final_reason || null,
		                    verify_raw_final_reason: verify.raw_final_reason || null,
		                    verify_fail_reason: verify.verify_fail_reason || null,
		                    verify_timeout_stage: verify.timeout_stage || null,
		                    verify_upstream_request_id: verify.upstream_request_id || null,
		                    verify_attempts: Number.isFinite(Number(verify.attempts)) ? Number(verify.attempts) : null,
		                    verify_latency_ms: Number.isFinite(Number(verify.latency_ms)) ? Number(verify.latency_ms) : null,
		                    agreement_score: verify.agreement_score,
		                    disagreement_reasons: verify.disagreement_reasons,
		                    hard_case_written: Boolean(verify.hard_case_written),
		                  },
		                  'diag verify: shadow run recorded',
		                );
                    try {
                      const shadowRecord = {
                        source: 'shadow_verify',
                        provider: 'gemini',
                        prompt_version:
                          verify &&
                          verify.verifier &&
                          typeof verify.verifier.schema_version === 'string' &&
                          verify.verifier.schema_version.trim()
                            ? verify.verifier.schema_version.trim()
                            : 'aurora.diag.verify_shadow.v1',
                        created_at: new Date().toISOString(),
                        input_hash: llmInputHash || null,
                        verdict: {
                          ok: Boolean(verify.ok),
                          final_reason: verify.final_reason || null,
                          raw_final_reason: verify.raw_final_reason || null,
                          verify_fail_reason: verify.verify_fail_reason || null,
                          agreement_score:
                            Number.isFinite(Number(verify.agreement_score)) ? Number(verify.agreement_score) : null,
                          disagreement_reasons: Array.isArray(verify.disagreement_reasons)
                            ? verify.disagreement_reasons.slice(0, 10)
                            : [],
                        },
                        meta: {
                          request_id: ctx.request_id || null,
                          trace_id: ctx.trace_id || null,
                          provider_status_code:
                            Number.isFinite(Number(verify.provider_status_code)) ? Number(verify.provider_status_code) : null,
                          attempts: Number.isFinite(Number(verify.attempts)) ? Number(verify.attempts) : null,
                          latency_ms: Number.isFinite(Number(verify.latency_ms)) ? Number(verify.latency_ms) : null,
                          upstream_request_id: verify.upstream_request_id || null,
                          hard_case_written: Boolean(verify.hard_case_written),
                        },
                      };
                      const savedShadow = await saveShadowVerifyForIdentity(
                        { auroraUid: identity.auroraUid, userId: identity.userId },
                        { shadow: shadowRecord },
                      );
                      if (savedShadow && savedShadow.shadow_id != null) {
                        await appendShadowIdToLastAnalysisForIdentity(
                          { auroraUid: identity.auroraUid, userId: identity.userId },
                          { shadowId: savedShadow.shadow_id, maxIds: 20 },
                        );
                        recordAuroraSkinShadowVerifyIsolatedWrite({ status: 'success' });
                      } else {
                        recordAuroraSkinShadowVerifyIsolatedWrite({ status: 'skip' });
                      }
                    } catch (shadowErr) {
                      recordAuroraSkinShadowVerifyIsolatedWrite({ status: 'fail' });
                      logger?.warn(
                        { err: shadowErr && shadowErr.message ? shadowErr.message : String(shadowErr) },
                        'diag verify: isolated shadow write failed',
                      );
                    }
		              })
		              .catch((err) => {
		                logger?.warn({ err: err && err.message ? err.message : String(err) }, 'diag verify: shadow run failed');
		              });
	          });
	        }

	        return {
            envelope,
            report,
            profile_for_guardrails: profile,
            analysis_for_persist: analysisSummaryPayload,
            photo_refs: normalizeAnalysisPhotoRefs([
              ...(Array.isArray(passedPhotos) ? passedPhotos : []),
              ...(Array.isArray(degradedPhotos) ? degradedPhotos : []),
              ...(Array.isArray(failedPhotos) ? failedPhotos : []),
            ]),
          };
	      };

      const analysisBudgetStartedAtMs = Date.now();
      const effectiveBudgetMs = AURORA_RULE_RELAX_AGGRESSIVE
        ? Math.max(AURORA_BFF_ANALYSIS_BUDGET_MS, 50000)
        : AURORA_BFF_ANALYSIS_BUDGET_MS;
      let output = null;
      try {
        output = await withTimeout(
          runOnce({
            pipelineVersion: outputPipelineVersion,
            persistLastAnalysis: true,
            shadowRun: false,
          }),
          effectiveBudgetMs,
          'AURORA_ANALYSIS_BUDGET_TIMEOUT',
        );
      } catch (err) {
        if (!(err && err.code === 'AURORA_ANALYSIS_BUDGET_TIMEOUT')) throw err;
        logger?.warn(
          {
            request_id: ctx.request_id,
            trace_id: ctx.trace_id,
            budget_ms: AURORA_BFF_ANALYSIS_BUDGET_MS,
          },
          'aurora bff: analysis budget timeout, degraded to low-confidence baseline',
        );
        logger?.info({ kind: 'metric', name: 'aurora.skin.analysis.timeout_degraded_rate', value: 1 }, 'metric');
        recordAuroraSkinFlowMetric({ stage: 'analysis_timeout_degraded', hit: true });
        recordAuroraSkinAnalysisRealModel({ source: 'baseline_low_confidence' });
        recordAuroraSkinLlmCall({ stage: 'vision', outcome: 'policy_skip' });
        recordAuroraSkinLlmCall({ stage: 'report', outcome: 'policy_skip' });

        const degradedAnalysis = buildLowConfidenceBaselineSkinAnalysis({
          profile: null,
          language: ctx.lang,
        });
        const timeoutReasonText = ctx.lang === 'CN'
          ? '分析超时，已降级为低置信度基础方案。'
          : 'Analysis timed out and was downgraded to a low-confidence baseline.';
        const timeoutElapsedMs = Math.max(0, Date.now() - analysisBudgetStartedAtMs);
        const timeoutStageTimingMeta = {
          stage_timings_ms: {
            analysis: timeoutElapsedMs,
          },
          slowest_stage: 'analysis',
          slowest_stage_ms: timeoutElapsedMs,
          slowest_stage_status: 'timeout',
        };
        const timeoutRoutineInput = resolveSkinAnalysisRoutineInput({
          parsedBody: parsed.data,
          rawBody: req.body || {},
        });
        const timeoutRoutineCandidate = timeoutRoutineInput.found ? timeoutRoutineInput.value : null;
        const timeoutRoutinePayloadShape = detectRoutinePayloadShape(timeoutRoutineCandidate);
        const timeoutRoutineCandidates = timeoutRoutineCandidate
          ? extractRoutineProductCandidatesForDeepScan(timeoutRoutineCandidate, {
              maxTotal: AURORA_ROUTINE_PRODUCT_AUTOSCAN_TOTAL_LIMIT,
            })
          : [];
        const timeoutRoutinePreviewCard = buildRoutineProductsPreviewCard({
          ctx,
          language: ctx.lang,
          candidates: timeoutRoutineCandidates,
          payloadShape: timeoutRoutinePayloadShape,
          profileSummary,
        });
        const timeoutPayload = {
          analysis: degradedAnalysis,
          low_confidence: true,
          photos_provided: Boolean(parsed.data && parsed.data.use_photo),
          photo_qc: [],
          used_photos: false,
          analysis_source: 'baseline_low_confidence',
          quality_report: {
            photo_quality: { grade: 'unknown', reasons: ['analysis_budget_timeout'] },
            detector_confidence: 0,
            degraded_mode: SKIN_DEGRADED_MODE,
            llm: {
              vision: { decision: 'skip', reasons: ['analysis_budget_timeout'] },
              report: { decision: 'skip', reasons: ['analysis_budget_timeout'] },
            },
            reasons: [timeoutReasonText],
          },
          recommendation_ready: false,
          photo_pipeline_enabled: AURORA_AURORAAPP_PHOTO_PIPELINE_ENABLED,
          analysis_meta: {
            analysis_mode: 'timeout_degraded',
            routine_payload_shape: timeoutRoutinePayloadShape,
            routine_preview_items_count: timeoutRoutineCandidates.length,
            routine_product_enrichment_deferred: Boolean(timeoutRoutinePreviewCard),
            reco_artifact_eligible: false,
            product_surface_mode: 'guidance_only',
            artifact_gate: {
              tier: 'ineligible',
              reason: 'artifact_missing',
              missing_core: ['skinType', 'sensitivity', 'barrierStatus', 'goals'],
            },
            gate_relax_mode: AURORA_RULE_RELAX_MODE,
            low_quality_tolerated: Boolean(AURORA_RULE_RELAX_AGGRESSIVE),
            report_failure_reason: 'ANALYSIS_BUDGET_TIMEOUT',
            report_stage_budget_ms: 0,
            report_stage_elapsed_ms: timeoutElapsedMs,
            report_stage_outcome: 'analysis_budget_timeout',
            report_stage_attempts: 0,
            budget_abort_stage: 'analysis',
            ...timeoutStageTimingMeta,
          },
        };
        scheduleSkinAnalysisKbBackfill({
          ctx,
          identity,
          analysisSummaryPayload: timeoutPayload,
          analysisMeta: {
            detector_source: 'baseline_low_confidence',
            llm_vision_called: false,
            llm_report_called: false,
            artifact_usable: false,
            routine_payload_shape: timeoutRoutinePayloadShape,
            routine_preview_items_count: timeoutRoutineCandidates.length,
            routine_product_enrichment_deferred: Boolean(timeoutRoutinePreviewCard),
            analysis_mode: 'timeout_degraded',
            reco_artifact_eligible: false,
            product_surface_mode: 'guidance_only',
            artifact_gate: {
              tier: 'ineligible',
              reason: 'artifact_missing',
              missing_core: ['skinType', 'sensitivity', 'barrierStatus', 'goals'],
            },
            gate_relax_mode: AURORA_RULE_RELAX_MODE,
            low_quality_tolerated: Boolean(AURORA_RULE_RELAX_AGGRESSIVE),
            degrade_reason: 'analysis_budget_timeout',
            report_failure_reason: 'ANALYSIS_BUDGET_TIMEOUT',
            report_stage_budget_ms: 0,
            report_stage_elapsed_ms: timeoutElapsedMs,
            report_stage_outcome: 'analysis_budget_timeout',
            report_stage_attempts: 0,
            budget_abort_stage: 'analysis',
            ...timeoutStageTimingMeta,
          },
          logger,
        });

        const timeoutChips = buildAnalysisSuggestedChips({
          language: ctx.lang,
          lowConfidence: true,
          hasIngredientPlan: false,
          hasRoutineProducts: false,
        });
        const timeoutAssistantText = ctx.lang === 'CN'
          ? '分析超时，已切换为保守方案。你可以重新拍照或直接提问。'
          : 'Analysis timed out and switched to a conservative plan. You can retake photos or ask questions.';

        const envelope = buildEnvelope(ctx, {
          assistant_message: makeAssistantMessage(timeoutAssistantText),
          suggested_chips: timeoutChips,
          cards: [
            {
              card_id: `analysis_${ctx.request_id}`,
              type: 'analysis_summary',
              payload: timeoutPayload,
              field_missing: [{ field: 'analysis', reason: 'analysis_budget_timeout' }],
            },
            ...(timeoutRoutinePreviewCard ? [timeoutRoutinePreviewCard] : []),
            {
              card_id: `conf_${ctx.request_id}`,
              type: 'confidence_notice',
              payload: buildConfidenceNoticeCardPayload({
                language: ctx.lang,
                reason: 'timeout_degraded',
                confidence: { score: 0.35, level: 'low', rationale: ['analysis_budget_timeout'] },
                actions: ['retry_analysis', 'upload_daylight_and_indoor_white', 'update_current_routine'],
                details: [timeoutReasonText],
              }),
            },
          ],
          session_patch: { next_state: 'S5_ANALYSIS_SUMMARY' },
          events: [
            makeEvent(ctx, 'value_moment', { kind: 'skin_analysis', used_photos: false, analysis_source: 'baseline_low_confidence' }),
            makeEvent(ctx, 'analysis_timeout_degraded', { budget_ms: AURORA_BFF_ANALYSIS_BUDGET_MS }),
          ],
          analysis_meta: {
            detector_source: 'baseline_low_confidence',
            llm_vision_called: false,
            llm_report_called: false,
            artifact_usable: false,
            routine_payload_shape: timeoutRoutinePayloadShape,
            routine_preview_items_count: timeoutRoutineCandidates.length,
            routine_product_enrichment_deferred: Boolean(timeoutRoutinePreviewCard),
            analysis_mode: 'timeout_degraded',
            reco_artifact_eligible: false,
            product_surface_mode: 'guidance_only',
            artifact_gate: {
              tier: 'ineligible',
              reason: 'artifact_missing',
              missing_core: ['skinType', 'sensitivity', 'barrierStatus', 'goals'],
            },
            gate_relax_mode: AURORA_RULE_RELAX_MODE,
            low_quality_tolerated: Boolean(AURORA_RULE_RELAX_AGGRESSIVE),
            degrade_reason: 'analysis_budget_timeout',
            report_failure_reason: 'ANALYSIS_BUDGET_TIMEOUT',
            report_stage_budget_ms: 0,
            report_stage_elapsed_ms: timeoutElapsedMs,
            report_stage_outcome: 'analysis_budget_timeout',
            report_stage_attempts: 0,
            budget_abort_stage: 'analysis',
            ...timeoutStageTimingMeta,
          },
        });
        const degradedGuardrail = await applyProductIntelGuardrailsToEnvelope({
          envelope,
          ctx,
          profile: null,
          language: ctx.lang,
          qaRuntime: {
            budget_ms: AURORA_BFF_ANALYSIS_BUDGET_MS,
            started_at_ms: analysisBudgetStartedAtMs,
            min_budget_ms: AURORA_LLM_QA_MIN_REMAINING_BUDGET_MS,
            qa_mode: AURORA_LLM_QA_MODE,
            qa_provider: AURORA_LLM_SINGLE_PROVIDER,
            allow_openai_fallback: AURORA_LLM_OPENAI_FALLBACK_ENABLED,
            product_qa_mode: AURORA_PRODUCT_RELEVANCE_QA_MODE,
          },
        });
        if (degradedGuardrail && Array.isArray(degradedGuardrail.rejected) && degradedGuardrail.rejected.length > 0) {
          persistRejectedCatalogCandidates(ctx, degradedGuardrail.rejected);
        }
        const degradedEnvelope = attachAnalysisResponseTiming({
          envelope: degradedGuardrail && degradedGuardrail.envelope ? degradedGuardrail.envelope : envelope,
          startedAtMs: analysisBudgetStartedAtMs,
        });
        emitAnalysisGuardrailObservability({
          envelope: degradedEnvelope,
          ctx,
          logger,
          shadowRun: false,
        });
        const finalizedDegradedEnvelope = applyBeautyCanonicalOwnershipToEnvelope({
          envelope: degradedEnvelope,
          route: 'analysis_skin',
          assistantText:
            isPlainObject(degradedEnvelope.assistant_message) && typeof degradedEnvelope.assistant_message.content === 'string'
              ? degradedEnvelope.assistant_message.content
              : '',
          policyMeta: { intent_canonical: 'analysis_skin' },
        });
        applyAnalysisResponseTimingHeaders(res, finalizedDegradedEnvelope);
        return res.json(finalizedDegradedEnvelope);
      }

      if (shadowRunV2) {
        setImmediate(() => {
          runOnce({ pipelineVersion: 'v2', persistLastAnalysis: false, shadowRun: true }).catch((err) => {
            logger?.warn({ err: err && err.message ? err.message : String(err) }, 'aurora bff: v2 shadow run failed');
          });
        });
      }

      if (output && output.skip_product_intel_guardrails) {
        const skipGuardrailEnvelope = attachAnalysisResponseTiming({
          envelope: output.envelope,
          startedAtMs: analysisBudgetStartedAtMs,
        });
        const finalizedSkipGuardrailEnvelope = applyBeautyCanonicalOwnershipToEnvelope({
          envelope: skipGuardrailEnvelope,
          route: 'analysis_skin',
          assistantText:
            isPlainObject(skipGuardrailEnvelope.assistant_message) && typeof skipGuardrailEnvelope.assistant_message.content === 'string'
              ? skipGuardrailEnvelope.assistant_message.content
              : '',
          policyMeta: { intent_canonical: 'analysis_skin' },
        });
        applyAnalysisResponseTimingHeaders(res, finalizedSkipGuardrailEnvelope);
        return res.json(finalizedSkipGuardrailEnvelope);
      }

      const guardrailResult = await applyProductIntelGuardrailsToEnvelope({
        envelope: output.envelope,
        ctx,
        profile: output && output.profile_for_guardrails ? output.profile_for_guardrails : null,
        language: ctx.lang,
        qaRuntime: {
          budget_ms: AURORA_BFF_ANALYSIS_BUDGET_MS,
          started_at_ms: analysisBudgetStartedAtMs,
          min_budget_ms: AURORA_LLM_QA_MIN_REMAINING_BUDGET_MS,
          qa_mode: AURORA_LLM_QA_MODE,
          qa_provider: AURORA_LLM_SINGLE_PROVIDER,
          allow_openai_fallback: AURORA_LLM_OPENAI_FALLBACK_ENABLED,
          product_qa_mode: AURORA_PRODUCT_RELEVANCE_QA_MODE,
        },
      });
      if (guardrailResult && Array.isArray(guardrailResult.rejected) && guardrailResult.rejected.length > 0) {
        persistRejectedCatalogCandidates(ctx, guardrailResult.rejected);
      }
      const finalEnvelope = guardrailResult && guardrailResult.envelope ? guardrailResult.envelope : output.envelope;
      const timedFinalEnvelope = attachAnalysisResponseTiming({
        envelope: finalEnvelope,
        startedAtMs: analysisBudgetStartedAtMs,
      });
      emitAnalysisGuardrailObservability({
        envelope: timedFinalEnvelope,
        ctx,
        logger,
        shadowRun: false,
      });
      if (isPlainObject(timedFinalEnvelope) && Array.isArray(timedFinalEnvelope.cards)) {
        const storyCard = timedFinalEnvelope.cards.find(
          (card) => isPlainObject(card) && String(card.type || '').trim().toLowerCase() === 'analysis_story_v2',
        );
        if (storyCard && isPlainObject(storyCard.payload)) {
          const realignedText = buildAssistantMessageFromStoryV2(storyCard.payload, { language: ctx.lang });
          if (realignedText) {
            storyCard.payload = {
              ...storyCard.payload,
              summary: realignedText,
            };
            timedFinalEnvelope.assistant_message = makeAssistantMessage(realignedText);
          }
          const sessionPatch = isPlainObject(timedFinalEnvelope.session_patch) ? timedFinalEnvelope.session_patch : {};
          const meta = isPlainObject(sessionPatch.meta) ? { ...sessionPatch.meta } : {};
          const photoRefs = Array.isArray(output && output.photo_refs) ? output.photo_refs : [];
          meta.analysis_context = {
            analysis_origin: photoRefs.length > 0 ? 'photo' : 'profile',
            photo_refs: photoRefs,
            source_card_type: 'analysis_story_v2',
            analysis_story_snapshot: storyCard.payload,
          };
          sessionPatch.meta = meta;
          timedFinalEnvelope.session_patch = sessionPatch;
          const persistedAnalysisSnapshot = buildPersistableLastAnalysisSnapshot({
            analysis: output && output.analysis_for_persist ? output.analysis_for_persist : null,
            latestRecoContext: sessionPatch && sessionPatch.state ? sessionPatch.state.latest_reco_context : null,
            profileSummary: sessionPatch && isPlainObject(sessionPatch.profile) ? sessionPatch.profile : null,
          });

          setImmediate(() => {
            saveLastAnalysisForIdentity(
              { auroraUid: identity.auroraUid, userId: identity.userId },
              {
                analysis: { ...(persistedAnalysisSnapshot || {}), analysis_story_snapshot: storyCard.payload },
                lang: ctx.lang,
              },
            ).catch(() => {});
          });
        }
      }
      const syncedFinalEnvelope = refreshLatestRecoContextFromAnalysisEnvelope(timedFinalEnvelope);
      const finalizedAnalysisEnvelope = applyBeautyCanonicalOwnershipToEnvelope({
        envelope: syncedFinalEnvelope,
        route: 'analysis_skin',
        assistantText:
          isPlainObject(syncedFinalEnvelope.assistant_message) && typeof syncedFinalEnvelope.assistant_message.content === 'string'
            ? syncedFinalEnvelope.assistant_message.content
            : '',
        policyMeta: { intent_canonical: 'analysis_skin' },
      });
      applyAnalysisResponseTimingHeaders(res, finalizedAnalysisEnvelope);
      return res.json(finalizedAnalysisEnvelope);
    } catch (err) {
      const status = err.status || 500;
      logger?.error(
        {
          err: err && err.message ? err.message : String(err),
          code: err && err.code ? err.code : null,
          stack: err && err.stack ? String(err.stack) : null,
          request_id: ctx.request_id,
          trace_id: ctx.trace_id,
          aurora_uid: ctx.aurora_uid,
        },
        'aurora bff: /v1/analysis/skin failed',
      );
      const envelope = buildEnvelope(ctx, {
        assistant_message: makeAssistantMessage('Failed to generate skin analysis.'),
        suggested_chips: [],
        cards: [{ card_id: `err_${ctx.request_id}`, type: 'error', payload: { error: err.code || 'ANALYSIS_FAILED' } }],
        session_patch: {},
        events: [makeEvent(ctx, 'error', { code: err.code || 'ANALYSIS_FAILED' })],
      });
      return res.status(status).json(envelope);
    }
  });

  mountTravelPlansRoutes(app, {
    logger,
    requireAuroraUid,
    resolveIdentity,
    classifyStorageError,
  });

  mountActivityRoutes(app, {
    logger,
    requireAuroraUid,
    resolveIdentity,
    classifyStorageError,
  });

  try {
    requiredRouteContractsHealth = Object.freeze({
      checked: true,
      ...assertRequiredRouteContracts(app, TRAVEL_PLANS_REQUIRED_ROUTE_CONTRACTS, {
        scope: 'travel_plans',
      }),
    });
  } catch (err) {
    requiredRouteContractsHealth = Object.freeze({
      checked: true,
      ok: false,
      scope: 'travel_plans',
      required_routes: TRAVEL_PLANS_REQUIRED_ROUTE_CONTRACTS.map((item) => ({ ...item })),
      missing_routes: Array.isArray(err && err.missing_routes) ? err.missing_routes : [],
    });
    logger?.error?.(
      {
        err: err && err.message ? err.message : String(err),
        code: err && err.code ? err.code : null,
        missing_routes: requiredRouteContractsHealth.missing_routes,
      },
      'aurora bff: required route contracts check failed',
    );
    throw err;
  }

  app.get('/v1/session/bootstrap', async (req, res) => {
    const ctx = buildRequestContext(req, {});
    try {
      requireAuroraUid(ctx);
      let profile = null;
      let recentLogs = [];
      let latestArtifact = null;
      let latestIngredientPlan = null;
      let dbError = null;
      const identity = await resolveIdentityForRoute(req, ctx);
      const identityRef = { auroraUid: identity.auroraUid, userId: identity.userId };

      try {
        profile = await runAuroraTimedOperation(
          () => getProfileForIdentityForRoute(identityRef),
          { timeoutMs: getAuroraStorageReadTimeoutMs(), timeoutCode: 'AURORA_BOOTSTRAP_PROFILE_TIMEOUT' },
        );
      } catch (err) {
        dbError = dbError || err;
        logger?.warn({ err: err.code || err.message, request_id: ctx.request_id }, 'aurora bff: bootstrap profile load failed');
      }

      try {
        recentLogs = await runAuroraTimedOperation(
          () => getRecentSkinLogsForIdentityForRoute(identityRef, 7),
          { timeoutMs: getAuroraStorageReadTimeoutMs(), timeoutCode: 'AURORA_BOOTSTRAP_LOGS_TIMEOUT' },
        );
      } catch (err) {
        dbError = dbError || err;
        logger?.warn({ err: err.code || err.message, request_id: ctx.request_id }, 'aurora bff: bootstrap recent logs load failed');
      }

      try {
        latestArtifact = await runAuroraTimedOperation(
          () => loadLatestDiagnosisArtifactForRouteWithOverride({ identity, session: null, ctx, logger }),
          { timeoutMs: getAuroraBootstrapArtifactTimeoutMs(), timeoutCode: 'AURORA_BOOTSTRAP_ARTIFACT_TIMEOUT' },
        );
      } catch (err) {
        dbError = dbError || err;
        logger?.warn({ err: err.code || err.message, request_id: ctx.request_id }, 'aurora bff: bootstrap artifact load failed');
      }

      const latestArtifactId = pickFirstTrimmed(latestArtifact && latestArtifact.artifact_id);
      if (latestArtifactId) {
        try {
          const existingPlan = await runAuroraTimedOperation(
            () => getIngredientPlanByArtifactIdForRoute({ artifactId: latestArtifactId }),
            { timeoutMs: getAuroraStorageReadTimeoutMs(), timeoutCode: 'AURORA_BOOTSTRAP_INGREDIENT_PLAN_TIMEOUT' },
          );
          if (existingPlan && existingPlan.plan_json && typeof existingPlan.plan_json === 'object') {
            latestIngredientPlan = {
              ...existingPlan.plan_json,
              plan_id: existingPlan.plan_id,
              created_at: existingPlan.created_at || existingPlan.plan_json.created_at,
            };
          }
        } catch (err) {
          dbError = dbError || err;
          logger?.warn(
            { err: err.code || err.message, request_id: ctx.request_id, artifact_id: latestArtifactId },
            'aurora bff: bootstrap ingredient plan load failed',
          );
        }
      }

      const profileSummary = summarizeProfileForContext(profile);
      const isReturning = Boolean(profile) || recentLogs.length > 0;
      const checkinDue = isCheckinDue(recentLogs);
      const lastAnalysisLatestRecoContext =
        !dbError
          ? extractLatestRecoContextSnapshotFromLastAnalysis(profile && profile.lastAnalysis)
          : null;
      const latestAnalysisContext =
        !dbError
          ? buildAnalysisContextSnapshotForRoute({
              latestArtifact,
              profile,
              recentLogs,
            })
          : null;
      const bootstrapLatestRecoContext =
        !dbError
          ? mergeIngredientRecoContextValue(
              buildLatestRecoContextFromAnalysisArtifacts({
                ingredientPlan: latestIngredientPlan,
                profileSummary,
                artifactId: pickFirstTrimmed(latestArtifact && latestArtifact.artifact_id),
                contextOrigin: 'latest_artifact',
                analysisSource: pickFirstTrimmed(
                  latestArtifact && latestArtifact.analysis_context && latestArtifact.analysis_context.analysis_source,
                  latestArtifact && latestArtifact.analysis_source,
                ),
                usePhoto: Boolean(
                  latestArtifact && (
                    latestArtifact.use_photo === true
                    || (latestArtifact.analysis_context && latestArtifact.analysis_context.use_photo === true)
                  ),
                ),
                usedPhotos: Boolean(
                  latestArtifact && (
                    (latestArtifact.analysis_context && latestArtifact.analysis_context.used_photos === true)
                    || latestArtifact.use_photo === true
                  ),
                ),
                photoQualityGrade: pickFirstTrimmed(
                  latestArtifact && latestArtifact.analysis_context && latestArtifact.analysis_context.quality_grade,
                  latestArtifact
                    && latestArtifact.analysis_context
                    && latestArtifact.analysis_context.quality_report
                    && latestArtifact.analysis_context.quality_report.photo_quality
                    && latestArtifact.analysis_context.quality_report.photo_quality.grade,
                  latestArtifact
                    && latestArtifact.quality_report
                    && latestArtifact.quality_report.photo_quality
                    && latestArtifact.quality_report.photo_quality.grade,
                ),
              }),
              lastAnalysisLatestRecoContext,
            )
          : null;

      const cards = [
        {
          card_id: `bootstrap_${ctx.request_id}`,
          type: 'session_bootstrap',
          payload: {
            profile: profileSummary,
            recent_logs: recentLogs,
            checkin_due: checkinDue,
            is_returning: isReturning,
            db_ready: !dbError,
            latest_analysis_context: latestAnalysisContext,
          },
          ...(dbError
            ? { field_missing: [{ field: 'profile', reason: 'db_not_configured_or_unavailable' }] }
            : {}),
        },
      ];

      const events = [makeEvent(ctx, 'state_entered', { state: ctx.state || 'unknown', trigger_source: ctx.trigger_source })];
      const envelope = buildEnvelope(ctx, {
        assistant_message: null,
        suggested_chips: [],
        cards,
        session_patch: {
          profile: profileSummary,
          recent_logs: recentLogs,
          checkin_due: checkinDue,
          is_returning: isReturning,
          ...(latestAnalysisContext ? { meta: { analysis_context_snapshot: latestAnalysisContext } } : {}),
          ...(bootstrapLatestRecoContext ? { state: { latest_reco_context: bootstrapLatestRecoContext } } : {}),
        },
        events,
      });
      return res.json(applyBeautyCanonicalOwnershipToEnvelope({
        envelope,
        route: 'session_bootstrap',
        policyMeta: { intent_canonical: 'session_bootstrap' },
      }));
    } catch (err) {
      const status = err.status || 500;
      logger?.warn({ err: err.message, status }, 'session bootstrap failed');
      const envelope = buildEnvelope(ctx, {
        assistant_message: makeAssistantMessage('Failed to bootstrap session.'),
        suggested_chips: [],
        cards: [{ card_id: `err_${ctx.request_id}`, type: 'error', payload: { error: err.code || 'BOOTSTRAP_FAILED' } }],
        session_patch: {},
        events: [makeEvent(ctx, 'error', { code: err.code || 'BOOTSTRAP_FAILED' })],
      });
      return res.status(status).json(envelope);
    }
  });

